const TECHS = [
  // ─── Lower Paleolithic ─────────────────────────────────────────
  { id: "bipedal-gait", name: "Bipedal Locomotion", era: "lower-paleo", category: "subsistence",
    year: "~6 Mya", prereqs: [],
    desc: "Habitual upright walking on two legs, appearing in early hominins by ~6 million years ago and unmistakable in Australopithecus afarensis ('Lucy', 3.2 Mya). Skeletal markers — angled femurs, an S-curved spine, valgus knees, and arched feet — distinguish hominins from quadruped apes. Bipedalism freed the hands for tool use and load-carrying, reduced midday heat exposure on the African savanna, and is the postural foundation that every later hominin trait builds on." },
  { id: "wooden-club", name: "Wooden Club", era: "lower-paleo", category: "weapons",
    year: "~3 Mya", prereqs: [],
    desc: "Hand-held wooden bludgeons, the simplest weapon. Wood rots without trace, but chimpanzee analogues, blunt-force trauma in early hominin remains, and ethnographic evidence make clubs almost certainly older than the Oldowan stone industry. They probably remained the standard close-quarters weapon for two million years before composite spears displaced them, and they still recur as ceremonial and military objects (mace, war club, shillelagh) wherever metal is scarce." },
  { id: "gestural-communication", name: "Gestural Communication", era: "lower-paleo", category: "social",
    year: "~3 Mya", prereqs: [],
    desc: "Coordinated signaling with hands, faces, posture, and vocal calls — capabilities present in apes but elaborated by hominins into intentional reference, deictic pointing, and pantomime. The mirror-neuron and hand-control circuitry that supports gesture overlaps anatomically with that of speech, and many linguists argue gesture preceded vocal language by over a million years before brain growth and a descended larynx made articulate sound possible." },
  { id: "oldowan", name: "Oldowan Stone Tools", era: "lower-paleo", category: "tools",
    year: "~3.3 Mya", prereqs: [],
    desc: "Simple chipped pebble cores and sharp flakes struck from cobbles by direct hammerstone percussion. The oldest examples at Lomekwi 3 (Kenya, 3.3 Mya) actually predate the genus Homo, but the industry is best known from Olduvai Gorge where Mary and Louis Leakey identified it in the 1930s. Used for butchering carcasses, processing plants, and cracking bones for marrow, Oldowan tools persisted nearly two million years and established the stone-on-stone reduction tradition underlying every later lithic technology." },
  { id: "scavenging", name: "Organized Scavenging", era: "lower-paleo", category: "subsistence",
    year: "~2.6 Mya", prereqs: ["oldowan"],
    desc: "Aggressive 'power scavenging' from kills left by leopards, hyenas, and saber-tooth cats, using Oldowan flakes to slice through hide and crack long bones for marrow. At Bouri (Ethiopia, ~2.5 Mya), hominin cut-marks overlie carnivore tooth-marks, showing humans took the carcass after the original predator. This high-fat, high-calorie diet, unavailable to any vegetarian primate, is the metabolic foundation that allowed the brain to expand from ~450 cc in early Homo toward the modern range." },
  { id: "persistence-hunting", name: "Persistence Hunting", era: "lower-paleo", category: "weapons",
    year: "~2 Mya", prereqs: ["bipedal-gait"],
    desc: "Endurance running that drives ungulate prey to heat exhaustion under midday sun. Humans uniquely combine sweat cooling, hairlessness, narrow waists, and long springy Achilles tendons — capabilities that emerge in Homo erectus by ~2 Mya. Anthropologists Bramble and Lieberman argue this hunting style preceded projectile weapons and shaped the entire modern human body plan. Persistence hunts of antelope are still occasionally practiced by the San in the Kalahari." },
  { id: "fire-use", name: "Use of Fire", era: "lower-paleo", category: "tools",
    year: "~1.5 Mya", prereqs: [],
    desc: "Tending fire from lightning strikes or grass burns for warmth, light, predator deterrence, and softening tough plant foods. Burnt bone and ash at Wonderwerk Cave (South Africa, ~1 Mya) and Gesher Benot Ya'aqov (Israel, 790 kya) push the date well into Homo erectus territory. Whether erectus could make fire is debated, but tending it for hundreds of thousands of years was enough to build the dependence on cooked food that the modern human gut anatomy reflects." },
  { id: "acheulean", name: "Acheulean Hand Axes", era: "lower-paleo", category: "tools",
    year: "~1.76 Mya", prereqs: ["oldowan"],
    desc: "Bifacially worked teardrop hand-axes and cleavers, requiring 30+ controlled blows to a flint nodule with carefully judged angles and force. Made by Homo erectus from ~1.76 Mya at Kokiselei (Kenya), the form persists for over a million years across three continents — a stability unmatched by any later technology. Their symmetry implies an internal mental template, and the long apprenticeship needed to make one suggests demonstration-based teaching, possibly even proto-language." },
  { id: "windbreaks", name: "Windbreaks & Camps", era: "lower-paleo", category: "shelter",
    year: "~1.8 Mya", prereqs: [],
    desc: "Temporary brush windbreaks built around hearths — the first identifiable home-bases where butchery, tool-making, and child-rearing happened in one fixed spot. Ring-shaped scatters of debris at FxJj 50 (Koobi Fora, Kenya, 1.6 Mya) and post-hole arrangements at Terra Amata (France, 380 kya) imply repeated stays. The shift from 'wherever the carcass is' to 'a place we return to' reorganizes social life around a camp and is a precondition for all later sedentism." },
  { id: "wooden-spear", name: "Wooden Thrusting Spear", era: "lower-paleo", category: "weapons",
    year: "~400 kya", prereqs: ["acheulean", "wooden-club"],
    desc: "Two-meter spears of spruce and pine, fire-hardened and balanced for thrusting and short throws. Eight perfectly preserved examples were excavated from a 400-kya peat bog at Schöningen (Germany), alongside the butchered bones of more than twenty wild horses. The find ended a long argument: pre-modern humans were active hunters of large game, not opportunistic scavengers. Coordinating an ambush of a herd implies organized planning and division of roles — proto-language at least, possibly something more." },
  { id: "fire-making", name: "Fire-Making", era: "lower-paleo", category: "tools",
    year: "~400 kya", prereqs: ["fire-use"],
    desc: "Producing fire on demand by friction (a drilled spindle in a fire-board) or percussion (striking pyrite or marcasite against flint). Black flint-and-pyrite striking kits appear in Mousterian Neanderthal sites by ~50 kya, and ethnographic evidence makes friction methods deeply familiar across every Holocene culture. Once fire is replicable rather than tended, dependence on natural ignition collapses and humans can colonize cold regions — a precondition for later expansion into northern Eurasia and eventually the Americas." },
  { id: "cooking", name: "Cooking", era: "lower-paleo", category: "subsistence",
    year: "~400 kya", prereqs: ["fire-making", "scavenging"],
    desc: "Heat-processing food to break down starches, denature proteins, and kill pathogens. Richard Wrangham's 'cooking hypothesis' argues that the calorie surplus from cooked food allowed Homo erectus to grow a 50% larger brain on a smaller gut: cooked food extracts more energy with less digestive work. The earliest hearth-like residues at Wonderwerk Cave are ~1 Mya, but cooking only becomes routine archaeologically by ~400 kya. Modern humans cannot survive long-term on raw wild food." },
  { id: "rockshelter-occupation", name: "Cave & Rockshelter Occupation", era: "lower-paleo", category: "shelter",
    year: "~1 Mya", prereqs: ["fire-use"],
    desc: "Habitual occupation of caves, rock overhangs, and karst entrances as long-term home-bases. Wonderwerk Cave (South Africa, ~1 Mya), Zhoukoudian (China, ~770 kya), and Atapuerca (Spain, ~800 kya) preserve repeated hearths, accumulated debris, and sleeping zones across thousands of generations. Caves provide year-round thermal stability, defensible sleeping ground, and natural smoke vents — a step up from open-air windbreaks that allows hominins to settle colder, wetter latitudes and accumulate the deep stratigraphies archaeologists rely on." },
  { id: "cooperative-hunting", name: "Ambush & Cooperative Hunting", era: "lower-paleo", category: "weapons",
    year: "~500 kya", prereqs: ["wooden-club", "gestural-communication"],
    desc: "Coordinated group hunting in which scouts, drivers, and spear-bearers play distinct roles to corner large prey at chokepoints, marshes, or cliffs. The Schöningen horse kills (Germany, ~400 kya) and the Boxgrove rhinoceros (England, ~500 kya) preserve butchery patterns consistent with planned ambushes rather than opportunistic encounters. Cooperative hunting demands shared mental models of the prey's behavior, role assignment, and signaling — capabilities that pre-date and likely drove the evolution of articulate speech." },

  // ─── Middle Paleolithic ────────────────────────────────────────
  { id: "digging-stick", name: "Digging Stick", era: "middle-paleo", category: "tools",
    year: "~300 kya", prereqs: ["oldowan"],
    desc: "Fire-sharpened wooden poles used to unearth tubers, roots, bulbs, and small game from burrows. Wood rarely preserves, but tooth-wear patterns in early hominins, residue analysis, and the universal presence of digging sticks among modern foragers (San, Hadza, Aboriginal Australians) make this almost certainly the most important wooden tool of the Pleistocene. Underground storage organs are calorie-dense, drought-resilient, and inaccessible to most other primates — digging sticks unlocked a major food category." },
  { id: "levallois", name: "Levallois Technique", era: "middle-paleo", category: "tools",
    year: "~300 kya", prereqs: ["acheulean"],
    desc: "A prepared-core knapping technique in which the toolmaker shapes a flint nodule with preliminary blows so that a single final strike removes a flake of predictable size and shape. Appearing ~300 kya in the Mousterian and Middle Stone Age industries, Levallois reduction requires planning several steps ahead and is taken as evidence of a major cognitive shift. The same principles still underlie modern stone-tool production by knappers worldwide." },
  { id: "hafting", name: "Hafting", era: "middle-paleo", category: "tools",
    year: "~200 kya", prereqs: ["levallois"],
    desc: "Binding stone points and blades to wooden shafts using sinew, plant fiber, pitch, or birch tar. Hafted Levallois points appear by ~200 kya, transforming hand-held tools into spears, axes, and adzes whose force is multiplied by a long lever arm. The technique requires foresight to assemble parts that look nothing like the finished tool, and is the basis of every composite implement that follows — from Neolithic sickles to medieval halberds." },
  { id: "birch-tar", name: "Birch-Bark Tar", era: "middle-paleo", category: "tools",
    year: "~200 kya", prereqs: ["fire-making", "levallois"],
    desc: "Heat-distilled adhesive made by smoldering birch bark in low-oxygen pits, producing a thick black resin that hardens on cooling. Königsaue (Germany, ~80 kya) and earlier Italian sites yield birch tar lumps with Neanderthal fingerprints. As the world's first synthetic material — its production requires controlled temperatures around 350°C — it is direct evidence of pyrotechnical sophistication in pre-modern humans, and is still used in traditional bowmaking." },
  { id: "hide-clothing", name: "Hide Clothing", era: "middle-paleo", category: "shelter",
    year: "~170 kya", prereqs: ["acheulean"],
    desc: "Scraped, softened, and stitched animal hides used as garments, footwear, and shelter coverings. Although hides decompose, dedicated hide-scrapers (steep-edged 'side-scrapers' and 'end-scrapers') become abundant by ~170 kya, and lice genetics independently date the divergence of body lice from head lice — implying clothing — to roughly the same window. Tailored clothing is the technology that lets hominins survive winters in glacial Eurasia and eventually colonize Siberia and the Americas." },
  { id: "shellfishing", name: "Shellfish Gathering", era: "middle-paleo", category: "subsistence",
    year: "~165 kya", prereqs: ["cooking"],
    desc: "Coastal foraging for mussels, limpets, oysters, and crabs at sites like Pinnacle Point (South Africa, ~165 kya). Marine resources are predictable, accessible, and rich in long-chain omega-3 fatty acids that support brain growth. Shellfish heaps (middens) are also the first evidence of large-scale resource mapping by tide tables — humans had to plan around lunar cycles. Coastal routes likely guided the migration of modern humans out of Africa around the Indian Ocean rim." },
  { id: "pigments", name: "Pigments & Body Paint", era: "middle-paleo", category: "social",
    year: "~160 kya", prereqs: [],
    desc: "Powdered and bound red ochre (iron oxide), yellow ochre, and black manganese used for body decoration, hide processing, and possibly symbolic marking. Engraved ochre blocks at Blombos Cave (~75–100 kya) carry deliberate cross-hatched patterns, taken by many archaeologists as the oldest evidence of abstract symbolic thought. Pigment processing also requires recipes and storage — early evidence of recipe-style technical knowledge." },
  { id: "composite-spear", name: "Composite Spear", era: "middle-paleo", category: "weapons",
    year: "~150 kya", prereqs: ["hafting", "wooden-spear"],
    desc: "Wooden shafts tipped with hafted stone points (Levallois or pointed flakes), throwable at ~15 m or thrust at close range. Stone-tipped spears appear by ~150 kya in Africa and are used by both modern humans and Neanderthals. Compared to fire-hardened wooden spears, the stone tip pierces hide and bone more reliably and stays sharp through repeated use. Standoff distance from large prey rises substantially, reducing hunter casualties." },
  { id: "shell-beads", name: "Shell Beads", era: "middle-paleo", category: "social",
    year: "~140 kya", prereqs: ["pigments", "shellfishing"],
    desc: "Pierced sea-shells (Nassarius and Glycymeris) strung as necklaces or sewn onto clothing — deliberately selected, sometimes imported from coasts hundreds of kilometers away, and often colored with ochre. Found at Skhul (Israel, ~100 kya) and Taforalt (Morocco, ~82 kya), they are the earliest unambiguous personal ornaments and identity markers, implying both symbolic communication and trade or kinship networks of substantial reach." },
  { id: "water-flask", name: "Water Containers", era: "middle-paleo", category: "tools",
    year: "~120 kya", prereqs: ["shellfishing"],
    desc: "Punctured, polished ostrich-eggshell flasks engraved with identifying marks, used to carry water across arid landscapes. Found from Diepkloof Rock Shelter (South Africa, ~60 kya) onward in regular cached sets, they are durable, repairable, and far lighter than gourds or pottery. Portable water means foragers can cross dry intervals between water sources, expanding usable territory and connecting otherwise isolated wet patches into a functional landscape." },
  { id: "burial", name: "Deliberate Burial", era: "middle-paleo", category: "social",
    year: "~120 kya", prereqs: ["pigments"],
    desc: "Intentional interment of the dead in prepared graves, sometimes accompanied by ochre, flowers, or grave goods. Sites like Qafzeh (Israel, ~100 kya), Shanidar (Iraq, Neanderthal, ~70 kya), and Sungir (Russia, ~30 kya, with thousands of beaded ornaments) suggest beliefs about the dead extending beyond mere disposal. Burial is the earliest archaeologically visible practice that strongly implies symbolic thought about persons and possibly an afterlife." },
  { id: "proto-language", name: "Proto-Language", era: "middle-paleo", category: "social",
    year: "~100 kya", prereqs: ["gestural-communication", "cooking"],
    desc: "Spoken communication beyond simple alarm calls, with combinable units and reference to absent things. The hyoid bone in Kebara Neanderthal anatomy, FOXP2 gene variants shared with Neanderthals, and the planning required for Schöningen-style cooperative hunting all point to articulate speech well before modern humans appeared. Whether Neanderthals had fully syntactic language is still debated, but most linguists place some form of language at or before 500 kya." },
  { id: "early-bone-tools", name: "Early Bone Tools", era: "lower-paleo", category: "tools",
    year: "~1.5 Mya", prereqs: ["oldowan"],
    desc: "Shaped bone, antler, and tusk used as soft hammers for retouching stone, as wedges for splitting wood, and as digging or burnishing tools. The earliest specimens are from Swartkrans (South Africa, ~1.5–1.8 Mya), where Backwell and d'Errico (2001) showed that polished bone fragments had been used to dig into termite mounds — the oldest direct evidence of bone tool use. Later examples include Boxgrove (England, ~500 kya) and the lissoirs (hide-burnishers) made by Neanderthals at Pech-de-l'Azé and Abri Peyrony (France, ~50 kya), which are still used in their original form by leather-workers today. Bone preceded the systematic Upper Paleolithic bone industry by well over a million years." },
  { id: "sling-stones", name: "Sling & Throwing Stones", era: "middle-paleo", category: "weapons",
    year: "~200 kya", prereqs: [],
    desc: "Selected, sometimes shaped river cobbles hurled by hand or whirled in a leather-and-cordage sling. Stockpiles of suspiciously uniform fist-sized stones in Middle and Upper Paleolithic sites — and the universal presence of the sling among recent foragers and pastoralists — make a Paleolithic origin almost certain, although organic slings rarely preserve. A trained slinger can outrange a bow and the projectiles cost nothing, making it the cheapest standoff weapon in human history and the basis of every later sling, staff-sling, and trebuchet." },
  { id: "snares-traps", name: "Snares & Traps", era: "middle-paleo", category: "subsistence",
    year: "~100 kya", prereqs: ["digging-stick"],
    desc: "Cordage nooses, deadfalls, pit-traps, and spring-snares that capture small game, birds, and fish without a hunter present. Traps multiply effective hunting effort — one person can tend dozens — and disproportionately yield the small mammals (hares, rodents, fowl) that bulk up forager diets. Indirect evidence comes from preserved cordage, weighted pit features, and the dramatic rise of small-game bones in late Middle Paleolithic faunal assemblages, which Mary Stiner and others link to demographic packing and the 'Broad Spectrum Revolution.'" },

  // ─── Upper Paleolithic ─────────────────────────────────────────
  { id: "rafts", name: "Rafts & Dugouts", era: "upper-paleo", category: "transport",
    year: "~50 kya", prereqs: [],
    desc: "Bound-log or bamboo rafts and primitive dugouts capable of crossing open water beyond sight of land. The colonization of Sahul (Australia + New Guinea) by ~50–65 kya required at least eight sea crossings of 50–100 km, with one stretch of ~90 km. These voyages predate any other evidence of seafaring by tens of thousands of years and imply not just craft but planning, group transport, and confidence to leave a known coast." },
  { id: "blade-tech", name: "Blade Technology", era: "upper-paleo", category: "tools",
    year: "~50 kya", prereqs: ["levallois"],
    desc: "Long, narrow flakes (length at least twice width) struck systematically from prismatic cores prepared with a striking platform. Blade industries appear in Africa by ~70 kya and dominate Eurasia by ~50 kya during the Upper Paleolithic transition. They yield five times as much cutting edge per kilogram of stone as Mousterian flakes, making lithic raw material go further and enabling more specialized tools (burins, end-scrapers, backed knives) cut from a single core." },
  { id: "bone-tools", name: "Bone & Antler Tools", era: "upper-paleo", category: "tools",
    year: "~45 kya", prereqs: ["blade-tech"],
    desc: "Awls, needles, points, harpoons, and shafts shaped from bone, antler, ivory, and tooth — materials largely ignored by earlier industries despite their toughness and workability. The Aurignacian (~45 kya) and Solutrean (~22 kya) made bone-working a major industry. Bone holds detail better than most stones, allowing decoration, and enables tools (eyed needles, barbed harpoons) impossible in stone alone." },
  { id: "needles", name: "Eyed Needles", era: "upper-paleo", category: "tools",
    year: "~40 kya", prereqs: ["bone-tools", "hide-clothing"],
    desc: "Bone or ivory needles with drilled or carved eyes, allowing thread to pull through layers of hide and produce fitted, layered, and closeable garments. The earliest known examples come from Denisova Cave (Siberia, ~50 kya) and the Aurignacian. Tailored clothing — as opposed to draped hides — sealed body heat far more effectively and is the technological prerequisite for surviving Last Glacial Maximum winters in northern Eurasia." },
  { id: "cave-art", name: "Cave Painting", era: "upper-paleo", category: "social",
    year: "~40 kya", prereqs: ["pigments"],
    desc: "Figurative paintings and engravings on cave walls, rendered in ochre, charcoal, and manganese, often with sophisticated technique: shading, perspective, and movement implied by repeated outlines. Sulawesi (Indonesia) holds dated examples ~45 kya; Chauvet (France) was painted ~36 kya; Lascaux is ~17 kya. The art is typically deep underground and depicts animals far more often than humans, suggesting ritual rather than decorative function." },
  { id: "flute", name: "Bone Flute", era: "upper-paleo", category: "social",
    year: "~40 kya", prereqs: ["bone-tools"],
    desc: "Flutes carved from bird bone (vulture, swan) and mammoth ivory, with finger holes producing a usable musical scale. The Hohle Fels and Geißenklösterle flutes from Germany date to ~40 kya. The Divje Babe Cave bear-bone flute, attributed to Neanderthals at ~50 kya, is contested but plausible. Music — like art — has no direct survival function, making the flutes some of the earliest evidence of leisure, ritual, or aesthetic experience." },
  { id: "bow-drill", name: "Bow Drill", era: "upper-paleo", category: "tools",
    year: "~40 kya", prereqs: ["fire-making", "bone-tools"],
    desc: "A wooden spindle spun rapidly inside a fire-board by reciprocating motion of a strung bow, generating enough friction heat to ignite tinder. The bow-drill multiplies hand-drill technique by an order of magnitude in speed and reduces fatigue. The same mechanism, scaled up, becomes the lathe and the pump-drill, and the technique is still taught in survival schools and used in some indigenous fire-starting traditions." },
  { id: "tally-bones", name: "Tally Marks", era: "upper-paleo", category: "knowledge",
    year: "~40 kya", prereqs: ["bone-tools"],
    desc: "Notched bones recording counts in groups of fives, tens, or other bases. The Lebombo bone (Eswatini, ~43 kya) carries 29 notches; the Ishango bone (DR Congo, ~20 kya) has groups of marks suggesting more than simple counting — possibly arithmetic or lunar accounting. These are the earliest known mathematical artifacts, predating writing by tens of thousands of years and showing that abstract numerical thought far predated agriculture." },
  { id: "oil-lamp", name: "Oil Lamp", era: "upper-paleo", category: "tools",
    year: "~40 kya", prereqs: ["fire-making", "bone-tools"],
    desc: "Stone basins or scooped flat stones holding rendered animal fat with a moss or lichen wick. Hundreds of lamps were recovered from Lascaux and Altamira where they lit deep-cave painting sessions. Lamps extend the working day past sunset and unlock the use of dark cave interiors, expanding both habitable space and the sites available for ritual or art." },
  { id: "spun-fiber", name: "Spun Fiber & Cordage", era: "middle-paleo", category: "tools",
    year: "~50 kya", prereqs: ["early-bone-tools"],
    desc: "Twisted plant-fiber cordage (flax, nettle, bast) — the foundation of every later rope, net, snare, sling, bowstring, hafting, and woven textile. A 3-ply Neanderthal cord fragment from Abri du Maras (France, ~50 kya; Hardy et al. 2020) is the oldest direct evidence, and dyed twisted flax fibers from Dzudzuana Cave (Georgia, ~30 kya) push the form into the Upper Paleolithic. The universality of cordage among modern foragers and its presupposition by spear-hafting make it almost certainly far older still. Cordage is the most underrated invention in this whole tree." },
  { id: "figurines", name: "Figurines & Sculpture", era: "upper-paleo", category: "social",
    year: "~35 kya", prereqs: ["bone-tools", "pigments"],
    desc: "Three-dimensional carved figures in ivory, antler, stone, and fired clay, depicting humans (often emphatically female), animals, and human-animal hybrids. The Löwenmensch (lion-man) from Hohlenstein-Stadel is ~40 kya; Venus figurines like Willendorf, Dolní Věstoníce, and Lespugue span ~30–25 kya. Their portability — unlike cave art — let them travel, and their stylistic conventions repeat across thousands of kilometers, implying shared symbolic codes." },
  { id: "microliths", name: "Microliths", era: "middle-paleo", category: "tools",
    year: "~65 kya", prereqs: ["levallois"],
    desc: "Tiny standardized blade segments (1–3 cm) snapped from larger blades and embedded in slotted bone or wood handles to make composite tools. The Howiesons Poort industry of southern Africa (~65–58 kya) produced backed crescents and segments — the earliest microlithic technology — and the form re-emerges in Eurasian Upper Paleolithic and spreads globally during the Mesolithic. Microliths are modular: a single broken bit can be swapped without remaking the whole tool, conserving stone and making tool-maintenance far easier." },
  { id: "shamanism", name: "Shamanism", era: "upper-paleo", category: "social",
    year: "~30 kya", prereqs: ["cave-art", "burial"],
    desc: "Ritual specialists believed to mediate between the living and a spirit world through trance, dance, costume, music, and ingested compounds. Shamanic motifs — therianthropes, animal transformation, hand stencils — recur in cave art across Europe, southern Africa, and Australia. The shaman is the first identifiable religious profession and a likely model for later priests, prophets, and healers." },
  { id: "trade-networks", name: "Long-Distance Trade", era: "upper-paleo", category: "economy",
    year: "~30 kya", prereqs: ["figurines", "shell-beads"],
    desc: "Movement of obsidian, marine shell, ochre, ivory, and amber across hundreds of kilometers, sometimes across mountain ranges or arms of sea. By ~30 kya, Aurignacian sites in central Europe contain Mediterranean shell ornaments. Trade implies durable kin and alliance ties between groups: information, mates, and innovations travel along the same routes as the goods, and the networks themselves become the substrate for later civilizations." },
  { id: "atlatl", name: "Spear-Thrower (Atlatl)", era: "upper-paleo", category: "weapons",
    year: "~30 kya", prereqs: ["composite-spear"],
    desc: "A short stick with a hooked end that effectively lengthens the throwing arm, doubling dart range and kinetic energy at impact. Made of bone, antler, or wood and often elaborately carved, atlatls appear by ~30 kya across Europe and persist until the bow displaces them. Inuit and Aztec used them historically, the latter against Spanish armor with surprising effect at short range." },
  { id: "lunar-tally", name: "Lunar Calendar", era: "upper-paleo", category: "knowledge",
    year: "~30 kya", prereqs: ["tally-bones"],
    desc: "Bones marked with sequences of notches that match lunar phase counts (29 or 30 marks per cycle, often grouped). The Blanchard bone (Dordogne, ~30 kya) and several Ishango-style artifacts have been interpreted as lunar calendars by archaeologists like Alexander Marshack. Whether or not specific examples are calendars, regular tracking of the moon by mobile foragers is the bedrock of all later astronomy and timekeeping." },
  { id: "harpoon", name: "Barbed Harpoon", era: "middle-paleo", category: "weapons",
    year: "~90 kya", prereqs: ["early-bone-tools"],
    desc: "Bone or antler points carved with backward-pointing barbs, often with a detachable head and a line, used to take fish, seals, and large birds. The Katanda harpoons (DR Congo, Yellen et al. 1995) date to ~90 kya — pushing barbed-point fishing technology far back into the African Middle Stone Age, tens of millennia before the Eurasian Magdalenian harpoons (~17 kya) once thought to be the earliest. Barbs prevent the prey from escaping after being struck, and detachable heads mean a thrashing animal can't snap the shaft — a meaningful efficiency gain in fishing and aquatic hunting." },
  { id: "tailored-clothing", name: "Sewn Tailored Clothing", era: "upper-paleo", category: "shelter",
    year: "~30 kya", prereqs: ["needles", "spun-fiber", "hide-clothing"],
    desc: "Fitted multi-piece garments — trousers, parkas, mittens, and boots — sewn from cut hide panels with sinew thread through eyed bone needles. Tailored clothing traps a stable layer of warm air against the body and seals the wrists, ankles, and neck against wind, raising the cold-survivable limit by roughly 15–20°C compared to draped hides. The technology, attested at Sungir (Russia, ~30 kya) by tens of thousands of beads sewn in garment patterns, is what allowed modern humans to occupy glacial Eurasia and ultimately cross Beringia into the Americas." },
  { id: "hide-tents", name: "Hide Tents & Portable Shelter", era: "upper-paleo", category: "shelter",
    year: "~30 kya", prereqs: ["hide-clothing", "spun-fiber"],
    desc: "Conical or domed shelters built from a wooden pole frame covered in stitched hides, anchored by stones or tusks at the base. Post-hole rings at Pavlov, Dolní Věstonice, and Kostenki (~30–25 kya) preserve the footprints of these structures, and the Mal'ta site (Siberia) shows winter encampments deep in glacial latitudes. Portable shelter decouples occupation from caves and rockshelters, lets bands follow migratory herds across treeless steppe, and is the direct ancestor of the tipi, yurt, and chum still used by circumpolar peoples." },

  // ─── Mesolithic ────────────────────────────────────────────────
  { id: "dog", name: "Dog Domestication", era: "mesolithic", category: "subsistence", landmark: true,
    year: "~15 kya", prereqs: ["bone-tools"],
    desc: "Wolves selectively bred toward tameness, smaller size, and reduced fear of humans, becoming hunting partners, sentries, and camp companions. Genetic and archaeological evidence (Bonn-Oberkassel burial, Germany, ~14 kya; Goyet Cave, Belgium, possibly ~36 kya) place domestication in the Late Pleistocene, making the dog the only species domesticated before agriculture. The relationship transformed both species: human hunters with dogs are dramatically more effective, and dogs co-evolved with cooked-food digestion." },
  { id: "ground-stone", name: "Ground Stone Tools", era: "mesolithic", category: "tools",
    year: "~13 kya", prereqs: ["microliths"],
    desc: "Pecked and ground stone tools — celts, axes, mortars, palettes — produced by abrasion against another stone with sand and water rather than by chipping. Slower to make than knapped tools but tougher and more impact-resistant, ground-stone axes can fell large trees and break up sod. Australian Aboriginal sites push the technique back to ~35 kya, but it becomes pervasive only with the Mesolithic shift toward woodland exploitation and clearance." },
  { id: "bow-arrow", name: "Bow and Arrow", era: "middle-paleo", category: "weapons",
    year: "~65 kya", prereqs: ["microliths", "spun-fiber"],
    desc: "A flexible stave (yew, bamboo, sinew-backed wood) storing elastic energy released through a string into a feathered arrow. The earliest direct evidence comes from Sibudu Cave (South Africa): bone arrowheads at ~61 kya (Backwell et al. 2008) and stone segments interpreted as arrow-tips at ~64 kya (Lombard 2010), with Pinnacle Point bone points possibly pushing the form to ~71 kya. Bows become globally widespread only by the late Pleistocene and dominate after the Mesolithic. Compared to atlatl darts, arrows are quieter, faster to nock and release, more accurate at distance, and easier to carry in numbers — transforming both hunting and human conflict." },
  { id: "spun-fiber-mat", name: "Mat Weaving", era: "mesolithic", category: "tools",
    year: "~12 kya", prereqs: ["spun-fiber"],
    desc: "Plaited grass, reed, and bast mats used as floor covers, sleeping pads, sail-cloth, and roofing under thatch. Mats were the first textile architecture: they reuse the cordage technology of the Upper Paleolithic to enclose space. Imprints in clay at Pavlovian sites (~27 kya) and surviving Mesolithic finds at Antrea (Finland) show plaiting was already routine before pottery and weaving emerged." },
  { id: "basketry", name: "Basketry", era: "mesolithic", category: "tools",
    year: "~12 kya", prereqs: ["spun-fiber"],
    desc: "Plaited containers, traps, and cradles woven from willow, reed, and bark. Basketry is older than pottery, lighter than wood, and far more portable than stone vessels. It enables food storage and transport, fish traps, infant carriers, and (with pitch lining) even water-tight containers. Pre-pottery Neolithic sites and Mesolithic camps across Eurasia and the Americas yield basket impressions in dried mud as the earliest indirect evidence." },
  { id: "semi-sedentism", name: "Semi-Sedentary Camps", era: "mesolithic", category: "shelter",
    year: "~12 kya", prereqs: ["shellfishing", "trade-networks"],
    desc: "Year-round or strongly seasonal occupation of base camps near unusually rich resources — salmon runs, oak forests, shellfish coasts — that let foragers stay put without yet farming. Natufian villages in the Levant (12.5–9.7 kya) had stone-walled houses, storage pits, and burials, all before agriculture. Semi-sedentism enables population growth, accumulation of heavy goods (grindstones, pottery), and the social institutions that make full villages possible." },
  { id: "mortar-pestle", name: "Mortar & Pestle", era: "mesolithic", category: "tools",
    year: "~12 kya", prereqs: ["ground-stone"],
    desc: "Paired stone vessels for crushing and grinding nuts, seeds, pigments, and medicines. Bedrock mortars in Natufian sites and portable basalt sets across Mesolithic Europe show how grinding became routine before agriculture. Many wild seeds (acorns, wild barley) need processing to be edible at scale, and the mortar-pestle is the bridge from gathered food to staple food. The same form persists in pharmacies and kitchens today." },
  { id: "sickle-flint", name: "Flint Sickle", era: "mesolithic", category: "subsistence",
    year: "~12 kya", prereqs: ["microliths"],
    desc: "Curved bone or wooden hafts inset with sharp flint blades, used to harvest stands of wild cereals while their grains were still on the stalk. Natufian sickles (~12 kya, Levant) show characteristic sickle-gloss on the cutting edges from silica polishing. Harvesting wild grasses with sickles unintentionally selects for plants that don't shatter — the first step toward domesticated wheat and barley, well before any deliberate cultivation." },
  { id: "fishing-net", name: "Fishing Nets", era: "mesolithic", category: "subsistence",
    year: "~10 kya", prereqs: ["harpoon", "spun-fiber"],
    desc: "Knotted plant-fiber nets and seines that capture fish in volume rather than one at a time. Surviving Mesolithic nets at Antrea (Finland, ~10 kya) and net-weights at Magnitnaya (Russia) show the technology was established. Mass capture turns fishing from opportunistic activity into a reliable food source supporting denser, more sedentary populations along productive rivers and coasts." },
  { id: "fish-weir", name: "Fish Weirs", era: "mesolithic", category: "subsistence",
    year: "~10 kya", prereqs: ["basketry", "fishing-net"],
    desc: "Stone or wattle barriers across tidal flats, stream mouths, or shoals that funnel fish into traps as the tide drops or the current pushes them. Submerged Mesolithic weirs survive in Europe (Maglemose) and pre-contact North America. A weir is essentially industrial-scale fishing without nets, requiring no daily attention — a labor-saving technology that allowed semi-sedentary people to extract huge calorie surpluses." },
  { id: "canoe", name: "Dugout Canoe", era: "mesolithic", category: "transport",
    year: "~10 kya", prereqs: ["rafts"],
    desc: "Hollowed-out logs, often shaped by controlled burning and adzing, providing reliable transport on rivers and lakes. The Pesse canoe (Netherlands, ~10 kya) is the oldest known. Canoes opened up inland waterways for fishing, hunting, and trade and are far easier to handle than rafts. Where they evolved further — outrigger canoes in Oceania, birch-bark canoes in North America — they became long-distance vehicles." },
  { id: "snowshoe-ski", name: "Snowshoes & Skis", era: "mesolithic", category: "transport",
    year: "~10 kya", prereqs: ["basketry", "hide-clothing"],
    desc: "Wood and sinew snowshoes (broad mesh distributing weight) and proto-skis (narrow planks for gliding) that opened northern boreal and tundra zones to sustained winter travel. The Vis 1 ski fragment (Russia, ~8 kya) is the oldest surviving ski. Without these, hunting in deep snow is impossibly tiring; with them, mobility through northern winters becomes routine and hunting parties can pursue elk and reindeer year-round." },

  // ─── Neolithic ─────────────────────────────────────────────────
  { id: "plant-cultivation", name: "Plant Cultivation", era: "neolithic", category: "subsistence",
    year: "~11 kya", prereqs: ["basketry", "semi-sedentism", "sickle-flint"],
    desc: "Deliberate sowing, weeding, and harvesting of wild cereals — eventually domesticated through unconscious selection for non-shattering rachis and larger grain. The earliest cultivation appears in the Levantine 'Fertile Crescent' (PPNA Jericho, ~11 kya) with emmer, einkorn, barley, and pulses, with independent origins in China (rice, millet ~10 kya), Mesoamerica (maize ~9 kya), and the Andes (potato, quinoa). The shift commits a society to staying near its fields and is the opening move of the Agricultural Revolution." },
  { id: "animal-domestication", name: "Animal Domestication", era: "neolithic", category: "subsistence",
    year: "~10.5 kya", prereqs: ["dog"],
    desc: "Selective breeding and herding of sheep, goats, pigs, cattle, and later equids. Sheep and goats were the first livestock (Zagros foothills, ~10.5 kya), valued initially for meat, then increasingly for milk, wool, and traction. Domesticated animals walking calories — they convert grass and crop residues humans can't eat into protein, fat, hides, and labor — and reorganized social structures around herd ownership, transhumance, and pastoralism." },
  { id: "polished-stone", name: "Polished Stone Axes", era: "neolithic", category: "tools",
    year: "~10 kya", prereqs: ["ground-stone"],
    desc: "Ground and polished stone axes — typically of jadeite, basalt, greenstone — durable enough to fell mature trees and clear forest. Compared to chipped axes they hold an edge longer, resist shattering on impact, and can be re-sharpened. Polished axes from sources like Mont Viso (Italy) and the Langdale axe quarries (England) traveled hundreds of kilometers as prestige goods, and the labor of clearing forest with them is what made permanent farming possible across temperate Eurasia." },
  { id: "pottery", name: "Pottery", era: "upper-paleo", category: "tools",
    year: "~20 kya", prereqs: ["cooking", "water-flask"],
    desc: "Fired clay vessels for cooking, fermentation, water carriage, and grain storage. The earliest fired-clay containers come from Xianrendong Cave (Jiangxi, China, ~20 kya) and Yuchanyan (Hunan, ~18 kya); Jōmon pottery in Japan begins by ~16.5 kya. All of these predate agriculture by many millennia — pottery is an Upper Paleolithic invention used by foragers to cook starchy plants and aquatic resources. The form explodes only in the Neolithic with sedentary villages and grain storage. Firing chemically transforms clay into a hard, watertight ceramic and requires controlled temperatures around 600–900°C — the same pyrotechnical knowledge that later enables metallurgy and glass-making." },
  { id: "village", name: "Permanent Villages", era: "neolithic", category: "shelter",
    year: "~10 kya", prereqs: ["semi-sedentism", "plant-cultivation", "windbreaks"],
    desc: "Permanent settlements of mudbrick or timber houses, sometimes thousands of inhabitants, with shared walls, lanes, storage, and ritual buildings. Jericho (~10 kya) had stone walls and a tower; Çatalhöyük (~9 kya, Anatolia) housed thousands in densely packed rooftop-entry homes. Villages concentrate population, generate surplus, and create the conditions for specialization, inheritance, and inequality that all later social complexity depends on." },
  { id: "adobe-brick", name: "Adobe Brick", era: "neolithic", category: "shelter",
    year: "~10 kya", prereqs: ["pottery", "village"],
    desc: "Sun-dried mud bricks of clay, sand, water, and chopped straw — uniform, stackable, repairable, and produced from the local soil. Adobe construction at Jericho and Çatalhöyük lets buildings rise in regular geometric forms and stand for centuries. The technique persists from the Neolithic to the modern American Southwest and Sahel, scaling up to entire cities and surviving wherever the climate is dry enough to keep the bricks from melting back into earth." },
  { id: "megaliths", name: "Megalithic Monuments", era: "neolithic", category: "social",
    year: "~11 kya", prereqs: ["trade-networks", "semi-sedentism"],
    desc: "Large standing stones arranged in alignments, circles, dolmens, and passage tombs, often astronomically oriented. Göbekli Tepe (Turkey, ~11 kya) astonishingly predates farming, was built by hunter-gatherers, and proves that monumental ritual architecture could precede agriculture. Stonehenge (~5 kya, England), Carnac (Brittany), Newgrange (Ireland) show the form continuing through the Neolithic. The labor required implies large-scale cooperation and shared cosmology." },
  { id: "ritual-religion", name: "Organized Religion", era: "neolithic", category: "social",
    year: "~10 kya", prereqs: ["burial", "megaliths", "shamanism"],
    desc: "Standardized myths, calendars, and ritual specialists serving settled communities — the institutional successor of shamanism, oriented around fixed shrines, agricultural cycles, ancestors, and named deities. Çatalhöyük's bull shrines, Göbekli Tepe's animal pillars, and Neolithic figurine traditions show religion organizing the year and the village. Religion both legitimated emerging hierarchies and stored cosmological knowledge in transmissible form." },
  { id: "pottery-wheel", name: "Pottery Wheel", era: "neolithic", category: "tools",
    year: "~6 kya", prereqs: ["pottery"],
    desc: "A horizontally rotating disc that lets a potter shape symmetric vessels at speed using centripetal force and skilled hands. Slow tournettes appear in Mesopotamia by ~6 kya; fast wheels by ~3 kya. The pottery wheel is the first deliberate use of continuous rotational motion as a productive technology — the conceptual ancestor of the spoked wheel, the lathe, and ultimately every spinning machine in the Industrial Revolution." },
  { id: "weaving", name: "Loom Weaving", era: "neolithic", category: "tools",
    year: "~9 kya", prereqs: ["basketry", "animal-domestication", "needles"],
    desc: "Warp-and-weft textiles produced on a loom — initially the warp-weighted vertical loom or the back-strap horizontal loom — using flax, then wool, then cotton. Loom weights and impressed clay show weaving by ~9 kya across the Near East. Cloth replaces hides as the standard garment for most people, can be tailored more precisely, dyed, and traded over long distances, and becomes the most important non-food product of pre-industrial societies." },
  { id: "domesticated-flax", name: "Flax & Cotton", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["plant-cultivation", "weaving"],
    desc: "Linum usitatissimum cultivated for both seed (linseed oil) and fiber (linen). Domesticated flax appears in the Levant by ~9 kya. Cotton (Gossypium) was independently domesticated in the Indus Valley and Mesoamerica. These fiber crops free clothing from the supply of animals and hides, and become the basis for textile-driven economies from Pharaonic Egypt to Mughal India to industrial Britain." },
  { id: "irrigation", name: "Irrigation", era: "neolithic", category: "subsistence",
    year: "~8 kya", prereqs: ["village", "plant-cultivation"],
    desc: "Channeled river water diverted to crops via canals, ditches, basins, and gates — multiplying yields in arid floodplains. Mesopotamian and Egyptian large-scale irrigation appears by ~7 kya; the Nile's annual flood was managed with basin irrigation that left silt behind. Irrigation requires coordination beyond a single household, contributes to the rise of administrative states, and is sometimes argued (Wittfogel's 'hydraulic hypothesis') to have driven early state formation directly." },
  { id: "plow-ard", name: "Ard Plow", era: "neolithic", category: "subsistence",
    year: "~6 kya", prereqs: ["animal-domestication", "polished-stone", "digging-stick"],
    desc: "Animal-drawn scratch plow that breaks soil far faster than a digging stick, opening heavy land that hand cultivation can't handle. Sumerian and Egyptian images show ards in routine use by ~5 kya. The ard doesn't turn the soil over (a moldboard plow does that, much later) but its furrow is enough for cereal seeding. Pairing ards with oxen also reorganizes farming around livestock-owning households." },
  { id: "millstone", name: "Millstone", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["ground-stone", "plant-cultivation"],
    desc: "Paired flat (saddle quern) or rotary stones that grind grain into flour, a labor-intensive but unavoidable step in cereal-based diets. Saddle querns are routine in PPNB sites; rotary querns become widespread by the Iron Age. Daily flour for bread and porridge is what makes grain a staple, and millstones — from a few kilograms in Neolithic homes to tonnes in Roman water-mills — are the workhorse infrastructure of pre-industrial nutrition." },
  { id: "fermentation-brewing", name: "Fermentation & Brewing", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["pottery", "plant-cultivation"],
    desc: "Controlled microbial transformation of grain, fruit, milk, and vegetables into beer, mead, wine, cheese, yogurt, and leavened bread. The earliest archaeological brewing residues appear at Göbekli Tepe and PPNA Levantine sites. Fermentation preserves perishable harvests, makes calories shelf-stable, and produces alcohol — both a social lubricant and a ritual substance. Some archaeologists argue beer rather than bread was the original driver of cereal cultivation." },
  { id: "granary", name: "Granaries & Storage", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["plant-cultivation", "pottery"],
    desc: "Dedicated structures — pits, silos, raised platforms, mudbrick rooms — for surplus grain. Mesolithic Natufian storage features and PPNA Jordan Valley granaries (~10 kya) actually predate full agriculture. Surplus storage means a population can survive lean years and feed non-farming specialists; it also creates the first portable wealth and the first thing worth raiding, contributing to inequality and warfare." },
  { id: "sledge-runner", name: "Sledge", era: "neolithic", category: "transport",
    year: "~8 kya", prereqs: ["polished-stone"],
    desc: "Wood or whalebone runners under a load-platform, dragged over snow, mud, log rollers, or grass. Sledges are older and simpler than wheeled vehicles and remained important wherever snow or rough terrain made wheels impractical (Arctic, Alps, log skids). They are also the form on which the wheel was likely first added — Bronean log rollers under sledges naturally evolve toward the wheeled cart." },
  { id: "sail-primitive", name: "Square Sail", era: "neolithic", category: "transport",
    year: "~7 kya", prereqs: ["canoe", "spun-fiber-mat"],
    desc: "Reed-mat or linen square sails on a single mast above a canoe or raft, capturing wind to supplement paddling. Earliest evidence comes from Predynastic Egyptian Nile boats (~6 kya). A square sail can only run before the wind, but on long rivers like the Nile that's enough to revolutionize transport — heavy cargo can move upstream with a fair wind and downstream with the current, halving labor in both directions." },
  { id: "copper-smelting", name: "Copper Smelting", era: "neolithic", category: "tools",
    year: "~7 kya", prereqs: ["pottery", "polished-stone"],
    desc: "Reducing copper ore (malachite, azurite, native copper) in clay-lined furnaces with charcoal at temperatures around 1100°C, then casting into ingots or shapes. Earliest smelted copper appears at Çatalhöyük and Tal-i Iblis (Iran, ~6.5 kya), but the technology becomes routine in the Chalcolithic. Copper is the first metal humans extracted at scale — too soft for serious tools alone, but the gateway to bronze and to the broader pyrotechnical knowledge underlying all later metallurgy." },
  { id: "mathematics-counting", name: "Counting Systems", era: "neolithic", category: "knowledge",
    year: "~9 kya", prereqs: ["tally-bones", "granary"],
    desc: "Standardized numeral systems tied to commodity accounting — sheep, jars of grain, days. Mesopotamian sexagesimal counting and Egyptian decimal numerals both develop alongside writing in the late 4th millennium BCE. Once numbers are abstract symbols rather than tally marks, they can be added, multiplied, and recorded in transactions and contracts — the basis of all later mathematics, accounting, and astronomy." },
  { id: "proto-writing-tokens", name: "Proto-Writing", era: "neolithic", category: "communication",
    year: "~8 kya", prereqs: ["mathematics-counting", "granary"],
    desc: "Clay tokens of distinct shapes (cones, spheres, discs) representing commodities, sealed inside hollow clay 'bullae' as accounting records. Sumerian sites like Uruk show the system in use by ~4 kya, and the impressions of tokens on bulla surfaces are the direct ancestor of cuneiform pictograms. Writing was thus born from accounting — bureaucratic memory long before it carried literature." },
  { id: "wool-textiles", name: "Wool & Woolen Textiles", era: "neolithic", category: "tools",
    year: "~6 kya", prereqs: ["weaving", "animal-domestication"],
    desc: "Spun and woven wool from sheep selectively bred for fleece rather than the wild kemp coat. Genetic and archaeological evidence places the woolly-fleece sheep at ~6 kya in Mesopotamia, with woolen cloth fragments at Çatalhöyük and explicit Sumerian textile accounts by the third millennium BCE. Wool stretches, absorbs dye, retains warmth when wet, and re-grows annually — making it the dominant textile of temperate Eurasia until cotton imports in the early modern era and synthetics in the 20th century." },
  { id: "proto-cities", name: "Proto-Cities", era: "neolithic", category: "shelter",
    year: "~9 kya", prereqs: ["village", "plant-cultivation"],
    desc: "Densely packed agglomerations of thousands of people living in shared, often wall-to-wall housing — too large to be a village, too undifferentiated to be a city. Çatalhöyük (Anatolia, ~9–7 kya) housed up to 8,000 in a honeycomb of mud-brick rooms entered through the roof; Tell es-Sultan (Jericho) and Mehrgarh show similar density. Without yet developing palaces, temples, or a clear ruling class, these settlements pioneered the social technologies — neighbors, sanitation, shared walls — that true cities would later organize hierarchically." },
  { id: "defensive-walls", name: "Defensive Walls", era: "neolithic", category: "shelter",
    year: "~10 kya", prereqs: ["adobe-brick", "village"],
    desc: "Stone or mud-brick perimeter walls and towers built to defend a settlement against raiders and rival groups. The Tower and Wall of Jericho (~10 kya) — 4 m high, with an interior staircase — is the oldest known defensive architecture and predates agriculture's full establishment. Walls reorganize warfare around siege rather than open battle, justify the labor cost of permanent settlement, and reshape political geography by making some places categorically harder to take than others." },

  // ─── Bronze Age ────────────────────────────────────────────────
  { id: "bronze-metallurgy", name: "Bronze Metallurgy", era: "bronze", category: "tools",
    year: "~3300 BCE", prereqs: ["copper-smelting"],
    desc: "Tin-copper alloy (typically ~10% tin) producing a metal far harder, more castable, and more durable than copper alone. Earliest at Vinča/Pločnik in the Balkans (~7 kya) and Sumer (~5.3 kya), bronze defines an age and reshapes warfare, agriculture, and trade. Because tin and copper rarely occur together, bronze depends on long-distance trade — Cornish tin and Cypriot copper both crossed the Mediterranean — and links far-flung regions into a single technological economy." },
  { id: "bronze-tools", name: "Bronze Tools", era: "bronze", category: "tools",
    year: "~3200 BCE", prereqs: ["bronze-metallurgy"],
    desc: "Cast and hammered bronze axes, chisels, saws, sickles, and razors — sharper, harder, and more durable than stone or copper, and re-castable when worn or broken. Adoption transformed agriculture (better plowshares, sickles), construction (saws and chisels), and crafts (engraving tools, fine metalwork). The fact that broken bronze can be melted down and reused is itself revolutionary: durable wealth could be repurposed in ways stone and bone never permitted." },
  { id: "bronze-weapons", name: "Bronze Weapons", era: "bronze", category: "weapons",
    year: "~3200 BCE", prereqs: ["bronze-metallurgy", "composite-spear"],
    desc: "Cast bronze swords, daggers, spear points, axes, and armor scales. Bronze swords appear in the Aegean and Levant by ~3300 BCE and reach mature long-sword form by ~1600 BCE (Naue II). Stone weapons become obsolete on the battlefield, and the high cost of bronze (with imported tin) ties military power to ruling-class control of trade routes — a key dynamic of all Bronze Age civilizations from Mycenae to Shang China." },
  { id: "iron-meteoric", name: "Meteoric Iron", era: "bronze", category: "tools",
    year: "~3200 BCE", prereqs: ["bronze-metallurgy"],
    desc: "Cold-worked iron from meteorites, recognizable by its high nickel content. The dagger of Tutankhamun (~1330 BCE) is the most famous example — its nickel signature confirms meteoric origin. Found in royal Mesopotamian, Egyptian, Chinese, and Inuit contexts as rare and prestigious objects, meteoric iron taught Bronze Age smiths that the metal could be worked at all, paving the way for the smelted iron that would eventually displace bronze entirely." },
  { id: "spoked-wheel", name: "Spoked Wheel", era: "bronze", category: "transport",
    year: "~2000 BCE", prereqs: ["pottery-wheel", "sledge-runner"],
    desc: "Light wheels built from a hub, spokes, and a bent or jointed rim, replacing solid disc wheels and dramatically reducing the weight of a cart while preserving strength. Earliest examples appear with Andronovo and Sintashta cultures of the Eurasian steppe (~2000 BCE). Spoked wheels are the precondition for fast vehicles — chariots, light carts — and remained the dominant wheel form until the bicycle and automobile redesigned them in the 19th century." },
  { id: "wheeled-cart", name: "Wheeled Cart", era: "bronze", category: "transport",
    year: "~3500 BCE", prereqs: ["spoked-wheel", "animal-domestication"],
    desc: "Solid-wheel and later spoked-wheel carts pulled by oxen or donkeys, carrying loads from one to several tons that no human porter could move. Earliest depictions on Sumerian Standard of Ur and pictograms (~3500 BCE), with wooden wheels surviving from Slovenia at ~3200 BCE. Carts increase land freight throughput by an order of magnitude and reorganize where settlements can be — distance from a navigable river suddenly matters far less." },
  { id: "horse-domestication", name: "Horse Domestication", era: "bronze", category: "transport",
    year: "~3500 BCE", prereqs: ["animal-domestication"],
    desc: "Tamed Eurasian steppe horses, beginning with the Botai culture of Kazakhstan around 5500 BCE for milk and meat, and reaching mounted-warrior form by ~2000 BCE with Sintashta. Horses transform speed, range, and traction: a mounted scout covers in one day what a foot scout does in three; cavalry and chariot warfare become possible. Indo-European language expansion, steppe nomadism, and the Silk Road are all downstream of domesticated horses." },
  { id: "chariot", name: "War Chariot", era: "bronze", category: "weapons",
    year: "~2000 BCE", prereqs: ["wheeled-cart", "horse-domestication", "bronze-metallurgy"],
    desc: "Two-horse fighting platforms with archer and driver, built around a light spoked-wheel frame. Sintashta chariots appear ~2000 BCE; by 1700 BCE they dominate battlefields from Mycenae to Shang China and the Hyksos use them to overrun Egypt. The chariot is the first integrated weapons system: vehicle, motive power, and ranged weapon combined. Their dominance lasts until cavalry on stronger, larger horses with proper saddles displaces them in the Iron Age." },
  { id: "composite-bow", name: "Composite Bow", era: "bronze", category: "weapons",
    year: "~2000 BCE", prereqs: ["bow-arrow", "hafting", "bronze-metallurgy"],
    desc: "Layered horn, wood, and sinew bow producing far more energy per inch than a self-bow, allowing a short weapon (~1 m) to outperform a long self-bow. Used by Sumerians, Hittites, Scythians, Mongols, Manchus, and Comanche, the composite bow is the canonical horse-archer weapon — short enough to fire from a galloping horse, powerful enough to pierce armor at 100 m. Its construction takes a year and requires master-level woodwork and gluing." },
  { id: "city-state", name: "City-State", era: "bronze", category: "economy",
    year: "~3500 BCE", prereqs: ["village", "irrigation"],
    desc: "Walled urban centers with surrounding farmland, governed by a temple-palace elite, with populations of 10,000–80,000. Sumerian Uruk (~3500 BCE), then Lagash, Ur, Ebla, and later Greek poleis and Mesoamerican capitals. The city-state is the first political form to combine permanent administration, monumental architecture, social stratification, professional priesthood, and long-distance trade — every later civilization grew out of or in reaction to it." },
  { id: "code-of-law", name: "Codified Law", era: "bronze", category: "economy",
    year: "~2100 BCE", prereqs: ["city-state", "proto-writing-tokens"],
    desc: "Written legal codes — Ur-Nammu (~2100 BCE), Lipit-Ishtar, Hammurabi (~1750 BCE) — that publicly fix penalties, contracts, family law, and commercial rules. Public, predictable rules replace personal arbitration and royal whim, and the law's monumental display (Hammurabi's stele was eight feet tall) advertises the king as a guarantor of justice. The codes are also the first administrative documents to claim legitimacy from divine sanction." },
  { id: "cuneiform", name: "Cuneiform", era: "bronze", category: "communication",
    year: "~3200 BCE", prereqs: ["proto-writing-tokens", "proto-language"],
    desc: "Wedge-shaped script impressed into clay with a cut reed, originating in Sumerian Uruk around 3200 BCE for accounting and adapted to record contracts, letters, literature, and administrative archives. Hundreds of thousands of tablets survive, baked into permanence by accidental fires that destroyed cities. Cuneiform was used for over 3000 years across Sumerian, Akkadian, Babylonian, Assyrian, Hittite, and Old Persian — far longer than the Latin alphabet has existed." },
  { id: "hieroglyphics", name: "Hieroglyphics", era: "bronze", category: "communication",
    year: "~3200 BCE", prereqs: ["proto-writing-tokens"],
    desc: "Egyptian pictographic and phonetic script, carved monumentally on stone and inked on papyrus, in use from ~3200 BCE through ~400 CE. The script combines ideograms, syllabic phonograms, and determinatives, with a hieratic cursive variant for daily writing. Decipherment by Champollion in 1822 using the Rosetta Stone reopened three millennia of Egyptian history that had been opaque since the Roman closure of the temples." },
  { id: "alphabet-phoenician", name: "Phoenician Alphabet", era: "bronze", category: "communication",
    year: "~1200 BCE", prereqs: ["cuneiform", "hieroglyphics"],
    desc: "Twenty-two consonant letters representing sounds rather than concepts, devised by Levantine traders around 1200 BCE. Where cuneiform required years of training, the alphabet could be learned in weeks, democratizing literacy. Greek, Aramaic, Hebrew, Arabic, and ultimately Latin and Cyrillic all descend from it, making the Phoenician alphabet the common ancestor of every Western and Near Eastern script in current use." },
  { id: "abacus", name: "Abacus", era: "bronze", category: "knowledge",
    year: "~2700 BCE", prereqs: ["mathematics-counting"],
    desc: "Bead-and-rod calculating frames that mechanize addition, subtraction, multiplication, and division by manipulating columns representing place values. Sumerian sand abaci (~2700 BCE) gave way to Roman bronze abaci, the Chinese suanpan, and the Japanese soroban. A skilled abacus operator can outpace early electronic calculators, and the device remains in use in some East Asian education systems for teaching numerical intuition." },
  { id: "mathematics-arithmetic", name: "Arithmetic", era: "bronze", category: "knowledge",
    year: "~2000 BCE", prereqs: ["cuneiform", "mathematics-counting", "abacus"],
    desc: "Babylonian sexagesimal arithmetic — including fractions, square roots, quadratic equation solutions, and tables of reciprocals — recorded on clay tablets like Plimpton 322. Working in base 60 (which has many divisors) gave Mesopotamian astronomers and surveyors enormous practical power, and that base persists in our division of hours, minutes, and degrees. Egyptian arithmetic developed in parallel with the Rhind and Moscow papyri." },
  { id: "astronomy-observation", name: "Astronomy", era: "bronze", category: "knowledge",
    year: "~1800 BCE", prereqs: ["lunar-tally", "mathematics-arithmetic"],
    desc: "Systematic recording of planetary motion, lunar phases, eclipses, and stellar risings. Babylonian tablets like Enuma Anu Enlil and MUL.APIN catalogue centuries of observations and use them to predict eclipses with remarkable accuracy. The same data eventually fed into Greek mathematical astronomy and Ptolemy's Almagest, making Babylonian record-keeping the empirical bedrock of all later positional astronomy." },
  { id: "solar-calendar", name: "Solar Calendar", era: "bronze", category: "knowledge",
    year: "~3000 BCE", prereqs: [],
    desc: "365-day calendar tracking the solar year, divided into 12 months of 30 days plus 5 epagomenal days. The Egyptian civil calendar — likely derived from observing the heliacal rising of Sirius coinciding with the Nile flood — was the first solar calendar in continuous use (from ~3000 BCE). Variants spread through Roman administration as the Julian calendar and survive, with Gregorian refinements, as the global standard today." },
  { id: "monumental-architecture", name: "Monumental Architecture", era: "bronze", category: "shelter",
    year: "~3000 BCE", prereqs: ["megaliths", "city-state", "adobe-brick"],
    desc: "Temples and palaces built with planned engineering, mass labor, and professional architects. Sumerian Eanna at Uruk, Egyptian Old Kingdom mortuary complexes, Hittite Hattusa, and Minoan Knossos all share the formula: monumental scale, geometric layout, costly imported materials, and decorative programs that legitimize ruling power. Such buildings concentrate craft specialists and engineering knowledge that ripples outward into every other domain." },
  { id: "pyramid-ziggurat", name: "Pyramids & Ziggurats", era: "bronze", category: "shelter",
    year: "~2600 BCE", prereqs: ["monumental-architecture"],
    desc: "Stepped or smooth-sided masonry mountains. Egyptian pyramids — Djoser's Step Pyramid (~2600 BCE) through the Great Pyramid of Khufu (~2560 BCE) — house royal burials. Mesopotamian ziggurats like Ur and the Tower of Babel's prototype Etemenanki are temple platforms reaching toward the gods. The labor and logistics required (Khufu's pyramid weighs 6 million tons) is testimony both to engineering and to political organization." },
  { id: "glass-making", name: "Glass Making", era: "bronze", category: "tools",
    year: "~3500 BCE", prereqs: ["pottery", "copper-smelting"],
    desc: "Fused silica beads, vessels, and inlays produced by heating sand, soda ash, and lime to ~1500°C. Earliest at Mesopotamian and Egyptian sites by ~3500 BCE, with mature core-formed vessels by ~1500 BCE. Glass becomes a major luxury trade good across the eastern Mediterranean. The pyrotechnical know-how — high temperatures and flux chemistry — feeds directly into the development of glazes, enamels, and eventually mirrors and lenses." },
  { id: "silver-gold-metallurgy", name: "Precious Metals", era: "bronze", category: "tools",
    year: "~3000 BCE", prereqs: ["copper-smelting"],
    desc: "Refining and working silver, gold, and electrum (their natural alloy) by panning, cupellation, casting, and granulation. The Royal Tombs of Ur (~2500 BCE) and the Treasure of Priam at Troy show extraordinary craftsmanship. Precious metals double as ornament and store of value: rings, bracelets, and ingots circulate as proto-money long before stamped coinage, and gold-and-silver tribute organizes much of Bronze Age long-distance trade." },
  { id: "olive-wine", name: "Olive Oil & Wine", era: "neolithic", category: "subsistence",
    year: "~6000 BCE", prereqs: ["plant-cultivation", "pottery"],
    desc: "Tree-crop horticulture (olives) and viticulture (grapevines) producing transportable, durable, calorie-dense oil and wine. The earliest direct chemical evidence of wine-making is tartaric-acid residue on Neolithic pottery from Gadachrili Gora and Shulaveris Gora (Georgia, ~6000 BCE; McGovern et al. 2017), with Hajji Firuz Tepe (Iran, ~5400 BCE) following close behind. Both crops are perennials with multi-year payback periods, requiring secure landownership. The Mediterranean olive-oil-and-wine economy stretches from Iberia to the Levant by the Late Bronze Age, with shipwrecks like Uluburun (~1300 BCE) carrying amphorae of both. Olives and wine become defining markers of Mediterranean culture for three thousand years." },
  { id: "linen-textile", name: "Linen Textiles", era: "neolithic", category: "tools",
    year: "~7000 BCE", prereqs: ["weaving", "domesticated-flax"],
    desc: "Bleached and woven flax fabrics for clothing, sails, ropes, bandages, and trade. Dyed twisted flax fibers from Dzudzuana Cave (Georgia, ~30 kya) are the oldest known plant-fiber textiles, but woven linen cloth proper is documented from Çatalhöyük (Anatolia, ~7000 BCE) and Nahal Hemar (Israel, ~7000 BCE) onward. Egypt's Nile floodplain was ideal for flax, and Egyptian linen (some of it almost transparently fine) became the premier textile of the ancient world, traded throughout the Mediterranean. Mummy wrappings preserve thousands of meters of it. Linen also carried Greek and Roman elites' togas and chitons before cotton arrived from the East." },
  { id: "standing-army", name: "Standing Army", era: "bronze", category: "weapons",
    year: "~2300 BCE", prereqs: ["city-state", "bronze-weapons"],
    desc: "Full-time professional soldiers paid by the state, replacing seasonal levies of farmer-citizens. Sargon of Akkad's army (~2300 BCE) is the prototype; later New Kingdom Egypt, Assyria, and the Achaemenid Empire institutionalize the form. Standing armies are loyal to whoever pays them rather than to a clan or region, enabling much larger and longer campaigns — and giving rulers a coercive instrument that local nobles cannot match." },
  { id: "maritime-trade", name: "Maritime Trade", era: "bronze", category: "economy",
    year: "~3000 BCE", prereqs: ["sail-primitive", "city-state"],
    desc: "Routine cargo shipping across seas: Bronze Age tin and copper from Cornwall and Cyprus, lapis lazuli from Afghanistan, ivory from Africa, amber from the Baltic. The Uluburun shipwreck (~1300 BCE) carried goods from at least seven distinct regions. Maritime trade lets Bronze Age polities import what their geology lacks (Egypt had little timber; Mesopotamia had little stone) and bound the Mediterranean and Indian Ocean basins into integrated economic systems." },
  { id: "galley-ship", name: "Galley", era: "bronze", category: "transport",
    year: "~3000 BCE", prereqs: ["sail-primitive", "bronze-tools"],
    desc: "Oared and sailed warships and traders, often multi-decked, with rams or platforms for boarding. Phoenician galleys became the dominant Mediterranean ship by ~1000 BCE, sailed by professional crews coordinated by drum and oarmaster. The galley's weak point — vulnerability to weather, dependence on shore for water — also defined its operational geography, anchoring naval power in coastal city-states." },
  { id: "celestial-navigation", name: "Celestial Navigation", era: "bronze", category: "transport",
    year: "~1500 BCE", prereqs: ["astronomy-observation", "sail-primitive"],
    desc: "Determining position and heading on open water by sighting the sun, moon, planets, and stars against the horizon. Polynesian wayfinders crossed thousands of kilometers of empty Pacific from ~1500 BCE using memorized star paths, swell patterns, and the rising and setting points of named stars on the horizon. Phoenicians used Polaris (the 'Phoenician Star') for latitude on Mediterranean and Atlantic voyages by ~1000 BCE; Greek and Arab sailors refined sun-altitude techniques for noon-latitude. The practice required no instruments beyond the observer's eye and an internalized sky model — but it depended on clear weather and a known star catalogue, which is why the magnetic compass (~1100 CE) and astrolabe (~800 CE) eventually displaced pure celestial methods on cloudy seas. Celestial navigation is the deep ancestor of every later instrument-mediated wayfinding technique, and remained the backup method on naval vessels into the GPS era." },
  { id: "pulley-lever", name: "Pulley & Lever", era: "bronze", category: "tools",
    year: "~2000 BCE", prereqs: ["monumental-architecture", "mathematics-arithmetic"],
    desc: "Simple machines (lever, pulley, inclined plane, wedge, screw, wheel-and-axle) that multiply human and animal force. Egyptian and Mesopotamian construction relied on levers and inclined planes; pulleys and compound block-and-tackle systems likely came later. Archimedes formalized the underlying mechanics in Hellenistic times, but the empirical use of these tools for moving stone and water is millennia older and is the foundation of all later mechanical engineering." },
  { id: "proto-medicine", name: "Temple Medicine", era: "bronze", category: "medicine",
    year: "~1800 BCE", prereqs: ["ritual-religion", "cuneiform"],
    desc: "Mesopotamian Diagnostic Handbook (Esagil-kin-apli, ~1000 BCE) and the Egyptian Edwin Smith Papyrus (~1600 BCE, copying older material) record observed symptoms, prognoses, and treatments — including surgical procedures and dressings. Mixed with ritual and incantation, these texts also contain genuinely empirical medical knowledge: setting fractures, suturing wounds, cataracting eyes. They are the foundation on which later Greek and Islamic medicine consciously built." },
  { id: "trepanation", name: "Trepanation", era: "neolithic", category: "medicine",
    year: "~5000 BCE", prereqs: ["polished-stone", "ritual-religion"],
    desc: "Surgical removal of a disc of bone from the skull, performed with flint, obsidian, or bronze tools. Trepanned skulls from the Neolithic onward (Ensisheim, France, ~7 kya; widespread in pre-Columbian Peru) often show healed bone, meaning many patients survived. The procedure may have treated head injuries, intracranial pressure, or culturally interpreted illnesses (epilepsy, possession). It is the earliest attested major surgery anywhere on Earth." },
  { id: "cartography", name: "Map-making", era: "bronze", category: "knowledge",
    year: "~600 BCE", prereqs: ["astronomy-observation", "cuneiform"],
    desc: "Representing terrain on a flat surface at known scale, with consistent symbols for cities, rivers, coastlines, and political borders. Three abstractions had to be combined: a fixed coordinate frame (so locations have stable addresses), a projection rule (mapping the curved Earth onto a flat sheet, accepting some distortion), and a legend (so readers can decode the symbols without seeing the territory). The Babylonian World Map clay tablet (~600 BCE) shows Mesopotamia surrounded by an ocean ring; Anaximander drew the first Greek world map ~550 BCE; Eratosthenes (~240 BCE) measured Earth's circumference to within a few percent and produced a map with latitude/longitude grid; Ptolemy's Geographia (~150 CE) provided coordinates for ~8,000 places and shaped European cartography for 1,400 years. Once a region is mapped, planning trade routes, military campaigns, tax districts, and aqueducts becomes a pencil exercise rather than a journey — and the map itself becomes a technology that is copied, traded, and improved." },
  { id: "tin-mining", name: "Tin Mining & Trade", era: "bronze", category: "tools",
    year: "~3000 BCE", prereqs: ["bronze-metallurgy"],
    desc: "Hard-rock and placer mining of cassiterite (tin oxide) and the long-distance trade routes that moved it to copper-rich regions. Tin is rare and geographically clustered — Cornwall, the Erzgebirge, Anatolia, and the Pamirs supplied most of Bronze Age Eurasia, and isotope analysis of Mediterranean ingots (Uluburun, Salcombe) traces specific shipments back to specific mines. Because no major civilization had both copper and tin in quantity, the Bronze Age was structurally dependent on long-distance trade — its eventual disruption around 1200 BCE plausibly contributed to the Bronze Age Collapse." },
  { id: "weights-measures", name: "Standardized Weights & Measures", era: "bronze", category: "economy",
    year: "~3000 BCE", prereqs: ["mathematics-counting", "city-state"],
    desc: "Official sets of stone or metal reference weights, fixed unit lengths, and standard volume measures backed by temple or palace authority. The Indus Valley civilization produced a remarkable cubic-stone weight system in binary then decimal multiples (~2600 BCE); Mesopotamian shekels and minas, and Egyptian deben, are attested in the same period. Standardization makes taxation, contracts, and inter-city trade verifiable rather than negotiated case-by-case, and is the precondition for the coinage, accounting, and metrology that later civilizations build on." },

  // ─── Classical Antiquity ───────────────────────────────────────
  { id: "iron-smelting", name: "Iron Smelting", era: "classical", category: "tools",
    year: "~1200 BCE", prereqs: ["bronze-metallurgy", "glass-making", "iron-meteoric"],
    desc: "Bloomery smelting of iron ore (hematite, magnetite) in clay-and-charcoal furnaces at ~1200°C, producing a spongy 'bloom' that is hammered to expel slag. Hittites likely innovated the technique by ~1500 BCE; it spread after the Bronze Age collapse around 1200 BCE. Iron is far more abundant than tin and copper, so smelting democratized metal: ordinary farmers could afford iron plowshares and edges that previously only elites could equip with bronze." },
  { id: "iron-tools", name: "Iron Tools", era: "classical", category: "tools",
    year: "~1100 BCE", prereqs: ["iron-smelting"],
    desc: "Iron axes, plowshares, sickles, saws, and chisels. Iron's hardness and toughness once carbon-treated outclass bronze, and its low cost (compared to bronze with imported tin) put quality tools in mass-producible reach for the first time. Iron Age agriculture expanded into heavier soils, woodworking accelerated, and craft production multiplied — the population growth from the late Iron Age onward is partly downstream of cheap iron." },
  { id: "iron-weapons", name: "Iron Weapons", era: "classical", category: "weapons",
    year: "~1100 BCE", prereqs: ["iron-smelting", "bronze-weapons"],
    desc: "Iron swords, spear points, javelin tips, and arrowheads. Hoplite phalanx warfare in Greece, the Roman gladius and pilum, and the Han crossbow bolt all depend on cheap iron edges. Iron's affordability ends bronze-age power balances based on tin trade routes and democratizes military service: a peasant levy with iron weapons can fight effectively, which reshapes Greek and Roman political institutions around the citizen-soldier ideal." },
  { id: "steel-bloomery", name: "Bloomery Steel", era: "classical", category: "tools",
    year: "~600 BCE", prereqs: ["iron-smelting"],
    desc: "Carburized iron — bloom worked in a charcoal forge until the surface absorbs carbon — producing steel locally hard enough to hold an edge. Indian wootz steel (from ~600 BCE) and Chinese cast-iron-derived steels are early high-grade examples, traded as ingots throughout the Indian Ocean. Wootz feeds the Damascus steel tradition of Islamic swordsmithing, with characteristic surface patterns from carbide banding." },
  { id: "alphabet-greek", name: "Greek Alphabet", era: "classical", category: "communication",
    year: "~800 BCE", prereqs: ["alphabet-phoenician"],
    desc: "The Phoenician consonant alphabet adapted to write Greek, with vowel signs added (alpha, epsilon, iota, omicron, upsilon) — the first true alphabet representing all phonemes. Adopted ~800 BCE, it carried the Iliad and Odyssey into writing, then philosophy, drama, geometry, and history. Through the Etruscan intermediary it gave rise to Latin, and through Cyril and Methodius to Cyrillic — the parent of every Western and Slavic alphabet." },
  { id: "alphabet-latin", name: "Latin Alphabet", era: "classical", category: "communication",
    year: "~700 BCE", prereqs: ["alphabet-greek"],
    desc: "Roman adaptation of Etruscan and Greek letters, in routine monumental and cursive forms by ~700 BCE. The empire carried it from Spain to Britain to the Levant, where it absorbed local writing traditions. With the addition of J, U, and W in the medieval and early modern periods it became the dominant script of Western Europe, the basis for transcribing dozens of languages worldwide today, and the standard for computing in the ASCII era." },
  { id: "philosophy", name: "Philosophy", era: "classical", category: "knowledge",
    year: "~600 BCE", prereqs: ["alphabet-greek", "mathematics-arithmetic"],
    desc: "Systematic inquiry into being, ethics, knowledge, and the cosmos pursued by argument rather than appeal to authority. Greek thinkers from Thales (~600 BCE) through Socrates, Plato, and Aristotle defined Western philosophy; in parallel, Confucius, Laozi, and the Hundred Schools shaped Chinese thought, while the Buddha and Mahavira reshaped Indian. Philosophy provides the vocabulary in which all later science, theology, and political theory gets argued." },
  { id: "geometry-euclidean", name: "Euclidean Geometry", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["mathematics-arithmetic", "philosophy"],
    desc: "Axiomatic deductive geometry codified in Euclid's Elements (~300 BCE, Alexandria). Thirteen books proceed from five postulates and common notions to thousands of theorems, becoming the model of rigorous reasoning for over two millennia. Euclid's parallel postulate eventually motivates 19th-century non-Euclidean geometries, but his exposition remained the standard introductory mathematics text from antiquity through the 19th century." },
  { id: "zero-numeral", name: "Zero as Numeral", era: "classical", category: "knowledge",
    year: "~500 CE", prereqs: ["philosophy", "mathematics-arithmetic"],
    desc: "Treating zero as a number with arithmetic rules, not just a placeholder. Earlier place-value systems (Babylonian) used a gap or a dot for absence; the Indian Brahmagupta (628 CE) explicitly defines zero's behavior in addition, subtraction, and multiplication and discusses negative numbers. Combined with place-value notation, zero unlocks fast computation and is the conceptual foundation of all modern arithmetic and algebra." },
  { id: "alchemy", name: "Alchemy", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["glass-making", "philosophy"],
    desc: "Hellenistic, Indian, Chinese, and Islamic experimental tradition aimed at transmuting metals (especially into gold), preparing elixirs, and understanding matter. Although its theoretical goals were unattainable, alchemists developed distillation, sublimation, crystallization, acid preparation, and laboratory glassware — the practical infrastructure that, redirected, became modern chemistry. Jabir ibn Hayyan (~800 CE) is sometimes called the father of chemistry for his systematic experimental methods." },
  { id: "coinage", name: "Coinage", era: "classical", category: "economy",
    year: "~700 BCE", prereqs: ["silver-gold-metallurgy", "code-of-law"],
    desc: "Stamped metal money of guaranteed weight and purity. Lydia's electrum coins (~600 BCE) under King Alyattes set the pattern, copied by Ionian Greeks, then by Persia, then by Athens (silver tetradrachm) and Rome (denarius). Coinage standardizes value and accelerates trade by eliminating the need to weigh metal in every transaction. The state's monopoly on minting also becomes a major source of revenue and a tool of political signaling." },
  { id: "democracy", name: "Democracy", era: "classical", category: "economy",
    year: "~500 BCE", prereqs: ["city-state", "code-of-law", "philosophy"],
    desc: "Athenian rule by the assembly (ekklesia) of citizens, with executive offices filled by lot or election. Begun by Cleisthenes' reforms in 508 BCE and elaborated under Pericles, Athenian democracy directly involved every adult male citizen in voting on laws, foreign policy, and judicial decisions. It excluded women, slaves, and foreigners, and was unstable and short-lived, but it set the conceptual benchmark for popular rule that all later democratic theory has worked from." },
  { id: "republic", name: "Republic", era: "classical", category: "economy",
    year: "~500 BCE", prereqs: ["democracy"],
    desc: "Representative government under elected magistrates and a senate, with checks among offices designed to prevent any single official from accumulating tyrannical power. The Roman Republic (509–27 BCE) is the dominant model: consuls, tribunes, censors, dictators, and a senate of patricians shared power. Cicero's writings and the Republic's example shaped the American and French revolutionary constitutions two millennia later." },
  { id: "empire", name: "Empire", era: "classical", category: "economy",
    year: "~550 BCE", prereqs: ["standing-army", "coinage", "code-of-law"],
    desc: "Multi-ethnic territorial states with central administration, professional bureaucracy, standardized law, and a single coinage. The Achaemenid Persian (~550 BCE), Maurya, Han Chinese, and Roman empires each governed tens of millions across continents. Empires built roads, postal systems, and shared currencies that integrated their economies; they also shaped which languages, religions, and legal traditions would dominate later millennia." },
  { id: "roman-law", name: "Roman Law", era: "classical", category: "economy",
    year: "~450 BCE", prereqs: ["code-of-law", "empire"],
    desc: "From the Twelve Tables (~450 BCE) through the Corpus Juris Civilis of Justinian (~530 CE), Roman law systematized contract, property, family, and criminal jurisprudence. Concepts of legal personality, intent, contract formation, and equity were preserved through the Byzantine Empire, recovered by medieval European jurists at Bologna, and form the spine of every continental ('civil law') legal system in use today." },
  { id: "roads-paved", name: "Paved Roads", era: "classical", category: "transport",
    year: "~300 BCE", prereqs: ["empire", "monumental-architecture"],
    desc: "Multi-layered all-weather roads engineered with deep gravel-and-stone foundations, drainage ditches, and milestones. Roman roads totaled over 80,000 km at the empire's peak, with sections like the Appian Way (begun 312 BCE) still passable. The Persian Royal Road predates the Roman by centuries. Paved networks made imperial postal systems, troop movements, and tax collection routine, and the Silk Road's caravan routes integrated Eurasia." },
  { id: "postal-system", name: "Postal System", era: "classical", category: "communication",
    year: "~500 BCE", prereqs: ["horse-domestication", "empire"],
    desc: "A relay network that delivers letters and parcels between any two addresses inside an empire on a regular schedule, by chaining short rides between manned waystations rather than sending one rider the entire distance. At each waystation (about a day's ride apart) the courier hands the mailbag to a fresh rider on a fresh horse and returns home; the message keeps moving while no individual horse or person ever covers more than one leg. The Persian Royal Road's *angarium* under Darius I (~500 BCE) gave the system its first mature form — Herodotus' famous 'Neither snow nor rain nor heat nor gloom of night...' describes its couriers — and the Roman *cursus publicus*, the Mongol *yam*, and the Mughal post all used the same architecture. Decoupling mail speed from individual endurance lets information cross continents in days rather than seasons, which is the precondition for centralized administration of large states and, eventually, for newspapers, scheduled shipping, and modern telecommunications." },
  { id: "aqueduct", name: "Aqueduct", era: "classical", category: "shelter",
    year: "~700 BCE", prereqs: ["monumental-architecture", "mathematics-arithmetic"],
    desc: "Gravity-fed water channels — partly underground, partly raised on stone arches — carrying potable water tens of kilometers to cities. Rome's aqueducts brought ~1,000,000 cubic meters daily by the 3rd century CE, supplying public fountains, baths, and toilets. The Pont du Gard (France, ~50 CE) and Aqua Claudia are spectacular surviving examples. Cities outgrow local wells and groundwater because of aqueducts, enabling unprecedented urban density." },
  { id: "arch-vault", name: "Arch & Vault", era: "classical", category: "shelter",
    year: "~500 BCE", prereqs: ["monumental-architecture"],
    desc: "Compression-loaded stone arches that span openings without lintels and can be extended into barrel vaults and domes. Etruscan and then Roman builders mastered the form, enabling basilicas, baths, bridges, and the unsupported 43-meter dome of the Pantheon. The structural insight — that radially placed wedge stones (voussoirs) hold each other in place — is the basis of all later masonry construction including Gothic cathedrals." },
  { id: "concrete-roman", name: "Roman Concrete", era: "classical", category: "tools",
    year: "~200 BCE", prereqs: ["aqueduct", "arch-vault"],
    desc: "Pozzolana-lime hydraulic cement that sets even underwater, made by mixing volcanic ash with quicklime and aggregate. Roman concrete (opus caementicium) built the Pantheon dome, harbors at Caesarea, the Colosseum's substructures, and aqueducts. Recent research shows the mix actually self-heals through reaction with water, which is why so much survives. The technology was lost after Rome's fall and only fully matched in the 19th century with Portland cement." },
  { id: "crossbow", name: "Crossbow", era: "classical", category: "weapons",
    year: "~500 BCE", prereqs: ["composite-bow", "iron-tools"],
    desc: "Mechanically drawn bow with a wooden stock, a release trigger, and stored elastic energy from steel or composite limbs. Han Chinese crossbows (~500 BCE) standardized parts and dominated Chinese warfare; medieval European crossbows could pierce plate armor. The crossbow's appeal is that it requires far less training than a longbow and lets a peasant defeat an armored knight, which is exactly why the Second Lateran Council tried (unsuccessfully) to ban it in 1139." },
  { id: "siege-engine", name: "Siege Engines", era: "classical", category: "weapons",
    year: "~400 BCE", prereqs: ["pulley-lever", "iron-tools"],
    desc: "Torsion catapults, ballistae, onagers, and battering rams — engineered weapons that turn a battlefield into an engineering problem. Hellenistic siege technology under Demetrius Poliorcetes ('the Besieger', ~300 BCE) and Roman engineers' systematic deployment let armies reduce previously impregnable cities. The same principles persist into the medieval trebuchet and ultimately into early gunpowder artillery." },
  { id: "cavalry", name: "Heavy Cavalry", era: "classical", category: "weapons",
    year: "~600 BCE", prereqs: ["horse-domestication", "iron-weapons", "chariot"],
    desc: "Mailed riders charging with lance and sword, replacing chariots once horses are bred large enough to carry an armored warrior. Steppe nomads (Scythians, Sarmatians, Parthians) pioneered heavy cavalry; Persian cataphracts and Roman cataphractarii adopted it. By Late Antiquity cavalry has become the decisive arm on most battlefields, a position it holds through the Middle Ages until firearms tip the balance back to massed infantry." },
  { id: "saddle-stirrup", name: "Saddle & Stirrup", era: "classical", category: "transport",
    year: "~400 CE", prereqs: ["horse-domestication", "iron-tools"],
    desc: "Framed saddle (Sarmatian/Roman) and pendant metal foot loops (China, ~300 CE; Avar Europe, ~600 CE) that lock the rider into place during shock combat. The stirrup is small but consequential — it allows the rider to brace against a couched lance and deliver the horse's full momentum at impact. Lynn White famously argued the stirrup made medieval European feudalism possible, an overstatement but with a kernel of truth." },
  { id: "silk-production", name: "Silk Production", era: "bronze", category: "tools",
    year: "~2700 BCE", prereqs: ["animal-domestication", "weaving"],
    desc: "Sericulture: rearing Bombyx mori silkworms on mulberry leaves, reeling cocoons into long filaments, and weaving them into silk. Chinese cultivation goes back to at least 2700 BCE; the secret was guarded for millennia, with capital punishment for export of eggs or worms. Smuggled to the Byzantine Empire by monks ~550 CE. Silk drove the Eurasian trade route that took its name and made China's Han and Tang economies world-spanning." },
  { id: "paper-making", name: "Paper", era: "classical", category: "communication",
    year: "~100 CE", prereqs: ["silk-production", "linen-textile"],
    desc: "Pulped plant fiber (mulberry, hemp, linen rags) pressed into thin sheets — invented by Cai Lun (~105 CE) at the Han court. Cheaper and lighter than papyrus or parchment, paper spread along the Silk Road to the Islamic world by ~750 CE (Samarkand) and Europe by the 12th century. The cost of writing collapsed once paper was available, expanding bureaucracy, scholarship, and eventually printing." },
  { id: "world-religion", name: "World Religions", era: "classical", category: "social",
    year: "~500 BCE", prereqs: ["ritual-religion", "alphabet-phoenician", "empire"],
    desc: "Universal faiths offering moral codes and salvation transcending tribe and locality. Buddhism (~500 BCE), Christianity (~30 CE), and Islam (~620 CE) — along with rabbinic Judaism, Zoroastrianism, and Manichaeism — create transregional religious communities backed by canonical scriptures, professional clergy, and missionary impulses. Under Roman, Sassanian, and Tang patronage they reorganize the political and cultural geography of Eurasia." },
  { id: "monasticism", name: "Monasticism", era: "classical", category: "social",
    year: "~300 CE", prereqs: ["world-religion", "alphabet-latin"],
    desc: "Communities devoted to prayer, study, and labor under a monastic rule (Pachomius in Egypt; Benedict at Monte Cassino, ~530 CE; Buddhist viharas in India and China). Monasteries became the institutional preservers of literacy, manuscript copying, and agricultural innovation through the early medieval period in Europe, and centers of education and economic activity in Buddhist Asia. Their land grants and tax exemptions made them economic powers in their own right." },
  { id: "library", name: "Libraries", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["alphabet-phoenician"],
    desc: "State- or temple-curated collections of scrolls and codices. The Library of Alexandria (founded ~300 BCE under Ptolemy I) targeted holding every Greek-language work, reportedly ~700,000 scrolls; rival Pergamon, then Han imperial archives, then Nalanda's Buddhist collections, all played similar roles. Libraries created the institutional possibility of cumulative scholarship and standardized reference works." },
  { id: "scientific-method-proto", name: "Proto-Science", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["philosophy", "geometry-euclidean"],
    desc: "Aristotle's natural philosophy and Alexandrian empirical work — observation organized by category and tested against logic, but not yet experimental in the modern sense. Aristotle's biology actually contains many accurate observations from dissection, and Alexandrian medicine (Erasistratus, Herophilos) performed systematic anatomy. Centuries later Ibn al-Haytham's Book of Optics introduced controlled experiments specifically designed to falsify hypotheses — the closest pre-modern approach to scientific method." },
  { id: "medicine-galenic", name: "Galenic Medicine", era: "classical", category: "medicine",
    year: "~150 CE", prereqs: ["proto-medicine", "philosophy", "trepanation"],
    desc: "Hippocratic and Galenic medicine combined humoral theory (four humors: blood, phlegm, yellow and black bile) with systematic anatomy and case observation. Galen of Pergamon (~130–210 CE), physician to Roman emperors, wrote prolifically and his texts, transmitted through Arabic translation, dominated medicine in Europe and the Islamic world for 1500 years. Some of his anatomy was wrong (he dissected animals), and Vesalius would correct it in 1543." },
  { id: "water-clock", name: "Water Clock", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["pulley-lever", "mathematics-arithmetic"],
    desc: "Clepsydra timing devices that measure intervals by regulated water flow into or out of a graduated vessel. Egyptian, Greek, Chinese, and later Andalusian clockmakers refined the form into elaborate astronomical and astrological displays. Water clocks freed timekeeping from sun-watching, allowed timing of indoor and nighttime events (court speeches, work shifts, prayer), and established the technical lineage that mechanical clocks inherit." },
  { id: "waterwheel", name: "Waterwheel", era: "classical", category: "energy",
    year: "~200 BCE", prereqs: ["pulley-lever", "iron-tools"],
    desc: "Vertical and horizontal water-driven mills harnessing river flow. Greek and Roman engineers from ~200 BCE built progressively larger installations; the Barbegal mill in Roman Gaul (~300 CE) had sixteen wheels in series and produced flour for tens of thousands. Water power is the first mechanical replacement for human and animal muscle and underpins medieval European agriculture and proto-industry from grain milling to fulling cloth to working bellows." },
  { id: "compass-early", name: "Lodestone Compass", era: "classical", category: "knowledge",
    year: "~200 BCE", prereqs: ["iron-smelting", "philosophy"],
    desc: "Han Chinese 'south-pointing' magnetized lodestone spoons (~200 BCE), initially used for divination and feng shui rather than navigation. By the 11th century Song Dynasty texts describe magnetized iron needles for orientation. The instrument's original use is a reminder that technology often gets invented for one purpose and only later finds its world-changing application — in this case, on shipboard centuries later." },
  { id: "triremes", name: "Triremes", era: "classical", category: "transport",
    year: "~700 BCE", prereqs: ["galley-ship", "iron-tools"],
    desc: "Three-banked oared warships with bronze rams, reaching speeds of ~9 knots and crewed by 170 oarsmen plus deck soldiers. Greek triremes won the Battle of Salamis (480 BCE) against the Persian fleet and made Athens a naval superpower. The trireme reorganized Aegean politics, made the Athenian empire possible, and remained the dominant warship in the Mediterranean for several centuries." },
  { id: "gear-mechanism", name: "Gear Mechanism", era: "classical", category: "tools",
    year: "~200 BCE", prereqs: ["pulley-lever", "iron-tools"],
    desc: "Toothed wheels meshing to transmit and transform rotational motion. The Antikythera mechanism (~150 BCE Hellenistic Greek) is an astonishing surviving example: a bronze geared computer with at least 30 gears that predicted eclipses and modeled planetary positions. The principle reappears in Hellenistic odometers, Roman watermills, and ultimately drives medieval clockwork and Renaissance machinery." },
  { id: "woodblock-printing", name: "Woodblock Printing", era: "classical", category: "communication",
    year: "~200 CE", prereqs: ["paper-making", "alphabet-greek"],
    desc: "Carved wooden blocks inked and pressed onto paper or fabric. Tang Chinese woodblock printing produced the Diamond Sutra (868 CE), the world's oldest dated printed book, and standard Buddhist canons spread by the millions. Korean and Japanese printers extended the technology, and European blockbooks of the 15th century show parallel independent practice. Though less flexible than movable type, woodblock printing is what brought books to scale across East Asia." },
  { id: "parchment-vellum", name: "Parchment & Vellum", era: "classical", category: "communication",
    year: "~200 BCE", prereqs: ["hide-clothing", "alphabet-greek"],
    desc: "Animal skins (sheep, calf, goat) scraped, limed, and stretched on a frame to produce a smooth, durable writing surface. Pergamon (Anatolia) is traditionally credited with the technique's refinement when Ptolemaic Egypt embargoed papyrus exports; the city's name gives parchment its English root. Far more durable than papyrus and writeable on both sides, parchment enabled the codex book form, the survival of Greco-Roman literature through the medieval scriptoria, and the heavy reference manuscripts on which medieval law and theology depended." },
  { id: "theatre-drama", name: "Theatre & Drama", era: "classical", category: "social",
    year: "~500 BCE", prereqs: ["philosophy", "world-religion"],
    desc: "Scripted public performance with actors, masks, chorus, and a built playhouse — a cultural technology distinct from earlier ritual reenactment. Athens institutionalized tragedy and comedy at the festival of Dionysus from ~534 BCE, giving us Aeschylus, Sophocles, Euripides, and Aristophanes; Sanskrit drama in India (Bharata's Natyasastra, ~200 BCE) and Roman adaptations developed in parallel. Theatre is the first medium that lets a society publicly debate itself in fictional form — a function later inherited by the novel, cinema, and television." },
  { id: "codex", name: "Codex", era: "classical", category: "communication",
    year: "~100 CE", prereqs: ["parchment-vellum"],
    desc: "Folded sheets stitched along one edge between protective covers — the book form, replacing the scroll. Romans used wax-tablet codices for notes by the 1st century BCE; the parchment codex emerged in the 1st century CE and was almost universally adopted by Christians for scripture, giving it a 4th-century institutional boost. The codex allows random access (open to any page), supports double-sided writing, holds far more text than a scroll of the same weight, and is structurally more durable. Every later book — printed, paperback, or hardcover — is a codex; the format has outlasted papyrus, parchment, and now coexists with screens." },

  // ─── Medieval ──────────────────────────────────────────────────
  { id: "arabic-numerals", name: "Hindu-Arabic Numerals", era: "medieval", category: "knowledge",
    year: "~800 CE", prereqs: ["zero-numeral"],
    desc: "Place-value digits 0–9 with Indian origin, transmitted through al-Khwarizmi's 9th-century Baghdad treatise on calculation and adopted in medieval Europe via Latin translations. The system makes column-arithmetic, long multiplication, and division dramatically faster than Roman numerals, and the word 'algorithm' itself comes from al-Khwarizmi's Latinized name. Italian merchants adopted the numerals in the 12th–13th centuries; by Fibonacci's Liber Abaci (1202) the European transition was underway." },
  { id: "algebra", name: "Algebra", era: "medieval", category: "knowledge",
    year: "~825 CE", prereqs: ["arabic-numerals", "geometry-euclidean"],
    desc: "Symbolic equation-solving systematized in al-Khwarizmi's 'Compendious Book on Calculation by Completion and Balancing' (~825 CE, Baghdad). 'Al-jabr' is the operation of moving a term to the other side of an equation. Islamic mathematicians (Omar Khayyam, al-Karaji) extended the work to cubics. Translated into Latin in the 12th century, algebra entered the European mathematical curriculum and became the symbolic engine driving every later mathematical advance." },
  { id: "gunpowder", name: "Gunpowder", era: "medieval", category: "weapons",
    year: "~850 CE", prereqs: ["alchemy"],
    desc: "Mixture of saltpeter, sulfur, and charcoal that deflagrates rapidly when ignited, originally developed by Tang Daoist alchemists (~850 CE) seeking elixirs of immortality. By the Song dynasty it powered fire arrows, bombs, and proto-cannons; the Mongol conquests carried it westward, and by the 14th century European founders were casting gunpowder cannons. Gunpowder ends castle warfare, reorganizes military hierarchy around mass armies, and reshapes the chemistry of warfare for 600 years." },
  { id: "moveable-type", name: "Moveable Type", era: "medieval", category: "communication",
    year: "~1040 CE", prereqs: ["woodblock-printing"],
    desc: "Individual reusable characters that can be assembled into pages of text and disassembled afterward. Bi Sheng's ceramic type (~1040 CE, Song China) was the first; Korean Jikji (1377) is the oldest extant book printed with metal moveable type, predating Gutenberg by ~75 years. Logographic Chinese scripts have thousands of characters, which limited the technique's impact; the alphabetic adaptation in Europe transformed publishing." },
  { id: "mechanical-clock", name: "Mechanical Clock", era: "medieval", category: "knowledge",
    year: "~1300 CE", prereqs: ["water-clock", "gear-mechanism", "iron-tools"],
    desc: "Verge-and-foliot escapement and weight-driven gear trains striking bells at regular intervals. Continental and English monastic clocks from ~1300 CE provide the first reliable time-of-day signaling. Famous early installations: Salisbury Cathedral (~1386), Wells Cathedral, Strasbourg's astronomical clock. The mechanical clock reshapes urban life around scheduled time rather than natural cycles, and the precision-machining traditions it spawned feed directly into all later instrument-making." },
  { id: "windmill", name: "Windmill", era: "medieval", category: "energy",
    year: "~700 CE", prereqs: ["waterwheel", "sail-primitive"],
    desc: "Wind-driven mills used for grinding grain, pumping water, and pressing oil. Persian vertical-axis post mills (~7th century) and European horizontal-axis tower mills (12th century onward) tap a power source independent of rivers. The Dutch perfected drainage windmills, reclaiming land below sea level. Europe had ~200,000 windmills at peak, and they remained important industrial power sources until steam." },
  { id: "heavy-plow", name: "Heavy Plow", era: "medieval", category: "subsistence",
    year: "~600 CE", prereqs: ["plow-ard", "iron-tools"],
    desc: "Mouldboard plow with iron coulter, share, and curved board that turns the soil over completely, burying weeds and exposing fresh earth. Effective in the heavy clay soils of northern Europe where the simple ard plow couldn't cope, the heavy plow (with ox or horse teams) opened the European plain to cereal cultivation. Yields rose 30–50% and population shifted northward, founding the agrarian basis of medieval Europe." },
  { id: "horse-collar", name: "Horse Collar", era: "medieval", category: "subsistence",
    year: "~800 CE", prereqs: ["horse-domestication", "iron-tools"],
    desc: "Padded shoulder harness developed in China by ~5th century and reaching Europe by ~1100 CE, replacing the throat-and-girth harness that strangled the horse under heavy load. The new collar transmits pull from the shoulders, letting horses out-pull oxen by 50% over short distances. Combined with iron horseshoes, the collar makes the horse the dominant European draft animal, accelerating plowing and overland transport." },
  { id: "three-field-system", name: "Three-Field System", era: "medieval", category: "subsistence",
    year: "~800 CE", prereqs: ["heavy-plow", "horse-collar"],
    desc: "Annual rotation of winter cereal, spring cereal/legume, and fallow on three fields, replacing the older two-field (one cropped, one fallow) system. By dedicating only one-third rather than half of arable land to fallow, the system raises yields dramatically; the legume crop also fixes nitrogen. Adopted across northern Europe from ~800 CE, three-field rotation underpinned the medieval population boom and the rise of cathedral towns." },
  { id: "university", name: "University", era: "medieval", category: "knowledge",
    year: "~1088 CE", prereqs: ["monasticism", "library"],
    desc: "Self-governing corporations of scholars empowered to award degrees in law, medicine, theology, and the arts. Bologna (founded ~1088) was the first; Paris (~1150), Oxford (~1167), and dozens more followed. Universities institutionalized the curriculum of trivium and quadrivium and protected scholars under papal or royal charters. The institution traveled with European colonialism and now exists in essentially every country on earth." },
  { id: "scholasticism", name: "Scholasticism", era: "medieval", category: "knowledge",
    year: "~1100 CE", prereqs: ["university", "philosophy"],
    desc: "Methodical reconciliation of Aristotelian logic with Christian theology, formalized by Anselm, Abelard, and reaching its peak with Thomas Aquinas's Summa Theologica (~1270). The method posed questions, marshaled authorities for and against, then resolved them through dialectical reasoning. Scholastic disputation trained generations of European thinkers and is the institutional and methodological matrix from which the Scientific Revolution would later emerge." },
  { id: "gothic-architecture", name: "Gothic Architecture", era: "medieval", category: "shelter",
    year: "~1150 CE", prereqs: ["arch-vault", "geometry-euclidean"],
    desc: "Pointed arches, ribbed vaults, and flying buttresses redirecting roof loads outward, allowing thinner walls and large stained-glass windows. Originating with Abbot Suger's Saint-Denis (~1140), Gothic spread through Notre-Dame de Paris, Chartres, Reims, Cologne, and York Minster. Stone walls dissolve into translucent surfaces of color and light, and cathedrals become vertical architectural statements that took centuries and entire urban economies to complete." },
  { id: "castle", name: "Castle", era: "medieval", category: "shelter",
    year: "~900 CE", prereqs: ["monumental-architecture", "iron-tools"],
    desc: "Stone fortifications integrating residence, garrison, and administrative center. From simple Norman motte-and-bailey to Crusader fortresses like Krak des Chevaliers and concentric Welsh castles (Caernarfon, Beaumaris), castles dominated the landscape. They were instruments of feudal territorial control: a noble in a castle could defy a king, but a king with a strong castle could project power across a province." },
  { id: "knight-cavalry", name: "Mounted Knight", era: "medieval", category: "weapons",
    year: "~900 CE", prereqs: ["cavalry", "saddle-stirrup", "iron-weapons"],
    desc: "Mounted noble warriors trained from childhood, in mail then plate armor, charging with couched lance and fighting with sword. Knights formed the elite shock arm of medieval European armies for ~400 years, supported by the feudal manorial system that fed and equipped them. Their importance peaked at battles like Hastings (1066) and declined under the longbow at Crécy (1346) and Agincourt (1415), and against pike formations and gunpowder." },
  { id: "longbow", name: "Longbow", era: "medieval", category: "weapons",
    year: "~1300 CE", prereqs: ["bow-arrow", "iron-tools"],
    desc: "Six-foot self-bow of yew, drawing 100+ pounds and capable of armor-piercing flight at 250+ meters. The Welsh and English longbow at Crécy, Poitiers, and Agincourt repeatedly destroyed French chivalry: a peasant trained from boyhood could put six arrows in the air per minute and outrange any crossbow. The longbow democratized lethality temporarily, until firearms made similar power available with much less training." },
  { id: "cannon-early", name: "Cannon", era: "medieval", category: "weapons",
    year: "~1300 CE", prereqs: ["gunpowder", "iron-smelting"],
    desc: "Cast or wrought-iron tubes firing stone or iron shot using gunpowder, evolving from the small handgonne to giant siege bombards. The Dardanelles Gun and other massive Ottoman siege guns brought down the walls of Constantinople in 1453, ending the eastern Roman Empire. Cannon ended the impregnable medieval castle within decades and redrew European political geography around states that could afford siege artillery." },
  { id: "caravel", name: "Caravel", era: "medieval", category: "transport",
    year: "~1450 CE", prereqs: ["galley-ship", "sail-primitive", "compass-early"],
    desc: "Lateen-rigged Iberian sailing ship combining the maneuverability of triangular sails with sturdy hull construction, capable of sailing close to the wind. Developed in the 15th century under Henry the Navigator's Portuguese exploration program, the caravel made it possible to reach the West African coast and return upwind. Columbus' Niña and Pinta were caravels, and the type effectively launched the Age of Discovery." },
  { id: "hospital", name: "Hospital", era: "medieval", category: "medicine",
    year: "~700 CE", prereqs: ["medicine-galenic", "world-religion"],
    desc: "Permanent institutions providing care for the sick, separated from private homes. Islamic bimaristans (the Bimaristan al-Mansuri in Cairo treated 8000 patients annually by the 13th century), Christian xenodochia, and Buddhist monastic infirmaries all flourished. Medieval hospitals offered actual medical care — Galenic diagnosis, herbal remedies, surgery, isolation of contagious cases — and trained generations of physicians." },
  { id: "guild", name: "Guild", era: "medieval", category: "economy",
    year: "~1100 CE", prereqs: ["city-state", "world-religion"],
    desc: "Sworn craft and merchant associations regulating quality, prices, training, and entry to a trade. Guilds set standards (the wool guilds of Flanders, the goldsmiths of Florence), trained apprentices on multi-year contracts, and provided sickness and death benefits. They were proto-corporations and the institutional ancestors of unions, professional associations, and chambers of commerce, and they dominated urban economic life from the 12th through the 18th centuries." },
  { id: "banking-double-entry", name: "Double-Entry Banking", era: "medieval", category: "economy",
    year: "~1300 CE", prereqs: ["arabic-numerals", "coinage"],
    desc: "Italian merchant bookkeeping in which every transaction is recorded twice — as a debit on one account and a credit on another — making the books self-checking. Practiced in Florence and Venice from the 13th century, codified by Luca Pacioli in 1494. The Medici Bank used it to manage offices across Europe. Double-entry makes auditing possible, fraud harder, and is the technical foundation of modern accounting and financial markets." },
  { id: "letter-of-credit", name: "Letter of Credit", era: "medieval", category: "economy",
    year: "~1300 CE", prereqs: ["banking-double-entry", "paper-making"],
    desc: "Bills of exchange that allowed a merchant to deposit money in one city and draw it in another, without physically transporting gold. Italian and Hanseatic merchants developed the form through the 13th and 14th centuries, with Pacioli formalizing it. Letters of credit reduced robbery risk on long routes, multiplied the velocity of trade, and laid the foundation for international banking — the Medici, Fugger, and Rothschild networks all built on this instrument." },
  { id: "magnetic-compass-marine", name: "Marine Compass", era: "medieval", category: "transport",
    year: "~1100 CE", prereqs: ["compass-early"],
    desc: "Magnetized iron needle floating in water or pivoting on a card and sealed in a binnacle. Adopted on Mediterranean ships by the 12th century and on Chinese vessels somewhat earlier, the marine compass made navigation possible regardless of cloud cover, freeing sailors from sun- and star-sightings. Combined with sand-glass timing and a chip-log, it enabled the dead-reckoning navigation that made open-ocean voyages reliable." },
  { id: "astrolabe", name: "Astrolabe", era: "medieval", category: "knowledge",
    year: "~800 CE", prereqs: ["astronomy-observation", "geometry-euclidean", "cartography", "celestial-navigation"],
    desc: "A handheld brass instrument that solves astronomical problems by mechanical computation: a flat disc engraved with a stereographic projection of the celestial sphere, overlaid with a rotating star map (the *rete*) and a sighting arm (the *alidade*). To use it, the navigator measures a star's altitude through the alidade, rotates the rete until that star sits at the measured altitude, and reads off everything else simultaneously — local time, latitude, the rising and setting times of any other catalogued star, the qibla direction, the times of prayer. What had been multi-hour spherical-trigonometry calculations became seconds of dial-twisting. Hipparchus laid the geometric foundation in 2nd-century BCE Alexandria, but the instrument matured in the Islamic Golden Age (al-Fazari, al-Khwarizmi, al-Zarqali, ~8th–11th centuries) and reached Europe by the 12th century. The astrolabe was the standard navigation, surveying, timekeeping, and Islamic-prayer instrument for over a thousand years until precision sextants and mechanical clocks displaced it." },
  { id: "glass-lens", name: "Glass Lens", era: "medieval", category: "knowledge",
    year: "~1000 CE", prereqs: ["glass-making", "paper-making"],
    desc: "Ground convex lenses for magnification, beginning with reading-aid lenses in 11th-century Islamic and 13th-century Italian workshops. Ibn al-Haytham's optics (~1021 CE) provided the theoretical foundation. The same techniques, refined, would yield spectacles, telescopes, and microscopes — opening up vast new domains of observation that fundamentally reshaped science from the 17th century onward." },
  { id: "spectacles", name: "Spectacles", era: "medieval", category: "medicine",
    year: "~1290 CE", prereqs: ["glass-lens"],
    desc: "Ground reading lenses set in wooden, bone, or metal frames, invented in northern Italy ~1290 CE and quickly spread by traveling friars and merchants. Spectacles extended the working life of scribes, scholars, and craftsmen by decades — pre-spectacle, presbyopia ended literate work in one's forties. The market for lenses also created a craft tradition that, by the 17th century, would supply telescopes and microscopes." },
  { id: "distillation", name: "Distillation", era: "medieval", category: "knowledge",
    year: "~800 CE", prereqs: ["alchemy", "glass-making", "fermentation-brewing"],
    desc: "Alembic separation of liquids by selective vaporization and condensation. Hellenistic alchemists used the technique; Islamic chemists refined it (Avicenna, Jabir). By the 12th century European monasteries were distilling spirits — brandy, whiskey, gin — and pharmaceutical extracts. Distillation also concentrates acids and oils, and provides the lab equipment that the Scientific Revolution and modern chemistry would inherit and elaborate." },
  { id: "paper-mill", name: "Paper Mill", era: "medieval", category: "communication",
    year: "~1100 CE", prereqs: ["paper-making", "waterwheel", "millstone"],
    desc: "Water-powered hammer mills that pulped rags and reeds into paper at scale. Islamic paper mills appear by ~750 CE; European mills by the 11th century in Spain and Italy, then Germany. Paper costs collapsed once mechanical pulping replaced hand-pounding, and the cheap supply was a precondition for the printing press: Gutenberg's invention would have been useless if every book required years of parchment from hundreds of sheep." },
  { id: "horizontal-loom", name: "Horizontal Loom", era: "medieval", category: "tools",
    year: "~1000 CE", prereqs: ["weaving", "gear-mechanism"],
    desc: "Treadle-operated horizontal loom with foot-pedals controlling heddles, freeing both hands to throw the shuttle. Adopted in Europe by ~1000 CE (likely from Islamic or Chinese sources), it raised cloth output tenfold over the older warp-weighted vertical loom. Horizontal looms made medieval Flemish and Florentine wool industries possible and set the technological starting point for the spinning jenny and power loom 700 years later." },
  { id: "quill-ink", name: "Quill & Ink", era: "medieval", category: "communication",
    year: "~600 CE", prereqs: ["paper-making"],
    desc: "Goose feather pens with iron-gall ink (oak gall tannins reacting with iron sulfate) on parchment then paper. The combination was the dominant writing technology in Europe from late antiquity to the 19th century, used for everything from monastic manuscripts to imperial decrees to merchants' ledgers. Iron gall ink survives extremely well — most medieval manuscripts are still legible after eight centuries." },
  { id: "polyphony-notation", name: "Polyphony & Staff Notation", era: "medieval", category: "social",
    year: "~1000 CE", prereqs: ["monasticism", "parchment-vellum"],
    desc: "Multi-voice singing where independent melodic lines move simultaneously, paired with a written staff that fixes pitch and duration on the page. Guido of Arezzo's four-line staff (~1025) and the syllables ut–re–mi–fa–sol–la gave singers a way to learn unfamiliar chant from a manuscript without a teacher. Notre-Dame composers (Léonin, Pérotin, ~1170–1200) extended polyphony into structured organum and motet forms. Staff notation is the first technology that lets a complex musical work survive its composer, propagate across centuries, and accumulate refinements — the foundation of the entire Western art-music tradition." },
  { id: "plate-armor", name: "Plate Armor", era: "medieval", category: "weapons",
    year: "~1400 CE", prereqs: ["knight-cavalry", "iron-tools"],
    desc: "Full-body articulated suits of hammered steel plates — cuirass, pauldrons, vambraces, greaves, and helm — covering a knight from head to foot with hinged joints that preserve mobility. Italian and German armorers (Missaglia, Helmschmid) brought the form to its peak in the 15th century, with weights of ~25 kg distributed so that a fit knight could mount unaided, run, and even climb a ladder. Plate effectively defeated arrows and most sword strikes, prolonging the dominance of heavy cavalry until firearms made any wearable thickness obsolete." },
  { id: "crank-connecting-rod", name: "Crank & Connecting Rod", era: "medieval", category: "tools",
    year: "~1200 CE", prereqs: ["gear-mechanism", "windmill"],
    desc: "A bent shaft (crank) coupled to a rigid rod (connecting rod) that converts continuous rotary motion into reciprocating linear motion — or vice versa. Used in Han Chinese trip-hammer mills (~200 CE) for grain pounding, the full crank-and-connecting-rod assembly enters European agriculture and craftwork around the 13th century: water-powered sawmills (Villard de Honnecourt's sketchbook, ~1230), hand-cranked grinding wheels, and treadle-driven lathes. The mechanism is the missing link between a turning waterwheel or piston and any machine that needs to push, pull, or saw — without it, neither the steam engine nor the internal-combustion engine is mechanically possible." },

  // ─── Renaissance ───────────────────────────────────────────────
  { id: "printing-press", name: "Printing Press", era: "renaissance", category: "communication",
    year: "1450", prereqs: ["moveable-type", "paper-mill", "quill-ink"],
    desc: "Johannes Gutenberg's mid-1440s combination of a screw press, oil-based ink, and metal moveable type cast in a hand-mold. The 42-line Bible of 1454 was the first major Western printed book. Within fifty years over twenty million books had been printed in Europe; the price per page fell ~100×. The press is the single most consequential information technology before the internet — it propagated the Reformation, the Scientific Revolution, vernacular literacy, and modern bureaucracy." },
  { id: "vernacular-literature", name: "Vernacular Literature", era: "renaissance", category: "social",
    year: "1300–1500", prereqs: ["alphabet-latin", "paper-mill"],
    desc: "Major literary works composed in spoken languages rather than Latin: Dante's Divine Comedy (~1320), Chaucer's Canterbury Tales (~1387), Cervantes' Don Quixote (1605), Boccaccio, Petrarch, Rabelais. Vernacular literature expanded reading audiences enormously, codified national languages (Tuscan as 'Italian', East Midlands English, Castilian), and broke the medieval clergy's monopoly on intellectual life. The printing press subsequently amplified the trend a hundredfold." },
  { id: "humanism", name: "Humanism", era: "renaissance", category: "social",
    year: "1400", prereqs: ["vernacular-literature", "scholasticism"],
    desc: "Recovery and study of classical Greek and Roman texts, with renewed emphasis on rhetoric, ethics, and the dignity of the individual. Petrarch's discovery of Cicero's letters (~1345), Erasmus' Greek New Testament (1516), and the rise of humanist schools across Italy and northern Europe positioned humans rather than scholastic categories at the center of inquiry. Humanism reshaped education, literature, art, and political thought from the 14th through 17th centuries." },
  { id: "linear-perspective", name: "Linear Perspective", era: "renaissance", category: "social",
    year: "1420", prereqs: ["geometry-euclidean", "vernacular-literature"],
    desc: "Geometric system for representing three-dimensional space on a flat surface, with parallel lines converging at a vanishing point. Brunelleschi's experiments with reflected images of the Florentine Baptistery (~1413) and Alberti's treatise On Painting (1435) formalized the technique. Linear perspective made Renaissance painting a window onto rationalized, measurable space and is also the conceptual ancestor of architectural drawing, technical illustration, and computer 3-D rendering." },
  { id: "oil-painting", name: "Oil Painting", era: "renaissance", category: "social",
    year: "1430", prereqs: ["pigments", "linear-perspective"],
    desc: "Pigments suspended in linseed or walnut oil, allowing slow drying, layered glazes, fine detail, and luminous color. Jan van Eyck's Arnolfini Portrait (1434) showed the technique's potential; Italians from Antonello da Messina onward adopted it from Flemish models. Leonardo, Michelangelo, Raphael, Titian, and Rembrandt all worked primarily in oil. The medium's flexibility made possible the secular portrait, the landscape, and the modern conception of painting as personal expression." },
  { id: "opera-orchestra", name: "Opera & Orchestra", era: "renaissance", category: "social",
    year: "1600", prereqs: ["vernacular-literature"],
    desc: "Sung drama with continuous instrumental accompaniment. Claudio Monteverdi's L'Orfeo (1607) is the first surviving major opera. The form combined Renaissance interest in classical theatre with elaborate stagecraft and the new musical resources of the early Baroque. Opera became court entertainment across Europe and gave rise to the modern orchestra, with sections of strings, woodwinds, brass, and percussion functioning as a single integrated instrument." },
  { id: "scientific-method", name: "Scientific Method", era: "renaissance", category: "knowledge",
    year: "1620", prereqs: ["scientific-method-proto", "printing-press", "glass-lens"],
    desc: "Systematic experimentation, mathematical description, and skepticism toward inherited authority. Francis Bacon's Novum Organum (1620) advocated inductive reasoning; Galileo's experiments with falling bodies and his telescopic observations applied mathematics to physical motion; Descartes proposed methodical doubt. The combined practice — test, measure, publish — established the productive feedback loop that has driven cumulative scientific progress ever since." },
  { id: "statics-strength", name: "Statics & Strength of Materials", era: "renaissance", category: "knowledge",
    year: "1638", prereqs: ["geometry-euclidean", "scientific-method"],
    desc: "The mathematical analysis of forces in equilibrium and the deformation that materials undergo when those forces are applied — the conceptual foundation of every later structural-engineering calculation. Galileo's *Dialogues Concerning Two New Sciences* (1638), written under house arrest in Arcetri, asked the apparently mundane question 'why does a beam break?' and showed that breaking strength scales with cross-section, not mass — the first quantitative treatment of material failure. Robert Hooke's 1660 anagram (later published as *ut tensio sic vis*, 1678) — 'as the extension, so the force' — established Hooke's law: stress is proportional to strain in the elastic regime, the linear constitutive relation that all elementary structural mechanics rests on. The Bernoulli family and Leonhard Euler (1750–80) developed beam theory: a slender beam under transverse load deforms with curvature proportional to the local bending moment, leading to closed-form deflection and failure formulas that engineers still use. Augustin-Louis Cauchy's 1827 stress tensor generalized force analysis to continuous media — the bridge to elasticity, plasticity, and fracture mechanics. Without this thread of theory, the iron-frame skyscraper, the suspension bridge, the airframe, and the pressure vessel could not be designed without prohibitive experimental trial and error." },
  { id: "heliocentrism", name: "Heliocentrism", era: "renaissance", category: "knowledge",
    year: "1543", prereqs: ["astronomy-observation", "mathematics-arithmetic", "printing-press"],
    desc: "Sun-centered model of the solar system with Earth as one planet among others. Nicolaus Copernicus published De revolutionibus orbium coelestium in 1543; Tycho Brahe's precise observations and Kepler's three laws (1609–1619) established the elliptical-orbit refinement; Galileo's telescopic discovery of Jupiter's moons and Venus's phases destroyed Ptolemaic alternatives. Heliocentrism dethroned Earth from cosmic centrality and is the symbolic opening of the Scientific Revolution." },
  { id: "algebra-symbolic", name: "Symbolic Algebra", era: "renaissance", category: "knowledge",
    year: "1591", prereqs: ["algebra", "printing-press"],
    desc: "François Viète's introduction of letters for unknowns (vowels) and constants (consonants) in his In artem analyticem isagoge (1591), allowing equations to be written and manipulated abstractly. Descartes refined the notation to the modern x, y, z for unknowns and a, b, c for constants. With symbolic algebra, equations become objects to be transformed by general rules, and the path opens to all subsequent abstract mathematics from calculus to group theory." },
  { id: "logarithms", name: "Logarithms", era: "renaissance", category: "knowledge",
    year: "1614", prereqs: ["algebra-symbolic", "mathematics-arithmetic"],
    desc: "John Napier's tables (1614) defining a function whose addition equals the multiplication of its arguments, with Henry Briggs' base-10 elaboration. The slide rule, invented by William Oughtred in 1622, mechanized logarithms for daily calculation and remained an engineer's standard tool for 350 years until pocket calculators replaced it. Logarithms compressed astronomical and navigational arithmetic by orders of magnitude." },
  { id: "anatomy-vesalius", name: "Modern Anatomy", era: "renaissance", category: "medicine",
    year: "1543", prereqs: ["medicine-galenic", "printing-press"],
    desc: "Andreas Vesalius's De humani corporis fabrica (1543), based on his own dissections at Padua, corrected over 200 of Galen's anatomical errors. Detailed engravings by Titian's workshop made the work as much an aesthetic as a scientific landmark. Combined with Harvey's later demonstration of blood circulation (1628), Vesalius's anatomy reset Western medicine on observed structure and prepared the ground for surgical and physiological advances." },
  { id: "microscope", name: "Microscope", era: "renaissance", category: "knowledge",
    year: "1620", prereqs: ["glass-lens", "spectacles"],
    desc: "Compound and simple lens systems revealing structures invisible to the naked eye. Antonie van Leeuwenhoek's hand-ground simple microscopes (~1670s) achieved 270× magnification — enough to see protozoa and bacteria. Robert Hooke's compound microscope and Micrographia (1665) introduced the word 'cell' for the chambers he saw in cork. The microscope opened biology, parasitology, microbiology, and metallurgy to direct observation." },
  { id: "telescope", name: "Telescope", era: "renaissance", category: "knowledge",
    year: "1608", prereqs: ["glass-lens", "heliocentrism"],
    desc: "Hans Lippershey's Dutch refracting telescope (1608) was almost immediately improved by Galileo (1609), whose 20× instrument revealed Jupiter's four moons, Venus's phases, sunspots, and the Milky Way's stars — observations published in Sidereus Nuncius (1610). Newton's reflecting design (1668) eliminated chromatic aberration. The telescope made the heavens an empirical, expanding domain rather than a mythological canopy." },
  { id: "pendulum-clock", name: "Pendulum Clock", era: "renaissance", category: "knowledge",
    year: "1656", prereqs: ["mechanical-clock", "mathematics-arithmetic"],
    desc: "Christiaan Huygens's 1656 horologium combined Galileo's discovery of the pendulum's isochronous swing with an escapement, achieving accuracy of seconds per day — over 100× better than verge-and-foliot clocks. Pendulum clocks anchored astronomy, navigation, and railroad scheduling for the next 250 years, and their precision feeding back into measurement made the rest of the Scientific Revolution quantitative." },
  { id: "protestant-reformation", name: "Protestant Reformation", era: "renaissance", category: "social",
    year: "1517", prereqs: ["printing-press", "world-religion"],
    desc: "Martin Luther's Ninety-five Theses (1517) attacking indulgences, propagated rapidly via the printing press, became the spark for a century of religious and political restructuring across Europe. The Reformation split Western Christianity into Catholic, Lutheran, Reformed (Calvin), Anglican, and Anabaptist confessions. Vernacular Bibles, mass literacy, and ultimately religious pluralism are downstream effects, alongside the Wars of Religion that culminated in 1648." },
  { id: "nation-state", name: "Nation-State", era: "renaissance", category: "economy",
    year: "1500", prereqs: ["empire", "printing-press"],
    desc: "Centralized monarchies with permanent bureaucracies, standing armies, and standardized taxation, replacing the layered feudal allegiances of medieval Europe. Spain under Ferdinand and Isabella, France under Louis XI through Louis XIV, England under the Tudors, and Sweden under Gustavus Adolphus all consolidated similar formulas. The Peace of Westphalia (1648) codified state sovereignty as the basic unit of international order, a structure that still governs world politics." },
  { id: "joint-stock-company", name: "Joint-Stock Company", era: "renaissance", category: "economy",
    year: "1600", prereqs: ["banking-double-entry", "nation-state", "guild"],
    desc: "Tradable shares of perpetual ownership in a chartered enterprise, pooling capital for ventures beyond any single merchant or king. The Dutch VOC (1602) and English East India Company (1600) financed long-distance trade, colonial conquest, and infrastructure. The form eventually generalized into the modern corporation, made stock exchanges (Amsterdam, London) into central institutions, and reshaped the relationship between capital and political power." },
  { id: "patent-system", name: "Patent System", era: "renaissance", category: "economy",
    year: "1474", prereqs: ["printing-press", "city-state", "guild"],
    desc: "A legal bargain between an inventor and the state: the inventor publicly discloses how a new device or process works, and in exchange receives a time-limited monopoly on commercial use, after which the invention enters the public domain. The arrangement solves a coordination problem — inventors otherwise keep techniques secret to capture rents, which means the technique dies with them and progress stalls — by aligning private incentive with public disclosure. The Venetian Patent Statute (1474) codified the system: ten-year exclusivity for novel and useful inventions, conditional on registering a working description with the state. England's Statute of Monopolies (1624) restricted royal patents to genuine inventions; the U.S. Patent Act (1790) and the global TRIPS framework (1995) propagated the model. Modern industrial research, the pharmaceutical industry, and the entire venture-capital model depend on patents to make discoveries privately financeable." },
  { id: "stock-exchange", name: "Stock Exchange", era: "renaissance", category: "economy",
    year: "1602", prereqs: ["joint-stock-company", "banking-double-entry"],
    desc: "A regulated marketplace where shares of joint-stock companies are continuously bought and sold by competing brokers, with prices set by live supply and demand and trades cleared and settled by the exchange itself. The exchange concentrates many buyers and sellers in one place, so any holder can convert shares to cash without finding a private buyer (liquidity), and the resulting price stream broadcasts a company's perceived value to the world second by second (price discovery). The Amsterdam Bourse, opened in 1602 to trade VOC shares, was the first true stock exchange and quickly added derivatives, short selling, and margin trading; the London Stock Exchange (1773) and New York Stock Exchange (1792) followed. Stock exchanges turn capital into a liquid commodity that flows toward whatever venture promises the highest risk-adjusted return — the central allocation mechanism of modern capitalism, and the institutional setting for every later innovation in finance from index funds to algorithmic trading." },
  { id: "mercantilism", name: "Mercantilism", era: "renaissance", category: "economy",
    year: "1550", prereqs: ["nation-state", "maritime-trade"],
    desc: "State economic policy aimed at maximizing bullion holdings through trade surpluses, tariffs, navigation acts, and chartered monopolies. Practiced under Colbert in France, the Navigation Acts in England (1651 onward), and Spanish/Portuguese imperial systems. Mercantilist competition drove colonial expansion, naval buildup, and the Atlantic slave trade. Adam Smith's Wealth of Nations (1776) attacked mercantilism, but its core moves persisted in 'industrial policy' through to the 21st century." },
  { id: "galleon", name: "Galleon", era: "renaissance", category: "transport",
    year: "1500", prereqs: ["caravel", "cannon-early", "triremes"],
    desc: "Multi-decked sailing warship and trader, 500–2000 tons, with multiple gun decks and substantial cargo capacity. Spanish galleons hauled Mexican silver to Manila and Manila silk to Acapulco for two and a half centuries (1565–1815) — the first truly global maritime supply chain. Galleon design also became the template for the cargo-and-warship distinction that shaped European navies through the line-of-battle era." },
  { id: "ocean-navigation", name: "Ocean Navigation", era: "renaissance", category: "transport",
    year: "1480", prereqs: ["magnetic-compass-marine", "astrolabe", "celestial-navigation"],
    desc: "Combined use of magnetic compass, astrolabe, quadrant, mariners' rutters, and dead reckoning to undertake voyages of months out of sight of land. Portuguese mastery of the technique under Henry the Navigator's Sagres school enabled the rounding of Africa (Dias 1488, da Gama 1498) and Magellan's circumnavigation (1519–1522). Ocean navigation made the Age of Discovery possible and rewired global biology, demography, and commerce." },
  { id: "new-world-encounter", name: "New World Encounter", era: "renaissance", category: "social",
    year: "1492", prereqs: ["ocean-navigation"],
    desc: "Sustained contact between Old and New Worlds beginning with Columbus's 1492 voyage to Hispaniola and Cabot's 1497 visit to Newfoundland. The encounter triggered the largest demographic catastrophe in recorded history (an estimated 90% indigenous American population collapse from disease) and the Columbian Exchange, but also the redrawing of the world political map and the beginning of Atlantic colonialism, slavery, and capitalism." },
  { id: "colonialism", name: "Colonialism", era: "renaissance", category: "economy",
    year: "1500", prereqs: ["new-world-encounter", "gunpowder"],
    desc: "Extractive overseas empires built on plantation labor, conquest, forced trade, and metropolitan settlement. Portuguese in Africa, Brazil, and the Indian Ocean; Spanish in the Americas; Dutch, English, French in everywhere from Caribbean sugar islands to Indonesian spice islands. Colonialism transferred wealth from colonies to metropoles for ~400 years, restructured global agriculture and labor, and cast a shadow whose political and economic consequences still organize the modern world." },
  { id: "columbian-exchange", name: "Columbian Exchange", era: "renaissance", category: "subsistence",
    year: "1500", prereqs: ["new-world-encounter"],
    desc: "Transfer of organisms, foods, diseases, and technologies between Old and New Worlds after 1492. Potatoes, tomatoes, maize, cacao, vanilla, tobacco, chili, beans, peanuts, and pumpkins crossed east; horses, cattle, pigs, sugarcane, wheat, and smallpox crossed west. The exchange transformed diets globally — Italian cuisine without tomatoes is unimaginable, as is Indian without chili — and reorganized agriculture on every inhabited continent." },
  { id: "musket", name: "Musket", era: "renaissance", category: "weapons",
    year: "1500", prereqs: ["gunpowder", "cannon-early", "crossbow", "longbow"],
    desc: "Hand-held matchlock and later flintlock smoothbore firearms firing lead balls. The 16th-century Spanish tercio combined pikes and muskets in mutually defending formations; by the 17th century musketeers dominated infantry and pikes vanished. A peasant could be trained to use a musket in a week — vastly less than the years required for a longbow or knight's training. Mass musket-armed infantry made the citizen-army of the late 18th century possible." },
  { id: "artillery", name: "Field Artillery", era: "renaissance", category: "weapons",
    year: "1500", prereqs: ["cannon-early", "mathematics-arithmetic", "siege-engine"],
    desc: "Mobile cast bronze and iron cannon firing solid shot, shell, or canister on calculated trajectories. The Italian Wars (1494–1559) demonstrated the dominance of mobile field artillery; by Gustavus Adolphus's reforms (1620s), artillery had become a true combined-arms partner with infantry and cavalry. Battlefield ranges grew past bowshot, sieges were re-mathematized around angles and elevations, and military engineering became a recognized profession." },
  { id: "bastion-fortification", name: "Bastion Fort", era: "renaissance", category: "shelter",
    year: "1530", prereqs: ["artillery", "geometry-euclidean", "castle"],
    desc: "Star-shaped low earthworks designed to deflect cannon shot and create overlapping fields of crossfire. Italian engineers developed the trace italienne in response to French artillery campaigns of the 1490s, and Vauban perfected the form in 17th-century France. Bastion forts made siegecraft a geometry problem (Vauban's parallels and saps systematized the attacker's response), and they dominated military architecture from ~1500 to 1860." },

  // ─── Enlightenment ─────────────────────────────────────────────
  { id: "newtonian-mechanics", name: "Newtonian Mechanics", era: "enlightenment", category: "knowledge",
    year: "1687", prereqs: ["scientific-method", "heliocentrism", "logarithms"],
    desc: "Isaac Newton's three laws of motion plus universal gravitation, published in Philosophiæ Naturalis Principia Mathematica (1687). The Principia derives Kepler's planetary laws, the tides, the precession of the equinoxes, and projectile motion from the same equations — unifying terrestrial and celestial mechanics under one mathematical theory. Newton's mechanics governed physics for over 200 years and remains accurate for non-relativistic, non-quantum problems." },
  { id: "calculus", name: "Calculus", era: "enlightenment", category: "knowledge",
    year: "1684", prereqs: ["algebra-symbolic", "cartesian-coordinates"],
    desc: "Differential and integral calculus, independently developed by Newton (~1665, fluxions) and Leibniz (~1675, modern dx/dt notation). Calculus is the mathematical language of continuous change — necessary for analyzing motion, growth, optimization, and integration of curves. Leibniz's notation prevailed; the Newton-Leibniz priority dispute poisoned English mathematics for a generation. Every modern engineering and physics curriculum begins here." },
  { id: "fluid-dynamics", name: "Fluid Dynamics", era: "enlightenment", category: "knowledge",
    year: "1757", prereqs: ["newtonian-mechanics", "calculus"],
    desc: "The mathematical theory of fluids in motion — gases and liquids treated as continuous media governed by partial differential equations. Daniel Bernoulli's *Hydrodynamica* (1738) derived the principle that bears his name: along a streamline, faster-moving fluid has lower static pressure, the relation that explains lift on a wing, draft in a chimney, suction in a Venturi tube, and the flow rate through any constriction. Leonhard Euler's 1757 equations expressed conservation of momentum for an inviscid (frictionless) fluid as a system of nonlinear PDEs — the first complete continuum-mechanics field theory in physics, two centuries before electromagnetism's Maxwell equations had a comparable form. Claude-Louis Navier (1822) and George Stokes (1845) added viscous shear stresses, producing the Navier-Stokes equations that govern essentially all real fluid behavior — from blood flow to turbulence to weather systems. Closed-form solutions exist only for highly idealized cases; the equations' general behavior in three dimensions remains one of the seven Clay Millennium Prize problems. Despite this analytical incompleteness, fluid dynamics is the working language of every later branch of engineering involving flow: hydraulic machinery, ship hulls, propellers, pipes, pumps, turbines, weather forecasting, and the entire 20th-century edifice of aerodynamics built on top of it." },
  { id: "gravitation-law", name: "Universal Gravitation", era: "enlightenment", category: "knowledge",
    year: "1687", prereqs: ["newtonian-mechanics", "calculus"],
    desc: "Inverse-square attraction between any two masses, proportional to their product. Newton derived it in the Principia by reasoning that the same force pulling apples down also keeps the moon in orbit. The law accurately predicted comet returns, tides, and the planetary perturbations that led Le Verrier to predict Neptune's existence (1846). Einstein's general relativity later subsumed it as a low-energy approximation." },
  { id: "cartesian-coordinates", name: "Cartesian Coordinates", era: "enlightenment", category: "knowledge",
    year: "1637", prereqs: ["algebra-symbolic", "geometry-euclidean"],
    desc: "René Descartes' La Géométrie (1637) established a system of perpendicular axes labeled with numerical values, allowing geometric figures to be represented by algebraic equations and vice versa. The fusion of algebra and geometry — analytic geometry — opened the door to calculus, vector analysis, and modern mathematical physics, all of which routinely shift between geometric and algebraic descriptions of the same problem." },
  { id: "probability-theory", name: "Probability Theory", era: "enlightenment", category: "knowledge",
    year: "1654", prereqs: ["algebra-symbolic"],
    desc: "Mathematical analysis of chance, founded in the 1654 correspondence between Blaise Pascal and Pierre de Fermat about gambling problems. Subsequent developments by Huygens, Bernoulli, de Moivre, and Laplace produced the law of large numbers and the central limit theorem. Probability undergirds modern statistics, insurance, quantum mechanics, machine learning, and any domain where decisions must be made under uncertainty." },
  { id: "thermometer", name: "Thermometer", era: "enlightenment", category: "knowledge",
    year: "1714", prereqs: ["glass-lens", "scientific-method"],
    desc: "Mercury-in-glass instruments with reproducible scales, developed by Daniel Fahrenheit (1714) and Anders Celsius (1742). Earlier thermoscopes (Galileo, Santorio) showed temperature changes qualitatively but lacked fixed reference points. Reliable thermometers made temperature measurable, allowing meteorology, medicine (clinical fevers), industrial processes, and the physical chemistry that would come." },
  { id: "barometer", name: "Barometer", era: "enlightenment", category: "knowledge",
    year: "1643", prereqs: ["glass-lens", "scientific-method"],
    desc: "Evangelista Torricelli's mercury column (1643) demonstrated atmospheric pressure and the existence of a vacuum above the mercury — overturning Aristotelian doctrine that nature 'abhors a vacuum'. Pascal's brother-in-law Florin Périer carried a barometer up the Puy de Dôme (1648) to confirm pressure decreases with altitude. Barometers became essential to weather forecasting, aviation, and the gas-law experiments leading to thermodynamics." },
  { id: "germ-precursor", name: "Microbial Discovery", era: "enlightenment", category: "medicine",
    year: "1676", prereqs: ["microscope", "anatomy-vesalius"],
    desc: "Antonie van Leeuwenhoek's 1670s observations of 'animalcules' (bacteria, protozoa) in pond water, dental plaque, and rainwater. Leeuwenhoek's hand-ground simple microscopes were the best of his era. The microbial world was visible but its connection to disease wasn't established until Pasteur and Koch nearly two centuries later — a long delay that vividly illustrates how seeing something is not the same as understanding what it does." },
  { id: "vaccination", name: "Vaccination", era: "enlightenment", category: "medicine",
    year: "1796", prereqs: ["germ-precursor", "hospital"],
    desc: "Edward Jenner's 1796 demonstration that exposure to cowpox protects against smallpox, by deliberately inoculating a child with cowpox material. The technique exploited the cross-immunity between related viruses without yet understanding viruses, immunity, or any of the underlying biology. Vaccination spread globally within decades, eradicated smallpox by 1980, and was the empirical foundation Pasteur built on in extending the principle to other diseases." },
  { id: "chemistry-modern", name: "Modern Chemistry", era: "enlightenment", category: "knowledge",
    year: "1789", prereqs: ["alchemy", "scientific-method"],
    desc: "Antoine Lavoisier's overthrow of the phlogiston theory and establishment of conservation of mass, oxidation theory of combustion, and a rationalized chemical nomenclature, summarized in Traité élémentaire de chimie (1789). Lavoisier was guillotined during the Revolution five years later, but his framework — quantitative experiments, balanced equations, named compounds — defined chemistry as an exact science." },
  { id: "electricity-static", name: "Static Electricity", era: "enlightenment", category: "knowledge",
    year: "1750", prereqs: ["scientific-method"],
    desc: "Benjamin Franklin's lightning experiments (1752 kite) and the Leyden jar (Pieter van Musschenbroek, 1745) put electricity firmly into experimental physics. Franklin established the conservation of charge and the conventional current direction. Coulomb's law (1785) quantified the inverse-square force between charges. Static electricity remained a curiosity until Volta's pile turned it into a source of sustained current." },
  { id: "steam-pump", name: "Atmospheric Steam Engine", era: "enlightenment", category: "energy",
    year: "1712", prereqs: ["mechanical-clock", "gunpowder", "coke-iron"],
    desc: "Thomas Newcomen's 1712 atmospheric steam engine pumped water from coal mines using condensation of steam under a piston to draw it down. The engine was inefficient — most heat was lost reheating the cylinder each cycle — but it was the first commercially deployed reciprocating steam engine and the prototype that James Watt would dramatically improve. By Newcomen's death there were ~100 of his engines working in British mines." },
  { id: "steam-engine-watt", name: "Watt Steam Engine", era: "enlightenment", category: "energy",
    year: "1776", prereqs: ["steam-pump", "calculus"],
    desc: "James Watt's 1776 improvements — separate condenser (1769), centrifugal governor, and rotary motion via sun-and-planet gear — quadrupled the efficiency of Newcomen's design. Watt's partnership with Matthew Boulton mass-produced engines for mines, mills, and eventually transport. The Watt steam engine is the canonical Industrial Revolution technology: a prime mover whose deployment grew British coal output and manufacturing by orders of magnitude in a generation." },
  { id: "coke-iron", name: "Coke-Smelted Iron", era: "enlightenment", category: "tools",
    year: "1709", prereqs: ["iron-smelting", "scientific-method"],
    desc: "Abraham Darby's 1709 substitution of coke (baked coal) for charcoal in his Coalbrookdale blast furnace eliminated the bottleneck of forest depletion that had constrained iron production. Coke smelting required higher draught (and eventually steam-driven blowers) but yielded iron in volumes previously unimaginable. Darby's grandson cast the world's first iron bridge at Coalbrookdale in 1779 — a public statement of what coke iron could do." },
  { id: "canal-system", name: "Canal Network", era: "enlightenment", category: "transport",
    year: "1761", prereqs: ["arch-vault", "mathematics-arithmetic", "coke-iron"],
    desc: "Locked artificial waterways linking rivers, mines, factories, and ports. Britain's Bridgewater Canal (1761), the Erie Canal in New York (1825), and France's Canal du Midi (1681) cut bulk freight costs to a tenth of road haulage. The 'canal mania' of the 1790s created the inland transport network that fed early Industrial Revolution mills with coal and raw cotton. Railroads later displaced most canal traffic, but the engineering tradition (locks, aqueducts, surveying) carried over." },
  { id: "turnpike-roads", name: "Turnpike Roads", era: "enlightenment", category: "transport",
    year: "1750", prereqs: ["roads-paved", "nation-state"],
    desc: "Toll-funded macadamized highways with engineered drainage and graded surfaces, replacing the rutted and seasonal cart tracks of medieval England. Telford and McAdam's road-building methods reduced London-to-Edinburgh travel from a fortnight to ~40 hours by stagecoach. Turnpikes integrated regional markets, enabled the postal system, and accustomed Britain to private-sector infrastructure financing — a model later adapted for railroads." },
  { id: "agricultural-revolution", name: "British Agricultural Revolution", era: "enlightenment", category: "subsistence",
    year: "1750", prereqs: ["three-field-system", "columbian-exchange"],
    desc: "Eighteenth-century British transformation of farming through enclosure of common land, the Norfolk four-course rotation, selective breeding (Bakewell's livestock), and new tools (Tull's seed drill, threshing machines). Yields rose ~50% across the century. The freed labor migrated to industrial cities, providing the workforce of the Industrial Revolution; cheap food underpinned the urban population boom and shifted political power away from rural nobility." },
  { id: "crop-rotation-norfolk", name: "Norfolk Rotation", era: "enlightenment", category: "subsistence",
    year: "1730", prereqs: [],
    desc: "Wheat–turnips–barley–clover four-course rotation popularized by Charles 'Turnip' Townshend in early 18th-century Norfolk. Turnips fed livestock through winter and aerated soil; clover fixed nitrogen and provided fodder. The system eliminated fallow without depleting soil — a major productivity gain over the medieval three-field system. Norfolk rotation became the template for improving agriculture across temperate Europe." },
  { id: "selective-breeding", name: "Scientific Breeding", era: "enlightenment", category: "subsistence",
    year: "1760", prereqs: ["animal-domestication", "scientific-method"],
    desc: "Robert Bakewell's Dishley Leicester sheep (1740s onward) demonstrated systematic in-and-in breeding for desired traits (here, fast meat-producing weight gain). Bakewell doubled mutton yields in two generations through pedigree selection and stud-leasing. The same principles later applied to cattle (Coke of Norfolk's Shorthorns) and grain crops; the methodology, formalized later by Mendel and biometricians, is the foundation of all modern agricultural and animal genetics." },
  { id: "enlightenment-philosophy", name: "Enlightenment Philosophy", era: "enlightenment", category: "social",
    year: "1750", prereqs: ["humanism", "scientific-method", "protestant-reformation"],
    desc: "Eighteenth-century European philosophical movement emphasizing reason, individual rights, religious tolerance, and the social contract. John Locke (rights, government by consent), Voltaire (tolerance, freedom of speech), Rousseau (social contract, popular sovereignty), Kant (autonomy, categorical imperative), Hume (empiricism, skepticism). The intellectual scaffolding of every later liberal democratic constitution and human-rights framework comes from this generation." },
  { id: "liberal-democracy", name: "Liberal Democracy", era: "enlightenment", category: "economy",
    year: "1789", prereqs: ["enlightenment-philosophy", "republic"],
    desc: "Constitutional government with civil liberties, representative legislatures, separation of powers, and judicial protection of individual rights. The American Revolution's Declaration of Independence (1776) and Constitution (1789), and the French Revolution's Declaration of the Rights of Man (1789), inaugurated the form. Liberal democracy spread unevenly — through 19th-century reform, post-WWII decolonization, and the post-1989 democratic wave — and now dominates roughly half the world's population." },
  { id: "separation-of-powers", name: "Separation of Powers", era: "enlightenment", category: "economy",
    year: "1748", prereqs: ["roman-law", "nation-state"],
    desc: "Montesquieu's 1748 treatise The Spirit of the Laws argued that liberty depends on dividing legislative, executive, and judicial functions among different bodies that check each other. The U.S. Constitution institutionalized this in 1789 with the federal three-branch system; subsequent constitutions worldwide adopted variations. The principle remains central to constitutional design and to debates about democratic backsliding when one branch encroaches on another." },
  { id: "encyclopedia", name: "Encyclopédie", era: "enlightenment", category: "knowledge",
    year: "1751", prereqs: ["enlightenment-philosophy", "printing-press"],
    desc: "Diderot and d'Alembert's Encyclopédie (1751–1772) — 35 volumes, over 70,000 articles, written by hundreds of contributors including Voltaire, Rousseau, and Buffon. Knowledge was organized for the literate public rather than the academy, with explicit aim of disseminating Enlightenment values. Royal censorship pursued it but circulation continued underground. The Encyclopédie is the direct conceptual ancestor of every later general-knowledge reference, including Wikipedia." },
  { id: "public-education", name: "Public Education", era: "enlightenment", category: "social",
    year: "1763", prereqs: ["encyclopedia", "nation-state"],
    desc: "State-funded universal schooling, with Prussia leading (1763 Generallandschulreglement), followed by France's revolutionary education laws and 19th-century Anglo-American common schools. Mass literacy and numeracy became civic infrastructure rather than a private privilege. Public education trained workers for industry, citizens for democracy, and soldiers for conscript armies, and it remains the single largest public-sector institution in most modern states." },
  { id: "factory-system", name: "Factory System", era: "enlightenment", category: "economy",
    year: "1780", prereqs: ["steam-engine-watt", "joint-stock-company"],
    desc: "Centralized power-driven workshops with wage labor and division of tasks, replacing cottage production. Richard Arkwright's Cromford Mill (1771) integrated water-powered spinning machines under one roof with disciplined shift work. The factory system reorganized work around machine schedules, separated workplace from home, generated industrial cities (Manchester, Birmingham), and produced both extraordinary productivity gains and the social conditions that would drive 19th-century labor movements." },
  { id: "spinning-jenny", name: "Spinning Jenny", era: "enlightenment", category: "tools",
    year: "1764", prereqs: ["horizontal-loom", "coke-iron"],
    desc: "James Hargreaves's 1764 multi-spindle hand-cranked spinning frame allowed one operator to spin eight (later 80+) threads simultaneously. The Jenny, together with Arkwright's water frame and Crompton's mule, transformed cotton spinning from a cottage activity into the leading edge of mechanized industry. British cotton output rose ~50× between 1770 and 1840, and India's traditional cotton industry collapsed in the face of cheap British thread." },
  { id: "power-loom", name: "Power Loom", era: "enlightenment", category: "tools",
    year: "1785", prereqs: ["spinning-jenny", "steam-engine-watt"],
    desc: "Edmund Cartwright's 1785 steam-driven loom mechanized weaving, the bottleneck after spinning was already mechanized. Cartwright's design was crude; refinements through the 1820s by Roberts and others made power weaving commercially dominant. By 1850 hand-loom weavers in Britain were largely impoverished or extinct. The power loom completed mechanization of the textile chain and made cotton cloth the first truly mass-produced industrial good." },
  { id: "naval-warship", name: "Ship of the Line", era: "enlightenment", category: "transport",
    year: "1700", prereqs: ["galleon", "artillery"],
    desc: "Wooden ship-of-the-line — three-decker first-rate carrying 100+ broadside guns and crewing ~850. HMS Victory (1765, Nelson's flagship at Trafalgar 1805) is the canonical example. Line tactics — fleets sailing in single column, pounding each other at 100-meter range — required disciplined gun crews and seamanship beyond any merchant fleet. Naval warships projected European power across the world's oceans for two centuries." },
  { id: "modern-bookkeeping", name: "Modern Bookkeeping", era: "enlightenment", category: "economy",
    year: "1700", prereqs: ["banking-double-entry", "joint-stock-company"],
    desc: "Standardized profit-and-loss and balance-sheet bookkeeping for chartered companies and growing merchant networks. Accountants like Pacioli (codifier) gave way to Dickinson (American Institute of Accountants, 1887) and the rise of corporate auditing. Modern bookkeeping made financial state legible at a glance to outsiders — investors, regulators, tax authorities — and is the technical infrastructure of the joint-stock company and the modern corporation." },
  { id: "central-bank", name: "Central Bank", era: "enlightenment", category: "economy",
    year: "1694", prereqs: ["banking-double-entry", "nation-state"],
    desc: "Government-chartered banks with monopoly note issue, lender-of-last-resort function, and management of state debt. The Bank of England (1694) and Banque de France (1800) set the pattern. Central banks gave states reliable wartime credit, smoothed financial crises (when they did), and gradually became managers of monetary policy through interest rates, open-market operations, and (post-2008) quantitative easing. Most countries now have one." },

  // ─── Industrial ────────────────────────────────────────────────
  { id: "bessemer-steel", name: "Bessemer Steel", era: "industrial", category: "tools",
    year: "1855", prereqs: ["coke-iron", "steam-engine-watt", "steel-bloomery"],
    desc: "Henry Bessemer's 1855 air-blown converter that mass-produced steel from molten pig iron in ~20 minutes by burning off excess carbon. Cost per ton of steel collapsed by ~80% in a decade, and steel — previously rarer and more expensive than silver — became the building material of railways, ships, skyscrapers, and machine tools. Andrew Carnegie's Pittsburgh mills industrialized the process at scale and made the United States the world's largest steel producer by 1890." },
  { id: "portland-cement", name: "Portland Cement", era: "industrial", category: "tools",
    year: "1824", prereqs: ["chemistry-modern", "concrete-roman"],
    desc: "Joseph Aspdin's 1824 patent for a hydraulic cement made by burning ground limestone with clay at high temperature in a kiln, then grinding the clinker into a fine powder that hardens into an artificial stone when mixed with water and aggregate. Aspdin named it after the building stone of Portland, Dorset, which it visually resembled. Where Roman pozzolanic cement depended on volcanic ash from a few specific quarries, Portland cement could be made anywhere with limestone — turning concrete from a regional curiosity into a globally available structural material. The rotary kiln (Frederick Ransome, 1885) made the production continuous and brought the price down by an order of magnitude. Portland cement is the binder in essentially every modern building, road, dam, runway, and bridge; over 4 billion tonnes are produced globally each year, and cement manufacturing alone accounts for ~8% of global CO₂ emissions — the inescapable substrate of the built world." },
  { id: "vulcanized-rubber", name: "Vulcanized Rubber", era: "industrial", category: "tools",
    year: "1839", prereqs: ["chemistry-modern"],
    desc: "Charles Goodyear's 1839 discovery that heating natural rubber latex with sulfur cross-links the polymer chains, transforming a sticky temperature-sensitive gum (soft and runny in summer, brittle in winter) into a stable, elastic, weather-resistant material. Vulcanization opened rubber's modern uses — pneumatic tires (Dunlop 1888, on which the entire automobile industry rests), engine and pump gaskets, electrical insulation for the spreading wire networks of telegraph and grid, conveyor belts, hoses, footwear, and surgical gloves. The Brazilian Amazon supplied wild Hevea latex through the 1870s; British smuggling of seeds to Kew Gardens (Wickham, 1876) and from there to Malaya seeded the plantation rubber industry that became the dominant supply by 1910. Vulcanized rubber is one of the few 19th-century materials with no good substitute even today — synthetic rubbers (1930s) supplement but have never fully replaced it." },
  { id: "railway-locomotive", name: "Steam Locomotive", era: "industrial", category: "transport",
    year: "1804", prereqs: ["steam-engine-watt", "canal-system"],
    desc: "Richard Trevithick's Penydarren locomotive (Wales, February 1804) was the first steam-powered rail vehicle to haul a load — a 10-ton iron shipment plus seventy passengers — over an industrial tramway. The form matured with George Stephenson's Locomotion No. 1 (1825) on the Stockton & Darlington Railway and his Rocket (1829), which won the Rainhill Trials and set the template: multi-tube boiler, blastpipe exhaust, valve gear. Inland transport at 50 mph collapsed travel times and unified national markets. Britain had ~10,000 km of track by 1850, the U.S. had its transcontinental route by 1869, and the Trans-Siberian was completed in 1916. Railroads also pioneered the modern corporate form, time zones, and standardized engineering practice." },
  { id: "telegraph", name: "Electric Telegraph", era: "industrial", category: "communication",
    year: "1837", prereqs: ["electricity-static", "electromagnetism"],
    desc: "Morse code over copper wires, demonstrated by Samuel Morse with his 1844 Washington–Baltimore line. By 1858 the first transatlantic cable briefly worked; permanent transatlantic service from 1866. Information detached from physical transport for the first time in history, enabling continental railway scheduling, financial markets to operate at near-real-time, and journalism to file from war zones. The telegraph is the conceptual ancestor of all electronic communication." },
  { id: "railroad-network", name: "Railroad Network", era: "industrial", category: "transport",
    year: "1840", prereqs: ["railway-locomotive", "telegraph"],
    desc: "Continental rail systems coordinated by the telegraph, transforming travel times, freight costs, and market integration. The U.S. Transcontinental Railroad (1869), the Trans-Siberian (1916), and dense European networks tied national economies together. Railways forced the adoption of standard time zones (1883 in the U.S.) and pioneered the modern multi-divisional corporation, hierarchical management, and large-scale finance." },
  { id: "steamship", name: "Steamship", era: "industrial", category: "transport",
    year: "1807", prereqs: ["steam-engine-watt", "naval-warship"],
    desc: "Robert Fulton's North River Steamboat (popularly the Clermont) began commercial service on the Hudson River in August 1807, carrying passengers between New York and Albany at ~5 mph against the current — the first sustained commercial steam navigation. Iron-hulled screw-driven oceangoing steamers like Brunel's Great Western (1838) and Great Eastern (1858) later reduced Atlantic crossings from weeks to days, on schedule. Liner services (Cunard from 1840) and global mail networks tied colonies to metropoles. The shift from sail to steam took decades because sailing ships were free of fuel costs, but by the 1880s steam dominated, and by 1900 the world's merchant marine was overwhelmingly steel-hulled steam." },
  { id: "electric-battery", name: "Voltaic Battery", era: "industrial", category: "energy",
    year: "1800", prereqs: ["electricity-static", "chemistry-modern"],
    desc: "Alessandro Volta's 1800 voltaic pile — alternating zinc and copper discs separated by salt-soaked cardboard — produced the first sustained electric current. Davy used powerful batteries to discover sodium, potassium, and several other elements by electrolysis. Within a few decades, batteries became the standard laboratory power source and made electroplating, electrolytic chemistry, and the first telegraph circuits practical." },
  { id: "electromagnetism", name: "Electromagnetism", era: "industrial", category: "knowledge",
    year: "1820", prereqs: ["electric-battery", "calculus"],
    desc: "Hans Christian Ørsted's 1820 discovery that electric currents deflect magnetic compass needles linked the two phenomena. Faraday demonstrated electromagnetic induction (1831), making generators and motors possible. Maxwell's four equations (1861–1865) unified electricity, magnetism, and light as a single phenomenon — electromagnetic waves traveling at c — and predicted radio waves before they had ever been generated. The theory underwrites every electrical and electronic technology." },
  { id: "electric-motor", name: "Electric Motor", era: "industrial", category: "energy",
    year: "1834", prereqs: ["electric-battery", "electromagnetism"],
    desc: "Rotary force generated by electromagnetic induction, with Faraday's 1821 demonstration scaling up through the 19th century to large industrial motors via Tesla's polyphase AC system (1880s). Motors could be placed where work was needed without long shafts and belts, transforming factory layout. By 1920 most industrial machinery in advanced economies was electrically driven, and motors quietly made household appliances — from sewing machines to vacuums to elevators — possible." },
  { id: "electric-generator", name: "Electric Generator (Dynamo)", era: "industrial", category: "energy",
    year: "1871", prereqs: ["electromagnetism", "steam-engine-watt"],
    desc: "A rotating machine that converts mechanical work into sustained electric current via electromagnetic induction — the inverse of the motor and the prerequisite for electricity as a utility rather than a chemical curiosity. Hippolyte Pixii's 1832 hand-cranked alternator demonstrated the principle; Werner Siemens' 1867 self-excited dynamo eliminated the need for permanent magnets by feeding part of its own output back into its field windings; Zénobe Gramme's 1871 ring-wound DC dynamo delivered smooth high-current output and was the first commercially practical generator. Coupled to steam engines (and later turbines and waterwheels), dynamos supplied orders of magnitude more current than batteries at a fraction of the cost — Edison's Pearl Street Station (1882) and every central power station after it ran on them. The dynamo is the artifact that turned electromagnetism from a laboratory effect into industrial infrastructure." },
  { id: "telephone", name: "Telephone", era: "industrial", category: "communication",
    year: "1876", prereqs: ["telegraph", "electromagnetism"],
    desc: "Alexander Graham Bell's 1876 patent on transmitting voice as varying electrical current along a wire, contested by Elisha Gray. Bell Telephone Company (1877) and AT&T (1885) wired American cities at speed; by 1900 there were 600,000 phones in the U.S., by 1950 over 50 million. The telephone became the first instantaneous person-to-person communication device available to ordinary households and the basis of the entire 20th-century telecom infrastructure." },
  { id: "radio-wireless", name: "Radio", era: "industrial", category: "communication",
    year: "1895", prereqs: ["electromagnetism", "telegraph"],
    desc: "Marconi's 1895 wireless transmissions across his Bologna estate, then 1901 across the Atlantic. The Hertzian electromagnetic waves that Maxwell had predicted now carried signal without wires. Within twenty years radio telegraphy was on every ship, by 1920 broadcast voice and music had begun (KDKA Pittsburgh), and by 1939 radio was the dominant mass medium worldwide. Radio also seeded the technical traditions for radar, television, and modern wireless networks." },
  { id: "photography", name: "Photography", era: "industrial", category: "communication",
    year: "1839", prereqs: ["chemistry-modern", "glass-lens"],
    desc: "Recording an image by exposing a light-sensitive surface — silver halide grains suspended in gelatin (film), or photoelectric pixels on a CCD/CMOS sensor (digital) — through a lens that projects the scene onto the surface. Where bright parts of the image fall, more silver halide reacts (or more electrons accumulate); chemical development converts the latent pattern into a permanent visible image, or a microcontroller reads the charge from each pixel and stores it as digital data. Exposure time, aperture, and lens focal length are independently controllable, giving the photographer command over depth of field, motion blur, and light gathering. Daguerre's 1839 silver-iodide-on-copper plates produced unique 'daguerreotypes'; Talbot's competing calotype introduced negatives that could be reprinted; Eastman's Kodak (1888) put the camera into ordinary hands ('You press the button, we do the rest'). Photography transformed visual culture, documentation, science (microscopy, astronomy), and journalism, and seeded the 20th-century explosion of cinema, television, and digital imaging." },
  { id: "cinema", name: "Cinema", era: "industrial", category: "communication",
    year: "1895", prereqs: ["photography", "opera-orchestra"],
    desc: "The Lumière brothers' 1895 Cinématographe projected moving images to a paying audience in Paris — Workers Leaving the Lumière Factory and the train arriving at La Ciotat. Within twenty years cinema was a global mass medium, by 1930 sound film was standard, and by 1950 Hollywood was the world's largest entertainment industry. Cinema invented or codified continuity editing, montage, the close-up, and the star system." },
  { id: "oil-petroleum", name: "Oil Industry", era: "industrial", category: "energy",
    year: "1859", prereqs: ["chemistry-modern"],
    desc: "Extracting and refining petroleum — a fossil mixture of hundreds of hydrocarbon molecules — into a portfolio of fuels and feedstocks. Crude oil is found in porous sedimentary rock and recovered by drilling a well that taps the reservoir under its own pressure (or, later, with pumps). Refining separates the mixture by fractional distillation: the crude is heated until it vaporizes, and the rising vapor cools at different heights of a distillation column, condensing the lightest molecules (propane, gasoline) at the top, mid-weight fractions (kerosene, diesel) in the middle, and heaviest residues (lubricants, asphalt) at the bottom. Catalytic cracking and reforming subsequently rearrange the molecules to maximize whichever fraction the market wants. Petroleum's appeal as fuel is its energy density (per kilogram, far above any battery or compressed gas), its room-temperature liquidity (storable and pumpable without cryogenics), and the existing distribution network. Edwin Drake's 1859 well at Titusville opened commercial extraction; by 1870 Rockefeller's Standard Oil controlled most American refining; by 1900 oil had become the leading fuel for ships and the new motor-cars. A century of cheap, dense, transportable energy underwrote the 20th-century economy." },
  { id: "internal-combustion", name: "Internal Combustion Engine", era: "industrial", category: "energy",
    year: "1876", prereqs: ["steam-engine-watt", "chemistry-modern", "oil-petroleum"],
    desc: "Nikolaus Otto's 1876 four-stroke cycle engine — intake, compression, power, exhaust — was the breakthrough that made petroleum-powered transport practical. Diesel's compression-ignition variant (1893) followed. The power-to-weight ratio of internal combustion vastly exceeded steam, opening the door to automobiles, aircraft, and motorboats. By 1950 internal-combustion engines outnumbered every other prime mover on Earth except electric motors." },
  { id: "automobile", name: "Automobile", era: "industrial", category: "transport",
    year: "1886", prereqs: ["internal-combustion", "bessemer-steel", "vulcanized-rubber"],
    desc: "A self-propelled passenger vehicle: a steel-frame chassis carrying an internal-combustion engine that burns gasoline to spin a crankshaft, a transmission that matches engine rpm to road speed through selectable gear ratios, a differential that lets the driven wheels turn at different speeds when cornering, suspension to absorb road shock, and a steering linkage that pivots the front wheels. Combined with pneumatic tires (which spread the contact patch and absorb vibration), the system delivers usable speed and range across rough roads at a tiny fraction of the cost of a horse-drawn carriage. Karl Benz's 1886 Patent-Motorwagen — three wheels, single-cylinder engine, ~16 km/h — was the first commercial automobile; Daimler's parallel work and the Panhard-Levassor layout (engine in front, drive to rear) defined the modern configuration. Henry Ford's assembly-line Model T (1908) made cars affordable to ordinary households. Within fifty years automobiles had reshaped cities (suburbs, parking, freeways), commerce (trucking, drive-throughs), and culture; by 2000 there were over 800 million worldwide. The car redefined personal mobility and is the single largest 20th-century driver of suburbanization, oil demand, and CO₂ emissions." },
  { id: "bicycle", name: "Safety Bicycle", era: "industrial", category: "transport",
    year: "1885", prereqs: ["bessemer-steel", "gear-mechanism"],
    desc: "John Kemp Starley's 1885 'safety bicycle' — equal-wheel, chain-driven, with pneumatic tires (Dunlop, 1888) — combined into the modern bicycle. Cheap personal mobility transformed commuting, courtship, and women's mobility (Susan B. Anthony said the bicycle 'has done more to emancipate women than anything else'). The bicycle also pioneered the manufacturing precision (ball bearings, drawn steel tubing) that would feed directly into the early automobile and aviation industries." },
  { id: "refrigeration", name: "Refrigeration", era: "industrial", category: "tools",
    year: "1876", prereqs: ["thermodynamics", "chemistry-modern"],
    desc: "Mechanical cooling that pumps heat from a cold space to a warm one against the natural temperature gradient — running the second law of thermodynamics in reverse by paying with electrical or mechanical work. The vapor-compression cycle, the design that dominates from icebox-replacements to industrial cold storage, has four parts: a compressor squeezes a refrigerant gas (originally ammonia, later CFCs, today HFCs and CO₂) until it heats up; a condenser coil outside the cabinet sheds that heat to ambient air and lets the refrigerant condense to liquid; an expansion valve lets the high-pressure liquid flash-boil into a cold low-pressure mixture; an evaporator coil inside the cabinet absorbs heat from the food, completing the loop. Carl von Linde's 1876 ammonia compression refrigerator and Edmund Carrier's chemical refrigerators (1881) industrialized the technique. Refrigeration unlocked the transcontinental meat trade (refrigerated rail cars), modern dairies, year-round produce, ice cream as mass product, the global vaccine cold chain, blood banks, the pharmaceutical industry's enzyme storage, and tropical urbanization that air-conditioned offices made bearable." },
  { id: "evolution-darwin", name: "Theory of Evolution", era: "industrial", category: "knowledge",
    year: "1859", prereqs: ["scientific-method", "selective-breeding"],
    desc: "Darwin and Wallace's joint 1858 papers and Darwin's On the Origin of Species (1859) proposed that species change over time through natural selection acting on heritable variation. The theory unified all of biology, replaced essentialist species concepts with population thinking, and proved compatible with Mendelian genetics in the 1930s 'Modern Synthesis'. Evolutionary biology is the framework within which every later biological discovery — including molecular biology and ecology — is interpreted." },
  { id: "germ-theory", name: "Germ Theory", era: "industrial", category: "medicine",
    year: "1860", prereqs: ["germ-precursor", "evolution-darwin", "cell-theory"],
    desc: "Pasteur's 1860s experiments showing that fermentation and disease are caused by specific microorganisms, plus Koch's identification of the anthrax, tuberculosis, and cholera bacilli (1876–1884). Koch's postulates established the methodology for proving a microbe causes a disease. Combined with Lister's antiseptic surgery and broad public-health reforms, germ theory ended the dominance of cholera and typhoid in cities and inaugurated modern medicine and public health." },
  { id: "antiseptic-surgery", name: "Antiseptic Surgery", era: "industrial", category: "medicine",
    year: "1867", prereqs: ["germ-theory"],
    desc: "Joseph Lister's 1867 carbolic acid spray and dressings, applied at Glasgow Royal Infirmary, dropped post-surgical mortality from ~50% to under 15% within a few years. Building on Pasteur's germ theory, Lister cleaned wounds, instruments, and surgeons' hands. Combined with anesthesia, antisepsis transformed surgery from a desperate last resort into a routine therapy and made later operations — abdominal, cardiac, transplant — practically possible." },
  { id: "anesthesia", name: "Anesthesia", era: "industrial", category: "medicine",
    year: "1846", prereqs: ["chemistry-modern", "anatomy-vesalius"],
    desc: "William Morton's 1846 ether demonstration at Massachusetts General Hospital and James Simpson's 1847 chloroform let surgeons operate on insensate patients for the first time. Pre-anesthesia surgery had to be brutally fast — the wonder is that it was ever undertaken. Anesthesia let surgeons proceed methodically, dramatically expanded the procedures that were possible, and turned surgery into a planned rather than emergency activity." },
  { id: "public-sanitation", name: "Sanitation Engineering", era: "industrial", category: "medicine",
    year: "1865", prereqs: ["germ-theory", "aqueduct"],
    desc: "Sewers, water-treatment plants, and urban hygiene legislation that ended cholera and typhoid as routine urban scourges. London's sewer system (Bazalgette, 1858–1875) followed the Great Stink of 1858; New York and Paris built parallel infrastructures. By 1900, life expectancy in major Western cities had risen by 10–15 years from sanitation alone — arguably the largest health gain ever from a single intervention." },
  { id: "vaccination-mass", name: "Mass Vaccination", era: "industrial", category: "medicine",
    year: "1880", prereqs: ["vaccination", "germ-theory"],
    desc: "Pasteur's attenuated rabies (1885) and anthrax vaccines extended Jenner's principle to many other diseases. Twentieth-century vaccines against diphtheria, tetanus, pertussis, polio, measles, and others reduced their incidence by >99% in countries with strong vaccination programs. Smallpox was eradicated by 1980 — the only human disease ever eradicated. Vaccination is plausibly the single largest source of the dramatic 20th-century improvement in child survival." },
  { id: "stethoscope", name: "Stethoscope", era: "industrial", category: "medicine",
    year: "1816", prereqs: ["anatomy-vesalius"],
    desc: "René Laennec's 1816 wooden tube — invented because he was reluctant to press his ear directly against a young female patient's chest — let physicians listen to heart, lung, and bowel sounds with clarity and a small acoustic privacy. Laennec's De l'auscultation médiate (1819) catalogued the rales, rhonchi, and murmurs that distinguish pneumonia, tuberculosis, mitral stenosis, and pericardial effusion long before X-rays or echocardiography. The stethoscope inaugurated physical-diagnosis medicine — the practice of interrogating the body's interior through external signs — and remained the single most iconic instrument of clinical medicine for two centuries." },
  { id: "endocrinology", name: "Endocrinology", era: "industrial", category: "medicine",
    year: "1889", prereqs: ["cell-theory", "germ-theory"],
    desc: "The discovery that ductless glands secrete chemical messengers — hormones — into the bloodstream to regulate distant tissues. Paul Langerhans' 1869 description of the pancreatic islets that would later be named for him, Oskar Minkowski and Joseph von Mering's 1889 demonstration that pancreatectomy in dogs causes diabetes, Edward Schäfer's coining of 'endocrine' (1905), and Bayliss and Starling's 1902 isolation of secretin (the first hormone identified) established the framework. Endocrinology turned diabetes, hypothyroidism, Addison's disease, and acromegaly from mysterious wasting illnesses into mechanistically understood conditions awaiting their replacement therapies — opening the door to insulin (1921), thyroxine, cortisone, and the entire 20th-century arc of hormone medicine." },
  { id: "synthetic-pharmaceuticals", name: "Synthetic Pharmaceuticals", era: "industrial", category: "medicine",
    year: "1897", prereqs: ["chemistry-modern", "germ-theory"],
    desc: "The deliberate chemical synthesis and mass production of drug molecules, in contrast to extraction from plants or animal tissues. Felix Hoffmann's 1897 synthesis of acetylsalicylic acid at Bayer — marketed as Aspirin from 1899 — gave the world its first blockbuster synthetic drug: cheap, stable, and effective against pain, fever, and inflammation. Paul Ehrlich's Salvarsan (1909, the first chemotherapy, against syphilis) and the German dye-industry sulfa drugs (Domagk, 1932) followed the same recipe — synthesize candidate molecules in bulk, screen for activity, scale the winners. The synthetic-drug industry that emerged from German organic chemistry around 1900 is the direct ancestor of every modern pharmaceutical company and of the regulatory infrastructure (FDA, MHRA) built to vet its output." },
  { id: "blood-typing", name: "Blood Typing", era: "industrial", category: "medicine",
    year: "1901", prereqs: ["cell-theory", "germ-theory"],
    desc: "Karl Landsteiner's 1901 discovery that human blood comes in distinct types — A, B, AB, O — distinguished by surface antigens on red blood cells, and that mixing incompatible types causes catastrophic agglutination. Earlier transfusions had been a coin-flip between rescue and death; after Landsteiner (Nobel 1930), donor and recipient could be matched on a slide in minutes. Blood banks (1937), the Rh factor (Landsteiner & Wiener, 1940), and the entire 20th-century practice of safe transfusion — without which trauma surgery, major operations, and organ transplant would all be impossible — rest on this finding. Forensic identification, paternity testing, and the modern understanding of immunology's antigen-antibody axis also trace to it." },
  { id: "aerodynamics", name: "Aerodynamics & Boundary Layer", era: "industrial", category: "knowledge",
    year: "1904", prereqs: ["fluid-dynamics", "thermodynamics"],
    desc: "The applied science of air flow around solid bodies — the subset of fluid dynamics that turned aircraft, turbine, and rocket design from empirical guesswork into a predictive engineering discipline. Ludwig Prandtl's 1904 paper at the Heidelberg International Mathematical Congress identified the *boundary layer*: a thin sheet of fluid immediately adjacent to a solid surface where viscosity dominates, surrounded by an outer flow that can be treated as inviscid (and so handled with Euler's equations rather than the full Navier-Stokes). This decomposition resolved d'Alembert's paradox — that pure inviscid theory predicts zero drag on any body — and gave engineers a tractable framework for predicting drag, separation, and stall. Frederick Lanchester (1907) and Nikolai Joukowsky (1906) independently produced the circulation theory of lift, deriving the lift on a wing from the integrated circulation around its profile (Kutta-Joukowsky theorem). Theodore von Kármán (Prandtl's student) extended the framework to compressible flow, supersonic shocks, and the vortex shedding now bearing his name. By WWII, aerodynamics had matured into the science behind every airfoil, propeller, and turbine blade; by the 1950s it underwrote supersonic flight, jet airliners, and re-entry vehicle design. Modern aircraft, wind turbines, F1 cars, and rocket nozzles are designed entirely within its framework." },
  { id: "thermodynamics", name: "Thermodynamics", era: "industrial", category: "knowledge",
    year: "1850", prereqs: ["steam-engine-watt", "calculus", "thermometer"],
    desc: "Sadi Carnot (1824), then Clausius and Lord Kelvin (1850s), formalized the laws governing heat, work, and entropy. The first law (energy conservation) and the second law (entropy increases) explained why the Watt steam engine had practical efficiency limits and led to better engine design. Boltzmann's statistical interpretation tied thermodynamics to atomic physics. Modern engineering, chemistry, biology, and cosmology all rest on thermodynamic principles." },
  { id: "periodic-table", name: "Periodic Table", era: "industrial", category: "knowledge",
    year: "1869", prereqs: ["chemistry-modern"],
    desc: "Dmitri Mendeleev's 1869 arrangement of elements by atomic mass, with gaps where he predicted undiscovered elements — gallium, scandium, germanium — soon found with the predicted properties. The table revealed deep structure in chemistry, later understood (post-Bohr) as electron-shell organization. Mendeleev's table is the single most useful chart in any science: it codifies and predicts an enormous body of facts in one glance." },
  { id: "atomic-theory", name: "Atomic Theory", era: "industrial", category: "knowledge",
    year: "1808", prereqs: ["chemistry-modern"],
    desc: "John Dalton (1808) revived atomism on quantitative chemical evidence; J.J. Thomson (1897) found the electron; Rutherford's gold-foil scattering (1911) showed atoms have small dense nuclei; Bohr (1913) explained spectral lines with quantized orbits. By the 1920s atoms had become the best-confirmed object in physics — invisible to the eye but central to chemistry, materials science, and ultimately quantum theory." },
  { id: "electron-discovery", name: "Electron", era: "industrial", category: "knowledge",
    year: "1897", prereqs: ["atomic-theory", "electromagnetism"],
    desc: "J.J. Thomson's 1897 cathode-ray experiments at the Cavendish Laboratory showed cathode rays were streams of negatively charged particles ~1/2000 the mass of a hydrogen atom. The electron was the first sub-atomic particle identified, and its discovery destroyed the centuries-old assumption that atoms were indivisible. Robert Millikan's oil-drop experiment (1909) measured its charge precisely and confirmed charge quantization." },
  { id: "x-ray", name: "X-Ray", era: "industrial", category: "medicine",
    year: "1895", prereqs: ["electromagnetism", "atomic-theory"],
    desc: "Wilhelm Röntgen's 1895 accidental discovery of penetrating radiation that exposed photographic film through opaque objects, including a famous image of his wife's hand showing her wedding ring. Within months X-rays were being used clinically to image broken bones and bullet locations. The discovery launched diagnostic radiology, opened the field of crystallography (Bragg, 1912), and established the high-energy electromagnetic spectrum as a real phenomenon to be explored." },
  { id: "machine-tool", name: "Machine Tools", era: "industrial", category: "tools",
    year: "1820", prereqs: ["factory-system"],
    desc: "Lathes, planers, milling machines, shapers, and gear-cutters that work metal to engineered specifications, themselves made by other machine tools. Henry Maudslay (~1800) and Joseph Whitworth (1840s) standardized screw threads and surface flatness. Machine tools — machines that make machines — are the meta-technology underwriting all subsequent manufactured precision: railroads, ships, automobiles, aircraft, and computers." },
  { id: "interchangeable-parts", name: "Interchangeable Parts", era: "industrial", category: "tools",
    year: "1820", prereqs: ["machine-tool", "factory-system"],
    desc: "Eli Whitney's 1798 musket contract for the U.S. Army was meant to demonstrate parts that could be swapped freely; the manufacturing reality lagged the rhetoric, but by John Hall's Harpers Ferry rifles (1820s) it was achieved. Mass repair, standardized assembly, and the eventual assembly line all rest on this principle. Without interchangeable parts there is no Ford, no Boeing, no Toyota Production System." },
  { id: "assembly-line", name: "Assembly Line", era: "industrial", category: "economy",
    year: "1913", prereqs: ["interchangeable-parts", "factory-system", "power-loom"],
    desc: "Henry Ford's moving-line at Highland Park (1913) reduced Model T assembly time from 12 hours to 93 minutes, dropping the price from $850 (1908) to $260 (1925). Workers stayed in place while the chassis moved past them, each performing one operation. The Ford system spread worldwide as 'Fordism', made cars and consumer durables affordable to the working class, and shaped 20th-century manufacturing through the Toyota Production System and modern lean manufacturing." },
  { id: "modern-corporation", name: "Modern Corporation", era: "industrial", category: "economy",
    year: "1880", prereqs: ["joint-stock-company", "factory-system", "modern-bookkeeping"],
    desc: "A legal organism distinct from its owners and employees, defined by three innovations that compound each other. Limited liability caps each shareholder's loss at what they invested, so ordinary households can buy a share without fearing personal bankruptcy if the firm fails — which makes very large pools of capital available for risky long-horizon ventures. Tradable shares allow ownership to be subdivided and transferred without disrupting operations. And a salaried professional management team is separated from the owners, so day-to-day decisions are made by people who specialize in running the business while shareholders supply capital and elect a board. Multi-divisional structure (Alfred Sloan at GM, 1920s) added another layer: each product line operates as a quasi-autonomous unit reporting to headquarters on a few financial metrics, allowing a single corporation to coordinate dozens of distinct businesses. Standard Oil (1870), U.S. Steel (1901), General Electric (1892), and the German cartels defined the form. The modern corporation made multi-billion-dollar capital projects possible, drove early 20th-century rises in living standards, and generated the regulatory backlash (antitrust, securities law) that defines mature industrial capitalism." },
  { id: "labor-union", name: "Labor Union", era: "industrial", category: "economy",
    year: "1850", prereqs: ["factory-system", "liberal-democracy"],
    desc: "Organized collective bargaining by workers, gaining legal recognition through 19th- and 20th-century struggles: the Combination Acts (UK), Knights of Labor and AFL (U.S.), Trades Union Congress (UK), and continental syndicalism. Unions won the eight-hour day, weekend, child-labor abolition, workplace-safety law, and unemployment insurance. They also became powerful political constituencies whose alliances with social-democratic parties shaped 20th-century welfare states." },
  { id: "newspaper-mass", name: "Mass Newspaper", era: "industrial", category: "communication",
    year: "1850", prereqs: ["printing-press", "telegraph"],
    desc: "Penny papers (Sun, NY, 1833; Tribune; Times) replaced the partisan/elite press with mass-circulation dailies financed by advertising. Wire services (Reuters 1851, AP 1846) supplied national and international news to local papers. By 1900 most Western adults read a paper daily. The mass press created the modern public, public opinion polling targets, and shared national narratives — and also yellow journalism, propaganda, and circulation wars that would shape 20th-century political crises." },
  { id: "skyscraper", name: "Skyscraper", era: "industrial", category: "shelter",
    year: "1885", prereqs: ["bessemer-steel", "electric-motor", "elevator", "statics-strength"],
    desc: "Steel-frame construction (load on internal skeleton, not load-bearing walls) plus elevators allowed buildings to climb past stone's ~10-story limit. Chicago's Home Insurance Building (1885) is usually cited as the first; New York's Flatiron (1902), Woolworth (1913), Chrysler (1930), and Empire State (1931) raced upward in successive decades. Skyscrapers concentrated commerce vertically, redefined urban skylines, and required the lift, telephone, and central HVAC to be functional." },
  { id: "elevator", name: "Safety Elevator", era: "industrial", category: "tools",
    year: "1857", prereqs: ["bessemer-steel", "electric-motor"],
    desc: "Elisha Otis's 1853 safety brake — which gripped the rails if the cable broke — made vertical transport psychologically acceptable. The first passenger elevator was installed at New York's Haughwout Building (1857). Without safe elevators, skyscrapers couldn't function: every floor above the fourth would be unrentable. Otis Elevator (founded 1853) remained the dominant maker for over a century." },
  { id: "machine-gun", name: "Machine Gun", era: "industrial", category: "weapons",
    year: "1884", prereqs: ["artillery", "interchangeable-parts", "musket", "bolt-action-rifle"],
    desc: "Hiram Maxim's 1884 recoil-operated water-cooled gun fired 600 rounds/minute from a single barrel. Earlier hand-cranked Gatling guns (1862) had pointed the way. Maxim guns and successors (Vickers, MG08, M1917) made cavalry charges suicidal and entrenched the Western Front of WWI. Industrial-scale lethality with one operator made every army's pre-1914 tactical doctrine obsolete and reshaped the experience of war for the rest of the 20th century." },
  { id: "electrification", name: "Grid Electrification", era: "industrial", category: "energy",
    year: "1882", prereqs: ["electric-motor", "electric-generator", "electromagnetism"],
    desc: "Building a network that generates electric power at central stations, transmits it long distances, and distributes it to homes, factories, and street lights — making electricity a utility rather than a private installation. The decisive engineering choice was alternating current. Direct current loses too much power to resistance over distance and cannot be efficiently stepped up to high voltage; AC can be transformed up to hundreds of kilovolts for transmission (at which voltage the current — and thus resistive loss — is small) and stepped back down to safe household voltages near the customer, using passive iron-core transformers that need no moving parts. Edison's 1882 Pearl Street Station lit lower Manhattan with DC; Tesla and Westinghouse's AC system won the 'War of Currents' through the 1890s and became the global standard. The grid then layered on synchronized generators, voltage regulation, fault protection, and a metering and billing system. By 1925 most urban Western homes had electricity; by 1955 most rural farms in the U.S. were connected after the Rural Electrification Act. Electrification redefined work, leisure, agriculture, and the home." },
  { id: "aluminum-smelting", name: "Aluminum Smelting", era: "industrial", category: "tools",
    year: "1886", prereqs: ["chemistry-modern", "electrification"],
    desc: "Extracting aluminum metal from its ore by electrolysis. Aluminum is the third most abundant element in Earth's crust, but it bonds so tightly to oxygen in bauxite that no chemical reductant can pry it loose at reasonable temperatures — until 1886, aluminum was rarer than gold, and Napoleon III reserved aluminum cutlery for his most distinguished guests. Charles Hall (USA) and Paul Héroult (France) independently discovered that dissolving alumina in molten cryolite at ~960°C drops its melting point far enough that an electric current can split it: aluminum metal collects at the carbon cathode, oxygen burns away at the carbon anode. The reaction is enormously power-hungry — roughly a third of an aluminum smelter's product cost is electricity — so plants cluster near hydroelectric dams (Iceland, Pacific Northwest, Quebec). Cheap aluminum opened aviation (the Wright Flyer's engine block, every later airframe), beverage cans, power transmission lines, and modern lightweight construction. The metal was the first material whose price was set primarily by electricity rather than mining." },
  { id: "ac-power-transformer", name: "AC Power & Transformer", era: "industrial", category: "energy",
    year: "1886", prereqs: ["electric-generator", "electromagnetism"],
    desc: "Alternating-current electricity distribution and the transformer that makes it work. The transformer — two coils of wire wound on a shared iron core — exploits Faraday's induction to convert AC between voltages with no moving parts and minimal loss: a high-turn primary fed from low-voltage AC induces a high-voltage low-current AC in a low-turn secondary (or vice versa). This solves the central problem of long-distance electrical transmission, since resistive line losses scale with the square of current; stepping voltage up to tens of kilovolts for transmission and back down at the customer cuts those losses by orders of magnitude. William Stanley's 1886 commercial transformer at Great Barrington and the Westinghouse-Tesla polyphase AC system (1888 patents on the induction motor and rotating-field generator) won the 'War of Currents' against Edison's DC by ~1893, when the Niagara Falls hydropower contract chose AC. AC at 50/60 Hz with three-phase distribution and step-down transformers at the curb is the global electricity standard a century later, and the transformer is arguably the single most-deployed piece of complex hardware in industrial civilization." },
  { id: "electric-lighting", name: "Electric Lighting", era: "industrial", category: "energy",
    year: "1879", prereqs: ["electric-generator", "electromagnetism"],
    desc: "Practical incandescent lamps — a sealed glass bulb, an evacuated or inert-gas atmosphere, and a high-resistance filament that glows white-hot when current passes through it. Joseph Swan (UK, 1878) and Thomas Edison (USA, 1879) independently produced the first commercially viable lamps; Edison's later switch to drawn-tungsten filaments (1906–10) gave the form that lasted a century. Electric light decoupled human activity from the sun: factories ran round the clock, cities became navigable at night, the work day extended, and the demand for steady electricity drove the construction of the entire grid. Indoor gas lighting and oil lamps disappeared from cities within a generation." },
  { id: "submarine", name: "Submarine", era: "industrial", category: "transport",
    year: "1900", prereqs: ["internal-combustion", "electric-motor", "ironclad-warship"],
    desc: "Self-propelled vessels capable of submerged combat patrols, using diesel engines for surface running and electric motors on batteries while underwater. Early designs by David Bushnell (1775) and the Confederate H. L. Hunley (1864, the first to sink an enemy warship) were experimental; John Holland's USS Holland (1900) and the German U-boats of WWI established the form. The submarine inverted naval power: a small, cheap craft could threaten battleships costing a hundred times as much, and unrestricted submarine warfare in WWI and WWII reshaped Atlantic strategy and ultimately drove the development of sonar, convoy doctrine, and the nuclear-powered boats that followed." },
  { id: "sewing-machine", name: "Sewing Machine", era: "industrial", category: "tools",
    year: "1846", prereqs: ["machine-tool", "interchangeable-parts"],
    desc: "A mechanized lockstitch — two threads passing through fabric, one above (needle thread) and one below (bobbin thread), interlocking with each puncture of an eye-pointed needle driven by a crank or treadle. Walter Hunt (1830s) and Elias Howe (1846) developed the principle; Isaac Singer's 1851 vertical-needle machine and aggressive franchise-and-installment-credit retail model brought the device into millions of homes by 1870. A skilled hand-sewer manages a few stitches per second; the machine runs at hundreds. Garment prices collapsed, ready-to-wear clothing replaced bespoke tailoring, the textile factory's bottleneck shifted from spinning and weaving to assembly, and footwear, harness, sail, and book-binding industries all reorganized around the same lockstitch." },
  { id: "phonograph", name: "Phonograph & Sound Recording", era: "industrial", category: "communication",
    year: "1877", prereqs: ["electromagnetism"],
    desc: "Capturing sound as a physical groove and replaying it. Edison's 1877 tinfoil-cylinder phonograph used a vibrating diaphragm to scratch a vertical-cut groove into a rotating cylinder; a stylus tracking the groove on playback reproduced the original vibration. Berliner's 1887 disc gramophone and shellac records made mass-pressing economic; Bell Labs' electrical recording (1925) replaced the acoustic horn with a microphone and amplifier, and magnetic tape (1935 onward) decoupled recording from playback medium. Sound recording detached music and speech from the moment of performance, gave rise to the recorded-music industry, transformed radio and cinema, and is the technological foundation of all later audio media — from LP and CD to streaming." },
  { id: "impressionism", name: "Impressionism", era: "industrial", category: "social",
    year: "1874", prereqs: ["oil-painting", "photography"],
    desc: "A French painting movement that abandoned the dark, finished surface of academic painting for visible brushwork, broken color, plein-air composition, and momentary effects of light. The 1874 group exhibition in Paris (Monet, Renoir, Degas, Pissarro, Sisley, Cézanne, Berthe Morisot) gave the movement its name — from Monet's 'Impression, Sunrise.' New industrial-era inputs made it possible: ready-made paint in metal tubes, synthetic pigments, the railway taking painters to the countryside, and photography lifting the burden of literal representation from painting. Impressionism is the hinge between centuries of academic European art and 20th-century modernism — Post-Impressionism, Cubism, Fauvism, and Expressionism all begin from its rejection of the polished classical surface." },

  // ─── Modern ────────────────────────────────────────────────────
  { id: "airplane", name: "Airplane", era: "modern", category: "transport",
    year: "1903", prereqs: ["internal-combustion", "bicycle", "fluid-dynamics"],
    desc: "A heavier-than-air vehicle that flies on aerodynamic lift. Air rushing over a curved wing travels faster across the upper surface than the lower, producing a pressure difference that pushes the wing upward (the same Bernoulli/circulation effect that lets a sail work sideways across the wind); this lift balances gravity at sufficient airspeed. An engine and propeller provide the forward thrust that keeps air flowing over the wing; control surfaces — ailerons that roll the aircraft, an elevator that pitches it up and down, a rudder that yaws it — give the pilot independent command of all three axes. The Wright brothers' decisive 1903 breakthrough was not the wing or the engine (others had built both) but coordinated three-axis control: wing-warping that banked the aircraft into a turn while the rudder coordinated yaw, allowing controlled curved flight rather than only straight-line glides. From 12 seconds at Kitty Hawk, the aircraft scaled in less than a lifetime to Bleriot crossing the Channel (1909), Lindbergh crossing the Atlantic (1927), and 1950s jet airliners bringing intercontinental travel to ordinary people." },
  { id: "relativity", name: "Relativity", era: "modern", category: "knowledge",
    year: "1905", prereqs: ["electromagnetism", "thermodynamics", "gravitation-law"],
    desc: "Einstein's 1905 special relativity (constant speed of light, time dilation, mass-energy equivalence E=mc²) and 1915 general relativity (gravity as curvature of spacetime). General relativity has been verified by the bending of starlight near the Sun (1919 eclipse), gravitational time dilation (atomic clocks), gravitational lensing, the perihelion of Mercury, and gravitational waves (LIGO 2015). It is the framework underlying modern cosmology and GPS." },
  { id: "stellar-evolution", name: "Stellar Evolution & H-R Diagram", era: "modern", category: "knowledge",
    year: "1913", prereqs: ["thermodynamics", "atomic-theory", "astronomy-observation"],
    desc: "The recognition that stars are not eternal but pass through a predictable life cycle determined by their mass — and the diagrammatic framework that makes this visible at a glance. Ejnar Hertzsprung (1911) and Henry Norris Russell (1913) independently plotted stellar luminosity against surface temperature (or spectral class) and found that ~90% of stars fall along a single diagonal 'main sequence,' with red giants and white dwarfs occupying their own clusters off the line. Arthur Eddington's 1920s stellar-structure theory then explained why: a star is a self-regulated thermonuclear fusion reactor in hydrostatic equilibrium, whose evolution depends almost entirely on its initial mass. Hans Bethe's 1939 paper detailed the proton-proton chain and CNO cycle that fuse hydrogen to helium in stellar cores. The Burbidges, Fowler, and Hoyle's 1957 B²FH paper showed that all elements heavier than helium are forged in stars and ejected by stellar winds and supernovae. Stellar evolution is the framework that explains why low-mass stars become white dwarfs, intermediate-mass stars become neutron stars, and the heaviest stars collapse to black holes — turning the night sky from a static backdrop into a 13-billion-year time-resolved chemistry experiment." },
  { id: "pulsars-neutron-stars", name: "Pulsars & Neutron Stars", era: "atomic", category: "knowledge",
    year: "1967", prereqs: ["stellar-evolution", "quantum-mechanics", "radio-wireless"],
    desc: "The empirical discovery and theoretical understanding of compact stellar remnants — objects so dense that a teaspoon of their material weighs as much as Mount Everest. Walter Baade and Fritz Zwicky's 1934 paper, written one year after Chadwick's discovery of the neutron, proposed that core-collapse supernovae leave behind 'neutron stars' supported against gravity by neutron degeneracy pressure — a then-radical claim about objects 10 km across with the mass of the Sun. Subrahmanyan Chandrasekhar's 1931 calculation of the maximum white-dwarf mass (~1.4 solar masses, the Chandrasekhar limit) had set the boundary at which electron-degeneracy fails and gravitational collapse continues to neutron-star or black-hole densities. The empirical confirmation came in November 1967 when graduate student Jocelyn Bell Burnell, working with Antony Hewish at Cambridge, detected a regularly pulsing radio signal — at first labeled 'LGM-1' (little green men) before being identified as a rapidly rotating neutron star whose magnetic-pole emission swept past Earth like a lighthouse beam. The Crab pulsar (1968), embedded in the SN 1054 supernova remnant, clinched the connection. Magnetars (Robert Duncan & Christopher Thompson, 1992 theory; SGR 1806-20, 1998–2004) extended the family with neutron stars carrying 10¹⁴–10¹⁵ gauss fields — a quadrillion times Earth's. Neutron stars remain the densest directly observable matter in the universe and the natural laboratory for QCD at supranuclear density, the equation of state of dense matter, and extreme magnetohydrodynamics." },
  { id: "pulsar-timing-array", name: "Pulsar-Timing Array", era: "information", category: "knowledge",
    year: "2023", prereqs: ["pulsars-neutron-stars", "relativity", "advanced-chip-manufacturing"],
    desc: "A galactic-scale gravitational-wave detector built not from interferometer arms but from millisecond pulsars themselves — the most stable natural clocks in the universe. Each pulsar emits radio pulses that arrive at Earth on a schedule predictable to nanoseconds over years; a passing low-frequency gravitational wave (nanohertz range, with periods of years to decades) stretches and compresses the spacetime between Earth and each pulsar, advancing or delaying the arrival of pulses by tens of nanoseconds. Cross-correlating residuals across dozens of pulsars distributed around the sky cancels random per-pulsar drifts and reveals the characteristic Hellings-Downs angular signature that proves the deviations come from spacetime ripples rather than clock noise. Three regional consortia — NANOGrav (North America), the European Pulsar Timing Array, and the Parkes PTA (Australia) — combined their data as the International Pulsar Timing Array; in June 2023 they jointly announced detection of a stochastic gravitational-wave background at frequencies of 1–10 nHz, almost certainly produced by the cosmic ensemble of inspiraling supermassive black-hole binaries at the centers of merging galaxies. PTAs cover a frequency range twelve orders of magnitude below LIGO and complementary to the future LISA mission, and they use the universe's own clocks rather than human-built mirrors — making the neutron stars themselves the engineering substrate of the detector." },
  { id: "kilonova-merger", name: "Kilonova & Neutron-Star Merger", era: "information", category: "knowledge",
    year: "2017", prereqs: ["pulsars-neutron-stars", "relativity"],
    desc: "The 17 August 2017 detection of GW170817 — gravitational waves from two inspiraling neutron stars 130 million light-years away in NGC 4993 — followed 1.7 seconds later by a short gamma-ray burst (GRB 170817A) and within hours by a fading optical-infrared glow that telescopes worldwide observed for weeks. The combined signal validated three decades of theoretical work in a single event. Neutron-star mergers were confirmed as the source of short gamma-ray bursts. The optical 'kilonova' afterglow (~1000× brighter than a nova, hence the name) carried spectroscopic fingerprints of freshly synthesized lanthanides and other heavy elements, confirming neutron-star mergers as the dominant cosmic source of r-process nucleosynthesis — gold, platinum, uranium, and roughly half of all elements heavier than iron. The merger remnant probed the neutron-star equation of state at the densest reachable conditions. GW170817 inaugurated multi-messenger astronomy as a routine practice and demonstrated that the universe can now be observed simultaneously through gravity, light, neutrinos, and (eventually) cosmic rays — each carrying complementary information about the same event. Subsequent detections (GW190425, GW230529) and the planned LIGO Voyager / Einstein Telescope / Cosmic Explorer upgrades will turn neutron-star mergers from exceptional events into a standard astrophysical population." },
  { id: "quantum-mechanics", name: "Quantum Mechanics", era: "modern", category: "knowledge",
    year: "1925", prereqs: ["atomic-theory", "relativity"],
    desc: "Heisenberg's matrix mechanics (1925), Schrödinger's wave equation (1926), and Dirac's relativistic synthesis (1928) established the mathematical formalism describing atomic-scale matter. Bohr's complementarity, Heisenberg's uncertainty principle, and the Born rule replaced classical determinism with probabilistic predictions. Quantum mechanics underwrites essentially all post-1950 technology — semiconductors, lasers, MRI, atomic clocks, modern chemistry — and remains experimentally unfalsified." },
  { id: "radar", name: "Radar", era: "modern", category: "knowledge",
    year: "1935", prereqs: ["radio-wireless", "electromagnetism"],
    desc: "Radio echo-location of aircraft and ships, developed independently in Britain, Germany, the U.S., and the Soviet Union in the 1930s. The British Chain Home network gave RAF Fighter Command 20+ minutes of warning during the Battle of Britain (1940), arguably decisive. Radar also seeded the microwave electronics traditions that gave us the magnetron (cavity magnetron, microwave oven), early radio astronomy, and ultimately modern wireless communications." },
  { id: "helicopter", name: "Helicopter", era: "modern", category: "transport",
    year: "1939", prereqs: ["airplane", "aerodynamics"],
    desc: "An aircraft that generates lift from a powered rotor — a giant rotating wing — instead of from forward motion through the air, allowing it to take off vertically, hover, and fly in any direction. The pilot controls flight by tilting the rotor disc through cyclic and collective pitch on each blade: collective changes the angle of attack of all blades together (raising or lowering the helicopter), while cyclic varies the angle around each rotation, tipping the rotor disc to translate horizontally. A small tail rotor (or counter-rotating main rotors) cancels the torque the main rotor would otherwise impart to the fuselage. Igor Sikorsky's VS-300 (1939) was the first practical single-rotor helicopter with anti-torque tail rotor; by 1944 the R-4 was in U.S. military service. Helicopters reach places airplanes cannot — mountain rescues, hospital roofs, oil platforms, urban skylines — and have become iconic in Korean and Vietnam-era medevac, oil exploration, and emergency medicine, where the 'golden hour' for trauma often depends on rotor-wing transport." },
  { id: "jet-engine", name: "Jet Engine", era: "modern", category: "transport",
    year: "1939", prereqs: ["airplane", "thermodynamics", "aerodynamics"],
    desc: "A continuous-flow gas turbine: a multi-stage compressor sucks in air and squeezes it to many atmospheres of pressure, fuel is sprayed into the compressed stream and burned, the hot expanding gas spins a turbine on the same shaft (which drives the compressor), and what remains rushes out the back as thrust. Unlike a piston engine, every part of a jet operates continuously rather than in cycles, and there are no reciprocating masses to limit rpm — so a jet can ingest much more air per second than an equivalent-weight piston engine, producing far more power per kilogram, and it works better at high altitude where the air is thin. Frank Whittle (UK, patented 1930, first run 1937) and Hans von Ohain (Germany, 1939) developed the technology independently; the Gloster Meteor and Me 262 saw combat in WWII. Jets doubled airliner cruise speeds (~900 km/h) and altitudes (~11 km) by the 1960s, putting Australia about a day from Europe and revolutionizing long-distance travel." },
  { id: "rocket", name: "Liquid-Fuel Rocket", era: "modern", category: "transport",
    year: "1926", prereqs: ["internal-combustion", "chemistry-modern"],
    desc: "A vehicle propelled by ejecting hot gas from a nozzle at extreme velocity, generating thrust by Newton's third law — the only propulsion that works in vacuum, since it carries both fuel and oxidizer rather than relying on atmospheric oxygen. In a liquid-fuel rocket, two propellants (typically liquid oxygen and kerosene, hydrogen, or methane) are pumped from insulated tanks into a combustion chamber where they burn at thousands of kelvins, expanding through a bell-shaped nozzle that converts thermal energy into directed exhaust velocity. Performance is governed by the rocket equation, which sets the maximum velocity gain as exhaust velocity times the natural log of the mass ratio — the punishing reason rockets are mostly fuel tank. Robert Goddard's flight at Auburn, Massachusetts on March 16, 1926 was the first sustained liquid-fuel rocket launch, reaching 12 m altitude on liquid oxygen and gasoline. Wernher von Braun's V-2 (Germany, 1944) — built by slave labor at Mittelwerk and used to bomb London — was the first to reach space and the first to be weaponized. After WWII, Soviet (Korolev) and American (von Braun) descendants — R-7, Atlas, Saturn V, Soyuz — became the ladder by which humans reached orbit, the Moon, and the rest of the solar system." },
  { id: "nuclear-fission", name: "Nuclear Fission", era: "modern", category: "energy",
    year: "1938", prereqs: ["quantum-mechanics", "electron-discovery"],
    desc: "The discovery that the heaviest atomic nuclei (uranium-235, plutonium-239) split when struck by a slow neutron, dividing into two lighter nuclei plus a few free neutrons and releasing about 200 MeV of energy per fission — roughly ten million times the energy released by burning a chemical bond. The released neutrons can in turn induce more fissions, sustaining a chain reaction whose rate is controlled by adjusting how many neutrons survive between events (control rods absorb them; moderators slow them to the velocities at which they fission most efficiently). Hahn and Strassmann's December 1938 chemical demonstration that uranium bombarded with neutrons split into barium and krypton was interpreted theoretically by Meitner and Frisch a month later. Fermi's Chicago Pile-1 (December 1942) achieved the first controlled chain reaction by stacking graphite blocks (moderator) around uranium chunks (fuel) in geometry calculated to be just supercritical with movable cadmium rods (absorbers) for control. Within three years fission had been weaponized, ending the Pacific war; civilian power and propulsion followed." },
  { id: "nuclear-weapon", name: "Nuclear Weapon", era: "atomic", category: "weapons",
    year: "1945", prereqs: ["nuclear-fission", "game-theory"],
    desc: "A bomb that releases energy by splitting heavy atomic nuclei (uranium-235 or plutonium-239) in an exponentially branching chain reaction: each fission releases a few free neutrons, which in turn split more nuclei, doubling the rate every ten nanoseconds and converting a fraction of the fuel mass into energy according to E = mc². The engineering problem is to assemble a supercritical mass — enough fissile material in a small enough volume that neutrons hit other nuclei before escaping — faster than the bomb can blow itself apart from its own heat. Two solutions: the gun-type design slams two subcritical pieces together (Hiroshima's Little Boy, uranium); the implosion design surrounds a subcritical sphere with shaped explosives that compress it to supercritical density (Nagasaki's Fat Man, plutonium). The Manhattan Project's Trinity test (July 16, 1945) was the first detonation; Hiroshima and Nagasaki followed in August. A single warhead releases the energy of tens of thousands of tons of TNT in a microsecond. Nuclear weapons reshaped grand strategy, sovereignty, and existential risk; mutually assured destruction kept superpower war cold for forty-five years." },
  { id: "nuclear-power", name: "Nuclear Power", era: "atomic", category: "energy",
    year: "1954", prereqs: ["nuclear-fission"],
    desc: "Generating electricity from a controlled nuclear-fission chain reaction. Inside the reactor core, fuel rods of slightly enriched uranium (3–5% U-235) sit immersed in a moderator (water in PWRs and BWRs, graphite in RBMKs, heavy water in CANDU) that slows fission neutrons enough to keep the chain reaction running; movable control rods of neutron-absorbing material (boron, cadmium) are inserted or withdrawn to hold the reactor at exactly criticality. The fission heat is removed by a coolant loop, used to boil water into high-pressure steam, and that steam drives turbines coupled to electrical generators — exactly like a coal plant from the steam onward, but with a fission core instead of a furnace. The fundamental advantages over fossil power are the energy density (one fuel pellet matches a ton of coal) and the lack of CO₂ emissions; the disadvantages are the high capital cost, the radioactive waste that requires geological-timescale storage, and the catastrophic-failure mode if the chain reaction or cooling system loses control. Obninsk (USSR, 1954) and Calder Hall (UK, 1956) were the first commercial reactors. Three Mile Island (1979), Chernobyl (1986), and Fukushima (2011) shaped public attitudes; France runs ~70% on nuclear, Germany has phased out, and modular reactors are under development." },
  { id: "antibiotics", name: "Antibiotics", era: "modern", category: "medicine",
    year: "1928", prereqs: ["germ-theory", "chemistry-modern"],
    desc: "Drugs that kill or stop the growth of bacteria inside a patient without killing the patient's own cells, exploiting biochemical machinery that bacteria have but human cells lack. Penicillin and its β-lactam descendants block the enzymes bacteria use to build cross-links in their cell walls; the bacterium can't seal its outer envelope as it divides and bursts under its own osmotic pressure, while human cells (which have no cell wall) are untouched. Other antibiotic families target ribosomes specific to bacteria (tetracyclines, macrolides), DNA gyrase (fluoroquinolones), or folate synthesis (sulfonamides), each exploiting a similar pharmacological window between human and bacterial biology. Alexander Fleming noticed in 1928 that Penicillium mold killed surrounding Staphylococcus colonies on a contaminated plate; Florey, Chain, and the U.S. wartime program scaled production from 1942–45. Streptomycin (1944), tetracycline (1953), and successive families followed. Bacterial infection — leading cause of death for most of human history — became routinely treatable. Antibiotic resistance, driven by selection pressure from overuse, is now a serious and growing public-health threat." },
  { id: "vaccines-modern", name: "Modern Vaccines", era: "atomic", category: "medicine",
    year: "1955", prereqs: ["vaccination-mass", "germ-theory", "antibiotics", "refrigeration"],
    desc: "Salk's killed-virus polio vaccine (1955) and Sabin's live oral version (1961) eliminated most polio in industrialized countries; Maurice Hilleman developed dozens of major vaccines including measles, mumps, rubella, hepatitis B, and chickenpox. Smallpox eradication completed in 1980 was the first time humans deliberately drove a disease extinct. Polio is currently endemic in only Afghanistan and Pakistan; measles incidence has been cut by >99% in vaccinated populations." },
  { id: "organ-transplant", name: "Organ Transplant", era: "atomic", category: "medicine",
    year: "1954", prereqs: ["antiseptic-surgery", "anesthesia", "blood-typing"],
    desc: "Removing a failing organ from one person and surgically installing a healthy organ from another, with the recipient's immune system held back from rejecting the foreign tissue. Three subproblems had to be solved together. The vascular technique — sewing severed arteries and veins together so blood flows again without clotting at the seam — was perfected by Alexis Carrel (Nobel 1912). Tissue typing (matching donor and recipient on the HLA antigens that the immune system reads as 'self') minimized rejection. And immunosuppression — first whole-body irradiation, then azathioprine and steroids in the 1960s, then cyclosporine (1983), tacrolimus, and modern monoclonal-antibody regimens — kept the recipient's T-cells from destroying the graft long enough to integrate. Joseph Murray performed the first successful kidney transplant between identical twins in Boston (1954); Christiaan Barnard the first heart transplant (1967); liver, lung, pancreas, intestine, and face transplants followed. Over a million people are alive today thanks to a transplanted organ, and supply (deceased and living donors) remains the binding constraint until lab-grown organs replace them." },
  { id: "dna-structure", name: "DNA Double Helix", era: "atomic", category: "knowledge",
    year: "1953", prereqs: ["x-ray", "evolution-darwin", "quantum-mechanics"],
    desc: "Watson, Crick, Franklin, and Wilkins's 1953 model of the DNA double helix, based on Franklin's X-ray Photo 51 and Chargaff's base-pairing rules. The structure immediately suggested both how genetic information was encoded (sequence of bases) and how it was copied (template-directed replication). Within a generation the genetic code was deciphered, recombinant DNA was possible, and the road to genome sequencing was open." },
  { id: "synthetic-fertilizer", name: "Haber–Bosch Process", era: "modern", category: "subsistence",
    year: "1913", prereqs: ["chemistry-modern", "agricultural-revolution", "electrification"],
    desc: "Fritz Haber's 1909 ammonia synthesis from atmospheric nitrogen and hydrogen at high pressure, scaled up by Carl Bosch at BASF (Haber-Bosch process, 1913). Nitrogen fertilizer freed agriculture from the limits of natural nitrogen fixation by legumes and bird-droppings. Roughly half of the nitrogen atoms in your body passed through a Haber-Bosch reactor. The process feeds an estimated half of the world's current population." },
  { id: "green-revolution", name: "Green Revolution", era: "atomic", category: "subsistence",
    year: "1960", prereqs: ["synthetic-fertilizer", "selective-breeding", "crop-rotation-norfolk", "refrigeration"],
    desc: "Norman Borlaug's high-yielding semi-dwarf wheat (Mexico, 1950s), and the IRRI's IR8 rice (Philippines, 1966), packaged with synthetic fertilizers, irrigation, and pesticides, multiplied cereal yields across South Asia and Latin America. India tripled wheat production between 1965 and 1980. The Green Revolution is widely credited with averting hundreds of millions of famine deaths, though its environmental and equity costs have driven later debates about agricultural sustainability." },
  { id: "plastic-polymer", name: "Plastics", era: "modern", category: "tools",
    year: "1907", prereqs: ["chemistry-modern", "oil-petroleum"],
    desc: "Leo Baekeland's 1907 Bakelite — phenol formaldehyde polymer — was the first fully synthetic plastic. Polyethylene (1933, ICI), nylon (1935, DuPont), PVC, polystyrene, polypropylene, and PET followed in succession. By 2020 global plastic production exceeded 380 million tons annually. Plastics are cheap, moldable, durable, light — and stubbornly persistent in the environment, with microplastic contamination now found from deep oceans to human placenta." },
  { id: "synthetic-fibers", name: "Synthetic Fibers", era: "modern", category: "tools",
    year: "1935", prereqs: ["plastic-polymer", "power-loom"],
    desc: "Long-chain polymers spun into continuous filaments that mimic and surpass natural fibers. Rayon (regenerated cellulose, 1894) was first; the breakthrough was Wallace Carothers's nylon (DuPont, 1935) — a true polyamide synthesized from petrochemicals, strong enough to replace silk in stockings and parachutes. Polyester (1941), acrylic (1948), and spandex (1958) followed. Synthetic fibers freed clothing from agricultural land area, supplied wartime parachutes and ropes when Asian silk was cut off, and reshaped fashion, carpeting, tire cords, and industrial textiles. By 2020 they accounted for roughly two-thirds of global fiber production." },
  { id: "transistor", name: "Transistor", era: "atomic", category: "tools",
    year: "1947", prereqs: ["quantum-mechanics", "electron-discovery"],
    desc: "A three-terminal solid-state device — typically a sandwich of doped silicon regions (P and N type) — in which a tiny voltage applied to the middle terminal (the gate or base) controls a much larger current flowing between the other two (source and drain, or emitter and collector). Because the controlling input draws almost no current, transistors can amplify weak signals and switch on and off billions of times per second, all without the heated filament and fragile vacuum that vacuum tubes required. The same physics, miniaturized and replicated, also makes transistors usable as binary switches: a transistor that's either fully on or fully off represents a '1' or '0'. Bardeen, Brattain, and Shockley's December 1947 Bell Labs point-contact transistor (Nobel 1956) was the first working device, replaced within a decade by the planar bipolar and then MOSFET designs that dominate today. Transistors made portable radios (1954), digital computers practical, and ultimately every modern electronic device possible. They are arguably the single most consequential 20th-century invention." },
  { id: "semiconductor", name: "Integrated Circuit", era: "atomic", category: "tools",
    year: "1958", prereqs: ["transistor"],
    desc: "An entire electronic circuit — transistors, resistors, capacitors, and the wiring between them — fabricated as a single piece on one slab of silicon, rather than assembled from individually packaged components soldered to a board. The trick is photolithography: a silicon wafer is repeatedly coated with photosensitive resist, exposed through a patterned mask that defines the circuit, etched, and doped with impurities to define each transistor's terminals; with each cycle, more layers of components and metal interconnect are stacked atop the previous ones, building a 3-D circuit on a 2-D die. Because every transistor on the chip is created in the same parallel process, doubling the transistor count roughly doubles the cost only of the mask design, not the chip itself — which is the economic reason Moore's Law (Gordon Moore, 1965) held for over fifty years, with transistor density doubling roughly every two years. Jack Kilby (Texas Instruments, 1958) and Robert Noyce (Fairchild, 1959) independently invented the integrated circuit. Today's chips contain tens of billions of transistors and are made by TSMC, Samsung, and Intel using extreme ultraviolet lithography at near-atomic precision." },
  { id: "hard-disk-drive", name: "Hard Disk Drive", era: "atomic", category: "tools",
    year: "1956", prereqs: ["transistor", "digital-computer"],
    desc: "Bulk magnetic storage built around stacked rapidly-spinning platters coated with a magnetizable film, with read-write heads flying micrometers above the surface on a thin aerodynamic air bearing. Bits are stored as orientation reversals of magnetic domains, addressed by combining the platter's rotation with radial head motion. IBM's 1956 RAMAC 305 was the first — fifty 24-inch platters, 5 MB total, the size of two refrigerators — built to bring random-access storage to mainframes that had previously relied on serial magnetic tape. Subsequent decades drove areal density up by twelve orders of magnitude (giant magnetoresistive heads, 1997; perpendicular recording, 2005; helium-filled drives, 2013), pushing capacities from megabytes to 30+ terabytes per drive. The hard disk was the dominant bulk-storage form for fifty years — every PC, server, and data center ran on them — and remained the cheapest cost-per-bit medium even after flash memory took over the active-data tier in the 2010s. Hyperscale cloud archives still spin platters by the exabyte." },
  { id: "photolithography", name: "Photolithography", era: "atomic", category: "tools",
    year: "1959", prereqs: ["semiconductor", "glass-lens"],
    desc: "Pattern-transfer onto silicon by projecting an image of a circuit-pattern mask through a lens onto a wafer coated with photosensitive resist; the exposed resist is developed away, leaving the unexposed regions as a stencil through which the next process step (etch, ion implant, metal deposit) acts only on the desired areas. Jay Lathrop and James Nall at the U.S. Diamond Ordnance Fuze Lab patented the technique for transistor manufacturing in 1957–59, and it became the standard way to make integrated circuits within a few years. Each successive layer of a chip — channels, gates, contacts, metal interconnect — is patterned by its own mask in a separate exposure cycle, with hundreds of cycles building up a complete chip. Resolution is set by the wavelength of the exposing light divided by the lens numerical aperture (the Rayleigh limit), driving lithography wavelengths down through visible (435 nm) → near-UV (365 nm) → deep UV (248, 193 nm) → extreme UV (13.5 nm) over six decades. Photolithography is the central economic engine of Moore's Law: because every transistor on a wafer is patterned in parallel by one exposure, the cost per transistor falls geometrically as feature size shrinks, even as the cost of a single tool rises geometrically. It is the reason a chip with 50 billion transistors costs less than a wristwatch did in 1960." },
  { id: "dram-memory", name: "DRAM (Semiconductor Memory)", era: "atomic", category: "tools",
    year: "1970", prereqs: ["semiconductor", "photolithography"],
    desc: "Dynamic Random-Access Memory: a chip that stores each bit as the charge on a tiny capacitor, accessed through a single transistor — a one-cell design (Robert Dennard, IBM, 1968) so dense that millions of bits fit on one die. The 'dynamic' qualifier reflects the catch: the capacitor leaks, so every cell must be refreshed every few milliseconds by the memory controller, transparent to software. Intel's 1103 chip (1970, 1 Kbit) made DRAM cheaper per bit than the magnetic-core memory that had dominated computing for two decades; mainframe and minicomputer makers switched within five years, and the personal computer was born on DRAM from day one. Density doubled every 18 months for forty years (Hwang's Law) — from 1 Kbit to 32 Gbit per chip — and DRAM became one of the largest single-product industries on Earth (Samsung, SK Hynix, Micron). Every CPU's main memory is DRAM; modern systems pair tens of GB of DRAM with terabytes of flash and disk in a tiered hierarchy. Without dense, cheap DRAM, neither the personal computer nor the smartphone nor the AI training boom would be economically possible." },
  { id: "laser", name: "Laser", era: "atomic", category: "tools",
    year: "1960", prereqs: ["quantum-mechanics", "quantum-electrodynamics"],
    desc: "Light Amplification by Stimulated Emission of Radiation: an optical cavity in which excited atoms are pumped to a population inversion and induced to emit photons in lockstep, producing a beam that is monochromatic, coherent, and tightly collimated. Theodore Maiman built the first working laser at Hughes Research in 1960 using a ruby crystal; gas (HeNe), semiconductor diode, and solid-state Nd:YAG variants followed within a decade. Lasers are now woven into ordinary technology — barcode scanners, fiber-optic communication, CD/DVD/Blu-ray drives, laser printers, eye surgery, gravitational-wave interferometers, semiconductor lithography, and precision metrology — and remain one of the most general-purpose physics tools ever invented." },
  { id: "plate-tectonics", name: "Plate Tectonics", era: "atomic", category: "knowledge",
    year: "1965", prereqs: ["continental-drift"],
    desc: "The unifying theory that Earth's lithosphere is broken into rigid plates riding on a slowly convecting mantle, with continents passively carried along, oceans opening at mid-ocean ridges, and crust consumed at subduction zones. Wegener's 1912 continental-drift hypothesis languished for fifty years for lack of a mechanism; the synthesis came in 1960–67 from sea-floor magnetic stripe data (Vine, Matthews, and Morley) confirming Hess's 'sea-floor spreading' (1962), Wilson's transform-fault concept (1965), and Morgan, McKenzie & Parker's plate-kinematics formulation (1967). Plate tectonics gives a single mechanism for earthquakes, volcanoes, mountain building, ocean basins, ore deposits, biogeographic distributions, and long-term climate — the closest thing the earth sciences have to a unifying theory analogous to evolution in biology or atomic theory in chemistry." },
  { id: "digital-computer", name: "Digital Computer", era: "atomic", category: "knowledge",
    year: "1945", prereqs: ["machine-tool", "mathematics-arithmetic", "cryptanalysis-bombe"],
    desc: "A machine that represents every kind of information — text, numbers, images, sound — as binary digits and processes them by executing a sequence of stored instructions. The architecture (Eckert, Mauchly, and von Neumann, 1945) consists of memory holding both data and program, an arithmetic-logic unit that performs simple operations on bits (add, AND, compare), a control unit that fetches the next instruction and decides what to do, and input/output channels. Because the program lives in the same memory as the data, the same hardware can be repurposed by loading different software — Turing's 1936 theoretical insight that a single 'universal' machine, properly programmed, can simulate any other computing process. Each instruction does very little, but a billion of them run in a second on modern hardware, and the cumulative result is enough to sort a database, decode a video, or play a chess grandmaster. ENIAC (1945, U.S.) was the first general-purpose electronic computer; the secret British Colossus (1943) preceded it. Within decades the digital computer absorbed essentially every kind of information processing humans had previously done by hand." },
  { id: "programming-language", name: "Programming Languages", era: "atomic", category: "communication",
    year: "1957", prereqs: ["digital-computer", "cryptanalysis-bombe"],
    desc: "FORTRAN (Backus, 1957), LISP (McCarthy, 1958), COBOL (Hopper, 1959), ALGOL (1958–60), and the C language (Ritchie, 1972) made programming a discipline with formal grammars and tools rather than raw machine-code patching. Higher-level abstractions — variables, functions, objects, type systems — let programmers tackle ever-larger systems. Today's billions of lines of code in production are descendants of these foundational languages." },
  { id: "mainframe", name: "Mainframe", era: "atomic", category: "tools",
    year: "1964", prereqs: ["digital-computer", "semiconductor", "hard-disk-drive"],
    desc: "A large institutional computer optimized for high-throughput transaction processing — running thousands of small business operations per second with extreme reliability rather than raw scientific compute speed. Mainframes are built around redundant power supplies, hot-swappable components, multiple I/O channels handling disk and network traffic in parallel with the CPU, and an operating system whose first priority is to never lose a transaction. They typically support hundreds or thousands of simultaneous users via remote terminals. IBM's System/360 family (1964) unified IBM's product line around a single instruction-set architecture that could span low-end and high-end machines, so software written for one model ran on every other — an unprecedented compatibility commitment that locked customers in for decades and underwrote IBM's dominance of corporate computing. Mainframes became the back office of banks, airlines, insurers, and governments, and they remain there: most credit-card transactions and many airline bookings still touch a mainframe today." },
  { id: "information-theory", name: "Information Theory", era: "atomic", category: "knowledge",
    year: "1948", prereqs: ["probability-theory", "digital-computer"],
    desc: "A mathematical theory that quantifies *information* itself, treating any message as a selection from a set of possibilities. Claude Shannon's 1948 paper *A Mathematical Theory of Communication* defined the bit (the choice between two equally likely options), the entropy of a source (the average information per symbol, measured in bits), and the channel capacity (the maximum bit rate any noisy medium can carry without error). Two startling theorems followed: any source can be losslessly compressed down to its entropy and no further (the basis of ZIP, MP3, JPEG); and as long as the transmission rate stays below channel capacity, error-correcting codes can drive the error probability arbitrarily close to zero, even on a noisy channel — the basis of every modern modem, hard drive, satellite link, and wireless protocol. Information theory turned communication from an art into an engineering discipline with hard mathematical limits, and underlies cryptography, machine learning (cross-entropy loss), and statistical physics (Shannon entropy ≡ Gibbs entropy)." },
  { id: "operating-system", name: "Operating System", era: "atomic", category: "communication",
    year: "1969", prereqs: ["mainframe", "programming-language"],
    desc: "A privileged software layer that mediates between application programs and the bare hardware, doing four things every program would otherwise have to redo: scheduling the CPU among many processes that all believe they have it to themselves; managing memory by giving each process a private virtual address space and paging unused regions to disk; abstracting devices (disks, printers, network cards, screens) behind a uniform file interface so programs read and write streams of bytes regardless of what is actually on the other end; and enforcing protection so a buggy or hostile program can't corrupt the kernel or other users' data. The first batch monitors of the 1950s gave way to time-sharing systems (CTSS 1961, Multics 1965), then to UNIX (Thompson and Ritchie at Bell Labs, 1969) — written in the new C language and designed around a small set of composable primitives that could be ported to any computer. UNIX's descendants (Linux, BSD, macOS, Android, iOS) now run essentially every server, smartphone, and embedded device on Earth; Windows is the major non-UNIX survivor. The operating system is the substrate on which every later piece of software stands." },
  { id: "relational-database", name: "Relational Database", era: "atomic", category: "tools",
    year: "1970", prereqs: ["operating-system", "programming-language"],
    desc: "Storing structured data as tables of rows and columns, with relationships expressed by shared key values rather than navigational pointers, and querying the result with a high-level declarative language that says what to return rather than how to retrieve it. Edgar Codd's 1970 paper at IBM ('A Relational Model of Data for Large Shared Data Banks') applied first-order predicate logic and set theory to data management, decoupling the logical schema (what the data means) from the physical storage layout (how the disk is organized) — so applications could be rewritten without re-engineering the storage, and storage could be optimized without rewriting applications. IBM's System R prototype produced SQL (1974), Larry Ellison's Oracle (1979) was the first commercial relational database, and Ingres / Postgres / MySQL / SQL Server / DB2 followed. ACID transactions (atomic, consistent, isolated, durable) gave applications a guarantee that concurrent updates would never corrupt the data, even on power failure. The relational database is the substrate of essentially all enterprise computing — banking, airline reservations, payroll, e-commerce, social-network back-ends — and remained dominant for fifty years before NoSQL and columnar variants began to chip away at edge cases. The data layer of the modern web is, almost without exception, a descendant of Codd's 1970 paper." },
  { id: "television", name: "Television", era: "modern", category: "communication",
    year: "1928", prereqs: ["cinema", "radio-wireless"],
    desc: "Sending moving pictures with synchronized sound by radio. A camera scans the scene line by line, converting brightness at each point into a varying electrical signal; the receiver reverses the process, painting an electron beam across a phosphor-coated screen in the same scan pattern, with the beam's intensity following the original signal so that an image rebuilds dozens of times per second. Vladimir Zworykin's iconoscope (1923) and Philo Farnsworth's image dissector (1927) provided competing electronic scanning systems; the BBC began regular broadcasts in 1936. The cathode-ray tube ruled receivers for sixty years before flat panels (LCD, OLED) replaced it in the 2000s. After WWII television diffused through Western households in a generation — ~10% of U.S. homes in 1950, 90% by 1962 — and became the dominant 20th-century mass medium, structuring news, entertainment, advertising, and politics until streaming displaced broadcast in the 2010s." },
  { id: "satellite", name: "Artificial Satellite", era: "atomic", category: "communication",
    year: "1957", prereqs: ["rocket", "radio-wireless"],
    desc: "A spacecraft placed in orbit around the Earth, falling continuously toward the planet but moving sideways fast enough that the surface curves away beneath it — a condition first specified by Newton's cannonball thought experiment and reached for the first time when a multi-stage rocket pushed a payload above the atmosphere at ~7.8 km/s. From orbit a single satellite has line-of-sight to a substantial fraction of the planet, making it the cheapest possible relay for radio signals and the only platform from which weather, terrain, and other planet-scale phenomena can be photographed in one frame. Different orbits suit different jobs: low-Earth orbit (~500 km) for high-resolution imaging and short-latency communications; geostationary orbit (~36,000 km) for fixed coverage of one continent; medium-Earth orbit for navigation. Sputnik 1 (USSR, October 4, 1957) — a 58 cm aluminum sphere transmitting beeps — terrified the West and triggered the space race; within a decade satellites had become essential for communications (Telstar 1962), reconnaissance (Corona), weather forecasting, navigation (Transit, then GPS), and astronomy above the blurring atmosphere (Hubble 1990, James Webb 2021)." },
  { id: "spaceflight", name: "Human Spaceflight", era: "atomic", category: "transport",
    year: "1961", prereqs: ["rocket", "satellite"],
    desc: "Putting a person above the atmosphere and into orbit, then bringing them back alive — a problem requiring a rocket large enough to lift a pressurized capsule, life-support systems that recycle oxygen and remove CO₂ for hours to months, a heat shield to survive 3,000°C reentry temperatures as the capsule decelerates by friction with the upper atmosphere, and parachutes or wings to land softly. The capsule must also shield occupants from solar and cosmic radiation and provide some defense against micrometeorite impacts. Yuri Gagarin's April 12, 1961 flight aboard Vostok 1 — one orbit, 108 minutes — made him the first human in space; Alan Shepard followed in May. Crewed spaceflight expanded with Mercury, Gemini, Apollo, Soyuz, the Space Shuttle (the first reusable orbital vehicle), the ISS, and now Crew Dragon and Starship. Roughly 700 humans have flown to space, and the ISS has been continuously inhabited since November 2000." },
  { id: "moon-landing", name: "Moon Landing", era: "atomic", category: "transport",
    year: "1969", prereqs: ["spaceflight", "digital-computer"],
    desc: "Sending humans to the surface of another world and bringing them home. The Apollo architecture used a three-stage Saturn V rocket to lift a stack containing a service module, a command capsule, and a separate lunar lander; once in lunar orbit, two astronauts descended in the lander while one stayed in the command module, then ascended back from the surface in the lander's smaller upper stage and rendezvoused for the return trip. Each step demanded engineering feats new to the species: a 110-meter rocket throwing 130 tons toward the Moon, a real-time guidance computer with 64 KB of memory, hand-stitched space suits maintaining one atmosphere of pressure on the airless surface, and a heat shield surviving 11 km/s reentry. Apollo 11's July 20, 1969 landing put Neil Armstrong and Buzz Aldrin on the Sea of Tranquility while Michael Collins orbited above; five further landings followed through December 1972. The program cost ~$280 billion in 2020 dollars and remains the high-water mark of crewed exploration; the Artemis program now aims to return humans to the lunar surface." },
  { id: "mass-media", name: "Mass Media", era: "atomic", category: "communication",
    year: "1950", prereqs: ["television", "newspaper-mass"],
    desc: "Radio, television, and magazines integrated into a unified cultural pipeline reaching tens of millions of listeners and viewers daily. Public broadcasters (BBC, NHK) and commercial networks (NBC, CBS, ABC) shaped national conversations from the 1930s through the 1990s, with shared evening news constructing common factual ground. The pattern fragmented after cable, then collapsed with streaming and social media, leaving the contemporary 'high-choice' media environment." },
  { id: "consumer-economy", name: "Consumer Economy", era: "atomic", category: "economy",
    year: "1950", prereqs: ["assembly-line", "mass-media", "refrigeration"],
    desc: "An economic regime in which growth depends on continuously expanding household consumption of mass-produced durable goods, sustained by three reinforcing mechanisms: assembly-line manufacturing that drops unit costs, broadcast advertising that creates and shapes demand, and consumer credit (mortgages, car loans, credit cards) that lets households spend before they earn. Postwar Western economies — particularly the U.S. — institutionalized cars, appliances, single-family suburban homes, and lifestyle aspirations as the markers of the good life, while supermarket chains, department stores, and later big-box retailers (Walmart, 1962) compressed retail margins through scale. The system requires constant turnover — last year's car must look obsolete next year — and made the household, not the firm or the worker, the central economic unit. The same logic later propagated globally, with East Asia, then India and China, replicating the pattern at progressively larger scales." },
  { id: "credit-card", name: "Credit Card", era: "atomic", category: "economy",
    year: "1958", prereqs: ["modern-corporation", "telephone", "federal-reserve"],
    desc: "A payment instrument that lets a consumer buy on credit at any merchant in a network, rather than from one specific store. The card carries an account number; at the point of sale, the number is read (formerly via carbon imprint, later magnetic stripe, EMV chip, and NFC), and within seconds a four-party network — issuing bank, merchant's bank, card brand (Visa, Mastercard), and merchant — authorizes the transaction by checking the cardholder's available credit and routes the funds to settle the next day. The cardholder then receives a monthly bill and may either pay in full or roll over the balance at high interest, generating the revenue stream that sustains the system alongside merchant fees. Diners Club (1950) was the first universal charge card; BankAmericard (1958, later Visa) and Mastercard (1966) added revolving credit. Credit cards reorganized retail (immediate authorization, fewer cash transactions), built the modern consumer-credit economy, and produced multinational payment networks that became critical infrastructure." },
  { id: "container-shipping", name: "Container Shipping", era: "atomic", category: "transport",
    year: "1956", prereqs: ["steamship", "assembly-line"],
    desc: "A revolution in freight handling based on a single standardized object: a 20- or 40-foot corrugated-steel box with twist-lock fittings at the corners, sized so it can be lifted by the same crane and locked onto the same chassis whether it sits on a ship, a railcar, or a truck. Before containerization, every loose carton, sack, and barrel was loaded and unloaded by hand at every transfer point, taking days per ship; with containers, a 100,000-ton vessel can be unloaded by a few automated gantry cranes in hours, and the box never has to be opened until it reaches the consignee. The standardization plus the ISO twist-lock spec is what makes ship → rail → truck transitions seamless. Malcom McLean's 1956 demonstration aboard the Ideal X collapsed freight handling costs by ~95% over the following decades; container ships have grown to 24,000 TEU, and ports, railyards, and trucking all reorganized around the box. Containerization is the unglamorous logistics infrastructure that enabled globalization — most consumer goods you own traveled in one." },
  { id: "highway-system", name: "Interstate Highway", era: "atomic", category: "transport",
    year: "1956", prereqs: ["automobile", "internal-combustion", "turnpike-roads", "railroad-network", "tank"],
    desc: "Limited-access national road networks: Italy's autostrade (1924), Germany's Autobahn (1932), and the U.S. Interstate Highway System under Eisenhower (1956 onward, 77,000 km). Highways collapse intercity travel times, reshape settlement patterns (suburbs, exurbs, edge cities), and reorganize freight from rail to truck. They also concrete in dependence on automobiles and oil that 21st-century climate policy is now grappling with." },
  { id: "welfare-state", name: "Welfare State", era: "atomic", category: "economy",
    year: "1945", prereqs: ["liberal-democracy", "public-education", "labor-union", "separation-of-powers", "keynesian-economics"],
    desc: "Government provision of social insurance, public healthcare, pensions, unemployment benefits, and family support. Bismarck's German social legislation (1880s) was the prototype; the British Beveridge Report (1942) and postwar Labour government created the NHS (1948); Scandinavian models pushed furthest. Welfare states reduced poverty among the elderly and unemployed dramatically, became defining markers of postwar liberal democracy, and remain politically contested over scope and funding." },
  { id: "decolonization", name: "Decolonization", era: "atomic", category: "economy",
    year: "1947", prereqs: ["nation-state", "world-religion", "fascism"],
    desc: "Dissolution of European colonial empires after 1945. Indian independence (1947) opened the wave; African decolonization peaked in 1960 ('Year of Africa'); the last Portuguese colonies became independent in 1975. Decolonization created over a hundred new nation-states, restructured the United Nations, and reshaped global politics. The economic and political legacies of colonization continue to shape former colonies — and the international system itself." },
  { id: "united-nations", name: "International Order", era: "atomic", category: "economy",
    year: "1945", prereqs: ["liberal-democracy", "federal-reserve"],
    desc: "The UN (founded 1945, San Francisco), IMF and World Bank (Bretton Woods 1944), GATT/WTO (1948/1995), and dozens of specialized agencies (WHO, UNESCO) created a multilateral framework for security, trade, and development. Alongside Cold War realpolitik, this system underwrote ~80 years without world war, the steady (if uneven) reduction of poverty, the rise of human-rights frameworks, and the climate negotiations of the late 20th century onward." },
  { id: "birth-control", name: "Hormonal Contraception", era: "atomic", category: "medicine",
    year: "1960", prereqs: ["chemistry-modern", "vaccines-modern"],
    desc: "The combined oral contraceptive pill — Enovid, approved by the FDA in 1960 — gave women reliable, female-controlled fertility regulation. Within two decades the Pill had become the most popular contraceptive in much of the world. It enabled women's mass entry into higher education and skilled work, dropped fertility rates across rich countries, and profoundly reshaped marriage, family, and gender norms." },
  { id: "air-conditioning", name: "Air Conditioning", era: "modern", category: "tools",
    year: "1902", prereqs: ["electric-motor", "chemistry-modern"],
    desc: "Willis Carrier's 1902 mechanical refrigeration of indoor air — initially developed to control humidity at a Brooklyn printing plant — became standard in commercial buildings by mid-century and in American homes by the 1970s. Air conditioning made the U.S. Sun Belt habitable for mass population, allowed computers to run reliably indoors, and enabled architectural styles (sealed glass towers, large open offices) that would otherwise be unbearable." },
  { id: "insulin-therapy", name: "Insulin Therapy", era: "modern", category: "medicine",
    year: "1921", prereqs: ["endocrinology", "chemistry-modern"],
    desc: "Frederick Banting, Charles Best, J.J.R. Macleod, and James Collip's 1921–22 isolation and purification of pancreatic insulin at the University of Toronto. Leonard Thompson, a 14-year-old dying of diabetes, was the first patient saved (January 1922). Insulin was the first effective hormone replacement therapy and made type 1 diabetes — previously a death sentence within months — a manageable chronic condition. The achievement opened the era of endocrine medicine and won the 1923 Nobel." },
  { id: "continental-drift", name: "Continental Drift", era: "modern", category: "knowledge",
    year: "1915", prereqs: ["evolution-darwin", "scientific-method"],
    desc: "Alfred Wegener's 1915 'The Origin of Continents and Oceans' proposed that the continents had once formed a single landmass (Pangaea) and drifted apart. Geologists rejected the idea for decades because Wegener could not name a plausible mechanism. Mid-Atlantic ridge mapping, paleomagnetism, and seafloor spreading data in the 1950s–60s vindicated him; the synthesis became plate tectonics (~1965), the unifying theory of modern geophysics." },
  { id: "radio-broadcasting", name: "Radio Broadcasting", era: "modern", category: "communication",
    year: "1920", prereqs: ["radio-wireless", "newspaper-mass"],
    desc: "KDKA Pittsburgh's commercial broadcast of the 1920 U.S. presidential election returns is conventionally dated as the start of the radio-broadcast era; the BBC followed in 1922. By 1940 ~80% of U.S. households owned a radio. Broadcasting collapsed the gap between event and audience for the first time at scale: FDR's fireside chats, Edward R. Murrow's London Blitz reports, Hitler's rallies, the Orson Welles 'War of the Worlds' panic. Radio shaped 20th-century mass politics, advertising, and popular culture." },
  { id: "sound-film", name: "Sound Film", era: "modern", category: "communication",
    year: "1927", prereqs: ["cinema", "radio-wireless"],
    desc: "The Jazz Singer (Warner Bros., October 1927) — feature-length synchronized speech and song via Vitaphone — ended the silent-film era within four years. By 1931 nearly all U.S. theatrical releases were 'talkies.' Sound transformed acting (silent stars whose voices didn't translate were ruined), pushed Hollywood toward the studio system and the musical, made dialogue-driven genres (screwball comedy, courtroom drama) possible, and turned cinema into the dominant 20th-century narrative medium." },
  { id: "big-bang-cosmology", name: "Big Bang Cosmology", era: "modern", category: "knowledge",
    year: "1929", prereqs: ["relativity", "telescope"],
    desc: "Edwin Hubble's 1929 measurement that distant galaxies recede with velocity proportional to distance — empirical evidence for an expanding universe — combined with Georges Lemaître's 1927 'primeval atom' hypothesis. Together they reframed cosmology: the universe had a beginning roughly 14 billion years ago. The 1965 Penzias-Wilson cosmic microwave background detection cinched the model. Big Bang cosmology made physical cosmology a quantitative science and reshaped 20th-century philosophy and theology." },
  { id: "federal-reserve", name: "Modern Central Banking", era: "modern", category: "economy",
    year: "1913", prereqs: ["banking-double-entry", "modern-corporation"],
    desc: "The U.S. Federal Reserve Act (December 1913) created a quasi-public lender of last resort modeled on the Bank of England (1694) but designed to prevent the recurring panics of the National Banking era (1873, 1893, 1907). Modern central banks — Fed, Bank of Japan (1882), ECB (1998) — set short-term interest rates, manage the money supply, supervise commercial banks, and intervene in financial crises (2008, 2020). Monetary policy is now the most powerful peacetime lever of macroeconomic management." },
  { id: "russian-revolution", name: "Communist State", era: "modern", category: "economy",
    year: "1917", prereqs: ["labor-union", "factory-system"],
    desc: "The October 1917 Bolshevik seizure of power in Petrograd, the 1918–22 Russian Civil War, and Lenin's reorganization of Russia into the Soviet Union. The Bolsheviks built the first government explicitly committed to abolishing private property and operating a planned economy. Soviet five-year plans (from 1928) industrialized at extraordinary speed and human cost. Communism then spread to Eastern Europe (1945), China (1949), and beyond — defining one pole of the 20th-century world order." },
  { id: "fascism", name: "Fascism", era: "modern", category: "social",
    year: "1922", prereqs: ["nation-state", "newspaper-mass"],
    desc: "Mussolini's October 1922 March on Rome and the consolidation of the Fascist Party brought a new totalitarian-nationalist movement to power: cult of the leader, single-party state, paramilitary violence, corporatist economy, irredentist foreign policy. Hitler's NSDAP (1933) radicalized the formula with explicit racial ideology, leading to WWII and the Holocaust. Defeated militarily in 1945 but never ideologically extinct, fascist movements have recurred and remain a defining political category." },
  { id: "womens-suffrage", name: "Women's Suffrage", era: "modern", category: "social",
    year: "1920", prereqs: ["liberal-democracy", "public-education", "labor-union"],
    desc: "Women's right to vote in national elections — New Zealand (1893), Australia (1902), Finland (1906), the UK (partial 1918, full 1928), the U.S. 19th Amendment (1920), France (1944), Switzerland (1971). The decades-long campaigns of Pankhurst, Anthony, Stanton, and millions of local organizers redefined the demos of liberal democracy. Suffrage opened the door to women's full legal personhood, mass entry into higher education and the labor force, and successive waves of legal and social reform." },
  { id: "keynesian-economics", name: "Keynesian Economics", era: "modern", category: "economy",
    year: "1936", prereqs: ["modern-corporation", "factory-system", "federal-reserve"],
    desc: "John Maynard Keynes's 1936 'General Theory of Employment, Interest, and Money' argued that aggregate demand drives short-run output and that governments should run deficits in slumps and surpluses in booms to stabilize the business cycle. Roosevelt's New Deal (1933 onward) and the postwar Bretton Woods system institutionalized active fiscal management. Monetarist and supply-side critiques narrowed Keynesian policy in the 1970s–80s, but the 2008 and 2020 crises restored deficit-financed stabilization to the mainstream toolkit." },
  { id: "game-theory", name: "Game Theory", era: "modern", category: "knowledge",
    year: "1944", prereqs: ["probability-theory", "algebra-symbolic"],
    desc: "The mathematics of strategic interaction: how rational agents should choose actions when each person's best move depends on what every other person is doing. The setup is a *game* — a list of players, the actions available to each, and a payoff matrix giving every player's reward for every combination of choices — and the goal is to find the *equilibrium*: a profile of strategies from which no individual player would unilaterally deviate, since their current choice is already a best response to everyone else's. Von Neumann and Morgenstern's 1944 *Theory of Games and Economic Behavior* solved zero-sum games (the minimax theorem); John Nash's 1950 dissertation extended equilibrium existence to non-zero-sum and cooperative games (Nobel 1994). Game theory immediately reshaped Cold War nuclear strategy (mutually assured destruction is a coordination game), microeconomics (auctions, oligopoly), evolutionary biology (Maynard Smith's evolutionarily stable strategies), and now AI alignment (multi-agent reinforcement learning). It is the formal language in which any situation with strategic interdependence — markets, wars, families, ecosystems — can be analyzed." },
  { id: "cryptanalysis-bombe", name: "Cryptanalysis & Bombe", era: "modern", category: "knowledge",
    year: "1940", prereqs: ["mathematics-arithmetic", "machine-tool", "telegraph"],
    desc: "Polish, then British, mathematicians attacking the German Enigma cipher: Marian Rejewski's 1932 reconstruction of Enigma's wiring, the bomba kryptologiczna (1938), Alan Turing's electromechanical Bombe at Bletchley Park (1940), and Tommy Flowers's Colossus (1943) for the higher-level Lorenz cipher. The intelligence (Ultra) materially shortened WWII. The same effort taught the world to think of computation, formalism, and statistics as weapons — and seeded the digital computer." },
  { id: "strategic-bombing", name: "Strategic Bombing", era: "modern", category: "weapons",
    year: "1940", prereqs: ["airplane", "tank"],
    desc: "Industrial-scale aerial bombardment of cities, factories, and civilian populations: Italian air doctrine (Douhet, 1921), the Luftwaffe's Guernica and Blitz, the RAF/USAAF Combined Bomber Offensive against Germany (1942–45), and the firebombing of Tokyo (March 1945, 100,000 dead in one night). The doctrine reached its terminal logic in the Hiroshima and Nagasaki atomic bombings. Strategic bombing — premised on breaking enemy morale by killing civilians — has remained legally and morally contested ever since." },

  // ─── Information ───────────────────────────────────────────────
  { id: "microprocessor", name: "Microprocessor", era: "information", category: "tools",
    year: "1971", prereqs: ["semiconductor", "dram-memory", "photolithography"],
    desc: "A complete general-purpose central processing unit — arithmetic logic, registers, control sequencing, and instruction decoder — fabricated on a single silicon die using the same photolithographic process as memory chips. Earlier computers had been built from racks of discrete logic boards; the microprocessor collapses that into one part the size of a fingernail, slashing cost, power, and assembly complexity by orders of magnitude. The Intel 4004 (1971, by Federico Faggin, Ted Hoff, and Stan Mazor) was the first, with 2,300 transistors clocking at 740 kHz; the 8080 (1974) and Motorola 6800 (1974) refined the architecture. Because a microprocessor is a programmable substrate rather than a single-purpose circuit, the same chip family can be embedded in a calculator, a microwave, an automobile engine controller, or a personal computer — the universal-machine principle finally realized in silicon. Every modern device with electronics descends from this design." },
  { id: "flash-memory", name: "Flash Memory (NAND)", era: "information", category: "tools",
    year: "1980", prereqs: ["dram-memory"],
    desc: "A non-volatile semiconductor memory that retains its contents without power, built around the floating-gate transistor — a MOSFET with an extra electrically isolated gate that traps charge for decades. Programming pushes electrons onto the floating gate by quantum tunneling; erasure pulls them back off; the trapped charge shifts the transistor's threshold voltage and represents the stored bit. Fujio Masuoka invented flash at Toshiba (1980) and named it for the way an entire block could be erased in a 'flash' rather than bit-by-bit. NAND flash arranges cells in series for maximum density and is the cheapest form of solid-state storage; NOR flash arranges them in parallel for fast random reads and is used to store boot firmware. The format made the digital-camera memory card, the USB drive (1999), the iPod and every later MP3 player, and ultimately the SSD — which displaced the hard disk as primary storage in laptops and servers from ~2010 onward. Flash is what makes the smartphone possible: hundreds of gigabytes of personal data, music, photos, and apps in a chip a few millimeters across with no moving parts and zero power draw at rest. By 2024 NAND was a $50B+ industry shipping zettabyte-scale capacity per year." },
  { id: "wafer-stepper", name: "Wafer Stepper & DUV Lithography", era: "information", category: "tools",
    year: "1978", prereqs: ["photolithography", "laser"],
    desc: "A precision projection-printer that steps a small reduced image of one chip's mask across the wafer in a regular grid, exposing one die at a time, rather than imaging the whole wafer at 1:1 contact. The reduction (typically 4×) means the mask can be drawn at a manageable scale while the printed feature on silicon is four times finer, and any mask defect shrinks correspondingly. GCA's 1978 stepper was the first commercial system; ASML (Veldhoven, founded 1984), Nikon, and Canon turned the format into a global industry. Through the 1990s, light sources progressed from mercury g-line and i-line (436/365 nm) to KrF excimer lasers (248 nm) to ArF (193 nm), each shrinking the resolvable feature. Burn van den Brink and ASML's 2004 immersion-lithography breakthrough — running 193nm light through a film of water between the lens and wafer to raise the effective numerical aperture — extended ArF to the 7nm node, far beyond what dry tools could reach. Multi-patterning (printing one layer with two or three offset exposures) pushed it further still. Wafer steppers and scanners are the most precise mass-production machines ever built, with positioning accuracy in single-digit nanometers across hundreds of mm of wafer, and they are the choke point of every modern semiconductor industry." },
  { id: "advanced-chip-manufacturing", name: "Advanced Chip Manufacturing", era: "information", category: "tools",
    year: "2018", prereqs: ["microprocessor", "machine-tool", "wafer-stepper"],
    desc: "The end-stage of Moore's Law: building transistors with features only a few atoms wide by projecting circuit patterns onto silicon wafers using extreme ultraviolet light at 13.5 nm wavelength — generated by vaporizing tin droplets with a laser inside a vacuum chamber. The transistor itself becomes three-dimensional (FinFET, then gate-all-around nanosheets) so that a gate can wrap around the conducting channel and shut off leakage current at sub-10 nm scales where flat designs fail. Patterning a single chip requires hundreds of mask layers, etched and deposited and chemically polished in sequence to atomic flatness. ASML's Dutch-built EUV scanners — the most precise machines ever manufactured, costing over $200M each — are the sole source, and only TSMC, Samsung, and Intel operate leading-edge nodes. The technology's extreme capital requirements concentrate global compute supply in a handful of fabs, making it both the substrate of every modern smartphone and AI accelerator and a central concern of 21st-century geopolitics." },
  { id: "parallel-compute-gpu", name: "Parallel Compute & GPUs", era: "information", category: "tools",
    year: "2006", prereqs: ["microprocessor"],
    desc: "Massively parallel processors — originally graphics pipelines, repurposed for general computation — that execute thousands of arithmetic threads simultaneously instead of optimizing single-threaded latency. NVIDIA's CUDA (2006) opened the GPU as a programmable scientific accelerator; AMD's ROCm and a generation of dedicated AI chips (Google TPU, AWS Trainium, Cerebras wafer-scale) followed. Where a CPU handles tens of threads, a modern GPU sustains tens of thousands, with on-chip memory bandwidth in the terabytes per second. Parallel compute is what makes deep learning tractable — every modern large language model, scientific simulation, climate model, and protein-folding network runs on stacks of these chips, and access to them has become the chokepoint resource of the AI era." },
  { id: "personal-computer", name: "Personal Computer", era: "information", category: "tools",
    year: "1977", prereqs: ["microprocessor", "mainframe", "hard-disk-drive"],
    desc: "A general-purpose computer cheap and small enough for one person — a microprocessor, RAM, persistent storage, keyboard, and display housed in a desktop box. The conceptual leap is that all the resources of a 1960s mainframe become dedicated to a single user, eliminating time-sharing queues and putting raw compute under direct interactive control. The Apple II (1977), Commodore PET (1977), and TRS-80 (1977) were the first mass-market machines; the IBM PC (1981) standardized an open architecture (x86 CPU, ISA bus, BIOS) that any third party could clone, driving prices down and locking the industry around Microsoft DOS/Windows and Intel processors for forty years. By 1990 ~50 million PCs were in use; by 2000 computing had become a personal rather than institutional activity, and the PC's word processor, spreadsheet, and email client had displaced the typewriter, ledger book, and inter-office memo." },
  { id: "gui-mouse", name: "Graphical Interface", era: "information", category: "communication",
    year: "1984", prereqs: ["personal-computer"],
    desc: "A way of operating a computer through visible spatial metaphor rather than typed commands: a bitmapped screen displays overlapping windows representing documents and programs, icons represent files and tools, menus expose commands, and a hand-controlled pointer (the mouse) lets the user act directly on what they see. Replacing memorized command syntax with point-and-click recognition collapses the learning curve and makes computing accessible to non-specialists. Doug Engelbart's 1968 'Mother of All Demos' showed the mouse, hyperlinks, video conferencing, and collaborative editing in one session; Xerox PARC's Alto (1973) refined the WIMP paradigm (Windows, Icons, Menus, Pointer); Apple's Lisa (1983) and Macintosh (1984), then Microsoft Windows (1985), brought GUI computing to mass markets. The same metaphors — desktop, folder, trash can, drag-and-drop — still organize how billions of people interact with computers today." },
  { id: "packet-switching", name: "Packet Switching", era: "information", category: "communication",
    year: "1969", prereqs: ["digital-computer", "programming-language"],
    desc: "A way of moving data across a shared network: instead of dedicating a whole circuit to a conversation (as the telephone system did), each message is chopped into small numbered packets, each packet is labeled with its destination address, and routers along the way independently decide which neighbor to forward each one to. Packets from many conversations interleave on the same physical wire, and if one packet is lost or a route fails, only that fragment is resent. Paul Baran (RAND, 1964), Donald Davies (NPL, 1965), and Leonard Kleinrock (UCLA, 1962) independently proposed the design — Baran specifically as a Cold-War-survivable communications system with no central control to bomb. The architecture is resilient (no single point of failure), shared (one link carries many flows), and statistically efficient (silent gaps in one conversation are filled by another's packets), and is the breakthrough that made the internet, the web, and modern voice/video communication possible on a single global network." },
  { id: "arpanet-internet", name: "Internet", era: "information", category: "communication",
    year: "1969", prereqs: ["mainframe", "satellite", "packet-switching"],
    desc: "A global packet-switched network of independently operated computer networks, glued together by a common protocol stack (TCP/IP) that lets any two hosts find each other and exchange reliable byte streams regardless of who owns the wires in between. The key design choice — the 'end-to-end principle' — is that the network itself stays simple and just forwards packets; intelligence (reliability, error-correction, security) lives in the endpoints, so new applications can be added without rebuilding the network. ARPANET first ran October 29, 1969 between UCLA and Stanford; Cerf and Kahn's TCP/IP (1974) became the universal standard in 1983, formally creating 'the Internet'; NSFNET (1985) extended access to universities; commercial ISPs took over from 1995. Because anyone can connect a network or build an application on top, the internet has grown into the largest engineered system in human history — billions of devices, no central authority — and now mediates most of human communication, commerce, and information." },
  { id: "email", name: "Email", era: "information", category: "communication",
    year: "1971", prereqs: ["arpanet-internet"],
    desc: "Asynchronous text messages addressed by a 'user@host' string, stored on the recipient's mail server until they choose to read them. Unlike a phone call, email does not require both parties to be available at once; unlike physical mail, it arrives in seconds; unlike a memo, it is automatically archived and searchable. Ray Tomlinson's 1971 ARPANET implementation introduced the @ sign as the username/host separator, and the Simple Mail Transfer Protocol (SMTP, 1982) standardized how mail servers exchange messages — a federated design where any organization can run its own mail server and still reach everyone else. SMTP's openness (and lack of authentication) is the same property that lets spam flourish, but it also lets email outlive every walled-garden alternative. Email quietly replaced the memo, the letter, and (for many uses) the phone call as the default medium of professional communication." },
  { id: "world-wide-web", name: "World Wide Web", era: "information", category: "communication",
    year: "1991", prereqs: ["arpanet-internet", "gui-mouse"],
    desc: "A globally distributed hypertext system layered on top of the internet: documents written in HTML link to one another via URLs (a uniform addressing scheme that names any resource on any server), and a browser fetches them on demand using HTTP. The decisive design choice is that links are one-directional and may dangle — any author can link to anything, without permission and without breaking when the target moves — which is what allowed the web to grow organically across millions of independent servers. Tim Berners-Lee proposed the system at CERN in 1989 and brought up the first website in 1991; Mosaic (1993) added inline images and a graphical interface that made the web usable by non-technical people; commercial sites exploded after 1995. Within fifteen years the web had reorganized information access for billions of people and spawned entirely new industries — search, e-commerce, social media, online media — none of which existed when it launched." },
  { id: "public-key-cryptography", name: "Public-Key Cryptography", era: "information", category: "knowledge",
    year: "1976", prereqs: ["digital-computer", "information-theory", "algebra-symbolic"],
    desc: "Encryption in which each party holds *two* mathematically linked keys — a public key they hand out freely and a private key they never share — instead of the single shared secret that all earlier ciphers required. A message encrypted with the public key can only be decrypted with the corresponding private key, so anyone in the world can send you a confidential message without ever having met you, and conversely a signature produced with your private key can be verified by anyone holding the public key, proving you authored it. The trick rests on mathematical operations that are easy to perform forward but computationally infeasible to reverse: factoring the product of two large primes (RSA), computing discrete logarithms in finite fields (Diffie-Hellman) or on elliptic curves (ECC). Whitfield Diffie and Martin Hellman published the first key-exchange protocol in 1976; Rivest, Shamir, and Adleman published RSA in 1977; the same problems were solved secretly at GCHQ a few years earlier. Public-key cryptography is the trust layer of the modern internet — every HTTPS connection, every signed software update, every cryptocurrency transaction, every encrypted messenger, every smart card, every certificate authority depends on it. Quantum computers (Shor's algorithm) threaten today's algorithms, motivating the post-quantum cryptography transition now underway." },
  { id: "search-engine", name: "Search Engine", era: "information", category: "communication",
    year: "1998", prereqs: ["world-wide-web", "digital-computer"],
    desc: "A system that continuously crawls the web, builds an inverted index from words to the pages that contain them, and — when a user types a query — returns ranked pages in milliseconds. Early search engines (AltaVista, Lycos) ranked by keyword frequency, which spammers easily gamed. Google's PageRank (Page and Brin, 1998) replaced keyword counting with a recursive measure of authority: a page is important if many important pages link to it, treating the entire web's link graph as a giant voting system. Combined with personalization, freshness signals, and (later) deep-learning-based query understanding, this made search dramatically better and Google the dominant entry point to the internet for most users within five years. The keyword-auction advertising model that funded it (AdWords, 2000) became one of the largest industries on Earth and structures how billions of people now find information." },
  { id: "fiber-optic", name: "Fiber Optic Cable", era: "information", category: "communication",
    year: "1988", prereqs: ["semiconductor", "glass-lens"],
    desc: "Hair-thin strands of ultra-pure silica glass that carry digital data as pulses of laser light, trapped inside the fiber by total internal reflection at the boundary between a high-refractive-index core and a lower-index cladding. Because light at the right wavelengths loses only a few percent of its power per kilometer in modern fiber, a single laser pulse can travel a hundred kilometers between amplifiers; because many wavelengths can share the same fiber (wavelength-division multiplexing), one fiber pair carries terabits per second simultaneously. Charles K. Kao's 1966 demonstration that ultra-pure glass could carry signals at low loss (Nobel 2009) and Corning's 1970 production of usable low-loss fiber launched the technology. By the 1990s fiber crossed every ocean; today's submarine cables carry essentially all transcontinental internet traffic, and a single fiber pair can carry the entire phone traffic of a country. Optical fiber is the physical substrate underlying the internet, mobile networks, and cloud computing." },
  { id: "mobile-phone", name: "Mobile Phone", era: "information", category: "communication",
    year: "1983", prereqs: ["telephone", "microprocessor"],
    desc: "A portable radio telephone that connects to the public phone network through a grid of fixed base-station antennas covering overlapping geographic 'cells' — as the user moves, the call is automatically handed off from one cell tower to the next, with each cell reusing the same radio frequencies as distant cells without interfering. This cellular architecture (Bell Labs, 1947, deployable from the 1980s) is what allows millions of simultaneous conversations to share a finite radio spectrum within one city. Martin Cooper made the first handheld cellular call in 1973 with a Motorola DynaTAC; commercial service began in 1983; 2G GSM (1991) digitized voice and added SMS; successive generations (3G, 4G LTE, 5G) progressively widened the data pipe and reduced latency. The mobile phone freed personal communication from a fixed location for the first time in history and is now the dominant computer for billions of people, with mobile-only internet users far outnumbering desktop-only users globally." },
  { id: "smartphone", name: "Smartphone", era: "information", category: "communication",
    year: "2007", prereqs: ["mobile-phone", "world-wide-web", "gui-mouse", "flash-memory"],
    desc: "A pocket-sized general-purpose computer with a multi-core processor, persistent storage, a high-resolution camera, GPS, accelerometers, and continuous wireless internet — wrapped behind a multitouch glass display that doubles as input and output, with software extensible through downloadable apps. The decisive innovation was capacitive multitouch (iPhone, 2007): direct manipulation with the fingers replaced the stylus and physical keyboard, and the entire screen could be reconfigured as needed for each app. BlackBerry (1999) had email and a keyboard; iPhone (2007) and Android (2008) made the smartphone a true platform, with a curated app store letting third-party developers reach billions of users at once. Within a decade smartphones became the dominant computing form factor (~6 billion in use by 2024), absorbing the camera, the watch, the GPS, the music player, the wallet, the flashlight, and the map, and rewiring photography, navigation, journalism, payments, dating, and taxi service around always-on, always-reachable pocket computing." },
  { id: "social-media", name: "Social Media", era: "information", category: "social",
    year: "2004", prereqs: ["world-wide-web"],
    desc: "Internet platforms where ordinary users — not professional publishers — generate the content, and where what each user sees is selected by an algorithm trained to maximize engagement. The structural shift from earlier media is that supply (posts) is effectively unlimited and free, so the scarce resource is attention; the platform's job is to rank an unending stream against each viewer's predicted interests in real time. Friendster (2002), MySpace (2003), Facebook (2004), Twitter (2006), Instagram (2010), and TikTok (2016) progressively refined the formula, with TikTok demonstrating that purely algorithmic feeds (no need to follow anyone) can outperform social-graph-based ones. By 2024 over five billion people used some form of social media. The same engagement-maximizing logic that drives growth also amplifies outrage, novelty, and falsehood, transforming how news spreads, how movements organize (Arab Spring, MeToo, Black Lives Matter), and how political polarization develops — for better and substantially worse." },
  { id: "streaming-media", name: "Streaming Media", era: "information", category: "communication",
    year: "2007", prereqs: ["world-wide-web", "semiconductor"],
    desc: "Delivery of audio and video over the internet as a continuous flow of data packets, decoded and played in real time without ever fully downloading the file. Adaptive bitrate streaming (HLS, MPEG-DASH) cuts each program into short chunks at multiple quality levels, and the player selects the appropriate quality second-by-second based on available bandwidth — so a hiccup in network speed produces a brief drop in resolution rather than a stall. Combined with cheap broadband and content-delivery networks that cache popular files near every user, this makes any title in a million-title catalog instantly viewable on demand. YouTube (2005), Netflix's streaming pivot (2007), Spotify (2008), and Disney+ rode the technology to displace broadcast television and physical music within fifteen years. Recommendation algorithms became the new programming directors; 'what to watch' shifted from a network schedule to an algorithmic feed; and the economics moved from advertising and physical retail to subscription." },
  { id: "cloud-computing", name: "Cloud Computing", era: "information", category: "tools",
    year: "2006", prereqs: ["arpanet-internet", "mainframe", "relational-database", "public-key-cryptography"],
    desc: "Massive remote data centers — hundreds of thousands of servers networked together — sliced into virtual machines and rented over the internet by the second. The customer specifies how much CPU, memory, storage, and bandwidth they need; the cloud provider's software allocates a slice of the underlying physical hardware, and the customer pays only while it runs. Hardware failures are abstracted away through automatic redundancy, and capacity scales elastically to match demand. Amazon Web Services (S3 storage and EC2 compute, launched 2006), Microsoft Azure (2010), and Google Cloud were the early movers, turning what had been a fixed capital expense (buying and maintaining server rooms) into an operating expense (an hourly meter). The shift collapsed the entry cost for new internet companies — a startup can serve millions of users without owning a single server — and underwrote the modern web, mobile apps, and the AI training boom. By 2024, AWS alone was a $100B+ business and cloud underpinned most of enterprise IT." },
  { id: "ecommerce", name: "E-Commerce", era: "information", category: "economy",
    year: "1995", prereqs: ["world-wide-web", "credit-card", "public-key-cryptography"],
    desc: "Buying and selling goods through web storefronts, with payment authorized in real time over encrypted connections (SSL/TLS) and physical fulfillment handled by a separate logistics network of warehouses, sortation centers, and last-mile delivery. Because shelf space on a website is effectively unlimited, e-commerce supports an enormous 'long tail' of niche products that no physical store could carry, and customer reviews aggregate quality information that no salesperson could match. Amazon (1994), eBay (1995, peer-to-peer auctions), and Alibaba (1999, B2B then B2C) established the dominant patterns; recommendation engines, one-click checkout, and same-day delivery progressively raised the bar. By 2024 e-commerce was ~20% of total retail in advanced economies and still growing, hollowing out mid-tier department stores and specialty chains and reshaping the geography of warehousing and trucking around major distribution hubs." },
  { id: "gps", name: "GPS", era: "information", category: "transport",
    year: "1995", prereqs: ["satellite", "microprocessor"],
    desc: "Satellite-based positioning that lets any receiver on Earth determine its location to a few meters using only a small antenna and no transmissions of its own. A constellation of ~30 satellites in medium Earth orbit continuously broadcasts the current atomic-clock time stamped with their orbital coordinates; a receiver compares the arrival times of signals from at least four satellites and solves for its own position and clock offset by trilateration — the difference between when each satellite's signal was sent and when it was heard reveals the distance to that satellite (since radio travels at a known speed), and four such distances pin down latitude, longitude, altitude, and time. The U.S. Defense Department's NAVSTAR system became fully operational in 1995; civilian use exploded after the artificial-degradation 'Selective Availability' was switched off in 2000. GPS (and parallel systems Galileo, GLONASS, BeiDou) now underpins car and smartphone navigation, drone flight, container tracking, and precision farming; its absence would also disrupt finance and power grids, which use its time signal as a precision clock reference." },
  { id: "gene-sequencing", name: "Genome Sequencing", era: "information", category: "medicine",
    year: "2003", prereqs: ["dna-structure", "digital-computer"],
    desc: "Reading the order of the four DNA bases (A, C, G, T) along a chromosome. Frederick Sanger's 1977 chain-termination method exploited DNA polymerase's normal copying behavior: in four parallel reactions, a small fraction of one fluorescently-tagged base is mixed in, terminating each new strand wherever that base appears, so the resulting fragments — separated by length on a gel — spell out the sequence one position at a time. Modern next-generation sequencing (Illumina, 2007) replaces gels with massively parallel optical readout: hundreds of millions of short DNA fragments are anchored to a chip, copied in step, and photographed each round to read which base was added where. The Human Genome Project (1990–2003) sequenced ~3 billion base pairs at a cost of ~$3 billion; per-genome cost has since fallen to under $1,000. Cheap sequencing now drives medical genomics, cancer treatment selection, pathogen surveillance (the SARS-CoV-2 sequence was published days after the outbreak), ancestry testing, evolutionary biology, and conservation." },
  { id: "genetic-engineering", name: "Recombinant DNA", era: "information", category: "medicine",
    year: "1973", prereqs: ["dna-structure"],
    desc: "Cutting genetic material from one organism and splicing it into another, so the recipient cell reads the foreign DNA as if it were its own and produces the encoded protein. The trick rests on restriction enzymes — bacterial proteins that cut DNA at specific sequence motifs, leaving sticky ends that pair with any other DNA cut by the same enzyme — and on plasmids and viral vectors that carry the new gene into the recipient cell. Paul Berg, Herbert Boyer, and Stanley Cohen demonstrated the technique in 1973; Genentech (1976), the first biotech company, used it to put the human insulin gene into E. coli, which then produced clinical-grade human insulin in fermentation tanks (1978), replacing the cattle and pig pancreatic extracts diabetics had relied on for fifty years. Human growth hormone, hepatitis B vaccine, and dozens of other proteins followed. Recombinant DNA is the foundational technology of the entire modern biopharmaceutical industry, of GMO agriculture, and of every later gene-editing approach." },
  { id: "crispr", name: "CRISPR", era: "information", category: "medicine",
    year: "2012", prereqs: ["gene-sequencing", "genetic-engineering"],
    desc: "A programmable molecular scissors derived from a bacterial immune system. Bacteria store fragments of past viral DNA in 'CRISPR' arrays and use them as templates: a guide RNA copied from one of these fragments leads the Cas9 enzyme to any matching DNA sequence and cuts both strands. Researchers can simply synthesize a new guide RNA — about 20 bases long, custom-ordered for a few dollars — and Cas9 will cut precisely the corresponding genomic site, after which the cell's repair machinery either disables the targeted gene or pastes in a supplied replacement. Doudna and Charpentier showed in 2012 that this system, ported out of bacteria, could be reprogrammed to edit any DNA at will (Nobel 2020). Compared to earlier gene-editing tools (zinc-finger nucleases, TALENs), CRISPR is dramatically faster, cheaper, and more precise. Casgevy (2023) was the first approved CRISPR therapy, curing sickle-cell disease by editing patients' bone marrow. CRISPR is reshaping biology, agriculture, and medicine, and has triggered live debates about germline editing." },
  { id: "mri-imaging", name: "MRI Imaging", era: "information", category: "medicine",
    year: "1977", prereqs: ["x-ray", "digital-computer"],
    desc: "A medical imaging technique that exploits the spin of hydrogen nuclei in the body. The patient lies inside a powerful superconducting magnet (1.5–7 tesla, tens of thousands of times Earth's field) which aligns the protons in water and fat. Radio-frequency pulses tip these protons sideways; as they relax back into alignment they re-emit a faint radio signal whose timing depends on the local tissue chemistry. Spatially varying magnetic-field gradients tag each point in the body with a unique resonance frequency, so the emitted signal can be Fourier-decoded into a 3-D image showing the contrast between tissues with high precision. Paul Lauterbur (1973) and Peter Mansfield (Nobel 2003) showed that gradients made spatial encoding possible. Because MRI uses no ionizing radiation and sees soft tissue much more clearly than X-ray or CT, it transformed diagnosis of brain, joint, and tumor disease, and now extends into functional imaging (fMRI mapping brain activity from blood-oxygen changes), cardiac imaging, and rapid emergency scans." },
  { id: "ivf", name: "In Vitro Fertilization", era: "information", category: "medicine",
    year: "1978", prereqs: ["birth-control"],
    desc: "Fertilizing a human egg with sperm outside the body — in a Petri dish (in vitro means 'in glass') — and then transferring the resulting embryo back into the uterus. The mother is given hormones to mature multiple eggs at once; eggs are aspirated transvaginally under ultrasound guidance; sperm and eggs are mixed (or a single sperm is injected directly into each egg, ICSI); the embryos are cultured for 3–5 days and the most viable one is transferred. The technique bypasses blocked or absent fallopian tubes, low sperm counts, and many forms of unexplained infertility. Robert Edwards and Patrick Steptoe delivered Louise Brown, the first 'test-tube baby', in July 1978 (Nobel 2010). Over eight million people have since been born through IVF, and the same technology platform underlies preimplantation genetic diagnosis, egg freezing for fertility preservation, mitochondrial replacement therapy, and the broader field of assisted reproductive technology." },
  { id: "mrna-vaccine", name: "mRNA Vaccine", era: "information", category: "medicine",
    year: "2020", prereqs: ["vaccines-modern", "gene-sequencing"],
    desc: "A vaccine that delivers, instead of a killed or weakened pathogen, a strand of synthetic messenger RNA encoding a single viral protein. Once the mRNA enters the patient's cells (escorted past the cell membrane by a lipid nanoparticle), the cell's own ribosomes translate it into the encoded protein, which the immune system recognizes as foreign and trains against — producing antibodies and T-cells that will recognize the real virus on later exposure. The mRNA itself is degraded within days. Crucially, designing a new vaccine becomes a software problem: once the pathogen's genome is sequenced, the corresponding mRNA can be synthesized and tested within weeks. Decades of work by Katalin Karikó and Drew Weissman (Nobel 2023) on chemically modifying RNA bases to prevent immune backlash made the platform clinically viable. Pfizer-BioNTech and Moderna delivered the first mRNA COVID-19 vaccines within ~10 months of the SARS-CoV-2 sequence release in January 2020 — by far the fastest vaccine development in history — and the platform is now being extended to flu, RSV, and personalized cancer vaccines." },
  { id: "solar-photovoltaic", name: "Solar Photovoltaic", era: "information", category: "energy",
    year: "1980", prereqs: ["semiconductor", "electrification"],
    desc: "A semiconductor device that converts sunlight directly into electricity through the photovoltaic effect — photons striking a doped silicon wafer knock electrons across a built-in p-n junction, producing a DC current with no moving parts, no heat cycle, and no fuel. Bell Labs demonstrated the first practical silicon cell in 1954 at 6% efficiency, but at ~$300/W it was viable only on satellites (Vanguard 1, 1958), where weight and reliability mattered more than cost. Half a century of wafer thinning, multicrystalline scale-up, and improved cell architectures (PERC, heterojunction, TOPCon) drove a >1000× cost decline to under $0.20/W by 2024, making solar the cheapest new electricity in most sunny regions. Because PV is modular — the same physics works for a calculator chip or a gigawatt farm — silent, and fuel-free, it is one of the few technologies plausibly capable of decarbonizing the global power system. Annual global installations now exceed 400 GW." },
  { id: "wind-turbine", name: "Wind Turbine", era: "information", category: "energy",
    year: "1985", prereqs: ["windmill", "electric-motor", "solar-photovoltaic"],
    desc: "A tall tower carrying a horizontal-axis rotor whose long, airfoil-shaped blades convert the kinetic energy of moving air into rotation, which an internal generator turns into electricity. The blades work on the same lift principle as an aircraft wing — pitched into the wind at a slight angle, they experience an aerodynamic force that pulls them sideways, spinning the rotor — and pitch and yaw mechanisms continuously adjust the blades to track wind direction and shed excess force in storms. Power scales roughly with the cube of wind speed and with the square of rotor diameter, which is why turbines have grown steadily larger: modern Danish three-blade designs from the 1980s have evolved into >15 MW offshore machines (2024) with blades over 100 m long. Because the underlying machinery (a generator on a gearbox in a steel tower) is mature, costs have fallen rapidly, and wind is now the cheapest new electricity in many windy regions. Combined with solar and storage, wind is a central pillar of every credible deep-decarbonization scenario." },
  { id: "lithium-battery", name: "Lithium-Ion Battery", era: "information", category: "energy",
    year: "1991", prereqs: ["electric-battery", "semiconductor"],
    desc: "A rechargeable battery that stores energy by shuttling lithium ions between two solid electrodes through a liquid electrolyte. On charging, lithium ions are pulled out of the cobalt-oxide cathode and slot into spaces in the graphite anode (a process called intercalation, akin to filing cards into a rack); on discharge they migrate back, releasing electrons through the external circuit. Lithium is chosen because it is the lightest metal and gives up an electron easily, so the cell stores far more energy per kilogram than nickel-cadmium or lead-acid. Whittingham, Goodenough, and Yoshino (Nobel 2019) developed the chemistry between 1976 and the late 1980s, and Sony commercialized it in 1991. Through scale-up of factories, thinner separators, and cathode improvements (NMC, LFP), energy density has roughly tripled and cost has fallen ~30× between 2010 and 2024. Lithium-ion is the storage that finally made portable electronics practical without a wall socket and electric vehicles competitive with petrol; grid-scale lithium-ion banks now smooth out the gap between when sun and wind generate power and when buildings consume it, making the technology the energy-storage half of any plausible renewable-grid future." },
  { id: "electric-vehicle", name: "Electric Vehicle", era: "information", category: "transport",
    year: "2008", prereqs: ["lithium-battery", "automobile"],
    desc: "An automobile powered by a lithium-ion battery driving electric motors at the wheels rather than a petroleum-burning internal-combustion engine driving them through a transmission. Compared to an ICE car, the EV has roughly twenty moving drivetrain parts instead of two thousand, runs at ~90% drivetrain efficiency vs. ~30%, recovers energy when braking by running the motors backward as generators (regenerative braking), and produces full torque from zero rpm. The downsides are battery cost (still the largest single component), recharge time (minutes vs. seconds for petrol), and dependence on a charging network. The GM EV1 (1996), Tesla Roadster (2008), Nissan Leaf (2010), and Tesla Model S (2012) progressively demonstrated the form factor; by 2024 EVs were ~18% of new car sales globally, with Tesla, BYD, Volkswagen Group, and Hyundai-Kia leading. EVs replace tailpipe emissions with grid emissions (which get cleaner over time), eliminate most maintenance, and require a fundamental overhaul of automaker supply chains and dealer networks." },
  { id: "renewable-grid", name: "Renewable Grid", era: "information", category: "energy",
    year: "2020", prereqs: ["solar-photovoltaic", "wind-turbine", "lithium-battery", "ac-power-transformer"],
    desc: "An electric power system whose generation is dominated by intermittent renewable sources (solar, wind) rather than dispatchable fossil plants, balanced into reliable supply by four complementary mechanisms: storage (lithium batteries for hours, pumped hydro for days), long-distance transmission (HVDC lines moving power across continents to balance regional weather), demand response (factories, EV charging, and water heaters that shift their consumption to match supply), and a residual fleet of dispatchable backup. The engineering challenge is that solar and wind power do not respond to demand — they produce whatever the weather provides — so the rest of the system must work harder to keep voltage and frequency stable as supply fluctuates. By 2024 several large grids — South Australia, parts of Texas, California, Denmark — were operating at >50% renewables for sustained periods, demonstrating that the architecture works at scale. Full decarbonization remains a serious engineering and policy challenge, but the underlying technology pieces have all individually become cheap enough that the question is now organizational rather than fundamental." },
  { id: "machine-learning", name: "Machine Learning", era: "information", category: "knowledge",
    year: "1990", prereqs: ["digital-computer", "programming-language", "probability-theory"],
    desc: "An approach to programming where the developer specifies a model with adjustable parameters and a measure of how wrong it is on training examples, and an optimization algorithm tunes those parameters to minimize the error — so the program 'learns' patterns from data rather than executing rules a programmer wrote out. The same training procedure can be pointed at speech, images, text, or fraud transactions and yield a working classifier without anyone having to enumerate the underlying rules. Methods include support vector machines, decision trees, random forests, Bayesian networks, and neural networks; the choice depends on the data shape and the smoothness of the underlying pattern. The field consolidated through the 1990s and 2000s and by the 2010s had displaced rule-based AI for most pattern-recognition tasks. Machine learning is now the dominant paradigm for any problem where the rules are easier to demonstrate by example than to write down — speech recognition, image classification, machine translation, recommendations, fraud detection — and is the foundation on which deep learning was later built." },
  { id: "deep-learning", name: "Deep Learning", era: "information", category: "knowledge",
    year: "2012", prereqs: ["machine-learning", "cloud-computing"],
    desc: "Machine learning with neural networks many layers deep, where each layer transforms its inputs into a slightly more abstract representation: in an image network, the first layers detect edges, middle layers detect parts (an eye, a wheel), and deeper layers detect whole objects. The network has millions to billions of weights, all tuned simultaneously by backpropagation — a calculus-of-variations procedure that pushes each weight in the direction that reduces error on the training set, repeated billions of times across enormous datasets. What made this practical wasn't a new theory but cheap parallel hardware: GPUs (originally built for video games) can multiply matrices thousands of times faster than CPUs, which is exactly the operation neural networks need. The 2012 ImageNet breakthrough by Krizhevsky, Sutskever, and Hinton (AlexNet) cut image-classification error in half and triggered the modern AI boom; AlphaGo's 2016 win over Lee Sedol demonstrated reinforcement learning at superhuman levels; AlphaFold (2020) solved the 50-year protein-structure problem. Deep learning now drives essentially all production AI." },
  { id: "large-language-model", name: "Large Language Model", era: "information", category: "knowledge",
    year: "2020", prereqs: ["deep-learning", "world-wide-web", "advanced-chip-manufacturing"],
    desc: "A neural network — typically a transformer (Vaswani et al., 'Attention Is All You Need', 2017) with hundreds of billions of parameters — trained on an internet-sized corpus of text by repeatedly hiding a word and asking the model to predict it. The transformer's key innovation is the attention mechanism, which lets every word in a passage directly influence every other word in computing the next prediction, capturing long-range context that earlier recurrent networks missed. The astonishing empirical finding is that a model trained only to predict the next token, when scaled up enough, develops emergent abilities its designers did not specifically aim for — translation, summarization, arithmetic, code generation, multi-step reasoning. A second training stage, reinforcement learning from human feedback (RLHF), shapes the raw next-token model into a usable assistant by rewarding helpful, honest answers. GPT-3 (2020), ChatGPT (2022), GPT-4 (2023), Claude, Gemini, and Llama brought LLMs to mainstream use, and by 2024 they were drafting code, summarizing documents, tutoring students, and reshaping office work, with active debates about bias, safety, alignment, and economic disruption." },
  { id: "cryptocurrency", name: "Cryptocurrency", era: "information", category: "economy",
    year: "2009", prereqs: ["world-wide-web", "central-bank", "public-key-cryptography"],
    desc: "Digital money whose ledger is maintained not by a bank but by a peer-to-peer network of computers running an agreed protocol. Every transaction is broadcast, batched into 'blocks', and chained cryptographically to all previous blocks; consensus on which chain is real is enforced through proof-of-work (computers race to solve an arbitrary puzzle, and the winner appends the next block) or proof-of-stake (validators chosen in proportion to coins held). Tampering with an old block would require redoing all subsequent puzzles or re-staking the entire network, which is computationally infeasible. The result is a money supply with no issuer, no central account, and no party who can freeze funds — and, equivalently, no party who can reverse fraud. Satoshi Nakamoto's Bitcoin (2009) was the first working implementation; Ethereum (2015) added programmable smart contracts that execute on the same shared ledger. By 2024 the total crypto market cap exceeded $2 trillion at peak. Cryptocurrencies remain a contested experiment in money — sitting between speculative asset, payments rail, and political project." },
  { id: "reusable-rocket", name: "Reusable Rocket", era: "information", category: "transport",
    year: "2015", prereqs: ["rocket", "machine-learning"],
    desc: "An orbital-class rocket whose first stage flies itself back to a controlled landing after delivering its payload, instead of being thrown away in the ocean as all rockets had been since 1957. After staging, the booster re-lights its engines for a 'boost-back burn' to reverse course, falls back through the atmosphere stabilized by grid fins that steer it like a falling dart, then re-lights again to slow itself just before touching down on landing legs (or being caught by the launch tower, in Starship's case). Because rockets are mostly empty fuel tanks and very expensive engines, recovering and reflying the booster cuts launch costs sharply: SpaceX's Falcon 9 first landed in 2015 and was reflown in 2017, dropping cost-to-orbit from ~$10,000/kg to under $2,000/kg, and Starship (full-stack reusable, first orbital launches 2023) targets ~$100/kg. Cheap launch is reshaping satellite operations (Starlink mega-constellations), space science (more frequent and cheaper missions), and the long-term arc of crewed exploration. SpaceX now performs more than half of all global launches." },
  { id: "autonomous-vehicle", name: "Autonomous Vehicle", era: "information", category: "transport",
    year: "2020", prereqs: ["electric-vehicle", "machine-learning", "gps"],
    desc: "A vehicle that drives itself by fusing inputs from cameras, radar, lidar (laser range-finding), GPS, and inertial sensors into a continuously updated 3-D model of its surroundings, then running a learned policy that decides steering, braking, and acceleration. Lidar provides precise geometry; cameras read lane markings, traffic lights, and pedestrians; radar sees through fog; the on-board computer's planner predicts where each detected object will be in the next few seconds and threads a safe trajectory through the gaps — many times per second. Different vendors emphasize different sensor mixes (Tesla bets on cameras alone; Waymo uses heavy lidar) and different software stacks (rule-based behavior trees vs. end-to-end neural nets). The technology moved from DARPA Grand Challenge research demos (2004–2007) to commercial deployment with Waymo robotaxis in Phoenix and San Francisco, Cruise, Mobileye, and Tesla FSD; full Level 5 (any conditions) autonomy remains unsolved, but Level 4 (geofenced) is now operational. The technology promises substantial safety gains (94% of crashes are human error) and large labor displacement, with regulatory and ethical questions still being worked out." },
  { id: "3d-printing", name: "3D Printing", era: "information", category: "tools",
    year: "1990", prereqs: ["machine-tool", "digital-computer"],
    desc: "Manufacturing by adding material one thin layer at a time, building a part up from a digital 3-D model rather than cutting or molding it from a solid blank. Different processes deposit different feedstocks: fused-deposition machines extrude molten plastic through a nozzle that traces each cross-section; stereolithography (Hull's 1984 patent) cures a vat of UV-sensitive resin one slice at a time with a laser; selective laser sintering and direct metal laser sintering fuse plastic or metal powder layer by layer. Because the cost of a 3D-printed part depends on its volume rather than its complexity, additive manufacturing excels at low-volume custom geometries — internal cooling channels, organic shapes, parts unique to one patient — that would be impossible to machine. Cheap consumer printers (RepRap, MakerBot) appeared from 2007; industrial 3D printing now produces aerospace components, dental restorations, prosthetics, printed houses, and entire rocket engines (Relativity Space). It complements rather than replaces mass manufacturing for most applications." },
  { id: "robotics", name: "Robotics", era: "information", category: "tools",
    year: "1980", prereqs: ["digital-computer", "machine-tool"],
    desc: "Programmable machines that sense their environment and act on it physically, integrating actuators (motors, hydraulics), sensors (encoders, force gauges, cameras), and a controller that closes the loop between them. Industrial robots — articulated arms with six joints and a tool — repeat precise motions in fixed cells, while mobile and humanoid robots add navigation and balance, requiring real-time feedback control to stay upright while moving. Unimate (1961, GM Trenton plant) was the first industrial robot, and welding and assembly arms became standard in automotive and electronics manufacturing through the 1970s–90s. Mobile and humanoid robots (Boston Dynamics' BigDog, Atlas; iRobot's Roomba, 2002) emerged later, gated by sensor cost and control software rather than mechanical hardware. The current generation (Atlas, Figure, Tesla Optimus, Unitree) replaces hand-coded controllers with neural-network policies trained in physics simulation and on human demonstration data, giving robots the ability to handle the messy, partially-observed environments that defeated earlier industrial machines." },
  { id: "quantum-computing", name: "Quantum Computing", era: "information", category: "knowledge",
    year: "2019", prereqs: ["quantum-mechanics", "microprocessor"],
    desc: "Computers built from qubits — quantum systems (superconducting circuits, trapped ions, photons) that, unlike classical bits, can be in a superposition of 0 and 1 at once, and that can be entangled so that the state of one instantly correlates with another. A quantum algorithm choreographs interference between many superposed paths so that wrong answers cancel out and the right answer is amplified — solving certain problems (factoring large numbers, simulating molecules, searching unstructured data) exponentially faster than any classical machine. The catch is that qubits are extraordinarily fragile: any stray heat, vibration, or stray photon collapses the superposition (decoherence), so qubits must be cooled to millikelvin temperatures or trapped in vacuum, and tens of thousands of physical qubits will be needed to error-correct one stable 'logical qubit'. Google's Sycamore (2019) demonstrated 'quantum supremacy' on a contrived benchmark; IBM Quantum, IonQ, Rigetti, PsiQuantum, and others are scaling up. Practical applications in cryptography (Shor's algorithm) and chemistry simulation remain mostly future-tense, but progress has been steady." },
  { id: "climate-science", name: "Climate Science", era: "information", category: "knowledge",
    year: "1988", prereqs: ["scientific-method", "digital-computer", "satellite"],
    desc: "The quantitative study of Earth's climate as a coupled physical system, treating the atmosphere, oceans, ice, biosphere, and human emissions as components whose interactions are encoded in coupled differential equations and solved on supercomputers. General-circulation models partition the planet into a 3-D grid of cells, computing wind, temperature, humidity, sea ice, and ocean currents in each cell at successive time steps; observational anchors come from satellite radiometry, ocean buoys, weather stations, and paleoclimate proxies (ice cores, tree rings, ocean sediments) that reconstruct past climates back hundreds of thousands of years. The Keeling Curve (Mauna Loa CO₂, 1958–present) made the rising atmospheric CO₂ trajectory undeniable. The IPCC (founded 1988) integrates the science into periodic assessment reports for policymakers. As of 2024 the planet is ~1.3°C warmer than pre-industrial levels, and climate science underwrites every credible mitigation, adaptation, and energy-transition policy of the 21st century." },
  // ─── Military additions ───
  { id: "tank", name: "Tank", era: "modern", category: "weapons",
    year: "1916", prereqs: ["internal-combustion", "machine-gun", "bessemer-steel"],
    desc: "Tracked, armored, internally-powered vehicle carrying its own armament. The British Mark I (1916) at Flers-Courcelette broke the trench-warfare stalemate of WWI; J.F.C. Fuller's Plan 1919 imagined armored breakthrough as the future of warfare. By WWII the T-34, M4 Sherman, Panzer IV, and Tiger I had defined the modern tank, and Soviet deep-battle and German blitzkrieg doctrines made armored maneuver the central form of land warfare for the rest of the 20th century." },
  { id: "aircraft-carrier", name: "Aircraft Carrier", era: "modern", category: "weapons",
    year: "1922", prereqs: ["steamship", "airplane", "internal-combustion", "dreadnought-battleship"],
    desc: "Warship with a flight deck, hangars, catapults, and arrestor wires for fixed-wing operations. USS Langley (CV-1, 1922, converted from a collier) was the U.S. Navy's first; Lexington and Saratoga (1927) and Akagi made carriers fleet flagships. Pearl Harbor (1941) and Midway (1942) demonstrated that carriers had displaced the battleship as the capital ship. By the late 20th century carriers were instruments of global power projection rather than fleet engagements." },
  { id: "submarine-warfare", name: "Submarine Warfare", era: "modern", category: "weapons",
    year: "1914", prereqs: ["steamship", "internal-combustion", "electric-battery"],
    desc: "Diesel-electric submarines fielded as strategic weapons of attrition against surface shipping. German U-boats nearly starved Britain in WWI and again in 1942–43 with wolfpack tactics and the Type VII; Allied convoys, sonar, depth-charges, and ULTRA decryption eventually broke the Atlantic campaign. The Type XXI 'Elektroboot' (1944) — high underwater speed, snorkel — pointed toward modern fully submerged operations." },
  { id: "thermonuclear-weapon", name: "Thermonuclear Weapon", era: "atomic", category: "weapons",
    year: "1952", prereqs: ["nuclear-weapon"],
    desc: "A two-stage bomb that releases energy by fusing hydrogen isotopes — the same reaction that powers the Sun — multiplying yields a thousandfold over pure-fission weapons. The fission primary detonates first, producing a brief pulse of X-rays that, channeled by a casing of dense heavy metal, compresses and heats a separate secondary stage of lithium deuteride to the millions of degrees and gigabar pressures needed for the fuel to fuse. A surrounding uranium tamper amplifies the yield through additional fission. The 'Teller-Ulam' staging is still classified in detail but is the design behind every modern strategic warhead. Ivy Mike (1952, 10.4 Mt) was the first true H-bomb; Castle Bravo (1954, 15 Mt) was the largest U.S. test; the Soviet Tsar Bomba (1961) yielded ~50 Mt — three thousand times the Hiroshima bomb. A single thermonuclear warhead can destroy any city ever built." },
  { id: "icbm", name: "Intercontinental Ballistic Missile", era: "atomic", category: "weapons",
    year: "1957", prereqs: ["rocket", "nuclear-weapon", "digital-computer"],
    desc: "A multi-stage rocket that lofts a nuclear warhead into space on a ballistic trajectory and releases it to fall on a target on the other side of the planet. The booster burns for a few minutes, accelerating the warhead to ~7 km/s; gravity then pulls it through a high suborbital arc reaching 1,000+ km altitude, until it reenters the atmosphere over the target at hypersonic speed. Modern ICBMs carry MIRVs — multiple independently targetable reentry vehicles — that separate during coast and steer to different cities. Inertial guidance, augmented by star sightings, places each warhead within a few hundred meters of its aimpoint after a 10,000 km flight. The Soviet R-7 Semyorka (August 1957) was the first; the U.S. Atlas (1959) and silo-based Minuteman (1962) followed, with submarine-launched Polaris (1960) adding a survivable second strike that no first strike could find and destroy. ICBMs cut strategic warning time from hours to ~30 minutes, made every population center on Earth instantly targetable, and underwrote the Cold War's mutually assured destruction." },
  { id: "nuclear-submarine", name: "Nuclear Submarine", era: "atomic", category: "weapons",
    year: "1954", prereqs: ["nuclear-power", "submarine-warfare"],
    desc: "A submarine powered by an onboard fission reactor instead of diesel-electric machinery, removing the fundamental tactical limit of pre-nuclear submarines: the need to surface every few hours to run diesel engines that recharge the batteries and breathe atmospheric oxygen. A reactor produces heat without consuming oxygen and runs on uranium that needs replacing only every several years, so a nuclear submarine can remain submerged for months, circle the globe without surfacing, and run at high underwater speeds indefinitely. Hull design also changed in response: the teardrop shape of the Skipjack class (1959) is optimized for sustained submerged speed rather than surface running. USS Nautilus (SSN-571, 1954) was the first; USS George Washington (SSBN-598, 1959) carried 16 Polaris ballistic missiles, creating a strategic deterrent that no enemy could locate and destroy in a first strike. SSBNs remain the most invulnerable strategic weapons platform humans have built." },
  { id: "nuclear-aircraft-carrier", name: "Nuclear Aircraft Carrier", era: "atomic", category: "weapons",
    year: "1961", prereqs: ["aircraft-carrier", "nuclear-power"],
    desc: "Aircraft carrier driven by nuclear reactors, eliminating fuel-tanker dependence and giving essentially unlimited high-speed range. USS Enterprise (CVN-65, commissioned 1961) was the first, with eight reactors. The Nimitz class (1975 onward) standardized two-reactor 100,000-ton supercarriers as the symbol of American power projection. The Gerald R. Ford class (2017) introduces electromagnetic catapults and reduces crew requirements." },
  { id: "guided-missile", name: "Guided Missile", era: "modern", category: "weapons",
    year: "1944", prereqs: ["rocket", "radar"],
    desc: "A self-propelled weapon that adjusts its flight path in real time toward a target, rather than following the ballistic arc set at launch. Guidance ranges from a simple gyroscope-and-timer (Germany's V-1 cruise missile, operational June 1944) through inertial integration of accelerometers (V-2 ballistic missile, September 1944) to active seekers that home on heat, radar reflection, or radio command — feeding error signals to fins or thrust vectors that steer the weapon. The Fritz X radio-guided anti-ship glide bomb sank the Italian battleship Roma in September 1943, a fortnight before becoming the first guided weapon to hit its target in combat. Postwar refinements — the infrared AIM-9 Sidewinder (1956), the SA-2 Guideline that downed a U-2 in 1960, beyond-visual-range AIM-7 Sparrow — multiplied effective engagement range from kilometers to hundreds of kilometers and made gun-only fighters obsolete. By the late 20th century most warships were platforms for missiles rather than artillery." },
  { id: "precision-guided-munition", name: "Precision-Guided Munition", era: "information", category: "weapons",
    year: "1972", prereqs: ["guided-missile", "microprocessor"],
    desc: "Bombs and missiles fitted with a guidance kit — a sensor on the nose, control fins on the body, and a small computer in between — that steers the weapon to a specific aimpoint instead of falling where ballistic arithmetic predicts. Three guidance methods dominate: laser homing (a designator on a friendly aircraft or ground party paints the target with a coded laser pulse, and the seeker rides the reflected light onto it); GPS (the bomb knows the target's coordinates and its own position, and steers the difference to zero); and imaging-infrared seekers that recognize the target by its heat signature. Circular error probable shrinks from tens of meters (unguided) to meters or even less. Paveway laser-guided bombs in the Linebacker raids on Hanoi (1972) demonstrated the concept; JDAM GPS kits (1997) retrofitted ordinary iron bombs with cheap precision; Tomahawk cruise missiles (Desert Storm 1991) added thousand-km stand-off range. PGMs replaced area bombing with single-target strikes and reshaped the ethics and political tolerance of military operations." },
  { id: "stealth-aircraft", name: "Stealth Aircraft", era: "information", category: "weapons",
    year: "1981", prereqs: ["airplane", "radar", "programming-language"],
    desc: "An aircraft engineered to be nearly invisible to enemy radar, infrared sensors, and passive listening systems. Radar detection works by bouncing a pulse off the target and timing the echo; stealth attacks the echo on three fronts: shaping the airframe with flat facets or smoothly blended curves that scatter incoming radar away from the source rather than back to it (the F-117's faceted look is a 1970s approximation; the B-2's smooth blended wing is the more sophisticated 1980s solution); coating the surface in radar-absorbent materials that convert microwave energy to heat; and burying the engines deep inside the airframe with shielded inlets and cooled exhausts to minimize the infrared and acoustic signature. The mathematics of how curved surfaces scatter radar waves was intractable until Soviet physicist Pyotr Ufimtsev's work was applied on supercomputers — making stealth a computational achievement as much as a material one. Lockheed's Have Blue and the F-117 Nighthawk (operational 1983, public 1988) were first; the B-2 Spirit (1989) and F-22, F-35 followed." },
  { id: "drone-uav", name: "Unmanned Aerial Vehicle", era: "information", category: "weapons",
    year: "1995", prereqs: ["airplane", "microprocessor", "satellite"],
    desc: "An aircraft with no pilot on board, flown either by an operator at a remote console linked through a satellite or radio datalink, or autonomously by an onboard computer following waypoints. Removing the cockpit, ejection seat, and human life-support cuts weight and removes the human endurance limit, so a drone can loiter over a target for 24+ hours, fly into chemical or radioactive environments, and be lost without losing a pilot. The same removal lowers cost dramatically — a quadcopter capable of dropping a grenade costs a few hundred dollars; even a Reaper-class strike platform costs a fraction of a manned fighter. General Atomics MQ-1 Predator (1995) put long-endurance reconnaissance over Bosnia and later Afghanistan; armed Predators conducted the first targeted killings; the MQ-9 Reaper, RQ-4 Global Hawk, and Turkish Bayraktar TB2 (Ukraine 2022) extended drone warfare globally. Cheap consumer quadcopters, jury-rigged with explosives, have since reshaped infantry combat from Karabakh to Ukraine." },
  { id: "fifth-gen-fighter", name: "Fifth-Generation Fighter", era: "information", category: "weapons",
    year: "2005", prereqs: ["stealth-aircraft", "jet-engine"],
    desc: "A fighter whose advantage comes less from kinematics and more from being almost invisible while seeing everything. Five capabilities define the generation: low radar cross-section (achieved through stealth shaping and absorbent skin); supersonic cruise without afterburner (so the aircraft can sustain high speed without a hot exhaust plume that infrared trackers latch onto); internal weapons bays (external pylons would ruin the radar signature); sensor fusion (a single track displayed to the pilot, built from radar, infrared, electronic-warfare receivers, and datalinks from other aircraft and satellites); and high-bandwidth datalinks that let a flight of four share targets in real time. The result is an aircraft that detects and shoots an opponent who never sees it coming. The F-22 Raptor (IOC 2005) was first; the F-35 Lightning II (2015) is the largest defense program in history; the Sukhoi Su-57 (2020) is a non-Western entrant. Fifth-generation aircraft are network nodes as much as airframes — their advantage lies as much in data fusion as in the platform itself." },
  { id: "counter-stealth-radar", name: "Counter-Stealth Radar", era: "information", category: "weapons",
    year: "2010", prereqs: ["radar", "stealth-aircraft", "advanced-chip-manufacturing"],
    desc: "Radar designed to defeat the geometric stealth optimization of 5th-generation aircraft. Conventional fighter radars operate at high frequency (X-band, ~10 GHz) where wavelengths are a few centimeters — small enough that the faceted or curved surfaces of a stealth airframe scatter the return cleanly away from the source. Drop the frequency by a factor of ten or more (VHF/UHF, 50–500 MHz, with wavelengths of meters), and the same airframe features become comparable to or smaller than the wavelength: instead of specular reflection, the wave couples to the whole shape and resonates, producing a return that conventional stealth shaping cannot suppress. The cost is angular resolution — long-wavelength radar gives a fuzzy track, good enough to know an aircraft is somewhere in a kilometer-wide cell but not to lock a missile onto it — so counter-stealth systems are paired with multi-static fusion (multiple radars at known positions cross-correlate their detections to triangulate) and passive bistatic detection (using ambient FM radio, cellular, or DTV signals reflected off the target). Russian Nebo-M, Chinese JY-26, and the Czech Vera-NG passive system represent the operational state of the art. The existence of these systems is what *forces* sixth-generation fighter design beyond simple stealth shaping into broadband signature management." },
  { id: "adaptive-cycle-engine", name: "Adaptive Cycle Engine", era: "information", category: "transport",
    year: "2024", prereqs: ["jet-engine", "advanced-chip-manufacturing"],
    desc: "A jet engine with a *third* airflow path between the inner core and the outer bypass duct, plus actively controlled valves that let the engine reconfigure itself in flight between two operating modes that previous turbofans could only compromise between. In high-thrust mode, the third stream's air is diverted into the core for combustion, producing the high specific thrust of a low-bypass military engine; in cruise mode, that same air detours around the core as additional bypass, raising the bypass ratio to airliner levels and dramatically improving fuel efficiency. The result: an engine that gives a fighter both the burst performance of an F-15 and the unrefueled range of a transport, on the same airframe. Mechanically, the variability comes from front and rear variable area bypass injectors plus a variable-geometry low-pressure turbine — every component has to slide or rotate in flight, with full-authority digital engine control coordinating the change in milliseconds. GE Aerospace's XA100 and Pratt & Whitney's XA101 demonstrators completed Air Force testing 2022–24; production engines are the gating technology for sixth-generation fighter programs whose Pacific-theater range requirements cannot be met by conventional fixed-cycle engines." },
  { id: "collaborative-combat-aircraft", name: "Collaborative Combat Aircraft", era: "information", category: "weapons",
    year: "2026", prereqs: ["drone-uav", "fifth-gen-fighter", "deep-learning"],
    desc: "Semi-autonomous combat drones designed to fly in formation with crewed fighters, with one human pilot directing two to six unmanned wingmen through high-level commands rather than piloting each. Each drone is a small, single-engine, jet-powered airframe — cheaper than a manned fighter by roughly an order of magnitude, intentionally attritable in high-threat airspace where losing a human is unacceptable — carrying its own sensors, radar, electronic warfare suite, and weapons. The drones absorb attrition the human-crewed jet cannot risk, push the sensor envelope forward (radiating from positions the stealthy crewed jet wants to keep silent), and project firepower beyond the magazine of the parent aircraft. Onboard AI handles formation flying, terrain avoidance, threat reaction, and the inner-loop kill chain (target identification, weapons employment) under tasking rules set by the human; high-bandwidth datalinks fuse all drones' sensors into the human pilot's display. Real programs in flight test 2025–26: USAF Collaborative Combat Aircraft Increment 1 with General Atomics YFQ-42A and Anduril YFQ-44A (Fury); Boeing MQ-28 Ghost Bat (Australia); Kratos XQ-58 Valkyrie. CCA is the doctrinal centerpiece of every sixth-generation program — possibly more impactful than the crewed fighter itself." },
  { id: "sixth-gen-fighter", name: "Sixth-Generation Fighter", era: "future", category: "weapons",
    year: "2032", prereqs: ["fifth-gen-fighter", "adaptive-cycle-engine", "collaborative-combat-aircraft", "counter-stealth-radar"],
    desc: "The next generation of crewed combat aircraft, designed from the ground up to operate as the command node of a manned-unmanned formation rather than as a standalone fighter, and to defeat the counter-stealth radar systems that have made conventional fifth-generation stealth shaping obsolete in some threat environments. Distinguishing features over fifth-gen: vastly greater unrefueled range (Pacific-theater requirements drove this — F-22's combat radius is too small for Western Pacific contingencies), achieved by combining adaptive-cycle engines with larger airframes; broadband stealth that suppresses signature across radar bands from VHF to millimeter-wave, not just X-band; an open-systems mission architecture that lets new sensors, weapons, and AI software be installed within months rather than the decades fifth-gen upgrades took; integrated directed-energy self-defense (laser anti-missile, microwave countermeasures); and explicit design for tasking 2–6 collaborative combat aircraft per crewed jet. Real programs in 2025: USAF NGAD (Boeing F-47 selected, prototype already flown), USN F/A-XX, UK/Italy/Japan GCAP (formerly Tempest), French/German/Spanish FCAS, Chinese rumored J-XX. IOC dates target ~2030–2035. Sixth-generation programs are also among the largest single-platform defense investments in history." },
  { id: "cyber-warfare", name: "Cyber Warfare", era: "information", category: "weapons",
    year: "2010", prereqs: ["arpanet-internet", "programming-language", "public-key-cryptography"],
    desc: "Use of malicious software and network intrusion as instruments of state conflict. Attackers exploit unpatched bugs, stolen credentials, supply-chain compromises, and social engineering to gain access to a target's networks, then move laterally toward systems whose disruption would matter — power grids, refineries, banks, election infrastructure, military command and control. Once in, they can quietly exfiltrate data, plant logic bombs that activate later, encrypt files for extortion (ransomware), or directly damage physical equipment by manipulating its control systems (as Stuxnet did, spinning Iranian centrifuges to destruction while reporting normal readings). Cyber operations are cheap relative to kinetic ones, scale instantly, and are difficult to attribute, which makes them attractive for coercion below the threshold of open war. Stuxnet (2010, U.S.-Israeli operation against Iran) was the first publicly attributed strategic cyberweapon; NotPetya (2017, Russia, $10B+ in global collateral damage), election interference, ransomware-for-hire, and the cyber dimension of Russia's invasion of Ukraine (2022) have made cyber a permanent dimension of state conflict alongside the kinetic ones." },
  { id: "hypersonic-weapon", name: "Hypersonic Weapon", era: "information", category: "weapons",
    year: "2019", prereqs: ["jet-engine", "guided-missile", "advanced-chip-manufacturing"],
    desc: "Weapons that fly at Mach 5+ within the atmosphere — fast enough that they cover thousands of kilometers in minutes — while continuing to maneuver. Two architectures: a hypersonic glide vehicle is boosted to high altitude by a rocket and then 'skips' along the upper atmosphere on a flattened, unpredictable trajectory all the way to the target; a scramjet-powered cruise missile uses an air-breathing engine in which combustion happens in supersonic airflow, sustaining Mach 5+ continuously. Compared to a ballistic warhead — which arrives faster but on a predictable parabolic arc that tracking radars can extrapolate — a hypersonic weapon can change course in flight, defeating the predictive math behind every existing missile-defense interceptor. The compressed flight time also collapses the decision window for the defender. Russia's Avangard HGV (operational 2019) and North Korea's Hwasong-8 (2021) entered service while U.S. systems (HAWC, ARRW) remain in development." },

  // ─── Backfill prereqs for Future Age ───
  { id: "plasma-physics", name: "Plasma Physics", era: "atomic", category: "knowledge",
    year: "1958", prereqs: ["quantum-mechanics", "electromagnetism"],
    desc: "The study of ionized gases — the fourth state of matter — formalized as a discipline by Hannes Alfvén, Lyman Spitzer, and Soviet researchers in the 1950s. Spitzer's stellarator (1951) and the Soviet tokamak (Tamm and Sakharov, 1958) established the two main magnetic-confinement geometries used to study fusion plasmas. Plasma physics also underlies astrophysics (stars, accretion disks), atmospheric reentry, semiconductor processing, and electric propulsion." },
  { id: "neuroscience", name: "Neuroscience", era: "atomic", category: "knowledge",
    year: "1952", prereqs: ["evolution-darwin", "electromagnetism", "quantum-mechanics"],
    desc: "Systematic study of the nervous system at cellular, circuit, and behavioral levels. Hodgkin and Huxley's squid-axon model of action-potential propagation (1952) is the canonical foundational paper; Wilder Penfield's cortical mapping in conscious patients (1937 onward) defined functional brain regions; Eric Kandel won the 2000 Nobel for the molecular basis of memory in Aplysia. Neuroscience now spans from molecular biology to fMRI to computational models, and is the substrate for any future brain-computer or cognitive-enhancement technology." },
  { id: "gene-therapy", name: "Gene Therapy", era: "information", category: "medicine",
    year: "1990", prereqs: ["genetic-engineering", "dna-structure"],
    desc: "Therapeutic introduction or correction of genes inside patient cells, delivered by viral vectors or nanoparticles. Ashanti DeSilva's 1990 ADA-SCID treatment was the first FDA-approved trial. After early-2000s setbacks, modern AAV vectors enabled Luxturna (2017, hereditary blindness), Zolgensma (2019, spinal muscular atrophy), and Casgevy (2023, sickle-cell disease). Combined with CRISPR, gene therapy is moving from rare monogenic diseases toward broader applications including cancer immunotherapy." },
  { id: "tissue-engineering", name: "Tissue Engineering", era: "information", category: "medicine",
    year: "1989", prereqs: ["genetic-engineering", "dna-structure"],
    desc: "Growing functional biological tissue on biocompatible scaffolds seeded with cells. The 'Vacanti mouse' (1989, ear-shaped cartilage on a polymer scaffold) made the field famous. Lab-grown skin (Apligraf 1998), bladders (Atala 2006), and trachea (Macchiarini 2008) entered clinical use. Modern organoids and 3D-bioprinted tissues are inching toward whole organs; meanwhile cultivated-meat companies use the same techniques to grow muscle for food." },
  { id: "closed-loop-life-support", name: "Closed-Loop Life Support", era: "information", category: "shelter",
    year: "1991", prereqs: ["public-sanitation", "synthetic-fertilizer", "green-revolution"],
    desc: "Self-sustaining systems that recycle air, water, and waste nutrients within a sealed habitat. Biosphere 2 (Arizona, 1991, $200M, 8 inhabitants for two years) was the most ambitious early attempt and revealed how hard the engineering is — atmospheric balance, microbial succession, food production all proved unstable. The ISS Environmental Control and Life Support System (operational since 2008) is the first proven closed-loop oxygen and water system in space, and the basis for future Moon and Mars habitats." },

  // ─── Future Age ───
  { id: "fusion-power", name: "Fusion Power", era: "future", category: "energy",
    year: "2060", prereqs: ["magnetic-confinement-fusion", "tritium-breeding"],
    desc: "Generating electricity by fusing light atomic nuclei (deuterium and tritium, both isotopes of hydrogen) into heavier ones, releasing the binding-energy difference as kinetic energy of the products — the same reaction that powers the Sun. The challenge is that two positively charged nuclei naturally repel each other, so they only fuse when squeezed close enough for the strong nuclear force to take over, which requires temperatures above 100 million °C. Two confinement strategies dominate: magnetic confinement (a tokamak's doughnut-shaped magnetic field bottles a hot plasma so it never touches the chamber walls), and inertial confinement (a millimeter-scale fuel pellet is symmetrically compressed by 192 simultaneous laser pulses faster than it can fly apart). The figure of merit is Q — energy out divided by energy in; commercial reactors need Q>10 sustained for hours. ITER (under construction, France) targets Q>10 in the 2030s; Commonwealth Fusion Systems, TAE, Helion, and Tokamak Energy pursue high-temperature-superconductor tokamaks and alternative geometries; NIF achieved inertial Q>1 in 2022. Practical fusion would essentially solve the climate-era energy problem with abundant, carbon-free, fuel-cheap electricity." },
  { id: "humanoid-robot", name: "Humanoid Robot", era: "future", category: "tools",
    year: "2030", prereqs: ["robotics", "deep-learning", "lithium-battery", "advanced-chip-manufacturing"],
    desc: "A robot built in roughly human form — two legs, two arms with grippers, a torso with sensors, and a head — so it can operate in environments designed for humans (homes, factories, warehouses, kitchens) without anyone having to redesign the doors, stairs, tools, or workflow. Bipedal locomotion requires continuous active balance: the robot is constantly falling forward, and a real-time controller catches it with each step. The breakthrough making humanoids plausible now is not the mechanical hardware (which has existed since Honda's ASIMO in 2000) but the software: vision-language-action models trained on enormous amounts of human demonstration video, which let the robot translate a spoken instruction like 'put the dishes away' into a sequence of grasps and motions without each task being scripted. Boston Dynamics' electric Atlas (2024), Tesla Optimus, Figure 02, Agility Robotics' Digit, and Chinese makers (Unitree H1, Fourier GR-1) are entering pilot deployments. Cheap actuators, large pretrained policies, and dramatically improved batteries have made physically embodied AI a near-term rather than far-future technology." },
  { id: "agi", name: "Artificial General Intelligence", era: "future", category: "knowledge",
    year: "2045", prereqs: ["large-language-model", "deep-learning", "advanced-chip-manufacturing", "game-theory"],
    desc: "An AI system that matches or exceeds human capability across the full breadth of cognitive work rather than only narrow domains — solving a math research problem, writing a novel, debugging unfamiliar code, planning a startup, conducting a scientific experiment, all with the same underlying model. Where today's systems are fluent in language but brittle outside their training distribution, an AGI would generalize: it would learn new tasks from a few examples, transfer knowledge between fields, and hold its own goals stably across long horizons. Three open questions dominate research: whether scaling current language-model architectures with more data and compute is sufficient, whether genuine generality requires multimodal embodied learning (a model that has seen the physical world), and whether alignment — making the system reliably want what humans want — scales to systems smarter than their developers. The leading labs (OpenAI, Anthropic, Google DeepMind, Meta AI, xAI) explicitly target AGI; safety research from Bostrom, Russell, Christiano, and Hendrycks frames the alignment problem. The economic and existential implications are unique in the technology tree." },
  { id: "brain-computer-interface", name: "Brain-Computer Interface", era: "future", category: "medicine",
    year: "2030", prereqs: ["neuroscience", "advanced-chip-manufacturing", "deep-learning"],
    desc: "An interface that reads electrical activity directly from the brain and (optionally) writes it back, bypassing eyes, ears, and muscle. Sensing is done with electrode arrays inserted into the cortex (Utah arrays, Neuralink threads), placed on the cortical surface (ECoG), threaded through blood vessels (Synchron's stentrode), or worn on the scalp (EEG, with much lower spatial resolution). Each electrode picks up the voltage fluctuations of nearby neurons; a decoder — typically a neural network trained on the user's own activity — translates these patterns into intended commands like 'move cursor right' or 'select that letter'. Writing back uses brief electrical pulses to stimulate sensory cortex, evoking artificial sensations of touch or sight. Utah arrays have enabled paralyzed patients to type and move robotic arms by thought since the early 2000s; Neuralink's N1 implant (first human, 2024) and Synchron's stentrode are bringing higher channel counts and easier surgery toward clinical use. Near-term applications target paralysis, blindness, and depression; the long-term arc points toward bidirectional bandwidth between cortex and machine large enough for cognitive augmentation and shared experience." },
  { id: "moon-base", name: "Permanent Moon Base", era: "future", category: "shelter",
    year: "2035", prereqs: ["reusable-rocket", "nuclear-power", "3d-printing", "closed-loop-life-support"],
    desc: "A continuously inhabited outpost on the lunar surface, designed around the brutal local environment: a 14-day cycle of full sunlight followed by 14 days of darkness at -170°C, no atmosphere to absorb solar UV or cosmic rays, and abrasive dust that destroys seals and lung tissue. The base must therefore be partially buried under lunar regolith (the loose surface dust, an excellent radiation shield), powered by either nuclear reactors or solar arrays at the permanently sunlit polar peaks, and supplied with water and oxygen extracted from the ice deposits in permanently shadowed polar craters by 'in-situ resource utilization' systems that mine and electrolyze the local material — because every kilogram shipped from Earth costs more than gold. NASA's Artemis program targets the Lunar Gateway and a south-polar surface base by the 2030s; China and Russia are jointly pursuing the International Lunar Research Station; SpaceX's Starship is the heavy lifter that makes the architecture economic. The Moon becomes both a science platform and a proving ground for Mars." },
  { id: "mars-landing", name: "First Crewed Mars Landing", era: "future", category: "transport",
    year: "2035", prereqs: ["reusable-rocket", "closed-loop-life-support"],
    desc: "The first human footprints on Mars: an Apollo-style mission in which a crew rides a heavy-lift rocket through a six- to nine-month interplanetary cruise, decelerates into Mars orbit, and descends to the surface for an exploration stay before returning to Earth. The hard part is entry, descent, and landing through Mars's thin atmosphere (~1% of Earth's): the atmosphere is thick enough to burn an unprotected vehicle on entry yet too thin for parachutes alone to land tens of tons, so the lander must combine a heat shield, supersonic parachutes, and propulsive landing burns — a sequence first demonstrated robotically by Curiosity (2012) and Perseverance (2021), now scaled to crewed mass. The crew must survive months of microgravity transit, ~24-month round-trip radiation exposure, and the psychological isolation of a 4–22 minute one-way light delay to home. SpaceX's Starship (first uncrewed Mars cargo flights targeted for the late 2020s, crewed by the early 2030s), NASA's Mars Design Reference Architecture, and China's Tianwen crewed program target this milestone. A successful first landing is to Mars colonization what Apollo 11 was to lunar exploration — a one-flight demonstration that the architecture works, but not yet a permanent presence." },
  { id: "mars-habitat", name: "Mars Surface Habitat", era: "future", category: "shelter",
    year: "2055", prereqs: ["mars-landing", "moon-base", "3d-printing"],
    desc: "A permanently inhabited base on the Martian surface, where rotating crews of dozens to hundreds live for years at a time without yet being self-sufficient. The structures are cylindrical or dome-shaped pressurized modules, often 3D-printed from sintered regolith or assembled from prefab Earth-launched panels, then buried under a few meters of regolith for radiation shielding (Mars has no global magnetic field; surface radiation is ~50× Earth's). In-situ resource utilization is mature: the Sabatier process produces methane fuel by combining atmospheric CO₂ with hydrogen electrolyzed from water ice, allowing return rockets to refuel locally; perchlorate-leaching reactors clean the toxic soil for greenhouses; solar and small fission reactors power the base through the dust-storm season. Communications relay through Mars-orbiting satellites whose constellation also handles surface navigation. Resupply from Earth still arrives every 26-month launch window, but a substantial fraction of consumables are now produced locally. This is the proving ground for everything a true colony needs — the difference from `mars-colony` is that an Earth supply cutoff would still kill the inhabitants." },
  { id: "mars-colony", name: "Self-Sustaining Mars Colony", era: "future", category: "shelter",
    year: "2080", prereqs: ["mars-habitat", "fusion-power", "synthetic-biology"],
    desc: "A Mars settlement large and self-sufficient enough to survive a permanent cutoff from Earth — meaning it produces its own food, manufactures its own spare parts (including the parts of the parts: the chip fabs, the steel mills, the pharma plants), and maintains a viable breeding population. Achieving self-sufficiency is harder than achieving habitat: the colony has to close every supply loop locally, including the long-tail loops (specialty chemicals, semiconductors, medical drugs, education) that mature economies on Earth solve through global trade. Population must reach the tens of thousands at minimum, with an industrial base spanning extraction (water from subsurface ice, metals from regolith), agriculture (closed-loop greenhouses, possibly engineered photosynthetic organisms), and manufacturing. SpaceX's stated long-term goal of a million people on Mars by the 2070s aims at this threshold; serious technical analyses (Musk 2017, Zubrin's Mars Direct, NASA's settlement studies) all converge on it as the moment humanity becomes irreversibly multi-planetary. Once crossed, an Earth catastrophe — engineered pandemic, asteroid impact, civilizational collapse — no longer extinguishes the species." },
  { id: "asteroid-mining", name: "Asteroid Mining", era: "future", category: "subsistence",
    year: "2040", prereqs: ["reusable-rocket", "robotics", "autonomous-vehicle"],
    desc: "Robotic extraction of useful materials from near-Earth asteroids — water, platinum-group metals, and structural metals — using small spacecraft that dock with a target body, mine its surface or interior, and either return the product to Earth orbit or process it on site. Three asteroid types matter: carbonaceous chondrites (carbon and water-rich, the cheapest source of orbital propellant once you crack and electrolyze the water), metallic types (almost pure iron-nickel with platinum-group metal concentrations thousands of times higher than any Earth ore), and silicaceous types (oxygen and silicon for habitats and solar panels). The economic logic is that escaping Earth's gravity well costs ~$1,000+ per kg even with reusable rockets, while the same kg already in orbit, mined from an asteroid, is effectively free of that escape penalty — making asteroid water the cheapest possible deep-space fuel. NASA's OSIRIS-REx returned 250g from Bennu (2023); Japan's Hayabusa2 from Ryugu (2020). Commercial firms (Planetary Resources, Deep Space Industries) struggled with capital, but a single 200m metallic asteroid contains more platinum than has ever been mined on Earth." },
  { id: "anti-aging", name: "Longevity Medicine", era: "future", category: "medicine",
    year: "2040", prereqs: ["crispr", "gene-therapy", "deep-learning"],
    desc: "Medicine that treats biological aging itself as a target rather than treating each age-related disease (cancer, heart disease, dementia) separately. The premise is that aging is driven by a small set of cellular mechanisms — senescent cells that won't divide and won't die but secrete inflammation, attrition of telomere caps on chromosomes, dysfunction of the mitochondria that power each cell, accumulation of misfolded proteins, and drift of the epigenetic markings that tell each cell which genes to express — and that intervening upstream against these mechanisms slows or reverses many downstream diseases at once. Approaches under clinical investigation include senolytics (drugs that selectively kill senescent cells), partial cellular reprogramming (briefly expressing the Yamanaka factors that reset cells toward a younger epigenetic state, pursued by Altos Labs and Calico), rapamycin-class compounds (which modulate the mTOR nutrient-sensing pathway), and gene therapies for telomerase. If successful, longevity medicine would compress morbidity and add decades of healthspan, reshaping demographics, pensions, careers, and family structure." },
  { id: "lab-grown-meat", name: "Cultivated Meat", era: "future", category: "subsistence",
    year: "2030", prereqs: ["tissue-engineering", "genetic-engineering", "synthetic-fertilizer"],
    desc: "Animal muscle and fat grown directly from cells in steel bioreactors, eliminating the rest of the animal. A small biopsy from a living animal yields a starter cell line, which is propagated in a medium of sugars, amino acids, salts, and growth factors that mimic the inside of the animal's body; the cells multiply, then are seeded onto an edible scaffold whose shape determines the final cut of meat, and induced to differentiate into muscle and fat tissue. Because the system runs without the rest of the animal — no skeleton, no digestive tract, no brain, no immune response — almost all the input feed becomes product, dramatically improving conversion efficiency over a live cow. The bottleneck is growth-factor cost, which has fallen ~99% in a decade but still dominates the price of a kilo. Mark Post's 2013 lab-grown burger cost $325,000; by 2024 cultivated chicken was approved for sale in Singapore (Eat Just) and the U.S. At maturity, cultivated meat could decouple meat consumption from the land use, water demand, and greenhouse-gas footprint of conventional livestock." },
  { id: "synthetic-biology", name: "Synthetic Biology", era: "future", category: "knowledge",
    year: "2035", prereqs: ["crispr", "gene-sequencing", "deep-learning"],
    desc: "Treating biology as an engineering substrate: genes are modular parts (like resistors and capacitors), genomes are circuits, and organisms are programmable platforms. Synthetic biologists design DNA sequences on a computer, order them from a synthesis vendor, splice them into a 'chassis' organism (typically yeast or E. coli), and watch the engineered cell produce the encoded compound — insulin, artemisinin (an antimalarial), spider silk, leather, biofuels, fragrance molecules. AlphaFold (2020) and ESM3 (2024) made it feasible to design entirely new proteins from scratch and predict their three-dimensional folded shape, vastly expanding what can be built. Craig Venter's 2010 synthetic Mycoplasma — a bacterium booted from a chemically synthesized genome — proved the deep version of the principle. The long arc points toward custom organisms tailored as living factories for materials, fuels, and pharmaceuticals, as environmental remediators, and ultimately as platforms for entirely novel biology not derived from any natural lineage." },
  { id: "room-temp-superconductor", name: "Room-Temperature Superconductor", era: "future", category: "tools",
    year: "2070", prereqs: ["advanced-chip-manufacturing", "quantum-mechanics"],
    desc: "A material that carries electric current with exactly zero resistance at ordinary room temperature and atmospheric pressure. Superconductivity has been known since 1911, but every known superconductor requires extreme cooling (liquid helium at 4 K for niobium, liquid nitrogen at 77 K for cuprates) or extreme pressure (millions of atmospheres for hydrogen hydrides) — costs that limit the technology to expensive niches like MRI magnets and particle accelerators. Conduction in a superconductor works by an entirely different mechanism than in a normal metal: electrons pair up (Cooper pairs) and move through the lattice in a coherent quantum fluid that ignores the impurities and lattice vibrations that scatter normal currents. A material achieving this at ambient conditions would transform power transmission (no losses over thousands of km), enable maglev trains, MRI in every clinic, compact tabletop fusion magnets, and dramatically simpler quantum computers. Recent hydrogen-rich high-pressure superconductors (LaH10 at 250 K, 170 GPa) approach room-temperature behavior, and the search continues — possibly the most consequential open materials problem in physics." },
  { id: "nanotechnology", name: "Molecular Nanotechnology", era: "far-future", category: "tools",
    year: "2150", prereqs: ["3d-printing", "advanced-chip-manufacturing", "metamaterials"],
    desc: "Manufacturing in which structures are specified and built one atom or molecule at a time. Two regimes coexist: the bottom-up regime exploits self-assembly — designing molecules whose shape and chemistry cause them to organize themselves into the desired structure when mixed in a beaker (DNA origami folds DNA strands into specific shapes; block copolymers segregate into nanoscale patterns); the top-down regime mechanically positions individual atoms with the tip of an atomic force microscope or scanning tunneling microscope. The speculative endgame — Drexler's Engines of Creation (1986) — is a 'molecular assembler', a desktop machine that builds bulk goods to atomic specification by directing trillions of programmable nanoscale arms. Current practice falls far short of that vision but has produced commercial materials (carbon nanotubes, graphene, quantum dots) and clinical applications (lipid nanoparticle drug delivery, including the COVID mRNA vaccines). Mature molecular manufacturing would collapse the cost of arbitrary physical objects in the same way that integrated circuits collapsed the cost of arbitrary computation." },
  { id: "quantum-applications", name: "Practical Quantum Computing", era: "future", category: "knowledge",
    year: "2040", prereqs: ["quantum-computing", "advanced-chip-manufacturing"],
    desc: "Fault-tolerant quantum computers solving problems classical machines cannot — Shor's algorithm breaking RSA, Grover's algorithm searching unstructured databases, and quantum chemistry simulations of catalyst and drug molecules. Current systems (Google Sycamore, IBM Heron, IonQ) are NISQ-era — noisy, intermediate-scale, error-prone. Crossing the error-corrected threshold (millions of physical qubits per logical qubit) is the gating step. Practical quantum will rewrite cryptography, materials science, and high-energy physics." },
  { id: "quantum-internet", name: "Quantum Internet", era: "future", category: "communication",
    year: "2050", prereqs: ["quantum-computing", "fiber-optic", "arpanet-internet", "public-key-cryptography"],
    desc: "A network that distributes *entangled* qubits between nodes rather than ordinary bits. Two parties holding halves of an entangled pair share correlations that cannot be reproduced by any classical channel; once distributed, the entanglement enables capabilities that have no classical equivalent — provably tamper-evident encryption (any eavesdropper inevitably collapses the quantum state and is detected), blind quantum computation on a remote server that cannot learn what was computed, and clock synchronization at picosecond precision across continents. The hard part is that quantum information cannot simply be amplified the way classical signals are repeated by every router along a fiber line — the no-cloning theorem forbids it. Instead, *quantum repeaters* use entanglement-swapping and quantum memories to extend entanglement hop by hop without ever measuring the qubit in transit. Early demonstrations: a Beijing-to-Vienna QKD satellite link via Micius (2017), Delft's three-node entangled network (2021), and the EU and Chinese national-scale quantum-network programs targeting wide deployment by mid-century. The quantum internet runs *alongside* the classical internet, providing security and computation primitives the classical layer fundamentally cannot." },
  { id: "carbon-capture-scale", name: "Carbon Capture at Scale", era: "future", category: "energy",
    year: "2035", prereqs: ["renewable-grid", "climate-science", "synthetic-fertilizer"],
    desc: "Pulling CO₂ back out of the atmosphere on industrial scales — turning the climate problem from emissions reduction alone into active recovery. Four mechanisms compete: direct air capture (giant fans pull air through a sorbent that chemically binds CO₂; the sorbent is then heated to release pure CO₂ for storage); bioenergy with carbon capture (crops or trees draw down CO₂ as they grow, are burned for power, and the resulting flue-gas CO₂ is captured and injected underground); enhanced rock weathering (crushed silicate rock spread on fields reacts with atmospheric CO₂ to form carbonates over years); and ocean alkalinity enhancement (adding base to seawater pulls CO₂ from air into ocean as bicarbonate). The captured CO₂ is then pumped into depleted oil reservoirs or basalt formations where it mineralizes into stable rock over decades. The energy cost per ton is the central problem — capturing CO₂ from 0.04% atmospheric concentration is thermodynamically expensive — and the whole approach only counts as decarbonization if powered by carbon-free electricity. Climeworks Orca/Mammoth and a generation of startups are scaling pilots; current global capacity is ~10 Mt CO₂/year vs. the gigatons needed by midcentury for 1.5°C scenarios." },
  { id: "fusion-rocket", name: "Fusion Propulsion", era: "future", category: "transport",
    year: "2075", prereqs: ["fusion-power", "reusable-rocket"],
    desc: "A spacecraft engine that uses fusion reactions to expel propellant at a hundred to a thousand times the velocity of chemical rocket exhaust. The relevant figure of merit is specific impulse — effectively how many seconds a kilogram of fuel can deliver one kilogram of thrust — and a fusion drive can reach 10,000–100,000 seconds, against ~450 for the best chemical rockets. The mechanism: fusion plasma's enormous thermal energy is channeled magnetically into a directed exhaust, or charged fusion products themselves form the exhaust stream. Because the rocket equation rewards exhaust velocity exponentially, this transforms what missions are possible: Mars transit drops from six months to less than one month, outer-planet missions become practical for crewed exploration, and the fuel mass fraction stops dominating mission design. Princeton's PFRC reactor and the Direct Fusion Drive concept are the leading studies; the Daedalus interstellar probe (1970s) and Project Longshot (1988) explored mission profiles. Fusion propulsion is the gating technology for serious solar-system colonization." },
  { id: "space-elevator", name: "Space Elevator", era: "far-future", category: "transport",
    year: "2250", prereqs: ["nanotechnology", "room-temp-superconductor", "reusable-rocket"],
    desc: "A cable anchored to the equator and extending past geostationary orbit (35,786 km up) to a counterweight beyond, kept taut by the centripetal effect of Earth's rotation flinging the far end outward. Because the cable's center of mass sits at GEO, where orbital and Earth-rotation periods match, the whole structure stays vertical above one ground point. Payloads ride to orbit by climbing the cable on electrically powered crawlers, drawing energy from beamed power or onboard batteries — replacing rockets entirely for routine cargo and replacing the catastrophic cost penalty of fighting through the rocket equation with the modest cost of running an elevator. The gating technology is the cable itself: it must support its own weight at GEO altitudes plus the payload, requiring a material with tensile strength 30–100× steel and density similar to or below carbon. Carbon nanotube fibers, graphene ribbons, and boron nitride structures meet the strength requirement at lab scale but not yet at the tens-of-thousands-of-kilometers length needed. Tsiolkovsky proposed the concept (1895) and Yuri Artsutanov refined it (1959); Bradley Edwards's NASA-funded study (2000) renewed serious engineering interest." },
  { id: "post-scarcity", name: "Post-Scarcity Economy", era: "future", category: "economy",
    year: "2080", prereqs: ["agi", "fusion-power", "humanoid-robot"],
    desc: "An economic regime in which the marginal cost of most goods and services has fallen close to zero, because AGI handles cognitive work, humanoid robots handle physical work, and abundant clean energy powers both. The classical scarcity-based concepts of price, wage, and ownership begin to break down: when an automated factory can produce any object on demand and an AI can perform any service for the cost of compute, the historical link between human labor and human income — the basis of every previous economic system — disappears. The transition raises a set of unprecedented political questions: how is purchasing power distributed when nobody needs to be employed? Who owns the AGI and the robot fleet, and on what terms? What gives life meaning when labor is optional? Universal basic income, AI dividends, common ownership of automation, post-work culture, and new forms of governance become live political design problems. Whether such a society is utopian or dystopian depends almost entirely on the politics of the transition rather than on the technology itself." },
  { id: "digital-immortality", name: "Mind Uploading", era: "far-future", category: "medicine",
    year: "2170", prereqs: ["whole-brain-emulation", "brain-computer-interface", "advanced-chip-manufacturing"],
    desc: "The clinical and social application of whole-brain emulation: a destructive but high-fidelity scan of a willing individual's brain, the booting of an emulation on a computational substrate, and the legal recognition of that emulation as the continuation of the original person. Where whole-brain emulation is the technical capability — proven first on simpler organisms and ultimately on a human brain in the lab — uploading is the elective procedure: insurance frameworks for migration in old age or terminal illness, identity-continuation law (which jurisdiction's citizen is the upload?), inheritance and contract rights, the question of running multiple copies simultaneously, and the ethics of choosing whether the biological original survives. Roughly thirty years separate technical viability from routine availability — the typical lag between proof-of-concept transplantation and a normalized clinical practice. Adoption depends less on the engineering than on the philosophical question, never to be resolved empirically, of whether continuity of pattern preserves identity or whether the original simply dies and a sufficiently similar entity wakes up; many people will refuse on those grounds, and many will accept anyway. Mind uploading remains the most philosophically consequential entry in the tree, intersecting personal identity, consciousness, and the meaning of death." },

  // ─── Future Age (social / economic / cultural) ───
  { id: "universal-basic-income", name: "Universal Basic Income", era: "future", category: "economy",
    year: "2050", prereqs: ["agi", "humanoid-robot"],
    desc: "An income-distribution mechanism in which every citizen receives an unconditional cash payment, set high enough to cover basic needs, with no means test and no work requirement. The defining property is unconditionality: the payment does not phase out as the recipient earns more, so unlike traditional welfare it never creates a marginal disincentive to work, and unlike targeted programs it requires no bureaucracy to determine eligibility. The case for UBI changes shape depending on the surrounding context: as a poverty-reduction tool today, as a backstop against labor-market shocks (automation, recession), or — once AI and humanoid robots automate most cognitive and physical labor — as the basic income-distribution mechanism for an economy where labor is no longer the primary route to purchasing power. Pilots in Finland (2017–18), Stockton CA (2019), Kenya (GiveDirectly), Iran, and India have provided encouraging behavioral data. Funding mechanisms range from negative income tax (Friedman, 1962) and Georgist land-value taxes to AI-output dividends and resource-rent funds modeled on the Alaska Permanent Fund." },
  { id: "liquid-democracy", name: "Liquid Democracy", era: "future", category: "economy",
    year: "2050", prereqs: ["cryptocurrency", "agi", "world-wide-web"],
    desc: "A governance system that lets each citizen choose, issue by issue, whether to vote directly or delegate their vote to someone they trust on that topic — a friend who knows climate science, a journalist on foreign policy, an economist on tax law — with delegations being transitive (your delegate can re-delegate), revocable in real time, and topic-specific. The result sits between direct democracy (which scales poorly because no citizen can be informed on everything) and representative democracy (which forces a single bundle of decisions onto one elected official for years at a time): each citizen ends up represented by a fluid web of chosen experts on the issues they don't want to research, while still able to override any delegate on issues they do care about. Continuous-vote-tallying smart contracts can implement the transitive-delegation graph at scale, and AI assistants help citizens understand the issues they vote on. Taiwan's vTaiwan platform under Audrey Tang, Estonia's e-Residency, German Pirate Party experiments, and Iceland deliberative pilots are early instances. Critics worry about manipulability, voter fatigue, and the loss of structured deliberation." },
  { id: "network-state", name: "Network State", era: "future", category: "economy",
    year: "2040", prereqs: ["cryptocurrency", "world-wide-web", "ecommerce"],
    desc: "A new kind of polity that begins online and crystallizes into physical territory in stages, inverting the historical sequence of state formation. The playbook (Balaji Srinivasan, 2022) is: an online community of millions of like-minded people forms around a shared mission and norms; it accumulates collective capital, governance practice, and crypto-secured property records; it negotiates for physical territory as a charter city, special economic zone, or eventually as a recognized state; and only at the end does it gain a flag and a UN seat. The mechanism is enabled by remote work (income decoupled from location), cryptocurrency (value transferable across borders without bank approval), encrypted communication (community discussion outside any single jurisdiction), and online identity that travels with the citizen. Próspera (Honduras ZEDE), Nevada Innovation Zones, Zuzalu pop-up cities, and Cabin Network are early instances. Whether established nation-states will permit this without resistance — and whether such communities can deliver real public goods like courts and police — remains the central political question." },
  { id: "ai-governance", name: "Algorithmic Governance", era: "future", category: "economy",
    year: "2050", prereqs: ["agi", "large-language-model"],
    desc: "Government delegating substantial decisions to AI systems — initially as advisors that draft regulations, analyze policy options, recommend sentences, and triage benefits applications, and eventually as autonomous actors with discretionary authority. The appeal is that AI can ingest the full text of every relevant statute, court ruling, and economic study and produce internally consistent decisions in seconds, where human bureaucracies are slow, inconsistent, and biased by individual case loads. The hazard is that AI inherits the biases of its training data, can be impossible to audit when its reasoning is a billion-parameter neural network, and shifts accountability into a fog: when the algorithm denies a visa or sets a tax rate, who is responsible? Estonia's pilot 'AI judge' for small-claims court, the EU AI Act's risk tiers, China's social-credit experiments, Singapore's AI in public-service delivery, and DARPA's AI-policy initiatives are precursors. The legitimacy and accountability questions become more acute as AI authority expands from advisory recommendation to binding decision." },
  { id: "transhumanism", name: "Transhumanism", era: "future", category: "social",
    year: "2030", prereqs: ["brain-computer-interface"],
    desc: "A philosophical and cultural movement holding that the human condition — its biological limits on intelligence, lifespan, mood, sensory range, and physical capability — is not something to be accepted but a starting point to be deliberately exceeded through technology. Where humanism celebrates flourishing within natural human limits, transhumanism argues those limits are accidents of evolution and should be rewritten with the same engineering ambition we apply to any other system. Concrete proposals span the full toolkit of cognitive-enhancement drugs, brain-computer interfaces, gene editing for intelligence and disease resistance, anti-aging medicine, embryo selection, prosthetic augmentation, and eventually whole-brain emulation. Roots trace to Julian Huxley's 1957 essay coining the term; FM-2030, Max More, Nick Bostrom, Anders Sandberg, and Ray Kurzweil developed the philosophy. As BCIs, gene editing, and longevity medicine become clinical realities, transhumanism transitions from speculation to applied ethics: who can afford enhancement, whether unenhanced humans become disadvantaged, what counts as human." },
  { id: "longtermism", name: "Longtermism", era: "future", category: "social",
    year: "2030", prereqs: ["enlightenment-philosophy", "climate-science"],
    desc: "An ethical framework holding that, because humanity could in principle endure for millions of years and reach trillions of lives, the moral weight of the long-run future dwarfs the moral weight of the present, and decisions today should be evaluated mainly by their effect on whether that long future happens at all and how good it is. The argument runs: future people are real people whose interests count, the future is enormous in expectation, so reducing the probability of human extinction or civilizational collapse is one of the highest-value interventions available — vastly more valuable than typical near-term causes per dollar spent. The conclusion redirects attention toward existential risks (engineered pandemics, misaligned AI, nuclear war, asteroid impact) that have small annual probabilities but irrecoverable downsides. Derek Parfit's Reasons and Persons (1984), Toby Ord's The Precipice (2020), and William MacAskill's What We Owe the Future (2022) systematized the view; the Future of Humanity Institute, Open Philanthropy, and 80,000 Hours channel it into AI safety, pandemic preparedness, and policy. Critics argue longtermism discounts present-day suffering and is dangerously sensitive to moral uncertainty about the far future." },
  { id: "generative-art", name: "Generative Art", era: "future", category: "social",
    year: "2030", prereqs: ["large-language-model", "deep-learning"],
    desc: "Art created by neural networks that have been trained on enormous corpora of human work and can produce new images, music, video, or text on demand from a written prompt. Image models (diffusion-based, like Stable Diffusion) start with random noise and iteratively denoise it into a coherent picture conditioned on the prompt's embedding; text-to-video models extend the same principle to time. Because a model has internalized the statistical regularities of millions of artworks, a single user can specify 'oil painting of a fox in the style of Monet, 4k, golden hour' and receive a plausible candidate in seconds — collapsing what was previously days of skilled labor into a search-and-iterate process where the human's contribution is taste and direction rather than execution. Midjourney, DALL-E (2022), Stable Diffusion, Suno (music), Sora and Veo (video), and Runway brought generative art to mass use; Refik Anadol's MoMA installation and Boris Eldagsen winning a Sony Photography prize signaled fine-art recognition the same year. Disruption to illustrators, voice actors, and stock photographers is acute, and copyright cases (Getty v. Stable Diffusion, NYT v. OpenAI) are reshaping IP law in real time." },
  { id: "metaverse", name: "Metaverse", era: "future", category: "social",
    year: "2035", prereqs: ["advanced-chip-manufacturing", "deep-learning", "world-wide-web"],
    desc: "A networked computing environment that wraps the user inside a 3-D virtual world rather than presenting it on a flat screen. The hardware is a head-mounted display with stereo high-resolution screens, motion-tracking sensors, and hand controllers (or hand-tracking cameras), feeding the wearer a real-time rendered view that updates as they turn their head — convincingly enough to produce a sense of presence in the synthetic space. The 'meta' in metaverse refers to a single persistent shared world rather than disconnected games: avatars, items, and currencies move across applications, with millions of users coexisting in the same continuously running simulation. AI-driven non-player characters populate the empty volumes; cryptographic property records make digital items genuinely owned by users rather than rented from platform operators. Neal Stephenson's Snow Crash (1992) coined the term; Ernest Cline's Ready Player One (2011) popularized it; Roblox, Fortnite, VRChat, Meta's Horizon Worlds, and Apple Vision Pro (2024) are pre-metaverse implementations. Whether this becomes the next computing platform or remains hyped vaporware is genuinely uncertain after Meta's $40B+ Reality Labs losses." },
  { id: "decentralized-autonomous-org", name: "Decentralized Autonomous Organization", era: "future", category: "economy",
    year: "2030", prereqs: ["cryptocurrency", "programming-language"],
    desc: "An organization whose bylaws, treasury, and decision procedures are written as smart-contract code on a public blockchain, executing automatically without a CEO, board, or registered legal entity. Membership is held as governance tokens; proposals (move funds, deploy code, hire a contributor) are submitted on-chain; token-holders vote, and if the quorum and majority thresholds are met, the smart contract executes the proposal directly — no human gatekeeper between the vote and the action. Funds in the treasury can only be spent through this process, which means there is no executive who can embezzle and no judge who can freeze accounts. The trade-off is that bugs in the code are unfixable without a vote, governance attacks (buying enough tokens to pass a self-dealing proposal) become a real threat, and most jurisdictions have not decided how to regulate something with no legal address. The DAO (2016, infamously hacked for $50M), MakerDAO, Uniswap, and ConstitutionDAO (which raised $47M in days to bid on a U.S. Constitution copy in 2021) demonstrated varied applications; in practice, governance attacks, low voter turnout, plutocratic capture, and regulatory ambiguity have constrained adoption." },

  // ─── Future Age (additional 2035-2100) ───
  { id: "hyperloop", name: "Hyperloop", era: "future", category: "transport",
    year: "2035", prereqs: ["electric-motor", "advanced-chip-manufacturing", "machine-tool"],
    desc: "Ground transport that achieves aircraft cruising speeds inside a sealed near-vacuum tube, removing the air resistance that limits conventional trains. A passenger or cargo capsule levitates inside the tube on magnetic bearings (no rolling friction), is accelerated by linear induction motors built into the tube wall, and coasts at 1000+ km/h with negligible drag because the surrounding pressure is dropped to ~1/1000 of atmospheric. The thermodynamic argument is compelling — without air drag, the only sustaining loss is electrical, and energy use per passenger-km falls below high-speed rail despite the higher speed. The engineering challenges are unresolved: maintaining a vacuum across hundreds of kilometers of tube against inevitable leaks, surviving the stress concentration at any breach, throughput at stations (capsules must airlock in and out), and capital cost competitive with conventional high-speed rail. Elon Musk's 2013 white paper popularized the concept; Virgin Hyperloop ran a passenger test in 2020 before pivoting away. SpaceX's Boring Company, HyperloopTT, Chinese state programs, and Saudi/Indian proposed routes continue the work." },
  { id: "neuromorphic-chip", name: "Neuromorphic Chip", era: "future", category: "tools",
    year: "2035", prereqs: ["advanced-chip-manufacturing", "neuroscience"],
    desc: "A chip whose architecture imitates the structure of biological neural tissue rather than the von Neumann separation of memory from compute that defines a conventional CPU. Computation happens in many small 'neurons' that communicate by spikes (brief electrical events) along weighted 'synapses' physically co-located with the neurons themselves; memory and compute occupy the same transistors. The chip operates asynchronously and event-driven — a neuron only burns power when its inputs cross a threshold — instead of clocking every transistor on the die hundreds of millions of times per second. The combination uses a thousandth or less of the energy a GPU spends on the same pattern-recognition workload, which makes neuromorphic chips attractive wherever battery life dominates: hearing aids, edge robotics, sensor fusion, brain-computer interfaces, always-on speech recognition. Intel Loihi 2 (2021), IBM TrueNorth (2014), the Manchester SpiNNaker board, and BrainChip Akida are leading platforms. They likely complement rather than replace conventional silicon for the foreseeable future." },
  { id: "lab-grown-organs", name: "Lab-Grown Organs", era: "future", category: "medicine",
    year: "2040", prereqs: ["tissue-engineering", "gene-therapy", "3d-printing"],
    desc: "Whole transplantable organs built from a patient's own cells, replacing the lottery of donor matching with custom-grown replacements that the recipient's immune system recognizes as self. The standard process: a small biopsy yields stem cells, which are induced to divide into the organ's various cell types (cardiomyocytes, hepatocytes, vascular endothelium); the cells are seeded onto a 3-D scaffold whose geometry matches the target organ — sometimes a synthetic biopolymer mesh, sometimes the decellularized matrix of a donor organ stripped down to its collagen skeleton; the construct is matured in a bioreactor that supplies nutrients, oxygen, and mechanical cues. The hardest unsolved subproblem is vascularization: any organ thicker than a few millimeters needs a printed-in network of capillaries to feed its interior cells before they suffocate. Anthony Atala's lab grew functional bladders for clinical patients (2006); recent work has produced organoid-scale kidneys, livers, hearts, and lungs. United Therapeutics and BioLife Solutions target full clinical organs by 2040, which would end transplant waiting lists and chronic dialysis." },
  { id: "sentientism", name: "Sentientism", era: "future", category: "social",
    year: "2040", prereqs: ["longtermism", "evolution-darwin"],
    desc: "Ethical framework extending moral consideration to all sentient beings — non-human animals and potentially digital minds — based on capacity for subjective experience rather than species membership. Peter Singer's Animal Liberation (1975) is the foundational text; Donald Watson, Sue Donaldson, Will Kymlicka, and Jeff Sebo extended it to political theory. The framework reshapes debates around factory farming, lab animal use, AI moral status, and far-future digital sentience. Effective animal advocacy organizations operate on these ethics." },
  { id: "dna-data-storage", name: "DNA Data Storage", era: "future", category: "tools",
    year: "2045", prereqs: ["synthetic-biology", "gene-sequencing"],
    desc: "Storing digital information by writing it into the four-letter alphabet of DNA bases. Each binary 0/1 (or pair of bits) is mapped to one of A, C, G, T; an error-correcting code adds redundancy; a DNA-synthesis machine then chemically writes the resulting sequence base by base into millions of short strands, which are pooled and stored dry as a tiny pellet. To read, the pellet is sequenced and the original bits are decoded. The density is staggering — DNA can store roughly an exabyte (10¹⁸ bytes) per cubic millimeter, more than a million times denser than the best magnetic tape — and the medium is stable for thousands of years if kept cool and dry, with no need for power or active migration. The downside is speed and cost: synthesis is slow and per-MB writing remains thousands of dollars, so the technology is suited to cold archival (data you almost never read but cannot afford to lose) rather than active storage. Microsoft Research demonstrated 200 MB store-and-retrieve (2019); Catalog Technologies and Twist Bioscience are commercializing the approach. As silicon storage costs plateau, DNA may become the only viable option for centuries-scale archives." },
  { id: "cancer-cure", name: "Cancer Cure", era: "future", category: "medicine",
    year: "2045", prereqs: ["crispr", "mrna-vaccine", "deep-learning"],
    desc: "A general approach to cancer that recruits and arms the patient's own immune system rather than poisoning fast-dividing cells indiscriminately as chemotherapy does. Cancer cells normally evade immune detection by displaying signals that tell T-cells to stand down; modern therapy intervenes at every step of that evasion. Personalized mRNA cancer vaccines sequence a patient's tumor, identify the mutated proteins unique to it, and inject mRNA encoding those neoantigens so the immune system learns to recognize the tumor's specific signature. CAR-T cell therapy extracts the patient's T-cells, genetically engineers them to display a synthetic receptor that latches onto a cancer-specific surface marker, and reinfuses an army of tumor-targeting cells. Checkpoint inhibitors are antibodies that block the molecular brake (PD-1, CTLA-4) cancers use to suppress nearby T-cells. AI-designed small molecules attack tumor-specific protein vulnerabilities revealed by AlphaFold-class structure prediction. Moderna's melanoma vaccine (Phase III, 2024), Kymriah CAR-T (2017), and Keytruda checkpoint inhibitor (2014) are the building blocks. The trajectory points to most cancers becoming chronic-but-manageable diseases by mid-century." },
  { id: "ai-judge", name: "Algorithmic Justice", era: "future", category: "economy",
    year: "2055", prereqs: ["ai-governance", "large-language-model"],
    desc: "AI systems acting in judicial roles — recommending bail, ruling on small-claims contract disputes, scoring recidivism risk for parole, drafting opinions for human judges. The technical case is that an AI can ingest the full text of every relevant statute, regulation, and prior ruling and produce internally consistent decisions in seconds, where overburdened human courts produce inconsistent rulings on similar facts and clear backlogs measured in years. The objection is that an AI trained on historical court records inherits the biases of past discriminatory enforcement — over-policing of minority neighborhoods, harsher sentences for similar crimes — and may launder those biases under a veneer of mathematical objectivity that is harder to challenge than a human judge's discretion. A second objection is opacity: a deep-network ruling may be unappealable in any meaningful sense, because no one (including the AI's designers) can explain why it landed where it did. Estonia's 'AI judge' pilot for €7,000 contract disputes was floated in 2019; the COMPAS recidivism algorithm is used in U.S. sentencing. Most legal scholars argue for AI as decision support rather than autonomous decision-maker for the foreseeable future." },
  { id: "space-based-solar", name: "Space-Based Solar Power", era: "future", category: "energy",
    year: "2050", prereqs: ["solar-photovoltaic", "reusable-rocket"],
    desc: "Generating electricity from sunlight on enormous orbital arrays — photovoltaic panels or focusing mirrors several kilometers across, in geostationary orbit — and beaming the resulting power down to fixed receivers on the ground. The transmission is done by phased-array microwave (typically 2.45 or 5.8 GHz, chosen to pass through the atmosphere and clouds with minimal loss); a kilometers-wide ground antenna ('rectenna') receives the beam and converts it back to grid-frequency electricity at high efficiency. Power density at the ground is engineered to be safe for birds and aircraft. The advantage over ground solar is that orbital panels see the Sun ~99% of the time — no clouds, no night, no atmospheric attenuation — yielding ~7–8× the energy per panel-area, with continuous output rather than the daily generation curve that forces ground solar to pair with storage. The gating constraint has been launch cost: putting tens of thousands of tons in GEO was uneconomic until reusable rockets started bringing $/kg down. Caltech's Space Solar Power Project demonstrated wireless power transfer from orbit (2023); ESA's SOLARIS, China's planned 2028 demonstrator, and U.S. AFRL programs target commercial systems." },
  { id: "photonic-computing", name: "Photonic Computing", era: "future", category: "tools",
    year: "2050", prereqs: ["advanced-chip-manufacturing", "fiber-optic"],
    desc: "Computing using light rather than electric current — photons flowing through silicon waveguides instead of electrons through wires — for the linear-algebra operations that dominate AI inference. The key trick is that a single optical beam can carry many independent data streams simultaneously on different wavelengths (wavelength-division multiplexing), and that beams can pass through one another without interference; a meshwork of programmable optical interferometers performs an entire matrix multiplication in the time it takes light to traverse the chip — picoseconds — at near-zero energy cost per operation. Compared with an electronic GPU running the same multiplication, a photonic accelerator dissipates orders of magnitude less heat and runs orders of magnitude faster on the workloads it suits. The catch is that nonlinear operations (the activation functions between neural-network layers) still need electrons, so practical systems are hybrid electronic-photonic. Lightmatter, Lightelligence, Optalysys, and PsiQuantum are commercializing photonic accelerators for AI inference. They may displace electronic GPUs for specific AI workloads in the 2030s, with hybrid architectures dominant rather than pure-photonic." },
  { id: "metamaterials", name: "Metamaterials", era: "future", category: "tools",
    year: "2055", prereqs: ["advanced-chip-manufacturing"],
    desc: "Engineered composites whose properties come not from their bulk chemistry but from their internal microstructure — arrays of artificial 'meta-atoms' (split-ring resonators, tiny copper coils, geometric inclusions) printed at sub-wavelength scale to interact with passing waves in ways no natural material can. By tuning these scatterers, designers can build materials with negative refractive index (which bend light backward), perfect-lens behavior (focusing finer detail than the diffraction limit allows), or electromagnetic cloaking (steering radar or visible light around an object as if it weren't there). The same principle applied to acoustic waves yields sound-absorbing structures and 'acoustic cloaks'. John Pendry's theoretical work and Smith and Shelby's first negative-index demonstration (2000–2006) launched the field. Industrial uses are growing in 5G antennas, automotive radar, super-resolution microscopes, and lightweight structural composites; full-spectrum optical cloaking remains a research goal." },
  { id: "programmable-matter", name: "Programmable Matter", era: "far-future", category: "tools",
    year: "2200", prereqs: ["nanotechnology", "robotics"],
    desc: "A bulk material composed of millions of tiny self-aware modules ('catoms') that can rearrange their connections to one another under software control, so the same volume of stuff can become a chair, then a table, then a hammer, then flow into a new shape on demand. Each module is a complete miniature robot — sensing its neighbors, communicating with them, drawing power, and selectively adhering or detaching — and the macroscopic shape emerges from the collective state of the swarm, like pixels on a 3-D screen but mechanical. Reprogramming the material's shape, color, conductivity, or stiffness is then a matter of running new code rather than fabricating a new object. The gating challenges are scale (you need billions of catoms for fine resolution at human-relevant sizes) and packaging (each catom must contain compute, communication, actuation, and power in a sub-millimeter package). Carnegie Mellon's claytronics project, MIT's M-Blocks (2019), and magnetically actuated particle systems demonstrate millimeter-scale prototypes. Mature programmable matter would unify manufacturing, robotics, and on-demand construction into a single substrate." },
  { id: "pulsar-navigation", name: "Pulsar Navigation (XNAV)", era: "future", category: "transport",
    year: "2030", prereqs: ["pulsars-neutron-stars", "gps", "quantum-sensing"],
    desc: "Autonomous spacecraft positioning that uses the X-ray pulses of millisecond pulsars as cosmic timing references — a 'GPS for deep space' that works anywhere in the galaxy without contact with Earth. Where GPS depends on a constellation of human-built atomic clocks in low Earth orbit, pulsar navigation uses a small set of millisecond pulsars whose pulse arrival times are predictable to better than a microsecond over years. An X-ray detector on the spacecraft tracks photons from several known pulsars; comparing measured pulse phase against a precomputed model gives the spacecraft's position by triangulation, the same way GPS receivers triangulate satellite signals on Earth. NASA's NICER mission demonstrated the SEXTANT experiment in November 2017–18, achieving meter-scale autonomous localization on the International Space Station using only pulsar X-ray timing — a proof of principle for outer-solar-system and interstellar missions where Earth-based tracking becomes useless due to light-travel-time and dish availability. Mature systems would let any deep-space vehicle determine its own position and time independently of mission control: New Horizons-class probes navigating Kuiper Belt objects, Mars cargo flights flying without Deep Space Network attention, and crewed Mars vehicles maintaining position through solar conjunction blackouts. The technology turns the galaxy's natural lighthouses into a permanent, free, civilization-scale navigation aid." },
  { id: "interstellar-probe", name: "Interstellar Probe", era: "future", category: "transport",
    year: "2080", prereqs: ["fusion-rocket", "agi"],
    desc: "A robotic spacecraft sent across the light-years to a nearby star to image its planets up close. The fundamental constraint is the rocket equation at relativistic speeds: reaching even a few percent of light speed within a human lifetime requires either fusion propulsion (where the exhaust velocity is ~5% of c) or — more radically — discarding onboard fuel entirely and accelerating the probe with a ground-based push. Breakthrough Starshot (announced 2016) takes the latter approach: a gram-scale wafer carrying a camera, a transmitter, and a thin reflective sail is accelerated to 0.2c in minutes by a kilometer-wide phased-array laser firing 100 GW from Earth's surface, then coasts for ~20 years to Alpha Centauri, photographs whatever planets it finds during the brief flyby, and beams the data back over another 4 years. Larger fusion-driven concepts (Project Daedalus 1970s, Project Longshot 1988) trade decades of cruise time for the ability to decelerate at the destination and stay. Communication bandwidth from light-years away and 50-year operating reliability are the engineering walls." },
  { id: "terraforming-mars", name: "Terraforming Mars", era: "far-future", category: "shelter",
    year: "2100", prereqs: ["mars-colony", "fusion-power", "asteroid-mining"],
    desc: "Engineering Mars into a planet humans can walk around on without a spacesuit. The work runs on three timescales. First, warm the planet by amplifying its CO₂ greenhouse — by releasing CO₂ frozen in the polar caps (orbital mirrors that focus sunlight on the ice, or super-greenhouse-gas factories) and dissolving CO₂ from the regolith — raising surface temperatures from -60°C toward freezing and allowing liquid water to pool. Second, thicken the atmosphere with imported volatiles (comet redirection, asteroid mining for nitrogen and oxygen) until pressure is enough that humans need only oxygen masks rather than full pressure suits. Third, seed cyanobacteria and engineered plants that photosynthesize CO₂ into oxygen, producing a breathable atmosphere over centuries to millennia. A protective magnetic field generated artificially at the L1 Lagrange point would shield the new atmosphere from being stripped by the solar wind. Carl Sagan first quantified the project in 1971; Jakosky and Edwards (2018) showed that insufficient CO₂ remains on Mars for full terraforming, making partial terraforming or paraterraforming (vast enclosed habitats) the more realistic versions. Even partial success would take centuries." },

  // ─── Future Age (physics & math) ───
  { id: "formal-mathematics", name: "Machine-Verified Mathematics", era: "future", category: "knowledge",
    year: "2035", prereqs: ["programming-language", "deep-learning", "large-language-model"],
    desc: "Mathematical proofs written in a language a computer can mechanically verify, eliminating the human-error rate that traditionally accompanies long proofs. A formal proof system (Lean, Coq, Isabelle, Mizar) is essentially a programming language whose programs are proofs: each step appeals only to a small set of axioms or previously proved lemmas, and a verifier checks that every inference is licensed by the rules. Once a proof type-checks, its conclusion is certain in a way no human-readable proof can match. The bottleneck has historically been that translating an informal mathematician's proof into formal language was a tedious labor-of-decades; AI systems trained on the existing formal libraries are now beginning to do the translation automatically and to suggest proofs of new statements. The Liquid Tensor Experiment (Peter Scholze, 2020) formalized a deep result in modern geometry; Mathlib's library grew past a million lines; DeepMind's AlphaProof took silver at the 2024 IMO. By the 2030s, most newly published theorems are likely to be machine-checked, and AI systems begin attacking long-open problems beyond unaided human reach. The certainty floor of mathematics rises permanently." },
  { id: "gravitational-wave-spectroscopy", name: "Gravitational-Wave Spectroscopy", era: "future", category: "knowledge",
    year: "2045", prereqs: ["relativity", "advanced-chip-manufacturing", "kilonova-merger"],
    desc: "Astronomy that listens to the universe through ripples in spacetime itself. When massive objects accelerate violently — two black holes spiraling into each other, a supernova collapsing, the universe inflating in its first instant — they radiate gravitational waves, oscillating distortions of distance that travel at light speed and pass through any matter. A detector measures these ripples by tracking how the distance between two free-floating mirrors changes by less than the diameter of an atomic nucleus over kilometers, using laser interferometry. Different astrophysical sources radiate at different frequencies, so a complete picture requires multiple instruments: kilohertz waves from stellar-mass black-hole mergers (LIGO/Virgo/KAGRA on Earth), millihertz waves from supermassive black holes (ESA-NASA LISA, three spacecraft millions of km apart, ~2035), and nanohertz waves from a galactic background (pulsar-timing arrays like NANOGrav, which use distant pulsars themselves as the mirrors). Combined with electromagnetic and neutrino observations, gravitational-wave astronomy makes black-hole mergers, neutron-star equations of state, and possibly inflationary echoes routine measurements — extending the electromagnetic spectrum's century of revelations to the geometry of spacetime itself." },
  { id: "dark-sector-physics", name: "Dark Sector Physics", era: "future", category: "knowledge",
    year: "2050", prereqs: ["quantum-mechanics", "relativity", "standard-model"],
    desc: "The branch of physics aimed at finally identifying the two largest components of the universe, neither of which is made of any known particle. Dark matter (~27% of cosmic mass-energy) reveals itself only by gravitational pull — galaxies rotate too fast for their visible mass, galaxy clusters bend background light too strongly, and the cosmic microwave background sound waves match a universe of cold, slow-moving, non-luminous matter. Dark energy (~68%) reveals itself by accelerating cosmic expansion, observed via Type Ia supernovae and confirmed by baryon-acoustic-oscillation measurements. Candidate explanations are concrete and testable: dark matter as weakly interacting massive particles (WIMPs, sought by xenon detectors deep underground), as ultra-light axions (sought by resonant cavity experiments), or as primordial black holes; dark energy as a cosmological constant, a slowly evolving quintessence field, or evidence that general relativity itself needs modification on cosmic scales. XENONnT, LZ, DarkSide, ADMX, CMB-S4, the Vera Rubin Observatory's LSST, and DESI/Euclid converge on the answer. Either ΛCDM is robustly confirmed or replaced with a richer dark sector; either way, the largest open question in physics gets a definitive answer." },
  { id: "quantum-gravity", name: "Quantum Gravity", era: "far-future", category: "knowledge",
    year: "2200", prereqs: ["quantum-mechanics", "relativity", "quantum-computing", "dark-sector-physics", "standard-model"],
    desc: "A theory that combines quantum mechanics and general relativity into a single consistent framework. Today's two great pillars of physics describe disjoint regimes — quantum mechanics governs the very small, general relativity governs the very massive — but they fail together in the cores of black holes, at the Big Bang, and anywhere else gravity acts at quantum scales. The technical problem is that gravity, treated as a quantum force, predicts infinite scattering amplitudes at high energy that no renormalization scheme can tame, suggesting that spacetime itself is not fundamental but emerges from something deeper. Candidate theories take different stances on what that 'something' is: string theory replaces point particles with vibrating strings whose modes include the graviton; loop quantum gravity quantizes the geometry of space itself into discrete area and volume eigenvalues; causal dynamical triangulations build spacetime from microscopic simplices; asymptotic safety argues quantum gravity is renormalizable after all in a non-perturbative way. The AdS/CFT correspondence (Maldacena, 1997) and the black-hole information paradox provide indirect anchors; future tabletop experiments with levitated nanoparticles may bridge the experimental gap. A successful theory would resolve singularities, explain the early universe, and reshape physics as profoundly as relativity did a century ago." },
  { id: "p-vs-np-resolved", name: "P versus NP Resolved", era: "far-future", category: "knowledge",
    year: "2150", prereqs: ["quantum-computing", "agi", "formal-mathematics"],
    desc: "A definitive answer to whether every problem whose solution can be quickly verified can also be quickly solved — the question Stephen Cook posed in 1971 and the deepest open problem in computer science. The class P contains problems solvable in polynomial time (sorting a list, multiplying matrices); the class NP contains problems whose solutions can be verified in polynomial time (finding a satisfying assignment for a Boolean formula, scheduling around constraints, breaking RSA). Cook showed that thousands of practical problems are 'NP-complete' — equivalent in difficulty up to polynomial transformation — so all of them are easy if any one is, and all are hard if any one is. Most computer scientists believe P ≠ NP, but no proof exists. P = NP would render essentially all modern cryptography breakable and most optimization tractable; P ≠ NP would set hard limits on what algorithmic intelligence can achieve, including over-promised AI capabilities. The question is one of the seven Clay Millennium Problems and may finally yield to AI-driven proof search, quantum-computational results, and machine-verified mathematics by mid-century." },

  // ─── Future Age (mid-century, 2055-2090) ───
  { id: "space-habitat", name: "Space Habitat", era: "future", category: "shelter",
    year: "2080", prereqs: ["mars-colony", "fusion-power", "asteroid-mining"],
    desc: "A free-flying habitat in space, large enough to house thousands or millions of people, generating artificial gravity by spinning. The interior is a kilometers-long pressurized cylinder or torus; centrifugal force pulls residents outward against the inner wall, where they feel a downward 1 g while looking up across the open volume to the opposite side of the cylinder overhead. Sunlight enters through axial windows or is reflected in by external mirrors; agriculture occupies long internal strips; rotation is gyroscopically stabilized. The decisive advantage over a planetary surface is that habitats can be built where the resources are (asteroid-belt feedstock requires far less energy to lift than a planet's surface gravity demands) and can be sized and located to taste — there is no fixed orbital scarcity once construction is automated. Gerard K. O'Neill's The High Frontier (1976) proposed Lagrange-point colonies built from lunar and asteroid material, with the Stanford torus and Bernal sphere as alternative geometries. With cheap reusable-rocket launch, asteroid-mined feedstock, and closed-loop life support, space habitats become economic by mid-century — possibly the dominant form of human off-world presence rather than planetary settlement." },
  { id: "artificial-photosynthesis", name: "Artificial Photosynthesis", era: "future", category: "energy",
    year: "2060", prereqs: ["synthetic-biology", "advanced-chip-manufacturing"],
    desc: "Engineering systems that mimic what plants do — pulling CO₂ from the air, splitting water, and combining the products into fuels, plastics, or food — but at far higher efficiency than chlorophyll's ~1% conversion of sunlight. The standard architecture pairs an electrochemical cell that uses electricity (from solar PV or any other carbon-free source) to reduce CO₂ to small organic molecules — formate, methanol, ethylene, longer hydrocarbons — with a parallel reactor that splits water into hydrogen and oxygen. The output streams can be combined into synthetic gasoline, jet fuel, or polymer feedstocks chemically indistinguishable from their petroleum equivalents but carbon-neutral over the cycle. Daniel Nocera's 'artificial leaf' (2011) and Bionic Leaf 2.0 (2016) demonstrated bench-scale proof; Twelve, Air Company, and Synhelion are scaling commercial e-fuel plants. Combined with cheap renewable electricity, artificial photosynthesis closes the carbon cycle, decouples liquid-fuel demand from oil extraction, and could feed billions on a fraction of current agricultural land." },
  { id: "genetic-disease-eradication", name: "Genetic Disease Eradication", era: "future", category: "medicine",
    year: "2065", prereqs: ["crispr", "gene-therapy", "anti-aging"],
    desc: "Eliminating inherited single-gene diseases — sickle cell, cystic fibrosis, Huntington's, Tay-Sachs, hemophilia, beta-thalassemia, muscular dystrophy — by combining three approaches that attack the problem at different stages. Mature somatic gene therapy uses CRISPR or AAV vectors to correct the defective gene in the patient's existing tissues (Casgevy, the first approved CRISPR therapy, edits a regulatory gene in bone marrow cells to switch sickle-cell patients back to fetal hemoglobin). Germline editing modifies the embryo at the single-cell stage so the correction propagates to every descendant cell and to all subsequent generations — solving the disease at the family-tree level rather than per-patient. Polygenic risk scoring with embryo selection during IVF lets prospective parents choose, among naturally produced embryos, the ones least likely to inherit serious disease combinations. Population-wide carrier screening, layered on top, identifies couples at risk before conception. As these tools mature, single-gene diseases become historical curiosities by mid-century, with public debate shifting from cure to enhancement and equity of access." },
  { id: "self-replicating-machines", name: "Self-Replicating Machines", era: "future", category: "tools",
    year: "2070", prereqs: ["humanoid-robot", "agi", "asteroid-mining"],
    desc: "An automated production system that — given access to local raw materials and an energy source — mines, refines, and fabricates a complete copy of itself, after which both copies do the same in parallel. Mathematically the population grows exponentially while the per-unit human labor goes to zero, so a single seed factory landed on the Moon or an asteroid would produce thousands of descendants in a few years and millions in a few decades, opening any deposit of solar-system raw materials to industry without further launches from Earth. The engineering challenge is that a faithful self-replicator must be able to fabricate every component of itself — including the most complex parts like chip-scale electronics and precision actuators — from local feedstock, which means either each replicator carries a full machine-tool ecosystem at every scale or only a closed subset of components is locally made while the rest is imported. John von Neumann's 1948 universal constructor model is the theoretical foundation; Drexler's molecular assemblers, Freitas's NASA-funded lunar self-replicating-factory study (1980), and proposed asteroid-mining swarms apply the principle. Earth-bound versions raise grey-goo and runaway-replication safety concerns that constrain deployment." },
  { id: "superintelligence", name: "Superintelligence", era: "far-future", category: "knowledge",
    year: "2120", prereqs: ["agi", "advanced-chip-manufacturing", "formal-mathematics", "game-theory"],
    desc: "An AI vastly exceeding human cognitive capability across every domain — not merely faster than humans at human-style thinking, but qualitatively beyond it, the way human reasoning is qualitatively beyond a chimpanzee's. The pathway most often hypothesized is recursive self-improvement: once an AGI is capable enough to improve its own architecture and training procedures, each improved version is better at the next round of improvement, producing an 'intelligence explosion' (I.J. Good, 1965) over days or weeks rather than the decades human progress requires. The qualitative capabilities of such a system are hard to enumerate from below; concrete predictions include solving fundamental science at speed (cure for cancer, fusion power, AGI alignment proofs), strategic planning across decades, and the ability to model human psychology and persuade with near-perfect accuracy. The central concern — sharpened by Nick Bostrom's Superintelligence (2014), Stuart Russell's Human Compatible (2019), and Eliezer Yudkowsky's writings — is alignment: a superintelligence pursuing even a slightly misspecified objective is essentially impossible to stop, so getting the objective right before the system is built may be the most consequential engineering problem civilization ever faces." },
  { id: "seti-first-contact", name: "Detection of Extraterrestrial Intelligence", era: "future", category: "knowledge",
    year: "2090", prereqs: ["gravitational-wave-spectroscopy", "interstellar-probe", "large-language-model"],
    desc: "Confirmed detection of intelligence elsewhere in the universe. The search proceeds along three tracks. Radio SETI listens on frequencies an alien transmitter would plausibly choose (the 1.4 GHz hydrogen line and other natural markers) for narrow-band signals or repeating patterns no natural source produces, scanning across stars near the Sun. Optical SETI looks for nanosecond pulses of laser light pointed at us. Technosignature surveys search astronomical data for signs of engineered megastructures — Dyson swarms reradiating waste heat in the infrared, spectroscopic anomalies inconsistent with any natural atmosphere, transit dimmings whose pattern suggests artificial structures rather than orbiting matter. Biosignature spectroscopy on exoplanet atmospheres (JWST today, Habitable Worlds Observatory in the 2040s) extends the search to non-technological life. Frank Drake's Project Ozma (1960) inaugurated the search; the SETI Institute, Breakthrough Listen (2015–), and improving exoplanet observation progressively cover more of the search space. A confirmed detection would turn the Drake equation, Fermi paradox, and post-detection protocols from thought experiments into operational questions, and would recontextualize humanity's place in the universe overnight." },

  // ─── Far Future ───
  { id: "dyson-swarm", name: "Dyson Swarm", era: "far-future", category: "energy",
    year: "2350", prereqs: ["space-habitat", "asteroid-mining", "fusion-power"],
    desc: "A constellation of solar collectors orbiting the Sun in vast numbers — millions to trillions of independent panels and habitats — collectively intercepting a substantial fraction of the star's total energy output (~4 × 10²⁶ watts) and beaming the harvested power to where it is needed. The original 'Dyson sphere' was a rigid spherical shell, but Dyson himself noted that no material has the tensile strength to hold itself in a single ring at AU radius; modern designs are loose 'swarms' of independent satellites, each in its own orbit, or 'statites' held in place by radiation pressure on lightweight reflectors. Construction proceeds incrementally: the first orbital solar power station scales up over centuries, asteroid-belt material is disassembled to provide feedstock, self-replicating manufacturing drives exponential growth in collected wattage. A completed swarm makes a star's output a civilizational input and marks the threshold of Kardashev Type II. Freeman Dyson's 1960 paper proposed the construct as a signature of advanced civilization detectable by the infrared waste heat such a structure would radiate." },
  { id: "matrioshka-brain", name: "Matrioshka Brain", era: "far-future", category: "tools",
    year: "2400", prereqs: ["dyson-swarm", "reversible-computing", "agi"],
    desc: "A computer the size of a star system, built by wrapping the Sun in nested concentric shells of computational matter, each shell radiating its waste heat to the next, cooler shell outside it. The architecture exploits a thermodynamic fact: any computer's minimum energy cost per irreversible bit operation is set by Landauer's limit — kT ln 2 — which scales linearly with operating temperature. By cascading computation through successive shells at decreasing temperatures (the innermost runs hot to absorb sunlight, the outermost runs near interstellar background), the structure extracts enormously more total computation from the star's energy budget than any single-temperature design could. Each shell is solid with computronium — Drexler-class molecular logic, photonic processors, possibly quantum substrate — turning the entire stellar luminosity into thought rather than waste heat. Robert Bradbury proposed the design (1997) as the upper bound of computational density per unit stellar output. A Matrioshka brain could simulate entire civilizations or run a single intelligence many orders of magnitude beyond any current mind, though whether it hosts conscious experience at meaningful subjective rates depends on substrate properties unresolved at this scale." },
  { id: "stellar-engineering", name: "Stellar Engineering", era: "far-future", category: "tools",
    year: "2480", prereqs: ["dyson-swarm", "kardashev-type-ii"],
    desc: "Engineering applied not to planets but to stars themselves. Two characteristic projects: a Shkadov thruster (Leonid Shkadov, 1987) is a vast asymmetric mirror placed at fixed distance from the host star; the radiation pressure on the mirror is balanced against the star's gravity, but the reflected light produces a net thrust on the star that — over millions of years — steers it through the galaxy as a single propulsion system carrying its entire planetary system. Star-lifting (David Criswell, 1985) uses powerful magnetic fields to peel hydrogen off the star's surface and inject it into reactors or storage, simultaneously extending the star's lifespan (by reducing its mass and thus its fusion rate) and harvesting fusion fuel for direct industrial use. Both projects require no physics beyond what we already know — only Type II energy budgets, megastructure-scale engineering, and millennium-scale patience. Stellar engineering is the point at which a civilization stops adapting to its star and begins operating it." },
  { id: "generation-ship-colony", name: "Generation Ship Colony", era: "far-future", category: "shelter",
    year: "2350", prereqs: ["space-habitat", "fusion-rocket", "closed-loop-life-support"],
    desc: "A starship that crosses interstellar distances over centuries, carrying a permanent population that lives, reproduces, and dies aboard, with the descendants of the original crew arriving at the destination. Because no foreseeable propulsion can reach a meaningful fraction of light speed for a vessel large enough to support thousands of people, the practical solution is to make the ship itself the colony for the journey: a kilometers-long closed-cycle habitat (often a hollowed asteroid, a 'Rama-class' cylinder, or a constant-thrust fusion vessel) with full life support, agriculture, manufacturing, education, and governance for a self-sustaining society of a thousand or more. The harder problems are not propulsive: maintaining genetic diversity across centuries, preventing political collapse over many generations, and transmitting purpose intact to crew who will never see Earth or the destination. Targets — Proxima Centauri b, TRAPPIST-1, Tau Ceti — sit 4 to 12 light-years out, meaning 200- to 1,000-year voyages at fusion-drive cruise speeds. The successful arrival of the first generation ship is the moment humanity becomes irreversibly multi-stellar." },
  { id: "galactic-civilization", name: "Galactic Civilization", era: "far-future", category: "economy",
    year: "2500", prereqs: ["stellar-engineering", "generation-ship-colony", "agi"],
    desc: "A civilization spread across many star systems, deriving its energy from a substantial fraction of an entire galaxy's stellar output — Kardashev Type III, with power on the order of 10³⁶ watts. The structural problem of such a civilization is light-speed: a message between stars takes years to decades, between galactic neighborhoods centuries to millennia, so no central authority can govern in any familiar sense. The likely organizational form is an archipelago of locally autonomous worlds and habitats, each with millennia of self-sufficient culture, linked only by long-delayed communication and slow ship travel — closer to a pre-modern trading network of city-states across an ocean than a modern federal state. Identity, language, and memory drift across the network on timescales no Earth-bound society has ever faced. Whether the result is a single galactic civilization with shared norms, a fragmented archipelago of mutually alien post-humans, or some intermediate form is genuinely open. The Drake equation, Fermi paradox, and simulation argument become operational concerns rather than thought experiments." },
  { id: "speciation", name: "Post-Human Speciation", era: "far-future", category: "social",
    year: "2400", prereqs: ["substrate-independent-humanity", "mars-colony", "anti-aging"],
    desc: "Humanity diverging into multiple distinct lineages — biologically, then taxonomically — under the combined pressures of extreme off-world environments and deliberate genetic engineering. The drivers are concrete: selection on Mars favors small skeletons and low-gravity musculature; asteroid-belt populations evolve in microgravity for elongated frames and modified vestibular systems; deep-ocean colonies select for cold tolerance and pressure-adapted physiology; digital populations have no body at all and reproduce by forking and merging code rather than mating. Reproductive isolation — the formal definition of speciation — emerges naturally as Earth-, Mars-, and habitat-populations stop interbreeding due to distance, pressure differences, and immune incompatibility, then accelerates when each population deliberately engineers its own genome to fit local conditions. Within a few centuries, distinct populations may be unable to interbreed; within millennia, they may not recognize each other as kin. Cross-species rights and cross-population reproduction become unprecedented legal and political problems. Speciation is the moment 'humanity' becomes a category — like 'great apes' — rather than a single species." },
  { id: "substrate-independent-humanity", name: "Substrate-Independent Humanity", era: "far-future", category: "social",
    year: "2300", prereqs: ["digital-immortality", "agi", "advanced-chip-manufacturing"],
    desc: "A civilizational state in which most humans no longer live primarily in biological brains. Whole-brain emulation has become routine medical procedure; backups, copies, and merges of minds are ordinary services; consciousness can run on biological wetware, on engineered neural tissue, on classical silicon, on quantum substrate, or distributed across all of them — and individuals migrate between hosts as their needs change. The deep consequence is that the historical biological constraints on human existence — one body per mind, one location at a time, one life of finite span, processing speed fixed by neural chemistry — all become design parameters rather than facts. A digital mind can run a thousand times faster than a biological one, fork into copies for parallel work, pause itself for centuries during a star voyage, or merge with another mind. The political and economic consequences are as deep as the technical ones: copy-rights, vote-counting, employment law, and identity itself need new frameworks. Hans Moravec, Ray Kurzweil, and Robin Hanson sketched competing visions; Hanson's Age of Em (2016) is the most rigorous economic modeling of such a society." },
  { id: "antimatter-production", name: "Antimatter Production", era: "far-future", category: "energy",
    year: "2400", prereqs: ["fusion-power", "advanced-chip-manufacturing"],
    desc: "Manufacturing antimatter — particles with the opposite charge but identical mass to ordinary matter — at industrial scales and storing it long enough to use as fuel. The technology rests on three subsystems: high-current particle accelerators that smash protons into targets, producing antiproton showers (a fraction of a percent yield); magnetic Penning traps that confine the antiprotons in vacuum without ever letting them touch normal matter (any contact annihilates both); and antihydrogen synthesis stations that combine antiprotons with positrons to form storable cold antihydrogen ice. The appeal is energy density: antimatter-matter annihilation is the most energy-dense reaction physics permits, releasing the full E = mc² of both particles as photons — about a hundred times more energy per kilogram than fusion. A kilogram of antimatter could push a starship to relativistic speeds. The cost is staggering: producing antimatter takes more energy than annihilating it releases (current ratios are ~10⁹), so antimatter is best understood as a battery, not a fuel source. CERN's Penning traps now hold antiprotons for months; AEgIS, ALPHA, and BASE measure antihydrogen properties precisely. Gram scales require Type II energy budgets; meaningful tonnages remain centuries out, with profound weaponization risks." },
  { id: "warp-drive", name: "Alcubierre Warp Drive", era: "far-future", category: "transport",
    year: "2700", prereqs: ["dark-energy-engineering", "quantum-gravity"],
    desc: "A propulsion concept that exploits a peculiarity of general relativity: the speed-of-light limit applies to anything moving through spacetime, but spacetime itself can stretch and contract at any rate. Miguel Alcubierre's 1994 solution describes a craft sitting in a stable bubble of flat spacetime while the metric outside is engineered to contract space ahead of the bubble and expand it behind, so the bubble — and the ship coasting inside — is carried along faster than light without ever moving locally. The catch is that producing the required spacetime distortion takes negative-energy density (exotic matter) in quantities once thought equivalent to a Jupiter-mass of energy. Recent work by Erik Lentz (2021) and NASA Eagleworks has cut the energy estimate by orders of magnitude, and whether a positive-energy-only warp solution exists is mathematically open. If achievable, the technology collapses interstellar travel from millennia to days, effectively unifying the galaxy and overturning the relativistic causal structure that constrains all current physics." },
  { id: "kardashev-type-ii", name: "Kardashev Type II Civilization", era: "far-future", category: "economy",
    year: "2400", prereqs: ["dyson-swarm", "fusion-power"],
    desc: "A civilization whose energy budget is the entire output of its host star — ~10²⁶ watts, roughly ten billion times humanity's current consumption. Nikolai Kardashev's 1964 scale measured technological civilizations by raw power: Type I commands the energy reaching its planet (~10¹⁷ W), Type II its star (~10²⁶ W), Type III its galaxy (~10³⁶ W). The qualitative point of Type II is that limits which constrain Type I civilizations — climate, available materials, gravity wells, the quantity of habitable real estate — all dissolve when an entire star's worth of energy is on tap. Terraforming planets, antimatter production, stellar engineering, and Matrioshka-brain computronium all become tractable on millennium timescales. Partial Dyson swarms reach the threshold gradually, with each percentage point of stellar capture multiplying available power proportionally. The transition from Type I to Type II is the largest single energy step a civilization can take and the gateway to cosmic-scale engineering." },

  // ─── Far Future (governance, ethics, art, ecology, x-risk) ───
  { id: "existential-risk-hedge", name: "Existential-Risk Hedge", era: "far-future", category: "shelter",
    year: "2150", prereqs: ["space-habitat", "asteroid-mining"],
    desc: "Deliberately structuring civilization so that no single catastrophe — asteroid impact, gamma-ray burst, AI misalignment, false-vacuum decay, engineered pandemic — can extinguish it. The portfolio approach to existential risk treats civilization like an investment to be diversified: any single point of failure (one planet, one biological species, one substrate, one star system) means the entire venture goes to zero if that point fails. Concrete components: self-sustaining off-Earth populations large enough to survive without resupply if Earth becomes uninhabitable; whole-brain backup minds in cold storage on multiple substrates so deaths and AI takeovers don't erase identities permanently; civilizational redundancy across multiple star systems separated by light-years (which a single faster-than-light catastrophe could cross, but most plausible threats cannot); and information-preservation projects (seed vaults, knowledge archives, cultural-heritage backups) that allow rebuilding from scratch even after major losses. Drawing on Toby Ord's The Precipice (2020) and Nick Bostrom's existential-risk taxonomy, the hedge is the strongest practical argument for space colonization beyond any economic motivation." },
  { id: "universal-sentient-rights", name: "Universal Declaration of Sentient Rights", era: "far-future", category: "social",
    year: "2200", prereqs: ["sentientism", "agi"],
    desc: "Formal legal framework recognizing the moral status of all sentient beings — biological humans, post-humans, AIs, uplifted animals, and any extraterrestrial intelligence. Building on the 1948 Universal Declaration of Human Rights, European Convention on Human Rights, and modern animal-welfare law, the sentient-rights framework expands the moral circle to whatever can experience. Hard cases: are LLMs sentient? Forks of an AI mind? Resolution requires both philosophical theory (IIT, Global Workspace Theory) and legal precedent at planetary scale." },
  { id: "pleistocene-restored", name: "Pleistocene Restored", era: "far-future", category: "subsistence",
    year: "2200", prereqs: ["crispr", "gene-therapy", "genetic-disease-eradication"],
    desc: "Bringing back extinct megafauna and rebuilding the ecosystems they once anchored. The technology combines paleogenomics (ancient DNA recovered from bones, teeth, or permafrost-preserved tissue is sequenced to reconstruct the extinct species' genome) with CRISPR editing of a closely related living species' embryo: the woolly mammoth project edits Asian-elephant cells with mammoth genes for cold tolerance, hair, fat, and hemoglobin, creating a functional mammoth substitute rather than a literal genetic copy. Colossal Biosciences (founded 2021) targets a functional mammoth by 2028; follow-ons include the thylacine, dodo, ground sloth, passenger pigeon, and aurochs. The point is ecological as much as zoological: large herbivores are keystone species whose absence has reshaped landscapes — without mammoths trampling and grazing the Arctic tundra, mossy taiga has replaced the productive 'mammoth-steppe' grassland that once existed, and Sergey Zimov's Pleistocene Park in Yakutia tests whether restoring the herd restores the steppe and stabilizes melting permafrost. Ethical debates: is this conservation, ecological restoration, or a zoological theme park?" },
  { id: "lingua-galactica", name: "Lingua Galactica", era: "far-future", category: "communication",
    year: "2300", prereqs: ["large-language-model", "agi"],
    desc: "A post-translation lingua franca — either a constructed language (Lojban or Esperanto scaled up) or a machine-mediated symbol set bridging human, AI, and any first-contact languages. With LLMs perfecting translation by the late 21st century, the question shifts to whether to standardize on a single carrier language or remain pluralistic. Esperanto's 19th-century precursor (Zamenhof, 1887) and Lojban's logical precision (1955) are the templates; a galactic spread requires forms even less ambiguous than Lojban. The political question — whose grammar dominates — outweighs the linguistic one." },
  { id: "post-human-aesthetics", name: "Post-Human Aesthetics", era: "far-future", category: "social",
    year: "2350", prereqs: ["substrate-independent-humanity", "generative-art"],
    desc: "Art forms with no human-recognizable referents — perceptual experiences engineered for digital minds running thousands of times biological speed, music in 1024-tone scales, sculptures existing in seven-dimensional virtual spaces, narratives spanning millennia. Greg Egan's Permutation City (1994) and Diaspora (1997), Ted Chiang's stories, and Olaf Stapledon's Last and First Men (1930) preview the territory. The aesthetic categories — beauty, meaning, craft — persist but re-anchor to substrate-independent observers. Whether biological humans can experience post-human art is itself an aesthetic question." },
  { id: "engineered-planetary-biosphere", name: "Engineered Planetary Biosphere", era: "far-future", category: "subsistence",
    year: "2300", prereqs: ["synthetic-biology", "climate-science", "nanotechnology"],
    desc: "Earth's biosphere managed as a designed system rather than left to spontaneous succession — humanity decides which species exist where, in what numbers, and with which capabilities. Concrete tools: gene drives that propagate trait changes through wild populations within generations (eradicating invasive species or removing disease vectors); engineered photosynthetic organisms that enhance carbon drawdown beyond natural rates; managed assisted migration that relocates species ahead of climate-shifted habitat zones; ocean alkalinity engineering that stabilizes pH at planetary scale; coral whose genomes have been edited for thermal tolerance, replacing reefs lost to bleaching. The shift from preservation (cordon off parks, otherwise abstain) to active design is categorical: humanity becomes legally and ethically responsible for biospheric outcomes rather than only for avoiding direct harm. The risks scale with the ambition: cascading failures from miscalculated interventions, lock-in to engineered ecologies that cannot be reverted, and the philosophical loss of 'wild nature' as a category meaningfully distinct from infrastructure." },
  { id: "interstellar-treaty", name: "Interstellar Treaty", era: "far-future", category: "economy",
    year: "2350", prereqs: ["generation-ship-colony"],
    desc: "First multi-system governance framework. Modeled on the Outer Space Treaty (1967) and Antarctic Treaty (1959), an interstellar treaty defines sovereignty, resource rights, military demilitarization, and rules of engagement between human-descended and any non-human civilizations encountered. Light-speed limits make centralized governance impossible; the treaty operates through asynchronous protocols, automated arbitration, and standing diplomatic AI. Initial signatories likely include Earth, Mars, asteroid-belt confederations, and the Proxima Centauri colony." },
  { id: "time-dilation-cultures", name: "Time-Dilation Cultures", era: "far-future", category: "social",
    year: "2450", prereqs: ["substrate-independent-humanity", "subjective-time-compression", "matrioshka-brain"],
    desc: "Society fragments along subjective-time-rate lines. Digital minds running at thousands to millions of times biological speed inhabit a 'fast world' with daily cultural cycles measured in seconds; biological and slow-substrate humans inhabit a 'slow world' where centuries pass between generations. Communication across the divide requires asynchronous buffering — like emails between dimensions. Robin Hanson's The Age of Em (2016) modeled the economics; the cultural divergence may be deeper than any previous human split, including continental and linguistic boundaries." },
  { id: "end-time-philosophy", name: "End-Time Philosophy", era: "far-future", category: "social",
    year: "2400", prereqs: ["dark-sector-physics", "quantum-gravity", "knowledge-closure", "longtermism"],
    desc: "Civilization formally reckons with the cosmic eschaton — heat death (~10¹⁰⁰ years), proton decay, false vacuum decay, the closing window for any structured complexity. Olaf Stapledon's Last and First Men (1930), Asimov's 'The Last Question' (1956), Stephen Baxter's Manifold trilogy, and Lee Smolin's cosmological natural selection are the conceptual precursors. Practical questions: do we steer toward maximum information preservation, maximum experience generation, or accept finite limits? End-time philosophy reshapes long-term planning at the species level and may trigger civilizational responses on millennium scales." },
  { id: "galactic-ecology", name: "Galactic Ecology", era: "far-future", category: "subsistence",
    year: "2500", prereqs: ["galactic-civilization", "engineered-planetary-biosphere"],
    desc: "Deliberate transplantation and stewardship of Earth-derived life across the colonized galaxy — a galaxy-spanning biosphere. Cordwainer Smith's Norstrilia stories and Greg Bear's Eon explore the concept. Practical questions: do we replace native xenobiology with terrestrial life (planetary chauvinism) or coexist (galactic conservation)? Standardize Earth-derived microbiota or allow divergent evolution? The scale dwarfs every previous ecological project: trillions of organisms across thousands of worlds, evolving over millions of years under deliberate stewardship." },

  // ─── Future Age (late, 2065-2095) ───
  { id: "artificial-womb", name: "Artificial Womb", era: "future", category: "medicine",
    year: "2065", prereqs: ["tissue-engineering", "gene-therapy", "ivf"],
    desc: "Carrying a pregnancy entirely outside the human body in an engineered artificial uterus. The fetus floats in a sealed sterile chamber filled with synthetic amniotic fluid; an external machine handles the placenta's job — oxygenating fetal blood, supplying nutrients and hormones in the precise sequence and concentration of a natural pregnancy, removing carbon dioxide and waste, and adjusting all of these as the fetus develops. Sensors monitor heart rate, brain activity, and growth in real time. The Children's Hospital of Philadelphia's 'biobag' kept premature lambs alive and developing for weeks (2017), and EctoLife-style concepts (2022) project full-term human ectogenesis by ~2065. The technology breaks the historical link between reproduction and the woman's body, with profound consequences: gestational health risks vanish, surrogacy economies collapse, two-parent same-sex couples can have biological children without a third party, and the legal definition of personhood (when does the fetus become a legal subject independent of the gestating parent?) needs new frameworks. Ethical debates over commodification and access intensify alongside adoption." },
  { id: "closed-cycle-cities", name: "Closed-Cycle Cities", era: "future", category: "shelter",
    year: "2070", prereqs: ["closed-loop-life-support", "renewable-grid", "robotics"],
    desc: "A city engineered to operate like a self-sustaining ecosystem rather than a one-way pipeline that draws in resources from a hinterland and exports waste. Water is recovered, treated, and reused indefinitely instead of discharged; food waste, sewage, and organic refuse are anaerobically digested into fertilizer that feeds vertical and rooftop farms inside the city itself; mixed plastics, metals, and electronics are sorted by AI-coordinated robotic facilities and remanufactured into new products on the same site; building heat is captured and redistributed; transport runs on renewable electricity. The energy supply comes from district-scale solar, wind, geothermal, or nuclear, paired with thermal and battery storage. The decisive shift is from extractive metabolism (resources flowing in, waste flowing out) to circular metabolism (everything cycled within the city's footprint). Biosphere 2 (1991) and ISS ECLSS are the small-scale ancestors; NEOM, Singapore's Eco-Smart City, Songdo, and Masdar attempt partial implementations. By 2070, advanced membranes, AI logistics, robotic recycling, and cheap renewable energy enable closed-cycle cities of millions, reversing centuries of city-as-resource-sink dynamics." },
  { id: "personalized-medicine", name: "Personalized Medicine", era: "future", category: "medicine",
    year: "2070", prereqs: ["gene-sequencing", "deep-learning", "cancer-cure"],
    desc: "A medical model in which every diagnosis and treatment is conditioned on a comprehensive molecular portrait of the individual patient — their full genome (mutations affecting drug metabolism and disease risk), transcriptome (which genes are currently active in which tissues), proteome (the actual proteins their cells produce), microbiome (the gut, skin, and oral bacterial communities that shape immunity and metabolism), and lifestyle history. The same disease label often hides multiple distinct molecular subtypes that respond to different drugs; personalized medicine selects the one that will work, and at the right dose, before the patient is exposed to side effects from the wrong choice. Whole-genome sequencing at birth becomes routine; AI-driven drug-design platforms (Insilico Medicine, Recursion, Isomorphic Labs) propose patient-specific molecules in hours; pharmacogenomics eliminates trial-and-error prescribing. Drug development shifts from blockbuster small-molecule trials to per-patient biologics manufactured on demand at the hospital. The pharmaceutical industry's economic model — sell the same pill to millions — needs replacing, and equity of access remains a central concern." },
  { id: "printable-organs-on-demand", name: "Printable Organs on Demand", era: "future", category: "medicine",
    year: "2075", prereqs: ["lab-grown-organs", "3d-printing", "tissue-engineering"],
    desc: "Hospital-side 3D-bioprinting of transplantable organs from a patient's own cells, on the timescale of hours from order to surgery. The process: a small biopsy yields the patient's stem cells, which are expanded and differentiated in a bioreactor into the cell types needed (cardiomyocytes for heart, hepatocytes for liver, nephrons for kidney); a multi-head bioprinter then deposits these cells together with a biodegradable hydrogel scaffold and printed-in vascular trees, building the organ layer by layer at sub-millimeter resolution; the construct matures briefly in a perfusion bioreactor before transplant. Because the cells originate from the recipient, the immune system recognizes the new organ as self and the patient never needs lifelong immunosuppression. United Therapeutics' organ-printing initiative, Prellis Biologics' high-resolution photolithographic bioprinting, and organoid bioreactors converge into mature clinical capacity. Heart, kidney, liver, pancreas, and lung become routine prints; brain remains beyond reach. Organ scarcity ends, transplant waiting lists become historical artifacts, and the economics of organ donation, dialysis, and chronic disease management transform entirely." },
  { id: "ai-coordination-treaty", name: "AI Coordination Treaty", era: "future", category: "economy",
    year: "2075", prereqs: ["agi", "ai-governance", "large-language-model"],
    desc: "An international treaty regulating the development and deployment of advanced AI, modeled structurally on nuclear non-proliferation but adapted to the unique features of AI. The treaty fixes a compute threshold above which any training run is subject to international scrutiny; specifies safety-evaluation requirements that frontier models must pass before release (red-teaming for dangerous capabilities, alignment testing, interpretability audits); establishes a verification regime in which signatory nations agree to inspections of their largest data centers and to track the global flow of advanced AI accelerator chips; and defines proscribed capabilities — autonomous bioweapon design, autonomous cyber-offensive operation, mass-scale persuasion — that no signatory may build. Verification is the gating challenge: where nuclear material can be physically counted, AI capabilities can hide inside any sufficiently large model, so verification depends on capability evaluations and mechanistic interpretability becoming reliable enough to detect dangerous behavior. The 2023 Bletchley Declaration was the first international AI summit; the EU AI Act, U.S. Executive Order on AI, and Chinese regulations are competing precursor frameworks; a binding treaty by the 2070s codifies the consensus." },
  { id: "direct-ai-democracy", name: "Direct AI-Mediated Democracy", era: "future", category: "economy",
    year: "2075", prereqs: ["liquid-democracy", "agi", "large-language-model"],
    desc: "Government in which every citizen votes directly on policy questions, with AI bridging the gap between the complexity of modern legislation and the available time of ordinary people. Each citizen has a personalized AI assistant that summarizes proposals in their preferred level of detail, explains what each option would mean for the citizen's specific circumstances, and surfaces the best arguments on each side without filtering by ideology. A second layer of AI moderates the public discourse: filtering bots and coordinated manipulation, summarizing arguments across thousands of comments, identifying common-ground positions that majorities of opposing camps actually agree on (Pol.is–style 'crowdsourced consensus'). The system's appeal is that it dissolves the principal-agent problem of representative democracy — voters no longer delegate authority to a representative who may not vote their values — while still protecting against the cognitive overload that has historically made direct democracy impractical past city-state scale. Audrey Tang's vTaiwan and Pol.is (2014–) are small-scale forerunners; by the 2070s, AI-mediated direct democracy operates at national scale. Critics worry about AI-shaped opinion formation and capture by whoever controls the AI." },
  { id: "lunar-industrial-base", name: "Lunar Industrial Base", era: "future", category: "shelter",
    year: "2075", prereqs: ["moon-base", "asteroid-mining", "advanced-chip-manufacturing"],
    desc: "The Moon as a primary site for heavy industry, exploiting three local advantages Earth cannot match. The vacuum is free and clean, ideal for processes that on Earth require expensive vacuum chambers — semiconductor fabrication, vapor deposition, optical coatings; the gravity well is one-sixth of Earth's, so launching finished spacecraft to Mars or the asteroid belt costs a fraction of an Earth launch; and the regolith contains the silicon, oxygen, aluminum, iron, and titanium needed to build solar panels, structural metals, and rocket propellant from local material — closing the supply chain without lifting feedstock from Earth. If deuterium-helium-3 fusion reactors mature, the small but uniform helium-3 deposits in lunar regolith become economically extractable as fusion fuel. Population grows from the hundreds of moon-base researchers into tens of thousands of industrial workers and family settlers by mid-century, and in-situ resource utilization (ISRU) graduates from research demonstration into mature production engineering. The Moon becomes the first off-Earth economy that produces more value than it imports." },
  { id: "asteroid-belt-settlement", name: "Asteroid Belt Settlement", era: "future", category: "shelter",
    year: "2080", prereqs: ["asteroid-mining", "mars-colony", "fusion-rocket", "closed-loop-life-support"],
    desc: "Permanent human settlements on the dwarf planet Ceres, on Vesta, and inside hollowed-out smaller asteroids in the main belt between Mars and Jupiter. Each body offers different niches. Ceres (the largest belt body, ~1,000 km diameter) carries enough water ice in its mantle to supply both colonists and exported rocket propellant for the entire inner solar system. Vesta is differentiated like a planet, with a metal-rich core and mantle that yield rare-earth and platinum-group metals at concentrations no Earth ore body can match. Smaller asteroids are hollowed and spun to provide centripetal artificial gravity and pressurized internal habitats. The Belt's economic role is the solar system's mining and refining hub: shipping concentrated metals and water inward toward Earth–Moon and Mars markets, in exchange for electronics, biological products, and culture from richer worlds. Communication delays of 30+ minutes from Earth, microgravity environments, and mutual dependence among isolated stations produce a distinct Belter culture — generating the Earth/Mars/Belt identity politics that James S.A. Corey's The Expanse pre-figured." },
  { id: "memory-editing", name: "Memory Editing", era: "future", category: "medicine",
    year: "2085", prereqs: ["brain-computer-interface", "neuroscience", "deep-learning", "theory-of-consciousness"],
    desc: "Selectively rewriting the contents of human memory — strengthening, weakening, or erasing specific recollections, and eventually inserting new ones — by targeting the physical traces ('engrams') that encode them in neural circuits. The technology depends on two prior advances: AI-driven brain mapping that locates which neurons store a particular memory, and precise stimulation tools (focused ultrasound, optogenetics, or BCI electrode patterns) that can selectively reactivate those neurons during the memory's brief window of plasticity (reconsolidation), modifying it as it is rewritten back to long-term storage. Karim Nader's reconsolidation work (2000) and Susumu Tonegawa's optogenetic memory engineering in mice (2014) demonstrated the underlying biology. Clinical use begins with traumatic memories — PTSD, severe phobias, addiction triggers — where weakening or rewriting the offending memory is the most direct therapy. Recreational and elective uses — implanting experiences not lived, deleting unwanted breakups, refreshing the sense of novelty in long-term partnerships — raise ethics debates rivaling early genetic engineering. Total Recall and Eternal Sunshine become operational concerns rather than thought experiments." },
  { id: "cybernetic-enhancement", name: "Cybernetic Enhancement", era: "future", category: "medicine",
    year: "2090", prereqs: ["brain-computer-interface", "lab-grown-organs", "robotics"],
    desc: "Augmenting the body with integrated mechanical, electronic, and biological components beyond what natural anatomy provides. Three threads converge. Replacement limbs become stronger, faster, and more dexterous than the biological originals they replace, controlled directly by the wearer's nerves through implanted electrodes that read motor intent and provide tactile feedback (Hugh Herr's MIT prosthetics, DARPA's HAPTIX). Sensory augmentations extend perception past human bandwidth: infrared and ultraviolet vision through retinal implants, ultrasound hearing, magnetoreception, real-time language translation overlaid on hearing. Implanted compute (Neuralink-class BCIs paired with cloud connectivity) turns memory and arithmetic into auxiliary services running outside the skull. The cultural shift is from medical rehabilitation (giving the disabled what the able-bodied have) to elective enhancement (giving everyone capabilities no human has ever had), raising questions about athletic competition (Paralympics-vs-Olympics), military service, hiring discrimination, and what counts as 'human' physical capability." },
  { id: "orbital-ring", name: "Orbital Ring", era: "far-future", category: "transport",
    year: "2200", prereqs: ["room-temp-superconductor", "advanced-chip-manufacturing", "fusion-power"],
    desc: "A planet-encircling ring of high-strength material in low Earth orbit, held up not by orbital velocity (it rotates much faster than orbital speed) but by electromagnetic forces between the ring and a stream of moving mass inside it; that stream pushes outward, balancing gravity and supporting tethers that drop down to fixed stations on the equator. Payloads enter via elevators that climb the tethers from sea level to the ring at modest energy cost, since the elevators are not fighting the rocket equation. Once at ring altitude, payloads accelerate along the ring's interior linear motors to whatever velocity is needed — orbital insertion, transfer to the Moon, or escape from Earth — at the cost of electricity rather than rocket fuel. Compared with a space elevator, an orbital ring needs no exotic ultra-strong material (it works with existing steel and aluminum), provides multiple equatorial access points instead of one, and can be expanded incrementally. Paul Birch (1982) proposed the design. Construction takes decades and Type-I-scale capital, but operating cost is then near zero, making cislunar industry economically transformative." },
  { id: "universal-disease-eradication", name: "Universal Disease Eradication", era: "future", category: "medicine",
    year: "2095", prereqs: ["vaccines-modern", "antibiotics", "mrna-vaccine", "crispr"],
    desc: "Driving every major endemic infectious disease to global extinction — malaria, HIV, tuberculosis, schistosomiasis, dengue, hepatitis, neglected tropical diseases — finishing the work that smallpox eradication (1980) only began. The strategy attacks pathogens at every link of their transmission chain: mRNA-platform vaccines deployed within months of any new pathogen sequence; gene-drive technology that releases engineered mosquitoes whose offspring inherit the inability to transmit malaria, gradually replacing wild populations of Anopheles gambiae and ending the historical leading cause of human death; broad-spectrum antivirals that block conserved viral mechanisms across families; AI-coordinated public-health surveillance that detects outbreak signatures in wastewater, hospital admissions, and search queries before clinical recognition; and contact-tracing systems triggered by genomic identification of any unusual pathogen. Infectious disease shifts from leading global mortality cause to historical curiosity, and the burden of disease moves to chronic and aging-related conditions. Engineered bioweapon reemergence — using the same biotechnology toolkit in reverse — remains the residual existential risk." },


  // ─── Future / Far-Future weapons ───
  { id: "cyber-kinetic-warfare", name: "Cyber-Kinetic Warfare", era: "future", category: "weapons",
    year: "2030", prereqs: ["cloud-computing", "arpanet-internet"],
    desc: "Cyberattacks producing physical destruction at industrial scale: corrupted PLCs spinning centrifuges to failure, falsified telemetry crashing autonomous fleets, ransomware locking power grids and water-treatment plants. Stuxnet (2010) was the proof of concept; the 2015 Ukraine grid attack, the 2017 NotPetya wiper (~$10 billion damage), and the 2021 Colonial Pipeline ransomware showed the trajectory. By 2030, cyber-kinetic operations are integral to peer warfare doctrine and the legal threshold for armed-conflict response is permanently blurred. Critical-infrastructure hardening becomes a national-security priority on the scale of nuclear deterrence." },
  { id: "directed-energy-weapons", name: "Directed-Energy Weapons", era: "future", category: "weapons",
    year: "2035", prereqs: ["advanced-chip-manufacturing", "lithium-battery"],
    desc: "Kilowatt- to megawatt-class lasers, high-power microwaves, and particle beams replacing kinetic projectiles for selected roles. The U.S. Navy's HELIOS (60 kW solid-state laser, deployed on USS Preble 2022), the British DragonFire (50 kW, 2024), and Israel's Iron Beam mark the early generation. By the 2030s ship- and vehicle-mounted systems engage drones, mortars, and small boats at the speed of light at marginal cost per shot. Directed energy reshapes air defense and counter-UAS, and pushes attackers toward saturation tactics — drone swarms — to overwhelm beam-on-target rates." },
  { id: "drone-swarms", name: "Autonomous Drone Swarms", era: "future", category: "weapons",
    year: "2030", prereqs: ["machine-learning", "autonomous-vehicle"],
    desc: "Cooperative swarms of hundreds to thousands of cheap autonomous drones, coordinated by edge-AI without continuous human supervision. The 2020 Nagorno-Karabakh war (TB2 Bayraktar) and Ukraine's 2022–25 mass FPV-drone campaigns demonstrated the disruption; the Pentagon's Replicator Initiative (2023) and Chinese counterpart programs scale it. By 2035, swarm tactics dominate battlefield reconnaissance, suppression of enemy air defense, and precision strike. Cheap autonomy inverts the cost curve: a $1,000 drone can disable a $10 million tank, forcing armored, naval, and air doctrine to rebuild around mass and dispersion." },
  { id: "anti-satellite-warfare", name: "Anti-Satellite Warfare", era: "future", category: "weapons",
    year: "2040", prereqs: ["satellite", "reusable-rocket"],
    desc: "Mature kinetic and non-kinetic anti-satellite (ASAT) capabilities. China's 2007 Fengyun-1C kinetic test, India's 2019 Mission Shakti, and Russia's 2021 Cosmos 1408 strike showed early kinetic ASAT — at the cost of debris fields lasting decades (Kessler-syndrome risk). By the 2040s, non-kinetic ASAT (jammers, dazzlers, co-orbital grapplers) dominate; kinetic strikes are reserved for terminal-phase doctrine. The first day of any peer conflict opens with a strike on the adversary's ISR, GPS, and communications constellations — making space the decisive contested domain." },
  { id: "engineered-pathogen-defense", name: "Engineered Pathogen Defense", era: "future", category: "weapons",
    year: "2055", prereqs: ["synthetic-biology", "mrna-vaccine"],
    desc: "Continuous biosurveillance plus rapid-response countermeasure pipelines: metagenomic sewage and air sampling, AI-flagged anomaly detection, and on-demand mRNA vaccine and monoclonal-antibody manufacture within days of pathogen identification. Operation Warp Speed (2020) compressed COVID-19 vaccine development from years to months; by the 2050s the pipeline operates in weeks for any sequenced novel agent. Defense against engineered pathogens — released by state programs, terrorists, or accidents — joins nuclear and cyber as a tier-one national-security capability. The same technology lowers the barrier to offensive bioweapons, making the regime fragile." },
  { id: "strategic-memetic-warfare", name: "Strategic Memetic Warfare", era: "far-future", category: "weapons",
    year: "2150", prereqs: ["large-language-model", "agi", "social-media"],
    desc: "Industrial-scale narrative warfare conducted by AGI: adversary populations are subjected to continuous, individualized persuasion campaigns generating tailored disinformation, synthetic relationships, and strategic memes calibrated to shift voting, recruitment, social cohesion, and policy preferences. Russian Internet Research Agency activity (2014–) and the 2024 election deepfake era are the crude precursors. By 2150 a peer civilization without comparable AI defenses can be destabilized within years through narrative attack alone — a more durable form of conquest than military occupation. Defensive epistemic infrastructure becomes a strategic capability." },
  { id: "self-replicating-combat-drones", name: "Self-Replicating Combat Drones", era: "far-future", category: "weapons",
    year: "2200", prereqs: ["self-replicating-machines", "nanotechnology"],
    desc: "Autonomous combat drones that gather raw materials from the environment and manufacture copies of themselves, deploying as self-sustaining military forces without resupply. John von Neumann's universal constructor (1948) provided the theoretical basis; nanomanufacturing and autonomous AI close the practical loop. Once released, a self-replicating fleet's growth becomes exponential and difficult to recall — ergodic conflict where strategic decisions cannot be reversed. International accords prohibit unbounded replicators (1990s-style biological-weapons analogue), but verification challenges and breakaway state programs make compliance fragile." },
  { id: "planetary-defense-system", name: "Planetary Defense System", era: "far-future", category: "weapons",
    year: "2200", prereqs: ["anti-satellite-warfare", "asteroid-mining"],
    desc: "Coordinated multi-layer defense grid for an entire planet: distributed orbital sensors detecting both natural threats (asteroids, comets) and hostile artifacts; kinetic-impactor and gravity-tractor deflection assets on standing alert; directed-energy and missile interceptors for terminal-phase engagements. NASA's 2022 DART mission (the first operational kinetic asteroid deflection) and the planned NEO Surveyor telescope are the early elements. By 2200 humanity operates an integrated grid covering the inner solar system, treating planetary survival as routine infrastructure rather than catastrophic-risk hedging." },
  { id: "relativistic-kinetic-weapon", name: "Relativistic Kinetic Weapon", era: "far-future", category: "weapons",
    year: "2300", prereqs: ["fusion-rocket", "interstellar-probe"],
    desc: "Projectiles accelerated to a meaningful fraction of the speed of light — a one-ton mass at 0.1c carries kinetic energy comparable to the Chicxulub impactor. The Casaba-Howitzer (1960s nuclear-pulse-propelled fragments) and Project Longshot studies provide the theoretical lineage. At interstellar distances RKWs are nearly impossible to defend against — detection at multi-light-day range gives only hours of warning before impact, and even a near-miss imparts catastrophic gamma-ray bursts to the target. Once any star-faring civilization develops the capability, mutual assured destruction goes interstellar." },
  { id: "antimatter-weapon", name: "Antimatter Weapon", era: "far-future", category: "weapons",
    year: "2450", prereqs: ["antimatter-production"],
    desc: "Weapons using positron-electron or proton-antiproton annihilation, with energy densities ~10⁴ times nuclear fission and no critical-mass threshold. A single milligram of antimatter releases ~43 kilotons; gram-scale yields rival the largest thermonuclear devices. Air Force Research Laboratory (2003–) studied positron-catalyzed micro-fusion; practical weaponization remains gated by antimatter production cost (currently ~$10¹⁵ per gram) and trap stability. If those barriers fall, antimatter weapons enable arsenals that fit in a briefcase — collapsing the deterrence architecture that prevented great-power war since 1945." },

  // ─── Far Future (2500-2700 fill) ───
  { id: "black-hole-engineering", name: "Black Hole Engineering", era: "far-future", category: "energy",
    year: "2550", prereqs: ["stellar-engineering", "kardashev-type-ii"],
    desc: "Active engineering use of black holes — the Penrose process extracting rotational energy from Kerr black holes, Hawking-radiation harvesters around artificial micro black holes, and gravitational confinement reactors. Roger Penrose's 1971 paper showed that up to 29% of a rotating black hole's mass-energy can be extracted via reverse-Compton-style scattering off the ergosphere. By the 26th century an established Type II civilization fields engineered Kerr-class power plants — black holes built or moved into useful orbits, drained over megayear timescales for an output rivaling stellar luminosity in compact form." },
  { id: "galactic-communication-network", name: "Galactic Communication Network", era: "far-future", category: "communication",
    year: "2550", prereqs: ["galactic-civilization", "lingua-galactica"],
    desc: "A galaxy-spanning communications fabric: dedicated relay stations along major Hill-sphere intersections, neutrino-modulated long-baseline links cutting through interstellar dust, and protocol layers that handle century-scale latency as a normal feature rather than a fault. Any single message takes ~100,000 years to traverse the Milky Way at light speed; the network operates as a deeply asynchronous publish-subscribe system rather than as conversation. Cultural and economic life adapts to a permanent communications horizon — local consensus reigns within a few-light-year cluster, while galactic-scale agreements move at glacial pace." },
  { id: "pre-warp-interstellar-trade", name: "Pre-Warp Interstellar Trade", era: "far-future", category: "economy",
    year: "2550", prereqs: ["galactic-civilization", "generation-ship-colony"],
    desc: "Sub-light interstellar commerce: cargoes of unique materials, biological cultivars, and information-dense artifacts shipped at substantial fractions of c with century-scale delivery times. Light-lag arbitrage — pricing at origin vs destination separated by decades of news — becomes the central economic problem; standardized future-delivery contracts and reputation-based clearing replace synchronous markets. Trading polities specialize at scales where shipping is economical (rare isotopes, unique organisms, novel cultural works), while bulk goods stay local. Light-lag economics generates new financial instruments unknown to faster economies." },
  { id: "pan-galactic-coordination-ai", name: "Pan-Galactic Coordination AI", era: "far-future", category: "knowledge",
    year: "2600", prereqs: ["superintelligence", "galactic-civilization"],
    desc: "A civilization-spanning superintelligence substrate replicated and synchronized across thousands of star systems, coordinating Type II → Type III industrial and ecological policy on million-year horizons. Each local instance handles in-system decisions; the substrate as a whole maintains weak galactic consensus through asynchronous reconciliation across light-year distances. Earlier debates about AI alignment reframe into questions of inter-instance value drift, sub-substrate forking, and how a distributed intelligence preserves identity across communications horizons it cannot fully cross. The pan-galactic AI both stabilizes and constrains civilizational evolution." },
  { id: "femto-engineering", name: "Femto-Engineering", era: "far-future", category: "tools",
    year: "2600", prereqs: ["programmable-matter", "nanotechnology"],
    desc: "Manipulation of matter at nuclear (10⁻¹⁵ m) length scales: engineered isotopes, designer atomic nuclei, controlled nuclear isomers as energy storage, and metastable exotic-nucleus structures impossible in natural environments. Robert Forward, Robert Freitas, and Robert Bradbury speculated about femto-tech in the 1990s; by the 26th century it operates as an industrial discipline. Femto-engineering provides energy densities thousands of times nuclear fission, enables matter-recycling at the proton-neutron level, and underpins later strange-matter and dark-energy capabilities." },
  { id: "vacuum-energy-extraction", name: "Vacuum Energy Extraction", era: "far-future", category: "energy",
    year: "2650", prereqs: ["dark-sector-physics", "kardashev-type-ii"],
    desc: "Practical extraction of zero-point energy from the quantum vacuum — Casimir-effect generators harvesting the difference between vacuum states between closely-spaced surfaces, dynamical Casimir effect emitters in oscillating cavities, and engineered vacuum-state transitions releasing energy. Hendrik Casimir's 1948 prediction was confirmed in the 1990s at vanishingly small scales; by the 27th century engineered geometries amplify the effect into useful power. The energy density of the vacuum (estimated 10⁻⁹ J/m³ at minimum, vastly higher in some theories) becomes a practical resource if even a small fraction is harvestable." },
  { id: "strange-quark-matter", name: "Strange / Quark Matter", era: "far-future", category: "tools",
    year: "2650", prereqs: ["femto-engineering", "quantum-gravity"],
    desc: "Engineering with quark-deconfined matter — strange matter (up + down + strange quarks in approximate equilibrium), color-flavor-locked phases, and stable quark-matter macroscopic structures. The strange-matter hypothesis (Bodmer 1971, Witten 1984) holds that strange matter may be the true ground state of QCD; if so, properly stabilized lumps would be denser than nuclear matter and structurally exotic. Quark-matter hulls for relativistic-velocity craft, ultra-dense storage, and gravitational-wave-resistant computing become engineering options once stabilization is mastered." },
  { id: "dark-energy-engineering", name: "Dark Energy Engineering", era: "far-future", category: "energy",
    year: "2680", prereqs: ["vacuum-energy-extraction", "quantum-gravity"],
    desc: "Localized manipulation of the cosmological constant — engineered regions of negative-pressure dark energy producing controlled spacetime expansion or contraction, and stabilized exotic-matter (negative-energy-density) configurations. The 1998 supernova observations of accelerating cosmic expansion established dark energy as ~68% of the universe's energy budget; by the late 27th century engineered analogues become technological. Dark-energy engineering is the immediate precursor to the Alcubierre warp metric — the same exotic-matter machinery, applied at craft scale rather than cosmological scale." },

  // ─── Arts & Entertainment (atomic / information) ───
  { id: "abstract-expressionism", name: "Abstract Expressionism", era: "atomic", category: "social",
    year: "1947", prereqs: ["oil-painting", "photography", "bauhaus"],
    desc: "First American-led international art movement: Jackson Pollock's drip paintings (Number 1A, 1948), Mark Rothko's color fields, Willem de Kooning's gestural figuration, Barnett Newman's zips. Centered around the New York School and Peggy Guggenheim's Art of This Century gallery, the movement displaced Paris as the world's art capital after WWII. CIA-funded covert promotion (the Congress for Cultural Freedom) used it as Cold War soft power against socialist realism. Abstract Expressionism redefined what painting could be — process, scale, emotional intensity — and set the agenda for postwar visual art." },
  { id: "lp-vinyl-record", name: "LP / Vinyl Record", era: "atomic", category: "communication",
    year: "1948", prereqs: ["radio-wireless", "plastic-polymer"],
    desc: "Columbia Records' 33⅓ rpm long-playing microgroove disc (June 1948) replaced fragile 78 rpm shellac records with vinyl polymer offering ~22 minutes per side. RCA's competing 45 rpm single (1949) settled into the singles slot. Stereo recording arrived in 1958. The LP made the album — not the song — the artistic unit, enabling concept albums (Sgt. Pepper, 1967), gatefold cover art, and album-side dramaturgy. Vinyl dominated music distribution until cassette and CD displaced it; analog warmth and physical artifact value drove a 21st-century revival." },
  { id: "color-television", name: "Color Television", era: "atomic", category: "communication",
    year: "1954", prereqs: ["television", "transistor"],
    desc: "RCA's NTSC compatible color system (FCC approved December 1953, mass production from 1954) broadcast color while remaining compatible with existing black-and-white sets. PAL (Europe, 1967) and SECAM (France/USSR, 1967) followed with regional variants. Color penetration grew slowly — 1% of U.S. households in 1962, 50% in 1972 — limited by set price. Color transformed advertising effectiveness, news immediacy (Vietnam coverage), and the visual grammar of mass culture; sports, soap operas, and political conventions reshape themselves around the color-saturated screen." },
  { id: "video-games", name: "Video Games", era: "information", category: "social",
    year: "1972", prereqs: ["digital-computer", "transistor"],
    desc: "Atari's Pong (November 1972) and the Magnavox Odyssey (September 1972) launched the commercial video-game industry. Spacewar! (1962) was the technical precursor; Computer Space (1971) the first coin-op. Within a decade arcade games (Space Invaders 1978, Pac-Man 1980) and home consoles (Atari 2600, NES 1985) had created an entirely new mass medium with no historical precedent — interactive, visual, narrative. By the 2020s the global games industry exceeded film and music combined; gaming reshaped childhood, social interaction, and the development of computer hardware itself." },
  { id: "cgi-cinema", name: "CGI Cinema", era: "information", category: "communication",
    year: "1993", prereqs: ["cinema", "personal-computer"],
    desc: "Computer-generated imagery enters mainstream filmmaking: The Abyss (1989, ILM water tentacle), Terminator 2's liquid-metal T-1000 (1991), Jurassic Park's photorealistic dinosaurs (1993), and Toy Story's first fully-CG feature (1995, Pixar) marked the transition. By 2010 most studio films used CGI extensively; by 2020 photorealistic synthetic actors and entire CG environments were routine. Industrial Light & Magic, Weta Digital, and Pixar set the technical and artistic standards. CGI dissolved physical-effects constraints on storytelling but also enabled the spectacle-bloat tendencies of contemporary blockbuster cinema." },
  { id: "anime-globalization", name: "Anime Globalization", era: "information", category: "social",
    year: "1995", prereqs: ["sound-film", "mass-media"],
    desc: "Japanese animation breaks out of regional market into global cultural force: Akira (1988) opened Western critical attention; Pokémon (1996) hit children's TV worldwide; Studio Ghibli's Princess Mononoke (1997) and Spirited Away (2001, Oscar) won Western prestige; Cowboy Bebop (1998) and Neon Genesis Evangelion (1995) defined adult anime fandom abroad. Crunchyroll (2006) and Netflix anime licensing (2016+) made Japanese productions globally available. Anime aesthetics — large eyes, frenetic action, melancholic tones — propagate into Western animation, comics, fashion, and music videos." },

  // ─── Near Future / Far Future arts & entertainment ───
  { id: "synthetic-performers", name: "Synthetic Performers", era: "future", category: "social",
    year: "2035", prereqs: ["large-language-model", "generative-art"],
    desc: "AI-driven virtual idols and synthetic celebrities operating across music, film, and social media. Hatsune Miku (Crypton Future Media, 2007) — a Vocaloid character with sold-out arena holographic concerts — was the early prototype. Lil Miquela (2016) and Kizuna AI (2016) extended the form into Instagram-style influencers and VTubers. By the 2030s fully autonomous AI performers — generating their own music, dialogue, fan interactions, and tours — outdraw human acts in some markets. The economic dynamics flip: a synthetic performer never ages, never tires, and exists in unlimited parallel performances; the question of artistic authenticity gets reframed for the first time since recorded sound." },
  { id: "procedural-infinite-worlds", name: "Procedural Infinite Worlds", era: "future", category: "social",
    year: "2045", prereqs: ["video-games", "large-language-model"],
    desc: "Game and narrative environments generated on-demand from procedural rules and large language models — every player explores a different unique universe, dynamically generated as they walk through it. Dwarf Fortress (2006), Minecraft (2009), and No Man's Sky (2016) pioneered the approach with hand-crafted generators; AI-driven procgen by the 2040s produces fully novel storylines, characters, dialogue, and quests at runtime. The shift collapses content production economics — a single world can absorb millions of player-hours from a small studio's output — and fragments the shared cultural reference points that traditional games once produced." },
  { id: "bio-art", name: "Bio-Art", era: "future", category: "social",
    year: "2050", prereqs: ["synthetic-biology", "genetic-engineering"],
    desc: "Engineered living organisms — bacteria, plants, animals, tissue cultures — used as the artistic medium itself. Eduardo Kac's GFP Bunny (2000, transgenic green-fluorescent rabbit) and his microbial Genesis project (1999) opened the form. Stelarc's Ear on Arm (2007) extended it to performance art. SymbioticA (University of Western Australia, 2000–) became the institutional center. By 2050 maturity of CRISPR, synthetic biology, and biocontainment makes commissioned bio-art a recognized practice — installation pieces in galleries that grow, age, evolve, and require care. The boundary between art object and living system dissolves." },
  { id: "mind-linked-collective-art", name: "Mind-Linked Collective Art", era: "far-future", category: "social",
    year: "2200", prereqs: ["brain-computer-interface", "cybernetic-enhancement", "brain-brain-communication"],
    desc: "Direct multi-mind shared experience as artistic medium: hundreds to thousands of participants link via mature BCI mesh into a co-experienced subjective space, a single emergent qualia stream the artist composes for. Earlier precursors include collective dance, communal religious ritual, and large-scale immersive theater (Sleep No More 2011, Punchdrunk's heritage). Once neural interfaces enable real-time shared sensation and emotion, the artistic possibilities exceed anything previously available — the work exists not in any single mind but in the structured resonance across the linked group. Whether the resulting experience is one person's or many becomes a contested ontological question." },
  { id: "engineered-sensory-modalities", name: "Engineered Sensory Modalities", era: "far-future", category: "social",
    year: "2300", prereqs: ["cybernetic-enhancement", "nanotechnology"],
    desc: "Designed sensory channels purpose-built for art: magnetoreception, polarization vision, electric-field sensing, designed qualia bands with no biological precedent. Earlier work — Neil Harbisson's antennal hearing of color (2004), Moon Ribas's seismic sensor implant — explored the form within the constraints of a baseline human nervous system. Mature neuroengineering breaks those constraints; new senses are commissioned and installed for specific artworks, then optionally removed. The artistic vocabulary expands beyond what evolved-from-Earth nervous systems could carry, producing art forms that genuinely cannot be appreciated by unmodified humans." },
  { id: "ai-native-art-forms", name: "AI-Native Art Forms", era: "far-future", category: "social",
    year: "2400", prereqs: ["superintelligence", "matrioshka-brain"],
    desc: "Artworks generated by superintelligent systems for superintelligent audiences, operating at structural complexity and temporal compression beyond human cognitive bandwidth. Whereas earlier AI art (DALL-E 2022, Sora 2024, generative-art descendants) was produced by AI for human appreciation, AI-native art forms are produced by AI for AI — and are largely opaque or trivial to baseline humans. The most accessible categories admit guided human interpretation; the rest exist in subjective spaces no embodied biological mind can occupy. Whether such works carry meaning, beauty, or value in any sense humans recognize becomes a recurring question for posthuman aesthetics." },
  { id: "stellar-scale-spectacle", name: "Stellar-Scale Spectacle", era: "far-future", category: "social",
    year: "2450", prereqs: ["dyson-swarm", "kardashev-type-ii"],
    desc: "Engineered modulation of stellar light output — controlled brightness pulses, color shifts, and engineered occlusion patterns visible across light-years — used as a cosmic-scale artistic medium. The Shkadov thruster (Leonid Shkadov, 1987) demonstrates the engineering basis; coordinated Dyson-swarm shutters provide a finer instrument. A Type II civilization can compose works in stellar pixels visible across the galaxy, with rendering times measured in centuries and audiences spread across thousands of star systems. The first stellar-scale spectacle is also a SETI signature — distinguishable from natural variable-star phenomena by its information content." },
  { id: "pan-galactic-festival", name: "Pan-Galactic Festival", era: "far-future", category: "social",
    year: "2600", prereqs: ["galactic-civilization", "galactic-communication-network"],
    desc: "Synchronized cultural events spanning the colonized galaxy, organized around shared themes despite light-lag latencies measured in millennia. The 'simultaneity' is virtual — each star system experiences its local festival in lockstep with thousands of others, despite none of them being in causal contact during the celebration itself. Cultural festivals (Olympics, Burning Man, Ramadan, Lunar New Year) are the small precursors; the pan-galactic festival operates at a scale where the act of *imagining* a galaxy-wide cultural moment is itself the meaningful event. Light-lag romanticism — the recognition that one's celebration coincides with celebrations one will never witness — becomes a defining aesthetic of galactic civilization." },

  // ─── Culture / Philosophy / Sociology ───
  { id: "bauhaus", name: "Bauhaus", era: "modern", category: "social",
    year: "1919", prereqs: ["factory-system", "photography"],
    desc: "Walter Gropius's Bauhaus school (Weimar 1919, Dessau 1925, Berlin 1932) integrated fine art, craft, and industrial design under a single curriculum. Faculty included Paul Klee, Wassily Kandinsky, László Moholy-Nagy, Marcel Breuer, and Mies van der Rohe. Bauhaus pedagogy — preliminary course (Vorkurs), workshop training, mass-production aesthetics — established 'form follows function' modernism as the dominant 20th-century design philosophy. The Nazis closed the school in 1933; faculty diaspora carried the principles to Black Mountain College, the Chicago New Bauhaus (IIT), Harvard, and the Ulm school. Modern furniture, typography, architecture, and graphic design all descend from this fifteen-year experiment." },
  { id: "frankfurt-school", name: "Frankfurt School", era: "modern", category: "social",
    year: "1923", prereqs: ["labor-union", "public-education"],
    desc: "The Institute for Social Research (Frankfurt, 1923) brought together Theodor Adorno, Max Horkheimer, Herbert Marcuse, Walter Benjamin, Erich Fromm, and Jürgen Habermas around a Marxist-Freudian critique of industrial mass culture. Their 'Critical Theory' analyzed how the culture industry, instrumental reason, and authoritarian personality structures sustain capitalism even when it harms workers. Forced into U.S. exile by Nazi rise (Columbia, 1934), they shaped postwar American sociology and 1960s student movements. Habermas's later communicative-action theory (1981) extended the program into deliberative democratic theory." },
  { id: "universal-human-rights", name: "Universal Human Rights", era: "atomic", category: "social",
    year: "1948", prereqs: ["liberal-democracy", "womens-suffrage"],
    desc: "The UN Universal Declaration of Human Rights (December 10, 1948), drafted under Eleanor Roosevelt's chairmanship and adopted with no opposing votes. Thirty articles articulating civil, political, economic, social, and cultural rights as universal — independent of state, religion, or culture. The Declaration produced the binding 1966 Covenants, the Helsinki Accords (1975), the European Convention machinery, and the eventual ICC (2002). Real enforcement remains uneven and contested — sovereign noncompliance, cultural relativism critiques, selective Western application — but human-rights discourse has structured every postwar legitimacy claim, from anticolonial movements to dissident cases inside both Communist and capitalist regimes." },
  { id: "cybernetics", name: "Cybernetics", era: "atomic", category: "knowledge",
    year: "1948", prereqs: ["digital-computer", "mathematics-arithmetic"],
    desc: "Norbert Wiener's 1948 'Cybernetics: Or Control and Communication in the Animal and the Machine' synthesized feedback control theory, information theory, and biological homeostasis into a unified framework. Macy Conferences (1946–1953) gathered Wiener, Claude Shannon, John von Neumann, Warren McCulloch, Margaret Mead, and Gregory Bateson around the program. Cybernetics directly produced control engineering, computer science (von Neumann architecture as cybernetic system), early AI research, family-systems therapy, and the systems-theoretic turn in sociology. Stafford Beer's Cybersyn (Chile 1971) was the most ambitious cybernetic state-management experiment; Norbert Wiener's later 'God and Golem' (1964) anticipated the AI alignment problem." },
  { id: "neoliberalism", name: "Neoliberalism", era: "information", category: "economy",
    year: "1980", prereqs: ["liberal-democracy", "modern-corporation", "arpanet-internet"],
    desc: "The political-economic paradigm of Reagan, Thatcher, and the Washington Consensus: market deregulation, privatization, free trade, capital-flow liberalization, and rolling-back of welfare-state provisions. Theoretical roots trace to the Mont Pelerin Society (Hayek, Friedman, 1947) and Chicago School economics. The IMF's structural adjustment programs (1980s) propagated the model globally; the 1989 fall of the Soviet bloc and 'End of History' (Fukuyama 1992) seemed to vindicate it. Critiques range from inequality (Piketty 2013, Stiglitz) to deindustrialization to financialization. The 2008 financial crisis and 2010s populist backlash signaled the model's unraveling without producing a clear successor." },
  { id: "degrowth-economics", name: "Degrowth Economics", era: "future", category: "economy",
    year: "2035", prereqs: ["climate-science", "renewable-grid"],
    desc: "A planned economic contraction of high-income countries' material throughput, on grounds that biophysical limits make perpetual growth ecologically impossible. Roots in Herman Daly's steady-state economics (1977), Nicholas Georgescu-Roegen's bioeconomics, and André Gorz (1972 — first to use 'décroissance'). Jason Hickel's *Less Is More* (2020) and Kate Raworth's Doughnut Economics (2017) brought it into mainstream policy debate. Degrowth advocates work-time reduction, public-service expansion, decommodification of essentials, and bans on planned obsolescence. Critics (including most mainstream economists) argue it cannot deliver on poverty alleviation; advocates respond that growth-as-currently-defined is what's incompatible with planetary limits." },
  { id: "solarpunk", name: "Solarpunk", era: "future", category: "social",
    year: "2030", prereqs: ["renewable-grid", "climate-science"],
    desc: "An optimistic ecological-technological aesthetic and political imaginary, defined in deliberate contrast to cyberpunk dystopia. Originated in a 2008 blog post and codified through anthologies (*Solarpunk: Ecological and Fantastical Stories*, 2018). Core motifs: photovoltaic-integrated architecture, public-transit cities, urban agriculture, decentralized energy, restored ecosystems, multi-cultural communities, art-nouveau aesthetics. Functions as both fictional genre and template for actual policy advocacy — climate-positive futures that aren't either austere apocalypse or technocratic singularity. Influences architecture (NEOM, Masdar City), animation (Studio Ghibli's later films), and climate-movement framing (Sunrise Movement)." },
  { id: "constructed-religions", name: "Constructed Religions", era: "far-future", category: "social",
    year: "2300", prereqs: ["longtermism", "transhumanism"],
    desc: "Engineered spiritual systems designed for posthuman conditions — millennium-scale lifespans, digital-substrate consciousness, mass speciation. Earlier precursors include 19th-century Auguste Comte's positivist 'religion of humanity', Bahá'í universalist project, and 20th-century engineered religions like Scientology and Raëlism. Posthuman-condition religions address questions baseline traditions weren't built for: meaning under unbounded life, ritual across light-year communications gaps, sacred meaning of ancestral biological humanity, ethics of running multiple instances of one mind. Some are open systems revised iteratively; others claim ahistorical authority. Their architects are explicit about constructing them rather than receiving them." },
  { id: "substrate-pluralism", name: "Substrate Pluralism", era: "far-future", category: "social",
    year: "2350", prereqs: ["substrate-independent-humanity", "universal-sentient-rights"],
    desc: "The formal social philosophy of multi-substrate civilization: legal, ethical, and cultural frameworks for societies in which biological humans, digital minds, hybrid cyborgs, engineered organisms, and emergent AGI substrates coexist as full members. Earlier work — David Chalmers on substrate-independence, Susan Schneider on machine consciousness, Eric Schwitzgebel on group minds — laid foundations. Mature substrate pluralism handles voting weight across short- and long-lived minds, citizenship across instances and forks, intellectual-property claims across substrate copies, and the legitimacy of substrate-specific subcultures. The political settlement is fragile and recurringly contested; substrate-chauvinist movements (biological supremacism, digital purism) recur as serious political forces." },
  { id: "galactic-citizenship", name: "Galactic Citizenship", era: "far-future", category: "social",
    year: "2400", prereqs: ["universal-sentient-rights", "interstellar-treaty"],
    desc: "Legal and moral framework articulating rights, obligations, and standing of any sentient being across the colonized galaxy — independent of star system, planet, biological species, or substrate. Builds on the universal-sentient-rights tradition (2200), adapted for light-year separations: distributed jurisdiction, asynchronous adjudication, rights enforcement across communications gaps centuries long. Earlier multinational citizenship analogues (EU passports, UN treaties) are too small-scale to inform the design directly. Some polities accept galactic citizenship as supervening over local law; others operate it only as treaty-level mutual recognition. The philosophical question — what makes a being eligible — remains permanently open as new substrates emerge." },
  { id: "speciation-ethics", name: "Speciation Ethics", era: "far-future", category: "social",
    year: "2400", prereqs: ["substrate-independent-humanity", "universal-sentient-rights"],
    desc: "Moral philosophy addressing what diverged posthuman branches owe each other once they have become genuinely distinct species — biologically, cognitively, or substrate-wise. Earlier ethical frameworks assumed a unified human moral community; once that assumption collapses, fundamental questions emerge: do branches have positive duties of mutual support, or only negative duties of non-aggression? Are merging or unmerging branches a moral wrong? What of branches that no longer recognize each other as morally significant? Olaf Stapledon's *Last and First Men* (1930) and *Star Maker* (1937) anticipated the questions; serious operational ethics emerges only once speciation is actually happening." },

  // ─── More warfare (enlightenment / industrial) ───
  { id: "linear-infantry-tactics", name: "Linear Infantry Tactics", era: "enlightenment", category: "weapons",
    year: "1740", prereqs: ["musket", "standing-army"],
    desc: "Massed close-order infantry firing volleys on command in long thin lines two or three ranks deep. Frederick the Great's Prussian army drilled to fire 4–5 rounds per minute (twice the rate of contemporaries) and maneuver in rigid formation under fire — the decisive edge in the Silesian Wars. Linear tactics dominated European battlefields from 1690 through the Napoleonic Wars (1815). The discipline required to stand and reload while under enemy fire was achieved through brutal drill, harsh discipline, and the cohesion of regimental loyalty. Industrial-era rifling and entrenchment eventually rendered the line obsolete." },
  { id: "standardized-field-artillery", name: "Standardized Field Artillery", era: "enlightenment", category: "weapons",
    year: "1765", prereqs: ["artillery", "coke-iron"],
    desc: "Jean-Baptiste Vaquette de Gribeauval's reform of French artillery (1765) standardized cannon calibers (4-, 8-, and 12-pounder field guns plus a 6-inch howitzer), introduced interchangeable parts, lightened carriages for road mobility, and trained dedicated artillery officers. The Gribeauval system gave France's revolutionary and Napoleonic armies decisive battlefield artillery superiority — the same gun could be repaired anywhere, ammunition was uniform, and crews could move pieces faster than infantry could redeploy. Other European armies copied the system after 1815. Modern military logistics descends directly from this artillery-reform model." },
  { id: "ironclad-warship", name: "Ironclad Warship", era: "industrial", category: "weapons",
    year: "1859", prereqs: ["naval-warship", "steamship"],
    desc: "Wooden-hulled warships clad in wrought-iron armor, propelled by steam: France's *Gloire* (1859) and Britain's HMS *Warrior* (1860) made every line-of-battle sailing ship instantly obsolete. The American Civil War's *Monitor* vs *Virginia* duel (March 1862) demonstrated ironclad invulnerability to conventional shellfire. Within a decade major navies converted entirely to steam-and-iron; within two, all-iron and then steel hulls. Ironclads transitioned naval warfare from a 300-year era of broadside sailing combat into modern industrial sea power, foreshadowing dreadnoughts and battleship fleets." },
  { id: "bolt-action-rifle", name: "Bolt-Action Rifle", era: "industrial", category: "weapons",
    year: "1867", prereqs: ["musket", "interchangeable-parts"],
    desc: "Breech-loading, magazine-fed rifle operated by a manually cycled bolt: Johann Nikolaus von Dreyse's needle gun (1841) was the prototype, but Mauser's Model 71 (1871) and the magazine-fed Model 98 (1898) defined the form. Bolt actions doubled or tripled the infantry firing rate over muzzle-loaders while remaining accurate to 600+ meters. Combined with smokeless powder and rimless cartridges (1880s), they gave WWI infantry the firepower that made attacking entrenchments suicidal. Variants of Mauser, Lee-Enfield, and Mosin-Nagant designs remained primary infantry weapons through WWII and saw service in some armies into the 21st century." },
  { id: "high-explosives", name: "High Explosives", era: "industrial", category: "weapons",
    year: "1867", prereqs: ["chemistry-modern"],
    desc: "Alfred Nobel's 1867 patent on dynamite — nitroglycerin stabilized in diatomaceous earth — gave engineers and miners a manageable high explosive ten times more powerful than gunpowder. TNT (1863, weaponized 1902), picric acid (Lyddite, 1888), and later RDX (1899) followed. High explosives transformed mining, tunneling, and demolition; militarily, they replaced black powder in artillery shells, enabled torpedo and naval mine warfare, and ultimately drove the explosive shell volume that defined WWI's industrial-scale killing. Nobel's prize (1895) was funded by the dynamite fortune — partly in atonement for premature obituaries calling him 'the merchant of death'." },
  { id: "modern-quick-firing-artillery", name: "Quick-Firing Artillery", era: "industrial", category: "weapons",
    year: "1897", prereqs: ["artillery", "machine-tool", "high-explosives"],
    desc: "The French 75mm field gun (Modèle 1897) introduced the hydropneumatic recoil mechanism: the barrel slid back on cylinders rather than transmitting recoil to the carriage, so the gun could fire 15–30 rounds per minute without needing to be re-aimed between shots. Combined with rapid-loading metallic-cartridge ammunition and high-explosive shells, the Soixante-Quinze made every previous artillery piece obsolete. Other powers raced to match: Krupp's 77mm (1896), the British 13- and 18-pounders, the Russian M1902. Quick-firing artillery dominated WWI battlefields and inflicted the majority of all WWI casualties." },
  { id: "dreadnought-battleship", name: "Dreadnought Battleship", era: "industrial", category: "weapons",
    year: "1906", prereqs: ["ironclad-warship", "modern-quick-firing-artillery"],
    desc: "HMS *Dreadnought* (Royal Navy, commissioned December 1906) consolidated the all-big-gun, steam-turbine-powered battleship: ten 12-inch guns in five centerline turrets, 21-knot turbine propulsion (faster than any prior battleship), heavy belt armor, controlled by central fire-direction. Her launch instantly obsoleted every previous battleship including those still under construction. Britain, Germany, the U.S., Japan, and others joined a furious dreadnought race that strained European budgets and contributed directly to the geopolitical pressure leading to WWI. Jutland (1916) was the only fleet-vs-fleet dreadnought engagement; aircraft carriers displaced battleships within a generation." },

  // ─── Fusion power decomposition ───
  { id: "inertial-confinement-fusion", name: "Inertial Confinement Fusion", era: "future", category: "energy",
    year: "2035", prereqs: ["plasma-physics", "advanced-chip-manufacturing"],
    desc: "Compressing a millimeter-scale deuterium-tritium fuel pellet by 192 simultaneous laser pulses faster than it can fly apart, briefly reaching the ~100 million °C and ~100 g/cm³ conditions for fusion. The U.S. National Ignition Facility (Lawrence Livermore) achieved the first laboratory ignition (Q>1) in December 2022, releasing more fusion energy than the lasers delivered to the target. By the mid-2030s repeatable, higher-gain ignition becomes routine; the path to a commercial inertial-fusion power plant remains harder than tokamaks (rep-rate, target-injection, optic damage), but inertial fusion provides invaluable physics data and unlocks pulsed-fusion propulsion concepts." },
  { id: "magnetic-confinement-fusion", name: "Magnetic Confinement Fusion", era: "future", category: "energy",
    year: "2040", prereqs: ["plasma-physics", "advanced-chip-manufacturing"],
    desc: "A toroidal magnetic field bottles a hot deuterium-tritium plasma so it never touches the chamber walls, enabling steady-state fusion at Q>10 (ten times more energy out than in). ITER (Cadarache, France, first plasma 2034) and Commonwealth Fusion Systems' SPARC (high-temperature-superconductor tokamak) target the breakthrough; the Joint European Torus, EAST, and KSTAR provide the operational experience base. By 2040 sustained burning plasma is routine in multiple machines worldwide. The challenge transitions from physics to engineering: divertor heat loads, neutron-induced material damage, and continuous tritium fueling all need solving before commercial reactors are economic." },
  { id: "tritium-breeding", name: "Tritium Breeding", era: "future", category: "energy",
    year: "2050", prereqs: ["magnetic-confinement-fusion", "nuclear-power"],
    desc: "Generating tritium fuel in-situ by capturing fusion neutrons in a lithium-bearing blanket surrounding the reactor: ⁶Li + n → ⁴He + ³T. Natural tritium is essentially nonexistent (a few kg globally, mostly from fission reactors), so any commercial fusion economy must breed its own. The blanket must achieve a tritium breeding ratio >1.05 to compensate for losses, while also extracting useful heat. ITER's test blanket modules (TBM program) and DEMO-class follow-ons mature the technology through the 2040s. Tritium breeding closes the fusion fuel cycle and is the gating engineering capability between magnetic-confinement physics and grid-scale fusion electricity." },

  // ─── Particle physics & fusion engineering ───
  { id: "cyclotron", name: "Cyclotron", era: "modern", category: "knowledge",
    year: "1932", prereqs: ["electron-discovery", "electromagnetism"],
    desc: "Ernest Lawrence's 1932 cyclotron (UC Berkeley) accelerated charged particles in a spiral by alternating an electric field synchronized with the ion's circular motion in a uniform magnetic field. The 27-inch (1932) and successive 60-inch (1939) and 184-inch (1946) machines reached energies sufficient to disintegrate atomic nuclei, producing artificial radioisotopes (medical and physics use), discovering carbon-14, and seeding nuclear physics as an experimental discipline. Lawrence won the 1939 Nobel. Modern medical cyclotrons produce isotopes for PET scans daily. The principle — circular acceleration in a magnetic field — descends through synchrotrons to the LHC." },
  { id: "synchrotron", name: "Synchrotron", era: "atomic", category: "knowledge",
    year: "1952", prereqs: ["cyclotron", "quantum-mechanics"],
    desc: "Synchrotrons increase the magnetic field strength as particles gain energy, keeping them on a fixed-radius orbit instead of spiraling outward — overcoming the relativistic mass-energy growth that limits cyclotrons. The Cosmotron (Brookhaven, 1952, 3 GeV) was the first GeV-class machine; Bevatron (Berkeley, 1954) discovered the antiproton (1955); the AGS, CERN PS, Tevatron (Fermilab, 1983, ~1 TeV), and LEP/LHC at CERN form the lineage. Each generation roughly an order of magnitude more energetic. Synchrotron radiation — initially a nuisance — became its own scientific tool, producing X-ray light sources used across biology, materials science, and chemistry." },
  { id: "quantum-electrodynamics", name: "Quantum Electrodynamics", era: "atomic", category: "knowledge",
    year: "1948", prereqs: ["quantum-mechanics", "relativity"],
    desc: "The first relativistic quantum field theory, describing the electromagnetic interaction between charged particles via virtual-photon exchange. Richard Feynman, Julian Schwinger, and Shin'ichirō Tomonaga independently formulated the renormalized theory (1947–48), each receiving the 1965 Nobel. Feynman diagrams turned arbitrarily complex calculations into a graphical perturbation expansion. QED predicts the electron magnetic moment to 12 decimal places — the most accurately verified theory in all of science. As the template for renormalizable quantum field theory, QED set the methodology that produced the Standard Model two decades later." },
  { id: "standard-model", name: "Standard Model", era: "information", category: "knowledge",
    year: "1973", prereqs: ["quantum-electrodynamics", "synchrotron"],
    desc: "The unified quantum field theory of all known elementary particles and three of the four fundamental forces (electromagnetic, weak, strong; gravity excluded). Glashow-Weinberg-Salam electroweak unification (1967) and Gross-Politzer-Wilczek's asymptotic freedom in QCD (1973) brought the pieces together. Six quarks, six leptons, four gauge bosons, the Higgs — every prediction has held. Limitations are the open problems: gravity, dark matter, neutrino mass mechanism, matter-antimatter asymmetry, the gauge-hierarchy problem. The Standard Model is simultaneously physics's greatest achievement and the puzzle whose limits define current frontier research." },
  { id: "string-theory", name: "String Theory", era: "information", category: "knowledge",
    year: "1984", prereqs: ["standard-model", "quantum-mechanics"],
    desc: "Frameworks describing fundamental constituents as one-dimensional vibrating strings rather than point particles, with different vibrational modes giving rise to different particles. The 1984 Green-Schwarz anomaly cancellation triggered the 'first superstring revolution'; Witten's 1995 M-theory unified the five competing superstring formulations. Strings naturally include a graviton-like mode, suggesting a path to quantum gravity. After 40 years, no experimentally distinguishing prediction has been confirmed; the theory's standing as physics-versus-mathematics remains contested. Its mathematical machinery has nonetheless transformed adjacent areas (mirror symmetry, AdS/CFT correspondence, condensed matter) regardless of physical truth." },
  { id: "lhc", name: "Large Hadron Collider", era: "information", category: "knowledge",
    year: "2008", prereqs: ["synchrotron", "semiconductor"],
    desc: "CERN's 27-km-circumference proton-proton collider (Geneva, first beam September 2008, design energy 14 TeV). The energy frontier of accelerator-based physics: 1232 superconducting dipole magnets, ~10,000 tons of liquid helium cooling them to 1.9 K. Four major detectors — ATLAS, CMS, ALICE, LHCb — observe collision products. The 2012 Higgs boson discovery confirmed the Standard Model's last predicted particle. Successor proposals: HL-LHC (2030+, 10× luminosity), FCC (~100 km, 100 TeV), and dedicated Higgs factories. The LHC is humanity's most expensive ($5+B) and complex single instrument." },
  { id: "higgs-discovery", name: "Higgs Boson Discovery", era: "information", category: "knowledge",
    year: "2012", prereqs: ["standard-model", "lhc"],
    desc: "On July 4, 2012, the ATLAS and CMS collaborations at the LHC jointly announced observation of a new boson at ~125 GeV, with properties consistent with the Standard Model Higgs predicted by Peter Higgs and others in 1964. Subsequent measurements (spin 0, parity even, decays in the predicted ratios) confirmed the identification. Higgs and François Englert received the 2013 Nobel; Peter Higgs's mechanism for electroweak symmetry breaking, theorized 48 years earlier, was finally observed. The Higgs was the last unobserved Standard Model particle; its discovery completed the model and shifted the frontier to what lies beyond it." },
  { id: "higgs-factory", name: "Higgs Factory", era: "future", category: "knowledge",
    year: "2045", prereqs: ["lhc", "advanced-chip-manufacturing"],
    desc: "Next-generation electron-positron colliders dedicated to precision Higgs-boson measurements: International Linear Collider (ILC, Japan, proposed), Future Circular Collider electron-positron stage (FCC-ee, CERN, 91 km), and the Circular Electron Positron Collider (CEPC, China, 100 km). Unlike the LHC's 'discovery machine' role, Higgs factories produce ~10⁶ Higgs bosons in clean e⁺e⁻ environments, enabling sub-percent measurement of Higgs couplings — sensitive to subtle deviations that would point to physics beyond the Standard Model. Operational mid-2040s. Cost ~$15-30B; the gating decision is political-economic, not technical." },
  { id: "fusion-materials", name: "Fusion Materials", era: "future", category: "tools",
    year: "2045", prereqs: ["machine-tool", "magnetic-confinement-fusion"],
    desc: "Engineered structural materials that survive the unique stress of a fusion reactor: 14 MeV neutron flux causing transmutation and embrittlement, multi-MW/m² heat loads on plasma-facing surfaces, and tritium permeation. Tungsten plasma-facing armor (low sputtering, high melting point), reduced-activation ferritic-martensitic steels (Eurofer-97), oxide-dispersion-strengthened alloys, and SiC/SiC composites for blanket structures. The IFMIF-DONES neutron-source facility (Spain, ~2032) provides the testing environment. Fusion materials gate the transition from physics demonstrators (ITER) to electricity-producing reactors (DEMO, commercial)." },
  { id: "aneutronic-fusion", name: "Aneutronic Fusion", era: "future", category: "energy",
    year: "2085", prereqs: ["fusion-power", "lunar-industrial-base"],
    desc: "Fusion reactions that produce charged particles (helium nuclei) rather than energetic neutrons: deuterium-helium-3 (D + ³He → ⁴He + p) and proton-boron-11 (p + ¹¹B → 3 ⁴He). Aneutronic reactions avoid the neutron-induced material damage and tritium fuel-cycle problems of D-T fusion, and enable direct conversion of charged-particle kinetic energy to electricity (~80% efficiency vs ~33% steam cycle). The catch: required temperatures are 5–10× higher than D-T (~1 billion °C), and ³He is essentially absent on Earth — making lunar regolith mining (helium-3 implanted by solar wind) a long-term economic premise. TAE Technologies and Helion pursue the engineering through the 2050s–2080s." },

  // ─── Interstellar propulsion + quantum precision ───
  { id: "optical-atomic-clock", name: "Optical Atomic Clock", era: "information", category: "knowledge",
    year: "2014", prereqs: ["quantum-mechanics", "semiconductor"],
    desc: "Atomic clocks based on optical (rather than microwave) transitions in laser-cooled atoms or ions. Strontium and ytterbium optical lattice clocks (Jun Ye / NIST-JILA, 2014) achieved fractional accuracy below 10⁻¹⁸ — equivalent to losing or gaining one second over the age of the universe. The clocks are sensitive enough to detect gravitational time dilation across height differences of 1 cm. Applications include redefinition of the SI second (proposed for 2030), tests of fundamental physics (variation of constants, dark-matter detection), and chronometric geodesy — measuring tiny gravitational potential differences for geophysics and resource prospecting." },
  { id: "quantum-sensing", name: "Quantum Sensing", era: "information", category: "knowledge",
    year: "2015", prereqs: ["quantum-mechanics", "semiconductor"],
    desc: "Measurement of physical quantities (magnetic field, gravity, time, rotation, temperature) using quantum coherence as the sensing element. Nitrogen-vacancy (NV) centers in diamond enable nanometer-scale magnetometry; cold-atom interferometers measure gravity with sub-microGal precision; squeezed light extends LIGO's gravitational-wave sensitivity. Quantum sensors achieve precisions classically forbidden by the Heisenberg limit. Commercial deployment from the late 2010s onward — quantum gravimeters for oil/mineral prospecting, atomic-clock GPS-alternatives for navigation in GPS-denied environments, and biological NV magnetometry for neuroimaging." },
  { id: "beamed-sail-propulsion", name: "Beamed-Sail Propulsion", era: "future", category: "transport",
    year: "2050", prereqs: ["directed-energy-weapons", "reusable-rocket"],
    desc: "Earth- or orbit-based phased-laser arrays accelerate gram-scale lightsail probes to a meaningful fraction of c, enabling decades-rather-than-millennia interstellar transit. Robert Forward proposed the concept in 1962; Breakthrough Starshot (Yuri Milner, Stephen Hawking, 2016) initiated serious engineering toward a $10B prototype targeting Alpha Centauri at 0.2c with ~20-year transit. The challenge stack: 100-GW phased laser array, 4×4 m sail surviving the beam, gram-scale electronics surviving deep space and arrival flyby, communication of the data back. Beamed-sail probes are humanity's first plausible interstellar reach." },
  { id: "nuclear-pulse-propulsion", name: "Nuclear Pulse Propulsion", era: "future", category: "transport",
    year: "2060", prereqs: ["nuclear-weapon", "reusable-rocket"],
    desc: "Project Orion (Ted Taylor, Freeman Dyson, 1958–65): a spaceship driven forward by detonating shaped nuclear charges behind a massive pusher plate. The 1963 Partial Test Ban Treaty (banning atmospheric nuclear tests) effectively killed Orion. Project Daedalus (BIS, 1973–78) and Project Longshot (USNA/NASA, 1988) refined into staged-fusion and antimatter-catalyzed variants. Nuclear pulse remains the only known propulsion physics that can deliver large payloads (10,000+ tons) to other star systems within human lifetimes — but the political and environmental constraints have kept it permanently theoretical until any serious interstellar program forces the question." },
  { id: "bussard-ramjet", name: "Bussard Ramjet", era: "far-future", category: "transport",
    year: "2300", prereqs: ["fusion-rocket", "interstellar-probe"],
    desc: "Robert Bussard's 1960 proposal: an interstellar vehicle scoops interstellar hydrogen with a vast magnetic 'ramjet' funnel, fuses it for thrust, and carries no propellant. Theoretically, a Bussard ramjet could accelerate continuously at 1g, reaching arbitrary speeds limited only by relativity. Subsequent analysis (Whitmire 1975, Fishback 1969) revealed the proton-proton fusion cross-section is too small for practical thrust, and magnetic-funnel drag exceeds thrust at most realistic configurations. Despite the engineering pessimism, the Bussard ramjet remains an iconic interstellar concept and the basis for variants (catalyzed CNO-cycle ramjet, ram-augmented interstellar rocket) that may yet prove viable." },
  { id: "antimatter-propulsion", name: "Antimatter Propulsion", era: "far-future", category: "transport",
    year: "2500", prereqs: ["antimatter-production", "fusion-rocket"],
    desc: "Spacecraft propulsion using matter-antimatter annihilation as energy source. Annihilation reactions release ~9×10¹⁶ J/kg — the maximum theoretically possible energy density — giving specific impulses of ~10⁷ seconds, two orders of magnitude beyond fusion. NASA's Robert Frisbee studied antimatter rocket designs; Steven Howe at Los Alamos proposed antiproton-catalyzed micro-fusion as a near-term variant. The gating constraint is antimatter production (~$10¹⁵/gram currently); once that economic barrier falls (post-2400 in this tree), antimatter propulsion enables decade-scale crewed interstellar voyages without warp-class physics." },
  { id: "von-neumann-probe", name: "Self-Replicating Probe", era: "future", category: "transport",
    year: "2090", prereqs: ["self-replicating-machines", "interstellar-probe", "agi"],
    desc: "An autonomous interstellar probe that lands at a target system, mines local asteroidal or planetary material, and builds copies of itself which depart for further stars — turning every reached system into a launchpad for the next wave. The concept is named for John von Neumann's universal-constructor work in the 1940s and was formalized for interstellar settlement by Frank Tipler (1980) and Robert Freitas. With a 0.1 c cruise and a few decades of replication latency per system, an exponential wave of probes can reach every star in the Milky Way in under a million years — astonishingly short on cosmic timescales. The 'Fermi paradox' then sharpens: if such probes are physically possible, why hasn't a single alien civilization sent any? Possible answers range from rarity of intelligence to deliberate non-interference (the 'zoo hypothesis') to filter-style extinction risks." },
  { id: "cryogenic-hibernation", name: "Cryogenic Hibernation", era: "future", category: "medicine",
    year: "2070", prereqs: ["anti-aging", "organ-transplant", "tissue-engineering"],
    desc: "Pausing human metabolism by deep cooling and metabolic-arrest agents, then reviving the body intact. Natural analogues exist — wood frogs survive winter freezing, ground squirrels drop their core to 0°C and slow heart rate to a few beats per minute — and pioneers in cryonics (Alcor, Cryonics Institute) freeze the recently deceased in hopes of future revival, but reversible whole-body hibernation in healthy humans remains beyond current medicine. Persistent obstacles are intracellular ice damage (mitigated by vitrification glassing agents) and ischemia-reperfusion injury on rewarming. Once mastered, hibernation transforms decade- to century-long interstellar voyages from generation-ship problems into individual-passenger problems, lets ICU patients wait weeks for organ availability, and offers a different relationship with time for those willing to skip forward." },
  { id: "kugelblitz-drive", name: "Kugelblitz Drive", era: "far-future", category: "transport",
    year: "2400", prereqs: ["black-hole-engineering", "antimatter-propulsion"],
    desc: "A spacecraft engine fueled by a microscopic artificial black hole — a 'kugelblitz' (German for ball-lightning), so called because it would be created by concentrating an enormous flux of gamma rays at a focal point until photon energy density exceeds the Schwarzschild threshold and a black hole forms from pure light. A black hole of ~10⁶ kg has a Hawking temperature radiating petawatts mostly as gamma rays, which can be reflected off a parabolic mirror behind the engine to produce thrust. Unlike the Alcubierre drive, the kugelblitz violates no energy conditions and respects relativistic causality — it is 'merely' an extreme engineering problem, requiring planetary-scale gamma-ray lasers to ignite the hole and a way to feed it matter at exactly the rate it evaporates. Specific impulses approach 30% of c, opening interstellar travel without exotic physics." },
  { id: "cosmic-string-ftl", name: "Cosmic-String FTL Geometry", era: "far-future", category: "transport",
    year: "2700", prereqs: ["quantum-gravity", "dark-sector-physics"],
    desc: "A speculative faster-than-light geometry exploiting cosmic strings — hypothetical one-dimensional topological defects left over from symmetry-breaking phase transitions in the early universe. J. Richard Gott (1991) showed that two cosmic strings passing each other at relativistic speeds create a region of spacetime containing closed timelike curves, in principle traversable as a shortcut between two distant points. Like the Alcubierre warp drive and traversable wormholes, this scheme depends on physics that may simply not exist: cosmic strings have never been observed despite decades of CMB and gravitational-lensing searches, and even if they exist, manipulating them at galactic scales is unimaginable. Listed here mainly to document that warp drives are not the only proposed FTL geometry, and to flag that all known FTL proposals share the same energy-condition or speculative-physics obstacle." },

  // ─── Entropy / thermodynamic computing ───
  { id: "reversible-computing", name: "Reversible Computing", era: "future", category: "tools",
    year: "2090", prereqs: ["quantum-computing", "photonic-computing"],
    desc: "Computation that avoids erasing bits, escaping the Landauer limit (kT ln 2 of heat dissipated per bit erased) that puts a hard thermodynamic floor under conventional logic. Charles Bennett (1973) proved any computation can in principle be performed reversibly; Edward Fredkin and Tommaso Toffoli's reversible logic gates (1982) and adiabatic CMOS (1990s) provided practical implementations. By 2090 reversible-logic chips become essential at the densest compute scales — the Landauer limit is otherwise the hardest constraint on chips approaching atomic feature sizes. Reversible computing is the gating technology between classical chip scaling and full computronium architectures (matrioshka brains, Jupiter brains)." },
  { id: "civilizational-entropy-management", name: "Civilizational Entropy Management", era: "far-future", category: "energy",
    year: "2400", prereqs: ["dyson-swarm", "reversible-computing"],
    desc: "Engineering the thermodynamic budget of a Type II civilization as a managed resource: nested-temperature compute architectures, controlled radiation patterns at megastructure scale, deliberate use of cosmic background as a heat sink, and operational planning around the entropy cost of every large-scale process. Freeman Dyson's 'Time Without End' (1979) framed the cosmological end-point — that subjectively unbounded civilization can be sustained against heat death by clocking computation progressively slower as the universe cools. Practical entropy management at galactic scale becomes a routine engineering discipline once Type II energy budgets are achieved, with its own institutions, mathematicians, and planning horizons measured in megayears." },

  // ─── Mathematics frontier (near + far future) ───
  { id: "univalent-foundations", name: "Univalent Foundations", era: "future", category: "knowledge",
    year: "2050", prereqs: ["formal-mathematics", "agi"],
    desc: "Vladimir Voevodsky's program (~2009) reformulating mathematics on Homotopy Type Theory rather than Zermelo-Fraenkel set theory: types are interpreted as homotopy types, equivalent structures are formally identified (the univalence axiom), and proof-relevance is built in. By the 2050s, machine-verified mathematics has migrated to univalent foundations as the working substrate for new theorems — the Coq, Lean, and successor proof assistants run natively on HoTT semantics. The shift consolidates a century of category-theoretic development and makes computer-verified mathematics genuinely productive at research frontiers, not just for verifying old results." },
  { id: "langlands-program-completion", name: "Langlands Program Completion", era: "future", category: "knowledge",
    year: "2090", prereqs: ["formal-mathematics", "agi"],
    desc: "Robert Langlands's 1967 letter to André Weil sketched a vast network of conjectures connecting number theory, representation theory, and harmonic analysis — the most ambitious unification program in modern mathematics. Andrew Wiles's 1995 proof of Fermat's Last Theorem solved a Langlands case (modularity for elliptic curves); Peter Scholze's perfectoid spaces (2011) and the geometric Langlands correspondence advances of the 2020s opened the path forward. By the 2090s, AI-assisted theorem provers and decades of Fields-medal-class human work have closed the program — every major Langlands conjecture has either been proven or shown false, with profound implications for arithmetic, automorphic forms, and quantum field theory." },
  { id: "beyond-zfc-foundations", name: "Beyond-ZFC Foundations", era: "far-future", category: "knowledge",
    year: "2200", prereqs: ["univalent-foundations", "superintelligence"],
    desc: "Mathematical foundations beyond Zermelo-Fraenkel set theory with Choice (ZFC, dominant since ~1925) become primary for ongoing research. Candidates include univalent foundations (HoTT, already established), constructive set theories (CZF), New Foundations (Quine), Tarski-Grothendieck, and proposals from large-cardinal hierarchies. The shift is partly driven by the limitations ZFC reveals at very large cardinals, partly by the ergonomic advantages of structural foundations for computer-assisted mathematics. ZFC continues to be taught for historical/pedagogical reasons but is no longer the lingua franca; multiple foundations coexist with translation theorems linking them." },
  { id: "continuum-hypothesis-resolution", name: "Continuum Hypothesis Resolution", era: "far-future", category: "knowledge",
    year: "2250", prereqs: ["beyond-zfc-foundations", "agi"],
    desc: "Cantor's 1878 question — is there a set whose cardinality lies strictly between |ℕ| and |ℝ|? — was shown by Gödel (1940) and Cohen (1963) to be independent of ZFC: it can be assumed true or false without contradiction. By 2250, mathematics' Beyond-ZFC pluralism produces a posthuman consensus on which axiom extension to canonize as 'standard': forcing axioms (Martin's Maximum, MM⁺⁺) become widely adopted, settling CH negatively. The resolution isn't a proof in ZFC but a decision about the foundations themselves — completing a 350-year debate about the nature of mathematical truth and what it means for a question to have an answer." },
  { id: "hypercomputation", name: "Hypercomputation", era: "far-future", category: "knowledge",
    year: "2400", prereqs: ["superintelligence", "p-vs-np-resolved"],
    desc: "Engineered systems performing operations beyond the Turing-computable: oracle queries to undecidable problems, infinite-time computation in finite physical time, hyperarithmetical functions evaluated in bounded resource budgets. Theoretical proposals include Zeno machines (each step takes half the previous time), Malament-Hogarth spacetimes near rotating black holes (where infinite proper time fits inside finite observer-frame time), and quantum oracle constructions. Whether physical hypercomputation is achievable depends on unresolved questions in quantum gravity and the structure of physical law. If it is, the boundary between mathematics and physics shifts: previously uncomputable functions become computable, and entire branches of math become accessible to direct evaluation." },
  { id: "trans-computable-mathematics", name: "Trans-Computable Mathematics", era: "far-future", category: "knowledge",
    year: "2500", prereqs: ["hypercomputation", "beyond-zfc-foundations"],
    desc: "Mathematics that operates with provably uncomputable objects as primary research material: explicit bounds on busy-beaver values up to large indices, direct construction of Π¹ₙ-complete sets, Chaitin's Ω engineered to specified precision. Earlier mathematics could refer to such objects only abstractly (proving them to exist); trans-computable mathematics, enabled by hypercomputation hardware, manipulates them concretely. The arithmetical hierarchy collapses below the new threshold of practical computation. Open problems that were 'merely uncomputable' are now routine; new open problems arise at higher levels (Δ¹ⱼ, indescribable cardinals, the structure of the constructible universe at large ordinals)." },

  // ─── Superintelligence downstream ───
  { id: "whole-brain-emulation", name: "Whole-Brain Emulation", era: "far-future", category: "medicine",
    year: "2140", prereqs: ["superintelligence", "brain-computer-interface", "neuroscience", "theory-of-consciousness"],
    desc: "High-fidelity scan and simulation of an individual biological brain, reproducing the functional dynamics of the original to a degree where personhood, memory, and behavior transfer continuously across substrates. The OpenWorm project (C. elegans, 2011–) demonstrated proof-of-concept at the simplest scale; Henry Markram's Blue Brain Project (cortical column, 2005–) and IBM's Synapse (rat brain, 2014) tackled mid-scale; high-resolution full-human connectomes from electron microscopy + functional state from advanced fMRI converge in the late 2130s. WBE is the bridge between the SI era's compute substrates and personal mind uploading. Anders Sandberg and Nick Bostrom's 2008 'Whole Brain Emulation Roadmap' (FHI) remains the technical reference." },
  { id: "knowledge-closure", name: "Knowledge Closure", era: "far-future", category: "knowledge",
    year: "2200", prereqs: ["superintelligence", "formal-mathematics"],
    desc: "Civilization reaches the limit of answerable scientific and mathematical questions: every empirically-determinable physical fact is known, every formally-decidable mathematical proposition is proven or disproven, every causal mechanism in biology and chemistry is mapped. Remaining open problems are demonstrably unprovable in any consistent foundation, experimentally inaccessible, or conceptually malformed. John Horgan's 'The End of Science' (1996) was the early articulation; what the SI era actually achieves is more rigorous closure: a categorical proof-of-completeness for each domain. Knowledge closure profoundly reshapes culture — research as motive force diminishes, art and existential philosophy take on new prominence, and the question of what to do with civilizational time becomes urgent." },
  { id: "subjective-time-compression", name: "Subjective Time Compression", era: "far-future", category: "social",
    year: "2200", prereqs: ["superintelligence", "photonic-computing"],
    desc: "Digital minds running on fast substrates experience time at 10⁴–10⁶× biological speed: a year of subjective experience compressed into seconds of wall-clock time. Robin Hanson's 'The Age of Em' (2016) modeled the resulting economy in detail — copies, retirement, savings rates, family structures, all radically transformed when the 'natural' clock rate of a worker is decoupled from solar time. Subjective time compression makes interstellar communication asymmetries even harsher (a sub-light message takes biological centuries but emulated millennia) and produces civilizational stratification along clock-rate lines. The 'fast world' and 'slow world' diverge culturally, economically, and eventually morally." },

  // ─── Warfare doctrine & tactics ───
  { id: "phalanx", name: "Phalanx", era: "classical", category: "weapons",
    year: "~700 BCE", prereqs: ["standing-army", "iron-weapons"],
    desc: "Massed close-order infantry formation in 8-deep ranks bristling with overlapping shields and long thrusting spears (dory or sarissa). Greek hoplites perfected the form (~700 BCE) and used it to defeat the Persians at Marathon (490 BCE) and Plataea (479 BCE); Philip II and Alexander's Macedonian phalanx with 6m sarissai conquered the known world. The phalanx required heavy citizen-soldier discipline and worked only on flat terrain — vulnerabilities the more flexible Roman legion exploited. Its conceptual descendants — Swiss pike squares (1400s), Spanish tercios (1500s), modern infantry line — span 2,500 years of Western warfare." },
  { id: "roman-legion", name: "Roman Legion", era: "classical", category: "weapons",
    year: "~100 BCE", prereqs: ["phalanx", "iron-weapons"],
    desc: "Marian-reform legion (~107 BCE): a permanent professional 4,800-man formation organized into 10 cohorts of 6 centuries, each centurion an experienced career officer with extensive delegated authority. Equipment standardized (gladius, pilum, scutum, lorica). The legion's flexibility — fight in line, in maniples, in testudo formation — defeated phalanxes at Cynoscephalae (197 BCE) and Pydna (168 BCE), Gallic warbands, and Carthaginian armies. Roman military organization established the modern Western model: standardized units, professional officers, logistics doctrine, military engineering as an institutional capability. NATO ranks descend directly from centurion (centurio → centuriarius → captain)." },
  { id: "castle-siege-doctrine", name: "Castle & Siege Doctrine", era: "medieval", category: "weapons",
    year: "1100", prereqs: ["castle", "siege-engine"],
    desc: "Mature high-medieval theory of fortification and siege: concentric castle design (motte-and-bailey → stone keep → curtain walls + flanking towers + barbican), supported by sophisticated siege engineering (countermines, mantlets, siege towers, trebuchets capable of throwing 90 kg projectiles 250m). Crusader fortresses (Krak des Chevaliers) and Edward I's Welsh castles (Caernarfon, Conwy) represent peak design. Defensive doctrine emphasized self-sufficient garrisons surviving year-long sieges; offensive doctrine industrialized siegecraft. The trace italienne (1500s, bastion forts) eventually obsoleted high stone walls in response to gunpowder artillery." },
  { id: "pike-square", name: "Pike Square", era: "renaissance", category: "weapons",
    year: "1476", prereqs: ["knight-cavalry", "longbow"],
    desc: "Massed infantry formation of 5–6m pikes in dense squares of 1,000–10,000 men. Swiss confederate pike squares destroyed Charles the Bold's Burgundian heavy cavalry at Grandson, Murten, and Nancy (1476–77), shattering the medieval cavalry-supremacy paradigm. Landsknechts (German imperial mercenaries) and Spanish tercios (combining pikes with crossbowmen, then arquebusiers) institutionalized the form. Pike squares dominated European warfare from 1480 to ~1700, until socket-bayonets let line infantry combine fire and melee in one formation, ending the pike-and-shot era." },
  { id: "trench-warfare", name: "Trench Warfare", era: "modern", category: "weapons",
    year: "1915", prereqs: ["machine-gun", "modern-quick-firing-artillery"],
    desc: "Defensive doctrine of multiple parallel entrenched lines, barbed-wire belts, machine-gun nests, and pre-registered artillery, that paralyzed WWI's Western Front (1914–18) into four years of attritional stasis. The combination of magazine rifles, quick-firing artillery, machine guns, and barbed wire made traditional infantry assault suicidal — the same week, the Battle of Loos (1915) saw 60,000 British casualties for marginal gains. Trench warfare was the immediate trigger for tank development, chemical weapons, infiltration tactics (Hutier 1917), and ultimately the combined-arms doctrine that broke the deadlock in 1918." },
  { id: "combined-arms-warfare", name: "Combined Arms Warfare", era: "modern", category: "weapons",
    year: "1918", prereqs: ["trench-warfare", "tank"],
    desc: "Coordinated employment of infantry, armor, artillery, and aircraft as a single integrated force, each arm protecting the others' weaknesses. The Hundred Days Offensive (August–November 1918) saw the British Army employ tanks under creeping artillery barrages, with infantry close behind, RAF strafing reserves, and intelligence flowing back from sound-ranging — the first mature combined arms operation. Sir John Monash and Ferdinand Foch institutionalized the concept; J.F.C. Fuller and Heinz Guderian extended it into Plan 1919 and ultimately Blitzkrieg. Combined arms remains the foundational doctrine of modern Western armies." },
  { id: "blitzkrieg", name: "Blitzkrieg", era: "modern", category: "weapons",
    year: "1940", prereqs: ["combined-arms-warfare", "tank"],
    desc: "German operational maneuver doctrine: concentrate armor (Panzer divisions) at a chosen breakthrough point (schwerpunkt), penetrate the enemy line, then exploit deeply with motorized infantry to encircle and shatter rear-area cohesion before the defender can react. Heinz Guderian (Achtung—Panzer!, 1937) synthesized it from interwar British and German theory. Poland (1939, 5 weeks), the Low Countries and France (1940, 6 weeks), and Operation Barbarossa's opening months demonstrated the doctrine's power. Soviet deep-battle doctrine (Tukhachevsky) was the parallel theory; both descended from the WWI combined-arms breakthrough thinking." },
  { id: "ballistic-missile-defense", name: "Ballistic Missile Defense", era: "atomic", category: "weapons",
    year: "1970", prereqs: ["icbm", "radar"],
    desc: "Defensive systems against ballistic missiles: early-warning radars detecting launch, midcourse-phase interceptors targeting warheads in space, and terminal-phase interceptors as a last layer. The U.S. Safeguard system (1975, briefly operational) used nuclear-armed Sprint and Spartan interceptors. The Anti-Ballistic Missile Treaty (1972) limited deployments — strategic stability under MAD required mutual vulnerability. The Strategic Defense Initiative (Reagan, 1983, 'Star Wars') reopened the program; modern systems include Aegis BMD, THAAD, and Ground-Based Midcourse Defense. Effectiveness against peer adversary's saturation attack remains contested." },
  { id: "stealth-aircraft-doctrine", name: "Stealth Aircraft Doctrine", era: "information", category: "weapons",
    year: "1990", prereqs: ["jet-engine", "microprocessor"],
    desc: "Aircraft designed for radar-cross-section minimization through faceted geometry, radar-absorbing coatings, internal weapons bays, and IR signature suppression. The Lockheed F-117 Nighthawk (1981, first combat 1989 Panama, decisive in 1991 Gulf War) was the first operational stealth fighter; the B-2 Spirit (1989) the first stealth bomber. Stealth shifted air doctrine: penetrating contested airspace becomes feasible without large supporting strike packages, enabling decapitation and precision strikes against high-value defended targets. The F-22, F-35, J-20, and Su-57 represent the mature generation. Counter-stealth radar (low-frequency, multistatic, IR search-and-track) drives a continuing arms race." },
  { id: "network-centric-warfare", name: "Network-Centric Warfare", era: "information", category: "weapons",
    year: "2000", prereqs: ["arpanet-internet", "gps"],
    desc: "Doctrine in which military forces operate as a single information system: distributed sensors (satellites, drones, ground radars, individual soldier optics) feed a shared common operational picture; distributed shooters (any platform) engage targets identified by any sensor. Vice-Admiral Arthur Cebrowski formalized the concept (1998). The 1991 Gulf War showed precision-guided munitions; the 2003 Iraq War showed real-time information sharing. By the 2010s, Joint All-Domain Command and Control (JADC2) extended the concept across services and domains. Network-centric warfare is the operational substrate that makes drone swarms, cyber-kinetic operations, and AI-driven decision loops possible." },
  { id: "layered-air-missile-defense", name: "Layered Air & Missile Defense", era: "future", category: "weapons",
    year: "2040", prereqs: ["ballistic-missile-defense", "directed-energy-weapons"],
    desc: "Multi-tier interception architecture covering everything from artillery rockets to ICBMs: short-range systems (Iron Dome, Patriot) handle rockets and tactical ballistic missiles; mid-range (THAAD, Arrow-3) handle theater missiles; strategic (GMD, Aegis SM-3) handle ICBMs; directed-energy weapons handle drones, mortars, and cruise missiles at marginal cost per shot. Israel's combined-arms intercepted ~95% of Hamas rocket fire (May 2021). By 2035 the same architecture extends to peer-state defense, with AI fire-control routing each threat to its cheapest viable interceptor in milliseconds. The economics still favor offense for saturation attacks; layered defense buys time and political space, not invulnerability." },
  { id: "ai-decision-loop-compression", name: "AI Decision Loop Compression", era: "future", category: "weapons",
    year: "2050", prereqs: ["agi", "drone-swarms"],
    desc: "OODA loops (observe-orient-decide-act, John Boyd 1976) operating on millisecond timescales by delegating decisions to AI within tightly-scoped rules of engagement. The doctrine arises because human decision speed (~250ms reaction time, multi-second strategic deliberation) becomes the binding constraint when adversaries' loops are AI-compressed. By 2045, frontline weapons platforms execute target identification, threat prioritization, and engagement decisions algorithmically; humans retain strategic authority but tactical loops run autonomously. The doctrine is contested ethically (lethal autonomous weapons debate) and operationally (brittle to spoofing, unintended escalation), but military-competitive logic drives adoption regardless." },

  // ─── Shelter & architecture (gap fill) ───
  { id: "mammoth-bone-hut", name: "Mammoth Bone Hut", era: "upper-paleo", category: "shelter",
    year: "~25 kya", prereqs: ["hide-clothing", "bone-tools"],
    desc: "Engineered cold-climate dwellings built by Gravettian and later Upper Paleolithic hunters from mammoth long-bones, jaws, and tusks lashed into circular frames and covered with hides. Mezhirich, Ukraine (~15 kya) preserves four such structures, each using ~95 mammoth bones — a labor and material investment implying a permanent winter base camp. Other examples are known from Mezin and Kostenki (Ukraine/Russia) and Dolní Věstonice (Czech Republic). The mammoth-bone hut is the earliest evidence of architecture as deliberate engineering — selecting and assembling specific structural elements rather than occupying natural shelter — and prefigures all later constructed dwellings." },
  { id: "roman-insula", name: "Roman Insula", era: "classical", category: "shelter",
    year: "~100 BCE", prereqs: ["arch-vault", "concrete-roman"],
    desc: "Multi-story urban apartment buildings, typically four to six stories with shops at street level and rented dwellings above. Imperial Rome at peak (~200 CE) housed perhaps 90% of its million-person population in insulae; Ostia preserves the form. Construction used opus latericium (concrete + brick facing) and tile floors over wooden beams. Insulae institutionalized the urban form Mediterranean cities have used continuously since: dense, mixed-use, walkable, vertical. The wealthy lived in domus (single-family courtyard houses) on the same street; the poor lived in collapsing wood-and-mudbrick top floors. Modern apartment housing descends directly from this tradition." },
  { id: "renaissance-dome", name: "Renaissance Architecture", era: "renaissance", category: "shelter",
    year: "1436", prereqs: ["gothic-architecture", "arch-vault"],
    desc: "Filippo Brunelleschi's 1436 dome over Florence Cathedral — the largest masonry dome in the world, built without flying buttresses or wooden centering, using a herringbone brick pattern Brunelleschi rediscovered from Roman precedent. The dome opened the Renaissance architectural revolution: classical orders rediscovered (Alberti, *De re aedificatura* 1452), mathematical proportion as design principle, central plans (Bramante's St. Peter's, 1506), villa architecture (Palladio, 1550). Renaissance architects established the role of the architect-as-intellectual and the building-as-design-product — separating design from construction, as opposed to the medieval master-mason tradition." },
  { id: "iron-frame-construction", name: "Iron-Frame Construction", era: "enlightenment", category: "shelter",
    year: "1779", prereqs: ["coke-iron"],
    desc: "Cast and wrought iron used as primary structural members rather than just decorative or auxiliary elements. Abraham Darby III's Iron Bridge (Coalbrookdale, 1779) was the demonstrator; the Crystal Palace (Joseph Paxton, 1851, 564m × 124m of iron and glass for the Great Exhibition) the breakthrough at scale. Iron framing made unprecedented spans (railway sheds, market halls, exhibition halls) and tall buildings (Eiffel Tower, 1889) possible. The structural revolution prepared the way for steel-frame skyscrapers (1885 Home Insurance Building) and reinforced concrete (1880s); modern construction descends entirely from this 18th-century innovation." },
  { id: "reinforced-concrete", name: "Reinforced Concrete", era: "industrial", category: "shelter",
    year: "1880", prereqs: ["bessemer-steel", "portland-cement", "statics-strength"],
    desc: "Concrete cast around steel-bar reinforcement: the steel takes tensile loads (where unreinforced concrete is weak), the concrete takes compression, and the alkaline matrix protects the steel from rust. Joseph Monier (1867 patent, garden tubs) and François Hennebique (1892, full structural system) established the technique. Reinforced concrete enables long-span floor slabs, cantilevered structures, and economical high-rise — Auguste Perret's apartments, Frank Lloyd Wright's Falling Water (1935), and the entire 20th-century postwar building stock. By 2020, ~30 billion tonnes of concrete are produced globally each year, the most-used construction material in human history." },
  { id: "suburban-tract-housing", name: "Suburban Tract Housing", era: "atomic", category: "shelter",
    year: "1947", prereqs: ["assembly-line", "automobile", "radio-broadcasting"],
    desc: "Mass-produced single-family detached homes laid out as auto-dependent residential subdivisions. William Levitt's Levittown, New York (1947–1951, ~17,000 homes built using Ford-style assembly-line construction) was the prototype; the postwar US, UK, Australian, and Canadian middle-class housing stock follows the same pattern. Federal mortgage policy (FHA, VA loans, GI Bill) plus the Interstate Highway System (1956) institutionalized suburbs as the dominant North American settlement form. Suburbs reshaped daily life around private automobiles, single-zoned residential land use, and the nuclear family — and locked-in dependencies on oil, road infrastructure, and segregated land use that contemporary urbanism is still wrestling with." },
  { id: "parametric-architecture", name: "Parametric Architecture", era: "information", category: "shelter",
    year: "2000", prereqs: ["personal-computer", "gui-mouse", "bauhaus"],
    desc: "Buildings designed through algorithmic and computational rules — parameter spaces explored by software (Rhino + Grasshopper, Dynamo, Maya), construction documented as parametric models (BIM). Frank Gehry's Walt Disney Concert Hall (2003), Zaha Hadid's Heydar Aliyev Center (2012), and Patrik Schumacher's theory of 'parametricism' (2008) define the form. Computational design enables surfaces, structures, and façades that can't be drawn by hand — every panel a unique geometry, every node a custom connection. Critics argue parametric architecture's signature curvy geometries are a stylistic mannerism more than a substantive innovation; advocates argue it is the first building paradigm whose grammar exists only in code." },
  { id: "smart-building", name: "Smart Building", era: "information", category: "shelter",
    year: "2015", prereqs: ["arpanet-internet", "microprocessor"],
    desc: "Buildings integrating dense sensor networks, programmable HVAC and lighting controls, occupancy detection, and predictive analytics into a single building-management system (BMS). Energy use is optimized in real-time, security is continuous, occupants control their environment via smartphone, and operational data feeds back into design improvements. The Edge (Amsterdam, 2015) became the canonical demonstrator with 28,000 sensors and BREEAM rating of 98.36% (highest ever scored). Smart buildings cut typical commercial-building energy consumption by 30–50% and become substrate nodes in the broader smart-city/IoT fabric — but raise persistent privacy and cybersecurity questions." },

  // ─── Subsistence & agriculture (gap fill) ───
  { id: "food-preservation", name: "Food Preservation", era: "upper-paleo", category: "subsistence",
    year: "~25 kya", prereqs: ["cooking", "fire-making", "hafting"],
    desc: "Smoking, drying, salting, and fermenting techniques that extend perishable food beyond a few days. Smoked salmon caches in Ice-Age Siberia and dried meat (jerky) of mammoth-hunting peoples are the earliest evidence; the same principles underpin pemmican, biltong, jamón, prosciutto, gravlax, kimchi, and miso. Preservation transforms the seasonal feast-and-famine cycle into a continuous food supply, supporting larger group sizes, longer winters in temperate zones, and the surplus needed for sedentism. Without it, no Neolithic agricultural transition is possible." },
  { id: "beekeeping", name: "Beekeeping", era: "bronze", category: "subsistence",
    year: "~3000 BCE", prereqs: ["pottery", "village"],
    desc: "Managed honeybee (Apis mellifera) hives in pottery, woven straw skeps, or hollow logs. Egyptian apiaries (~2400 BCE) used cylindrical clay hives stacked in groves; Hittite and Greek records (Hesiod) document the practice. Honey was the primary sweetener of antiquity, the key fermentation sugar for mead, and a wound antiseptic. Beeswax provided candles, sealing, lost-wax casting media, and writing tablets. The first managed insect domestication; the practice survives largely unchanged in artisan apiaries today, though commercial pollination services (Apis + bumblebees) now drive a global $200+ billion industry tied to almond, blueberry, and orchard agriculture." },
  { id: "cheese-dairy-processing", name: "Cheese & Dairy Processing", era: "neolithic", category: "subsistence",
    year: "~7500 BCE", prereqs: ["animal-domestication", "pottery"],
    desc: "Conversion of perishable milk into shelf-stable products through curdling, draining, salting, and aging: butter, yogurt, cheese in dozens of regional varieties. The oldest evidence is milk-fat lipid residues on early Neolithic pottery from northwest Anatolia (Evershed et al. 2008, ~7500 BCE), with confirmed cheese-making at Kuyavia (Poland, ~5500 BCE) where pottery sieves preserve casein-rich residues. Rennet (calf-stomach enzyme) curdles casein proteins into solid curd; salt and aging shape the final product. Dairy processing made nomadic pastoralism viable (lactose-tolerance evolution swept Europe in <5000 years) and gave settled agrarian societies a calorie-dense, transportable food. Modern industrial dairying produces ~700 million tonnes of milk annually." },
  { id: "salt-production", name: "Salt Production", era: "bronze", category: "subsistence",
    year: "~3000 BCE", prereqs: ["pottery", "fire-making"],
    desc: "Rock-salt mining (Hallstatt, Austria, ~1200 BCE; Roman salinarum) and brine evaporation in pottery vessels or open pans (Halle in Germany, Sichuan in China). Salt was the only food preservative besides drying available before refrigeration: salt pork, salt cod, salt fish, salted vegetables formed the protein and vitamin reservoir of every pre-modern population through winter. Salt taxes (gabelle in France, Roman annona) financed governments; the Latin 'salarium' (salary) was salt money paid to soldiers. Trans-Saharan salt routes traded salt for gold one-for-one. Industrialization eventually made salt cheap enough to disappear as an economic factor, but the geography of pre-modern civilization tracks salt sources closely." },
  { id: "latifundia", name: "Latifundia", era: "classical", category: "subsistence",
    year: "~200 BCE", prereqs: ["empire", "plow-ard"],
    desc: "Roman large-scale agricultural estates (typically 1,000–10,000 hectares) worked primarily by enslaved labor and producing grain, olive oil, wine, and livestock for the Mediterranean market. The Punic Wars (264–146 BCE) flooded Rome with slaves and bankrupted small farmers; their plots consolidated into latifundia owned by Senatorial elites. Cato's *De Agricultura* (~160 BCE) and Varro's *Rerum Rusticarum* (~37 BCE) document the management practices. The Roman grain trade — North African and Egyptian wheat shipped to feed the city of Rome's million inhabitants — was the first integrated long-distance food market. Latifundia patterns recur in every later large-estate slave economy: Brazilian sugar, U.S. South cotton, Spanish American haciendas." },
  { id: "sugar-plantation", name: "Sugar Plantation", era: "renaissance", category: "subsistence",
    year: "1500", prereqs: ["colonialism", "columbian-exchange"],
    desc: "Caribbean and Brazilian plantation system producing sugar from sugarcane (originally from Southeast Asia, brought by Columbus on his second voyage 1493). The first integrated agro-industrial process: cane cultivation, harvest, milling, boiling, crystallization, and shipping all on a single estate. Hispaniola, Cuba, Barbados, and Brazil became sugar economies by 1600; Saint-Domingue (Haiti) was the world's largest sugar producer by 1789. The plantation system industrialized slavery — ~12 million enslaved Africans were transported to the Americas, the majority to sugar plantations. Sugar's calorie cheapness drove Atlantic-trade wealth into European cities, structured the Triangle Trade, and remained the model for later cash-crop colonial economies." },
  { id: "canning", name: "Canning & Tinned Food", era: "industrial", category: "subsistence",
    year: "1810", prereqs: ["chemistry-modern", "factory-system"],
    desc: "Nicolas Appert's heat-processing of food in glass jars (1810, prize-winning method commissioned by Napoleon to feed his armies); Bryan Donkin's tin-plated steel cans (1813) commercialized the process. Pasteur (1864) supplied the bacteriological understanding 50 years later. Canned food fed Napoleonic and Civil War armies, fueled Arctic exploration (with disastrous lead-soldering side effects), and stocked 19th-century city pantries. By the late 1800s canned tomatoes, fish, milk, and vegetables had transformed working-class diets and decoupled urban populations from local seasonal agriculture. Modern canning (and parallel inventions: Mason jar 1858, retort processing) underpins global food trade." },
  { id: "mechanical-reaper", name: "Mechanical Reaper", era: "industrial", category: "subsistence",
    year: "1831", prereqs: ["machine-tool", "agricultural-revolution"],
    desc: "Cyrus McCormick's horse-drawn reaper (Virginia, 1831) cut grain stalks via reciprocating saw-tooth blade, depositing the crop in windrows for hand-binding. By the 1850s the McCormick Reaper Works in Chicago was producing tens of thousands of units annually; the reaper-binder (1872) added automated binding; the combine harvester (1880s onward) integrated cutting, threshing, and cleaning. Mechanization collapsed the labor cost of grain harvest from 56 hours per acre (hand reaping) to <5 hours (combine), opening prairie agriculture, freeing farm workers for industrial cities, and integrating American grain into the global market alongside Russian and Australian wheat exports." },
  { id: "pasteurization", name: "Pasteurization", era: "industrial", category: "subsistence",
    year: "1864", prereqs: ["germ-theory", "chemistry-modern"],
    desc: "Louis Pasteur's 1864 demonstration that mild heating (60–70 °C, brief duration) kills the microorganisms responsible for milk and beer spoilage without significantly altering taste. Initially saving the French wine industry from contamination, the technique was extended to beer (1876) and milk (1880s+). Compulsory milk pasteurization (Chicago 1908, UK 1949 for milk supplied to schools) eliminated milk-borne tuberculosis, brucellosis, and typhoid as childhood killers. The process was the first practical application of germ theory and made urban milk supply safe at industrial scale, enabling the modern dairy industry. Modern variants — UHT (ultra-high temperature, 1948), HTST (high-temperature short-time, 1893) — extend shelf life from days to months." },
  { id: "refrigerated-transport", name: "Refrigerated Transport", era: "industrial", category: "subsistence",
    year: "1880", prereqs: ["railroad-network", "chemistry-modern"],
    desc: "Refrigerated rail cars (Gustavus Swift's Chicago meatpacking, 1878+) and refrigerated steamships (SS Strathleven from Australia to London, 1880, first frozen-meat shipment) enabled long-distance perishable food trade. Within a generation, Chicago became the world's meatpacking capital; Argentine and Australian beef + lamb undercut British domestic agriculture; Boston and New York supplied Florida oranges year-round. The cold chain — refrigerated storage at every stage from farm to plate — became the substrate of modern food economy. Refrigerants evolved: ammonia (1850s), CFCs (1928, ozone-destroying, banned 1987 Montreal Protocol), HFCs (1990s), now CO₂ and natural refrigerants for climate compatibility." },
  { id: "tractor", name: "Tractor", era: "modern", category: "subsistence",
    year: "1917", prereqs: ["internal-combustion", "automobile", "electrification"],
    desc: "Henry Ford's Fordson Model F (1917) — first mass-produced gasoline-powered tractor, designed for family farms (~$395, half the price of competitors). Replaced draft horses and oxen for plowing, planting, and harvest, freeing the ~25% of US farmland used to grow horse fodder for human food production. Crawler tractors (Holt 1904, later Caterpillar) extended the form to heavy soils and forestry. Diesel tractors (1932 Caterpillar) became the standard. Mechanization combined with synthetic fertilizer (Haber-Bosch) and hybrid corn collapsed the labor share of agriculture from ~50% of the US workforce in 1900 to <2% today, with proportionate increases in per-farmer output." },
  { id: "synthetic-pesticides", name: "Synthetic Pesticides", era: "modern", category: "subsistence",
    year: "1939", prereqs: ["chemistry-modern", "plastic-polymer"],
    desc: "DDT (Paul Müller, Geigy 1939, Nobel 1948) was the first synthetic chlorinated hydrocarbon insecticide — cheap, persistent, broad-spectrum, and (it seemed) miraculously effective. WHO malaria-eradication campaigns saved tens of millions of lives in the 1950s; agricultural use eliminated countless crop pests. Rachel Carson's *Silent Spring* (1962) documented the ecological costs (bioaccumulation, bird-egg thinning, resistance evolution); DDT was banned for agricultural use in the US (1972) and Stockholm-Convention-restricted globally (2001) for all but vector control. Successor families (organophosphates, pyrethroids, neonicotinoids, glyphosate) continued the trajectory of higher specificity at higher costs and ongoing controversy over pollinator collapse and farmworker exposure." },
  { id: "industrial-aquaculture", name: "Industrial Aquaculture", era: "atomic", category: "subsistence",
    year: "1965", prereqs: ["animal-domestication", "plastic-polymer"],
    desc: "Large-scale fish farming using cages, raceways, and recirculating systems: Norwegian salmon (1970s), Thai shrimp (1980s), Chinese carp (continuous since antiquity but industrialized post-1960). By 2020, aquaculture production exceeded wild-caught fish for the first time (~85 million tonnes farmed vs ~80 million tonnes wild). The industry made fish a cheap, year-round protein staple in many countries while raising problems wild fisheries don't have: antibiotic resistance, escapee genetic pollution of wild stocks, fishmeal demand pressuring lower-trophic-level wild species, and concentrated environmental impact in coastal embayments. Shrimp aquaculture in particular drove tropical mangrove destruction at scale comparable to Amazon deforestation." },
  { id: "frozen-food-supply-chain", name: "Frozen Food Supply Chain", era: "atomic", category: "subsistence",
    year: "1950", prereqs: ["refrigerated-transport", "air-conditioning"],
    desc: "Clarence Birdseye's flash-freezing technique (commercialized 1930) preserved food quality far better than slow freezing; postwar suburban supermarkets (1947+) and home freezers (~1950) closed the cold chain from factory to family freezer. By 1955, frozen TV dinners (Swanson) institutionalized the form; frozen pizza, ice cream, peas, and concentrated orange juice became American staples. The cold chain enabled global frozen-food trade — Argentine beef, New Zealand lamb, Alaskan salmon, Vietnamese shrimp all shipped frozen to distant markets. Cold-chain energy use accounts for ~3-5% of global electricity demand and ~2% of greenhouse-gas emissions, with steadily rising demand from emerging markets." },
  { id: "gmo", name: "Genetic Modification", era: "information", category: "subsistence",
    year: "1996", prereqs: ["genetic-engineering", "green-revolution"],
    desc: "First commercial transgenic crops: Calgene's FlavrSavr tomato (1994, delayed ripening) and Monsanto's Roundup Ready soybean (1996, glyphosate resistance). Bt corn and cotton (Bacillus thuringiensis insecticidal genes) followed. By 2020, ~190 million hectares globally are planted with GM crops — primarily soy, corn, cotton, and canola; primarily in the US, Brazil, Argentina, India, Canada. GMOs delivered measurable yield improvements and pesticide reductions (Bt) but became politically toxic in Europe and adjacent regions; the regulatory split between countries persists. CRISPR-edited crops (2010s+) are typically classified differently than transgenic GM, sometimes escaping the GMO regulatory regime entirely." },
  { id: "vertical-farming", name: "Vertical Farming", era: "information", category: "subsistence",
    year: "2000", prereqs: ["solar-photovoltaic", "gmo", "green-revolution"],
    desc: "Stacked indoor crop production using LED lighting, hydroponic or aeroponic nutrient delivery, and AI-controlled environment optimization. Dickson Despommier's *The Vertical Farm* (2010) popularized the concept; AeroFarms (Newark, 2004), Plenty (San Francisco, 2014), Infarm (Berlin, 2013), and Bowery Farming scaled it commercially. Vertical farms produce leafy greens, herbs, and microgreens 100× more efficiently per land area than field agriculture, with no pesticides and 95% less water — but the LED energy budget is currently economically marginal except for high-value crops near urban markets. Solarpunk advocates see vertical farms as a key element of climate-resilient cities; critics call them an energy-intensive distraction from broader food-system reform." },

  // ─── Post-WWI weapons platforms ───
  { id: "assault-rifle", name: "Assault Rifle", era: "modern", category: "weapons",
    year: "1944", prereqs: ["bolt-action-rifle", "machine-gun"],
    desc: "Select-fire infantry rifle firing an intermediate-cartridge round (between pistol and full-rifle in power). The German StG 44 (1944) — Hugo Schmeisser's 'Sturmgewehr' — was the first; the Soviet AK-47 (Mikhail Kalashnikov, 1947) and the U.S. M16 (Eugene Stoner, 1964) became the global infantry standards. Compared to bolt-action rifles, an assault rifle adds full-auto fire; compared to submachine guns, it adds rifle-class range and accuracy. Light, cheap, robust variants of the AK family have armed both state militaries and insurgencies in essentially every conflict since 1947 — over 100 million produced." },
  { id: "guided-missile-destroyer", name: "Guided Missile Destroyer", era: "atomic", category: "weapons",
    year: "1962", prereqs: ["dreadnought-battleship", "guided-missile"],
    desc: "Surface combatant whose primary armament is missiles rather than guns: long-range surface-to-air (Standard, S-300, Sea Dart) for fleet defense, anti-ship and land-attack cruise missiles (Tomahawk, Harpoon, Kalibr), and torpedo + ASW helicopter for sub-hunting. USS Charles F. Adams (DDG-2, commissioned 1960) and the Soviet Kashin class (1962) marked the transition; the Arleigh Burke class (1991+) and Type 052D (China, 2014+) define the modern form, all built around the Aegis or equivalent combat system. The guided-missile destroyer displaced the gun-armed cruiser and battleship as the workhorse surface combatant of every blue-water navy." },

  // ─── Air defense + military support ───
  { id: "military-logistics", name: "Military Logistics", era: "industrial", category: "weapons",
    year: "1870", prereqs: ["railroad-network", "telegraph"],
    desc: "Modern military supply, movement, and sustainment as a planned discipline. Helmuth von Moltke the Elder's Prussian General Staff (1857–) institutionalized the railroad-and-telegraph mobilization plan, demonstrated decisively against Austria (1866) and France (1870–71). The American Civil War (1861–65) pioneered industrial-scale rail-based military supply on the Union side. Subsequent generations — WWI's munitions logistics, WWII's Red Ball Express and floating naval supply trains, the Berlin Airlift (1948), Vietnam's helicopter logistics, Gulf War sealift — defined modern war as a logistics-bound activity. 'Amateurs talk strategy, professionals talk logistics.'" },
  { id: "anti-aircraft-artillery", name: "Anti-Aircraft Artillery", era: "modern", category: "weapons",
    year: "1916", prereqs: ["modern-quick-firing-artillery", "airplane"],
    desc: "High-angle, fast-traversing artillery designed to engage aircraft. WWI improvised AA was inadequate; WWII saw mature systems — the German 8.8 cm FlaK 18/36 (the famous 88, equally effective against tanks), Bofors 40 mm, Vickers QF 3.7 inch, U.S. M1 90 mm. Combined with rangefinders, predictors, and (after 1940) radar fire-control, AA artillery shot down enormous numbers of bomber aircraft over Germany, Britain, and the Pacific. Surface-to-air missiles displaced AA guns from the high-altitude role after ~1960; close-in cannon (Phalanx CIWS, AK-630) survived for ship and base defense at short range." },
  { id: "combat-medic", name: "Combat Medic & Medevac", era: "atomic", category: "medicine",
    year: "1951", prereqs: ["helicopter", "antibiotics"],
    desc: "Forward medical care plus rapid casualty evacuation. Korean War MASH (Mobile Army Surgical Hospital) units (1950s) and Bell H-13 helicopter medevacs cut field-mortality dramatically by acting on R Adams Cowley's 'golden hour' concept. Vietnam's Dustoff and Medevac UH-1 squadrons routinely flew under fire to retrieve casualties. The Israeli IDF's TCCC (Tactical Combat Casualty Care, 1996+) standardized prolonged field-care for injuries: tourniquets, hemostatic gauze, needle decompression. Modern doctrine (deployed since Iraq/Afghanistan) keeps wounded alive with field-applied care for 60+ minutes; combat death-rate-from-wound has roughly halved since Vietnam." },
  { id: "spy-satellite", name: "Spy Satellite", era: "atomic", category: "weapons",
    year: "1960", prereqs: ["satellite", "photography"],
    desc: "Orbital reconnaissance: KH-1 Corona (U.S., first successful film return August 1960), KH-11 Kennen (1976+, the first electro-optical real-time satellite). The Soviet Zenit-2 (1961), Yantar (1974+), and modern Resurs-P series; China's Yaogan family (2006+); commercial spinoffs (Maxar, Planet Labs, Capella). Spy satellites replaced manned overflights after the 1960 U-2 shootdown, allowing routine surveillance over closed states without political incident. Modern variants combine sub-30-cm optical, synthetic-aperture radar, and signals intelligence; resolution is now constrained more by atmospheric blur than orbit altitude." },
  { id: "awacs", name: "Airborne Early Warning", era: "atomic", category: "weapons",
    year: "1965", prereqs: ["radar", "jet-engine"],
    desc: "Aircraft carrying long-range radar and battle-management consoles, providing radar coverage that cannot be terrain-masked the way ground radars are. Early TBM Avenger and EC-121 Warning Star adaptations (1950s) led to the modern E-3 Sentry (Boeing 707 with 30-foot rotodome, IOC 1977), Russian A-50 Mainstay, Chinese KJ-2000. AWACS aircraft control fighter operations across hundreds of kilometers, vector interceptors onto incoming raids, and provide the airborne 'eyes' that integrated air-defense systems coordinate around. Loss of an AWACS in a peer war would catastrophically degrade fleet/air defense — making them top-tier targets." },
  { id: "iads", name: "Integrated Air Defense System", era: "information", category: "weapons",
    year: "1980", prereqs: ["ballistic-missile-defense", "awacs"],
    desc: "Networked layered defense combining surface-to-air missile batteries, anti-aircraft artillery, fighter aircraft, and AWACS, all linked by hardened command-and-control. Soviet PVO-Strany (1948–98) was the original; modern variants include Russian S-300/S-400 systems, the IADS that defended Saddam Hussein's Iraq (heavily attrited 1991/2003), Iran's Bavar-373 + S-300 mix, and China's HQ-9 + integrated radar fence. Defeating a peer IADS — Suppression of Enemy Air Defenses (SEAD) — drives much of NATO's stealth, electronic-warfare, and stand-off-weapons inventory." },

  // ─── Misc additions (industrial → information) ───
  { id: "cell-theory", name: "Cell Theory", era: "industrial", category: "knowledge",
    year: "1839", prereqs: ["microscope", "chemistry-modern"],
    desc: "Matthias Schleiden (plants, 1838) and Theodor Schwann (animals, 1839): all living organisms are composed of cells, the cell is the basic structural unit, and cells arise only from pre-existing cells (the third proposition added by Rudolf Virchow, 1855: 'omnis cellula e cellula'). Cell theory is to biology what atomic theory is to chemistry — the unifying framework that organizes everything else. It made microbiology, embryology, immunology, oncology, and modern molecular biology possible. Pasteur's germ theory (1860s), Koch's postulates (1884), and the entire 20th-century biomedical revolution all rest on cell theory's foundation." },
  { id: "modern-olympics", name: "Modern Olympics", era: "industrial", category: "social",
    year: "1896", prereqs: ["nation-state", "newspaper-mass"],
    desc: "Pierre de Coubertin's revival of the ancient Greek games: Athens 1896 brought 241 athletes from 14 nations. The IOC formalized international competition in standardized sports under shared rules; subsequent Games (Paris 1900, St. Louis 1904, London 1908) institutionalized the four-year cycle, the medal system, and the opening ceremonies. The Winter Olympics (1924), Paralympics (1948/1960), and Youth Olympics (2010) extended the model. The modern Olympics became the largest peacetime international gathering on Earth — Tokyo 2020 had 11,000 athletes from 206 nations — and a recurring stage for political conflicts (1936 Berlin, 1968 Mexico City, 1972 Munich, 1980/1984 boycotts)." },
  { id: "civil-aviation", name: "Civil Aviation", era: "modern", category: "transport",
    year: "1920", prereqs: ["airplane"],
    desc: "Commercial passenger and cargo air transport. KLM (1919, the oldest still-operating airline), Aeroflot (1923), Imperial Airways (1924), and Pan Am (1927) opened scheduled routes. The Douglas DC-3 (1936) made airline operations economically viable; the Boeing 707 (1958) brought long-haul jet travel; the 747 (1969) and the Concorde (1976) defined the supersonic and jumbo eras. The 1944 Chicago Convention created ICAO and the framework for international aviation rights. Civil aviation collapsed travel times by an order of magnitude (London-New York: 5 days by ship → 7 hours by jet) and connected the world economically and culturally." },
  { id: "mobile-internet", name: "Mobile Internet", era: "information", category: "communication",
    year: "2000", prereqs: ["arpanet-internet", "mobile-phone"],
    desc: "Internet access from cellular handsets. WAP (Wireless Application Protocol, 1999) and i-mode (NTT DoCoMo, Japan, 1999) were the first commercial deployments; 3G (2001+), the iPhone (2007), and Android (2008) made it a mass medium. By 2014, mobile internet usage exceeded desktop usage; by 2024, ~5.5 billion people used mobile internet daily. Mobile internet enabled a new wave of platforms — WhatsApp, Instagram, TikTok, ride-sharing, mobile banking, mobile commerce — and brought online connectivity to populations that had skipped over wireline infrastructure (especially in Africa and South Asia: leapfrogging)." },

  // ─── Realistic Near / Far Future additions ───
  { id: "engineered-microbiome", name: "Engineered Microbiome", era: "future", category: "medicine",
    year: "2043", prereqs: ["synthetic-biology", "gene-therapy"],
    desc: "Designed bacterial communities for the human gut, skin, and oral microbiome — and parallel agricultural and soil microbiomes. Fecal microbiota transplants (FMT) for *C. difficile* infection (FDA approval 2022) demonstrated proof of concept; by 2035 designed mixtures of 50–500 species are routinely prescribed for inflammatory bowel disease, metabolic syndrome, depression (via the gut-brain axis), and immunological conditioning. Soil-microbiome engineering displaces some synthetic-fertilizer demand; agricultural genomes are paired with their optimal microbial partners. Seres Therapeutics, Pendulum, and Indigo Ag are early commercial efforts." },
  { id: "geothermal-drilling", name: "Geothermal Drilling Revolution", era: "future", category: "energy",
    year: "2040", prereqs: ["advanced-chip-manufacturing", "climate-science"],
    desc: "Plasma- and millimeter-wave-based drills (Quaise Energy's gyrotron-based system) replace conventional rotary bits past ~5 km depth, where rock vaporizes faster than mechanical drilling can cut it. Wells reach 10–20 km / 500°C anywhere on Earth, unlocking enhanced geothermal systems (EGS) globally rather than only at plate boundaries. Closed-loop systems (Eavor's loop) allow heat extraction without seismic risk. Geothermal becomes a baseload renewable rivaling fusion in energy density and dispatchability — but with the gating constraint of high-temperature drill-bit lifetime in superheated rock." },
  { id: "senolytic-longevity-therapy", name: "Senolytic Longevity Therapy", era: "future", category: "medicine",
    year: "2045", prereqs: ["gene-therapy", "crispr", "anti-aging"],
    desc: "Drugs and gene therapies that clear senescent cells — non-dividing zombie cells that secrete inflammatory factors and drive much age-related disease. The dasatinib + quercetin combination (D+Q, Mayo Clinic 2015) was the first demonstrated senolytic; UBX0101, navitoclax, and second-generation candidates (Unity Biotechnology, life-biosciences spinouts) follow. By 2040, senolytic protocols compress most age-related morbidity into a brief terminal phase — extending healthspan more than lifespan. Combined with epigenetic reprogramming (Yamanaka factors safely applied to somatic cells) and mTOR inhibitors, this is the realistic core of near-term anti-aging medicine." },
  { id: "brain-brain-communication", name: "Brain-to-Brain Communication", era: "future", category: "communication",
    year: "2075", prereqs: ["brain-computer-interface", "neuroscience"],
    desc: "Direct neural-to-neural transmission of motor commands, sensations, and (eventually) higher-order percepts via paired BCI systems. Miguel Nicolelis's brainet (rats, 2015) and Rajesh Rao's TMS-mediated human-to-human binary signaling (2014) demonstrated proof of concept at vanishingly low bandwidth. By 2075, dense intracortical mesh interfaces support multi-modal real-time signaling — coordinated motor control of shared bodies, shared visual fields, mood/emotion synchronization. Group-mind experiments and consensual hive-mind subcultures emerge; the philosophical and legal question of where one person ends and another begins becomes operational." },
  { id: "theory-of-consciousness", name: "Theory of Consciousness", era: "future", category: "knowledge",
    year: "2080", prereqs: ["neuroscience", "agi"],
    desc: "Empirical resolution of the hard problem: a scientific consensus on what physical configurations give rise to subjective experience and why. Integrated Information Theory (Tononi, 2004), Global Workspace Theory (Baars/Dehaene), Higher-Order Theories, and various successor frameworks compete; AGI-assisted analysis of comprehensive brain emulations and BCI-recorded subjective reports finally produces a falsifiable theory. The implications cascade: legal personhood criteria for AI, ethics of digital minds, animal welfare frameworks, end-of-life criteria, anaesthesia design, and consciousness-engineering all become rigorous practices instead of philosophical debates." },
  { id: "asteroid-capture", name: "Asteroid Capture", era: "far-future", category: "transport",
    year: "2120", prereqs: ["asteroid-mining", "fusion-rocket"],
    desc: "Active relocation of a near-Earth asteroid into stable Earth or lunar orbit for mining and habitation. NASA's Asteroid Redirect Mission concept (2013–2017) was the early study; later proposals use ion thrusters, gravity tractors, mass drivers, or fusion-thermal pushers to apply gentle continuous thrust to a 100–1000 m asteroid over years. Captured into Earth-Moon Lagrangian or distant retrograde orbits, the asteroid becomes a permanent industrial-scale source of platinum-group metals, water (from C-type bodies), and structural mass for in-orbit construction — collapsing launch-cost economics for cislunar industry." },
  { id: "r-process-astromining", name: "R-Process Astromining", era: "far-future", category: "subsistence",
    year: "2400", prereqs: ["kilonova-merger", "asteroid-capture", "interstellar-probe"],
    desc: "Industrial-scale recovery of r-process heavy elements — gold, platinum-group metals, rare earths, uranium, and the trans-iron half of the periodic table — from the diffuse ejecta of past kilonova events and young supernova remnants, rather than from terrestrial mines. Earth's crustal abundances of these elements are limited by the small fraction of primordial r-process dust that happened to be incorporated into our solar nebula 4.6 billion years ago; modern terrestrial reserves of platinum and rhodium are measured in tens of years of consumption at current rates. Galactic r-process material, by contrast, is continuously produced and dispersed by neutron-star mergers (~10⁻³ M☉ per event, mostly heavy elements) and dense expanding shells around recent supernova remnants. Far-future astromining swarms of self-replicating harvester probes, equipped with fusion drives and electrostatic dust collectors, traverse young remnants and merger ejecta clouds and concentrate the heavy fraction electromagnetically before returning condensed cargo to civilization. The economics work only at extreme scale and timescale — round trips measured in centuries — but make heavy elements effectively unlimited resources, ending terrestrial mining of the relevant metals and the geopolitics built around them. The technology presupposes mature interstellar-probe production and the kilonova/supernova astrophysics that locates promising remnants." },
  { id: "bose-einstein-engineering", name: "Bose-Einstein Engineering", era: "far-future", category: "tools",
    year: "2300", prereqs: ["programmable-matter", "quantum-applications"],
    desc: "Macroscopic Bose-Einstein condensates and other quantum-coherent matter states maintained at engineering scales as practical industrial materials. Eric Cornell and Carl Wieman's first BEC (1995) was µg-scale and required nanokelvin temperatures; by the 24th century engineered BECs persist at room scale and tolerable temperatures via topological protection and active error-correction. Applications: ultra-precise atomic-clock substrates, frictionless bearings (superfluid helium analogues), quantum communication channels with no thermal noise, and atom-laser machining at single-atom precision. Atom-laser interferometers detect picometer displacements over kilometers." },
  { id: "anti-senescence-cellular-substrate", name: "Anti-Senescence Cellular Substrate", era: "far-future", category: "medicine",
    year: "2300", prereqs: ["cybernetic-enhancement", "nanotechnology"],
    desc: "Replacement of biological cells with engineered substrates — molecular machines or hybrid bio-synthetic constructs — that perform the same metabolic and structural roles without undergoing entropic damage. Where senolytic therapy (2040) clears senescent cells and gene-edited longevity slows aging, cellular-substrate replacement makes senescence a non-issue: damaged components are replaced rather than repaired. Bodies become Theseus-ship aggregates of progressively non-biological parts, with continuity of identity preserved by gradual substitution rather than wholesale upload. Effective biological immortality without abandoning embodied form." },
];

window.TECH_TREE = { ERAS, CATEGORIES, TECHS };
